        function initPartTimeNpcs() {
            partTimeNpcs = [];
            // Staff NPCs in kitchen area (4 staff)
            for (let i = 0; i < 4; i++) {
                partTimeNpcs.push({
                    x: worldWidth * (0.2 + Math.random() * 0.6),
                    y: worldHeight * (0.05 + Math.random() * 0.22),
                    targetX: 0, targetY: 0,
                    moveTimer: Math.random() * 200,
                    speed: 1.5 + Math.random() * 1.5,
                    walkCycle: Math.random() * Math.PI * 2,
                    bodyHue: randInt(0, 40),
                    limbHue: randInt(0, 40),
                    isStaff: true,
                    scale: 0.95 + Math.random() * 0.15,
                    skinTone: `hsl(25, ${58 + randInt(0, 20)}%, ${78 + randInt(0, 10)}%)`,
                    hairColor: `hsl(${randInt(15, 45)}, ${30 + randInt(0, 25)}%, ${35 + randInt(0, 25)}%)`,
                    faceType: randInt(0, 4),
                    isBoy: Math.random() < 0.5,
                    hairStyle: randInt(0, 2),
                    cheekColor: "hsl(350, 62%, 78%)"
                });
            }
            // Customer NPCs lined up (8 customers)
            for (let i = 0; i < 8; i++) {
                partTimeNpcs.push({
                    x: worldWidth * (0.10 + (i % 4) * 0.22),
                    y: worldHeight * (0.36 + Math.floor(i / 4) * 0.10 + Math.random() * 0.04),
                    targetX: 0, targetY: 0,
                    moveTimer: 0,
                    speed: 0,
                    walkCycle: Math.random() * Math.PI * 2,
                    bodyHue: randInt(0, 360),
                    limbHue: randInt(0, 360),
                    isStaff: false,
                    scale: 0.90 + Math.random() * 0.15,
                    skinTone: `hsl(25, ${58 + randInt(0, 20)}%, ${78 + randInt(0, 10)}%)`,
                    hairColor: `hsl(${randInt(15, 45)}, ${30 + randInt(0, 25)}%, ${35 + randInt(0, 25)}%)`,
                    faceType: randInt(0, 4),
                    isBoy: Math.random() < 0.5,
                    hairStyle: randInt(0, 2),
                    cheekColor: "hsl(350, 62%, 78%)"
                });
            }
            partTimeNpcs.forEach(n => {
                n.targetX = n.x;
                n.targetY = n.y;
            });
        }

        function updatePartTimeNpcs() {
            partTimeNpcs.forEach(npc => {
                if (!npc.isStaff) {
                    npc.walkCycle += 0.015;
                    return;
                }
                npc.moveTimer--;
                if (npc.moveTimer <= 0) {
                    npc.targetX = worldWidth * (0.15 + Math.random() * 0.7);
                    npc.targetY = worldHeight * (0.04 + Math.random() * 0.26);
                    npc.moveTimer = 30 + Math.random() * 60;
                }
                const dx = npc.targetX - npc.x;
                const dy = npc.targetY - npc.y;
                const dist = Math.hypot(dx, dy);
                if (dist > 4) {
                    npc.x += (dx / dist) * npc.speed;
                    npc.y += (dy / dist) * npc.speed;
                    npc.walkCycle += 0.35;
                    npc.dir = dx > 0 ? 1 : -1;
                } else {
                    npc.walkCycle += 0.02;
                }
                resolveObstacleCollision(npc, 15);
            });
        }

        function drawBaseballCap(c, HR) {
            // Crown: shallow arch covering top of head only
            c.fillStyle = "#cc2222";
            c.beginPath();
            c.arc(0, -HR * 0.5, HR * 0.75, Math.PI * 1.1, -Math.PI * 0.1, false);
            c.closePath(); c.fill();
            // Band (rim of cap)
            c.fillStyle = "#aa1818";
            c.beginPath(); c.roundRect(-HR * 0.72, -HR * 0.52, HR * 1.44, 3, 1); c.fill();
            // Brim: large, clearly protruding forward
            c.fillStyle = "#bb2020";
            c.beginPath(); c.ellipse(HR * 0.8, -HR * 0.45, HR * 0.65, 5, -0.1, 0, Math.PI * 2); c.fill();
            // Brim underside shadow
            c.fillStyle = "rgba(0,0,0,0.18)";
            c.beginPath(); c.ellipse(HR * 0.8, -HR * 0.38, HR * 0.55, 3, -0.1, 0, Math.PI); c.fill();
            // Logo badge
            c.fillStyle = "#ffcc00";
            c.beginPath(); c.arc(0, -HR * 0.75, 3, 0, Math.PI * 2); c.fill();
        }

        function drawTopDownNpc(npc, ctx) {
            ctx.save();
            ctx.translate(npc.x, npc.y);

            const s = npc.scale || 0.7;
            const t = npc.walkCycle || 0;
            const moving = Math.abs(Math.sin(t)) > 0.15;
            const verticalBob = moving ? Math.abs(Math.sin(t)) * 2.5 : 0;
            const dir = -(npc.dir || 1);
            ctx.scale(dir * s, s);
            ctx.translate(0, -verticalBob);

            const skinColor = npc.skinTone || "hsl(25, 60%, 80%)";
            const hairColor = npc.hairColor || `hsl(${20 + npc.bodyHue * 0.3}, 30%, 40%)`;
            const cheekColor = npc.cheekColor || "hsl(350, 62%, 78%)";
            const faceType = npc.faceType != null ? npc.faceType : 0;
            const isBoy = npc.isBoy != null ? npc.isBoy : true;
            const hairStyle = npc.hairStyle != null ? npc.hairStyle : 0;

            const bodyColor = npc.isStaff ? "#cc3333" : `hsl(${npc.bodyHue}, 55%, 65%)`;
            const limbColor = npc.isStaff ? "#333" : `hsl(${npc.limbHue || npc.bodyHue}, 45%, 55%)`;
            const longPants = npc.isStaff;
            const shoeColor = "hsl(25, 15%, 30%)";
            const soleColor = "hsl(25, 10%, 22%)";
            const sockColor = "hsl(0, 0%, 93%)";

            let legSwingL, legSwingR, kneeL, kneeR, armSwingL, armSwingR, headBobA;
            if (moving) {
                legSwingL = Math.sin(t) * 0.26;
                legSwingR = Math.sin(t + Math.PI) * 0.26;
                kneeL = Math.max(0, -legSwingL) * 0.4;
                kneeR = Math.max(0, -legSwingR) * 0.4;
                armSwingL = Math.sin(t + Math.PI) * 0.22;
                armSwingR = Math.sin(t) * 0.22;
                headBobA = Math.sin(t * 2) * 0.02;
            } else {
                legSwingL = 0; legSwingR = 0; kneeL = 0; kneeR = 0;
                armSwingL = -0.05; armSwingR = -0.05; headBobA = 0;
            }

            const dp = (x, y, ang, fn) => { ctx.save(); ctx.translate(x, y); ctx.rotate(ang); fn(ctx); ctx.restore(); };

            const drawLeg = (x, y, upperAng, kneeAng) => {
                dp(x, y, upperAng, c => {
                    c.fillStyle = limbColor;
                    c.beginPath(); c.roundRect(-7, -3, 14, 25, 5); c.fill();
                    dp(0, 17, kneeAng, c2 => {
                        if (longPants) {
                            c2.fillStyle = limbColor;
                            c2.beginPath(); c2.roundRect(-6, -4, 12, 22, 4); c2.fill();
                        } else {
                            c2.fillStyle = skinColor;
                            c2.beginPath(); c2.roundRect(-5, 2, 10, 16, 4); c2.fill();
                            c2.fillStyle = limbColor;
                            c2.beginPath(); c2.roundRect(-6.5, -4, 13, 9, 4); c2.fill();
                            c2.fillStyle = sockColor;
                            c2.beginPath(); c2.roundRect(-5.5, 13, 11, 7, 3); c2.fill();
                        }
                        c2.fillStyle = shoeColor;
                        c2.beginPath(); c2.ellipse(2, 20, 10, 5.5, 0, 0, Math.PI * 2); c2.fill();
                        c2.beginPath(); c2.roundRect(-5, 16, 12, 5, [3,3,0,0]); c2.fill();
                        c2.fillStyle = soleColor;
                        c2.beginPath(); c2.moveTo(-6, 21); c2.lineTo(12, 21); c2.lineTo(11, 24); c2.lineTo(-5, 24); c2.closePath(); c2.fill();
                    });
                });
            };
            const drawArm = (x, y, swingAng) => {
                dp(x, y, swingAng, c => {
                    c.fillStyle = bodyColor;
                    c.beginPath(); c.roundRect(-5.5, -2, 11, 10, 4); c.fill();
                    c.fillStyle = skinColor;
                    c.beginPath(); c.roundRect(-4.5, 8, 9, 12, 4); c.fill();
                    dp(0, 20, 0.12, c2 => {
                        c2.fillStyle = skinColor;
                        c2.beginPath(); c2.roundRect(-3.5, 0, 7, 11, 3.5); c2.fill();
                        c2.beginPath(); c2.ellipse(0, 12, 4.5, 3.5, 0, 0, Math.PI * 2); c2.fill();
                    });
                });
            };

            // === Draw order: back-leg → back-arm → body → pants → front-leg → front-arm → head ===
            drawLeg(-8, -7, legSwingL, kneeL);
            drawArm(-15, -54, armSwingL);

            // Body
            if (npc.isStaff) {
                // Staff: red polo + dark apron
                ctx.fillStyle = "#cc3333";
                ctx.beginPath(); ctx.roundRect(-17, -58, 34, 32, 8); ctx.fill();
                ctx.fillStyle = skinColor;
                ctx.beginPath(); ctx.moveTo(-7, -58); ctx.quadraticCurveTo(0, -53, 7, -58); ctx.fill();
                // Collar
                ctx.fillStyle = "#bb2222";
                ctx.beginPath(); ctx.moveTo(-9, -58); ctx.lineTo(-5, -53); ctx.lineTo(-1, -58); ctx.closePath(); ctx.fill();
                ctx.beginPath(); ctx.moveTo(1, -58); ctx.lineTo(5, -53); ctx.lineTo(9, -58); ctx.closePath(); ctx.fill();
                // Apron
                ctx.fillStyle = "#2a2a2a";
                ctx.beginPath(); ctx.roundRect(-15, -42, 30, 22, [0,0,4,4]); ctx.fill();
                ctx.strokeStyle = "#3a3a3a"; ctx.lineWidth = 1;
                ctx.beginPath(); ctx.moveTo(-15, -42); ctx.lineTo(-18, -46); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(15, -42); ctx.lineTo(18, -46); ctx.stroke();
                // Apron pocket
                ctx.strokeStyle = "rgba(255,255,255,0.12)"; ctx.lineWidth = 0.7;
                ctx.beginPath(); ctx.roundRect(-6, -38, 12, 8, 2); ctx.stroke();
            } else {
                // Customer: random color T-shirt
                ctx.fillStyle = bodyColor;
                ctx.beginPath(); ctx.roundRect(-17, -58, 34, 32, 8); ctx.fill();
                ctx.fillStyle = skinColor;
                ctx.beginPath(); ctx.moveTo(-7, -58); ctx.quadraticCurveTo(0, -51, 7, -58); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.08)";
                ctx.beginPath(); ctx.ellipse(2, -44, 10, 12, 0, 0, Math.PI * 2); ctx.fill();
            }

            // Pants
            ctx.fillStyle = limbColor;
            ctx.beginPath(); ctx.roundRect(-16, -28, 32, 24, [0,0,6,6]); ctx.fill();
            ctx.beginPath(); ctx.ellipse(-8, -7, 10, 9, 0, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(8, -7, 10, 9, 0, 0, Math.PI * 2); ctx.fill();

            drawLeg(8, -7, legSwingR, kneeR);
            drawArm(15, -54, armSwingR);

            // Head
            dp(0, -72, headBobA, c => {
                c.scale(-1, 1);
                const HR = 21;
                // BACK HAIR
                c.fillStyle = hairColor;
                if (isBoy) {
                    if (hairStyle === 1) { c.beginPath(); c.arc(0, -1, HR + 5, Math.PI * 0.95, Math.PI * 0.05, false); c.closePath(); c.fill(); }
                    else if (hairStyle === 2) { c.beginPath(); c.arc(0, -1, HR + 2, Math.PI, 0, false); c.closePath(); c.fill(); }
                } else {
                    if (hairStyle === 0) {
                        c.beginPath(); c.arc(0, -1, HR + 4, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.roundRect(-HR - 5, -6, 9, 22, 4); c.fill();
                        c.beginPath(); c.roundRect(HR - 4, -6, 9, 22, 4); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.arc(0, -1, HR + 3, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.ellipse(-20, -8, 8, 14, -0.2, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.ellipse(20, -8, 8, 14, 0.2, 0, Math.PI * 2); c.fill();
                    } else {
                        c.beginPath(); c.arc(0, -1, HR + 4, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.ellipse(-18, -4, 7, 16, 0.25, 0, Math.PI * 2); c.fill();
                    }
                }
                // FACE BASE
                c.fillStyle = skinColor;
                c.beginPath(); c.arc(0, 0, HR, 0, Math.PI * 2); c.fill();
                // Ears
                c.beginPath(); c.arc(-18, 3, 5.5, 0, Math.PI * 2); c.fill();
                c.beginPath(); c.arc(18, 3, 5.5, 0, Math.PI * 2); c.fill();
                // FRONT HAIR
                c.fillStyle = hairColor;
                if (isBoy) {
                    if (hairStyle === 0) {
                        c.beginPath(); c.arc(0, -1, HR + 3, Math.PI, 0, false); c.closePath(); c.fill();
                        c.fillStyle = skinColor;
                        c.beginPath(); c.arc(0, 0, HR, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.arc(-18, 3, 5.5, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.arc(18, 3, 5.5, 0, Math.PI * 2); c.fill();
                        c.fillStyle = hairColor;
                        c.beginPath(); c.moveTo(-17, -21); c.lineTo(-17, -13);
                        c.quadraticCurveTo(-8, -16, 0, -13);
                        c.quadraticCurveTo(8, -16, 17, -13);
                        c.lineTo(17, -21); c.closePath(); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.moveTo(-19, -21); c.lineTo(-19, -10);
                        c.quadraticCurveTo(-10, -13, 0, -10); c.quadraticCurveTo(10, -13, 19, -10);
                        c.lineTo(19, -21); c.closePath(); c.fill();
                    } else {
                        c.globalAlpha = 0.45;
                        c.beginPath(); c.moveTo(-16, -21); c.lineTo(-16, -17); c.lineTo(16, -17); c.lineTo(16, -21); c.closePath(); c.fill();
                        c.globalAlpha = 1;
                    }
                } else {
                    if (hairStyle === 0) {
                        c.beginPath(); c.moveTo(-18, -21); c.lineTo(-18, -11); c.lineTo(18, -11); c.lineTo(18, -21); c.closePath(); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.moveTo(-17, -21); c.lineTo(-17, -11); c.lineTo(17, -11); c.lineTo(17, -21); c.closePath(); c.fill();
                        c.fillStyle = "hsl(345, 65%, 65%)";
                        [[-20, -14], [20, -14]].forEach(([rx, ry]) => {
                            c.beginPath(); c.ellipse(rx - 4, ry, 4, 2.5, -0.3, 0, Math.PI * 2); c.fill();
                            c.beginPath(); c.ellipse(rx + 4, ry, 4, 2.5, 0.3, 0, Math.PI * 2); c.fill();
                            c.beginPath(); c.arc(rx, ry, 1.5, 0, Math.PI * 2); c.fill();
                        });
                    } else {
                        c.beginPath(); c.moveTo(-15, -21); c.lineTo(-15, -12);
                        c.quadraticCurveTo(0, -10, 17, -13); c.lineTo(17, -21); c.closePath(); c.fill();
                    }
                }
                // Staff: red cap over hair
                if (npc.isStaff) {
                    drawBaseballCap(c, HR);
                }
                // FEATURES
                drawBabyFace(c, faceType, skinColor, cheekColor, null, false);
            });

            ctx.restore();
        }

        function initPartTimeDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo || !inheritedChordProgression) return;
            for (let i = 0; i < PARTTIME_DROPS.length; i++) {
                const fac = PARTTIME_DROPS[i];
                const timbres = PARTTIME_FACILITY_TIMBRES[fac.id] || ["register-beep"];
                const pick = randInt(0, timbres.length - 1);
                const timbreName = timbres[pick];
                const patternStyle = PARTTIME_PATTERN_STYLES[timbreName] || "staccato-burst";
                const variant = randInt(0, 1);
                const kbBundle = buildKeyboardLine(baseRhythmInfo, patternStyle, inheritedChordProgression, variant);
                const kb = createPartTimeSynth(timbreName);
                toneDrops.push({
                    x: worldWidth * fac.xFrac,
                    y: worldHeight * fac.yFrac,
                    pattern: kbBundle.pattern,
                    velocityPattern: null,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "keyboard",
                    keyboardSynth: kb.synth,
                    keyboardEffects: kb.effects,
                    keyboardNotes: kbBundle.notes,
                    keyboardAttacks: kbBundle.attacks,
                    keyboardDurations: kbBundle.durations,
                    keyboardSustainType: kbBundle.sustainType,
                    partTimbre: timbreName,
                    activityId: fac.id,
                    activityName: fac.name,
                    activityNameEn: fac.nameEn,
                    dropColor: fac.color,
                    activityLabels: fac.labels,
                    ripples: []
                });
            }
            primeToneDrops();
        }

        function drawPartTimeBackground() {
            const wW = worldWidth, wH = worldHeight;
            const kitchenBottom = wH * 0.22;
            const counterTop = wH * 0.22;
            const counterBottom = wH * 0.27;
            const customerTop = wH * 0.32;
            const seatingTop = wH * 0.55;
            const entranceTop = wH * 0.80;

            // === Floor tiles per zone ===
            const tileSize = 32;
            for (let ty = 0; ty < wH; ty += tileSize) {
                for (let tx = 0; tx < wW; tx += tileSize) {
                    const isEven = ((Math.floor(tx / tileSize) + Math.floor(ty / tileSize)) % 2 === 0);
                    let c1, c2;
                    if (ty < kitchenBottom) { c1 = "#b0b0b0"; c2 = "#a4a4a4"; }
                    else if (ty < counterBottom) { c1 = "#e8ddd0"; c2 = "#ddd2c4"; }
                    else if (ty < seatingTop) { c1 = "#e5ddd2"; c2 = "#dcd4c8"; }
                    else if (ty < entranceTop) { c1 = "#d4c0a8"; c2 = "#ccb8a0"; }
                    else { c1 = "#c0a888"; c2 = "#b8a080"; }
                    ctx.fillStyle = isEven ? c1 : c2;
                    ctx.fillRect(tx, ty, tileSize, tileSize);
                }
            }
            // Grout lines
            ctx.strokeStyle = "rgba(0,0,0,0.06)"; ctx.lineWidth = 0.5;
            for (let ty = 0; ty <= wH; ty += tileSize) { ctx.beginPath(); ctx.moveTo(0, ty); ctx.lineTo(wW, ty); ctx.stroke(); }
            for (let tx = 0; tx <= wW; tx += tileSize) { ctx.beginPath(); ctx.moveTo(tx, 0); ctx.lineTo(tx, wH); ctx.stroke(); }

            // === Kitchen area — steel floor overlay ===
            const kitchenG = ctx.createLinearGradient(0, 0, 0, kitchenBottom);
            kitchenG.addColorStop(0, "#b0b0b0"); kitchenG.addColorStop(1, "#9a9a9a");
            ctx.fillStyle = kitchenG;
            ctx.fillRect(0, 0, wW, kitchenBottom);

            // -- Fluorescent lights (kitchen) --
            for (let li = 0; li < 3; li++) {
                const lx = wW * (0.2 + li * 0.3), ly = wH * 0.005;
                const lgr = ctx.createRadialGradient(lx, ly, 0, lx, ly, wH * 0.06);
                lgr.addColorStop(0, "rgba(255,255,240,0.10)"); lgr.addColorStop(1, "rgba(255,255,240,0)");
                ctx.fillStyle = lgr;
                ctx.fillRect(lx - wW * 0.08, ly, wW * 0.16, wH * 0.06);
                ctx.fillStyle = "#f8f8f0";
                ctx.beginPath(); ctx.roundRect(lx - wW * 0.04, ly, wW * 0.08, wH * 0.006, 2); ctx.fill();
            }

            // -- Exhaust hood --
            ctx.fillStyle = "#888";
            ctx.beginPath(); ctx.roundRect(wW * 0.08, wH * 0.012, wW * 0.30, wH * 0.015, 2); ctx.fill();
            ctx.fillStyle = "#777";
            ctx.beginPath(); ctx.roundRect(wW * 0.55, wH * 0.012, wW * 0.30, wH * 0.015, 2); ctx.fill();

            // -- Fryer (left) — 3D box style --
            const fryX = wW * 0.10, fryY = wH * 0.03, fryW = wW * 0.20, fryH = wH * 0.08;
            const fryDepth = 8;
            // Side panel (3D depth)
            ctx.fillStyle = "#555";
            ctx.beginPath(); ctx.moveTo(fryX + fryW, fryY); ctx.lineTo(fryX + fryW + fryDepth, fryY + fryDepth);
            ctx.lineTo(fryX + fryW + fryDepth, fryY + fryH + fryDepth); ctx.lineTo(fryX + fryW, fryY + fryH); ctx.closePath(); ctx.fill();
            // Front panel (3D depth)
            ctx.fillStyle = "#5a5a5a";
            ctx.beginPath(); ctx.moveTo(fryX, fryY + fryH); ctx.lineTo(fryX + fryDepth, fryY + fryH + fryDepth);
            ctx.lineTo(fryX + fryW + fryDepth, fryY + fryH + fryDepth); ctx.lineTo(fryX + fryW, fryY + fryH); ctx.closePath(); ctx.fill();
            // Control panel on front
            ctx.fillStyle = "#484848";
            ctx.fillRect(fryX + 6, fryY + fryH + 1, fryW - 12, fryDepth - 2);
            ctx.fillStyle = "#ff4444"; ctx.beginPath(); ctx.arc(fryX + 14, fryY + fryH + fryDepth * 0.5, 2, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#44ff44"; ctx.beginPath(); ctx.arc(fryX + 24, fryY + fryH + fryDepth * 0.5, 2, 0, Math.PI * 2); ctx.fill();
            // Temp dial
            ctx.strokeStyle = "#888"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.arc(fryX + fryW - 16, fryY + fryH + fryDepth * 0.5, 3, 0, Math.PI * 2); ctx.stroke();
            ctx.strokeStyle = "#f44"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(fryX + fryW - 16, fryY + fryH + fryDepth * 0.5); ctx.lineTo(fryX + fryW - 14, fryY + fryH + 1); ctx.stroke();
            // Main body top
            ctx.fillStyle = "#6a6a6a";
            ctx.beginPath(); ctx.roundRect(fryX, fryY, fryW, fryH, 4); ctx.fill();
            // Steel highlight
            ctx.fillStyle = "rgba(255,255,255,0.10)";
            ctx.beginPath(); ctx.roundRect(fryX + 2, fryY + 2, fryW - 4, fryH * 0.12, 2); ctx.fill();
            ctx.fillStyle = "rgba(0,0,0,0.10)";
            ctx.fillRect(fryX + 2, fryY + fryH - 3, fryW - 4, 3);
            // Oil basin with glossy gradient
            const oilG = ctx.createLinearGradient(fryX, fryY + fryH * 0.15, fryX, fryY + fryH * 0.85);
            oilG.addColorStop(0, "#d4a840"); oilG.addColorStop(0.4, "#c89830"); oilG.addColorStop(1, "#b08020");
            ctx.fillStyle = oilG; ctx.globalAlpha = 0.65;
            ctx.beginPath(); ctx.roundRect(fryX + 4, fryY + fryH * 0.15, fryW - 8, fryH * 0.7, 3); ctx.fill();
            ctx.globalAlpha = 1;
            // Oil surface shine
            ctx.fillStyle = "rgba(255,240,180,0.15)";
            ctx.beginPath(); ctx.ellipse(fryX + fryW * 0.4, fryY + fryH * 0.3, fryW * 0.25, fryH * 0.08, -0.2, 0, Math.PI * 2); ctx.fill();
            // Bubbles — upward only
            ctx.fillStyle = "rgba(220,190,100,0.45)";
            for (let b = 0; b < 7; b++) {
                const bx = fryX + 8 + ((b * 0.14 + 0.08) * (fryW - 16)) + Math.sin(Date.now() * 0.001 + b * 2.1) * 4;
                const by = fryY + fryH * 0.7 - Math.abs(Math.sin(Date.now() * 0.003 + b * 1.7)) * fryH * 0.4;
                ctx.beginPath(); ctx.arc(bx, by, 2 + Math.sin(Date.now() * 0.005 + b) * 1.2, 0, Math.PI * 2); ctx.fill();
            }
            // Basket handle
            ctx.strokeStyle = "#888"; ctx.lineWidth = 2;
            ctx.beginPath(); ctx.moveTo(fryX + fryW * 0.3, fryY - 3); ctx.lineTo(fryX + fryW * 0.7, fryY - 3); ctx.stroke();
            // Basket mesh hint
            ctx.strokeStyle = "rgba(150,150,150,0.3)"; ctx.lineWidth = 0.5;
            for (let bm = 0; bm < 4; bm++) {
                const bmx = fryX + fryW * 0.35 + bm * fryW * 0.08;
                ctx.beginPath(); ctx.moveTo(bmx, fryY + fryH * 0.2); ctx.lineTo(bmx, fryY + fryH * 0.75); ctx.stroke();
            }

            // -- Heat lamp over fryer --
            ctx.fillStyle = "#cc6600"; ctx.globalAlpha = 0.3;
            ctx.beginPath(); ctx.ellipse(fryX + fryW * 0.5, fryY - 6, fryW * 0.3, 8, 0, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = 1;

            // -- Griddle (right) — 3D box with spatulas --
            const grdX = wW * 0.58, grdY = wH * 0.03, grdW = wW * 0.24, grdH = wH * 0.08;
            const grdDepth = 8;
            // Side panel
            ctx.fillStyle = "#444";
            ctx.beginPath(); ctx.moveTo(grdX + grdW, grdY); ctx.lineTo(grdX + grdW + grdDepth, grdY + grdDepth);
            ctx.lineTo(grdX + grdW + grdDepth, grdY + grdH + grdDepth); ctx.lineTo(grdX + grdW, grdY + grdH); ctx.closePath(); ctx.fill();
            // Front panel
            ctx.fillStyle = "#4a4a4a";
            ctx.beginPath(); ctx.moveTo(grdX, grdY + grdH); ctx.lineTo(grdX + grdDepth, grdY + grdH + grdDepth);
            ctx.lineTo(grdX + grdW + grdDepth, grdY + grdH + grdDepth); ctx.lineTo(grdX + grdW, grdY + grdH); ctx.closePath(); ctx.fill();
            // Legs
            ctx.fillStyle = "#3a3a3a";
            ctx.fillRect(grdX + 4, grdY + grdH + grdDepth, 4, 6);
            ctx.fillRect(grdX + grdW - 8, grdY + grdH + grdDepth, 4, 6);
            // Temp meter on front
            ctx.fillStyle = "#333"; ctx.beginPath(); ctx.roundRect(grdX + grdW * 0.4, grdY + grdH + 1, grdW * 0.2, grdDepth - 2, 1); ctx.fill();
            ctx.fillStyle = "#ff6633"; ctx.fillRect(grdX + grdW * 0.42, grdY + grdH + 2, grdW * 0.12, 2);
            ctx.fillStyle = "#66ff66"; ctx.fillRect(grdX + grdW * 0.42, grdY + grdH + 5, grdW * 0.06, 1);
            // Top surface
            const grdG = ctx.createLinearGradient(grdX, grdY, grdX + grdW, grdY + grdH);
            grdG.addColorStop(0, "#585858"); grdG.addColorStop(0.5, "#505050"); grdG.addColorStop(1, "#484848");
            ctx.fillStyle = grdG;
            ctx.beginPath(); ctx.roundRect(grdX, grdY, grdW, grdH, 3); ctx.fill();
            // Grill lines
            ctx.strokeStyle = "rgba(80,50,30,0.25)"; ctx.lineWidth = 2;
            for (let s = 0; s < 6; s++) {
                const sx = grdX + 8 + s * (grdW - 16) / 5;
                ctx.beginPath(); ctx.moveTo(sx, grdY + 6); ctx.lineTo(sx, grdY + grdH - 6); ctx.stroke();
            }
            // Grease gutter
            ctx.fillStyle = "rgba(100,70,30,0.2)";
            ctx.fillRect(grdX, grdY + grdH - 4, grdW, 4);
            // Patties
            const pattyColors = ["#8a5030", "#7a4525", "#905535"];
            for (let p = 0; p < 3; p++) {
                ctx.fillStyle = pattyColors[p];
                ctx.beginPath(); ctx.ellipse(grdX + grdW * 0.25 + p * grdW * 0.25, grdY + grdH * 0.5, 8, 6, 0, 0, Math.PI * 2); ctx.fill();
                // Sizzle marks
                ctx.strokeStyle = "rgba(60,30,10,0.3)"; ctx.lineWidth = 0.8;
                ctx.beginPath(); ctx.moveTo(grdX + grdW * 0.22 + p * grdW * 0.25, grdY + grdH * 0.5);
                ctx.lineTo(grdX + grdW * 0.28 + p * grdW * 0.25, grdY + grdH * 0.5); ctx.stroke();
            }
            // Spatula 1 (left)
            ctx.save(); ctx.translate(grdX + grdW * 0.12, grdY + grdH * 0.3); ctx.rotate(-0.3);
            ctx.fillStyle = "#888"; ctx.fillRect(-2, -18, 4, 14);
            ctx.fillStyle = "#aaa"; ctx.beginPath(); ctx.roundRect(-6, -4, 12, 8, 2); ctx.fill();
            ctx.fillStyle = "#555"; ctx.fillRect(-1, -18, 2, 5);
            ctx.restore();
            // Spatula 2 (right)
            ctx.save(); ctx.translate(grdX + grdW * 0.88, grdY + grdH * 0.25); ctx.rotate(0.2);
            ctx.fillStyle = "#888"; ctx.fillRect(-2, -16, 4, 12);
            ctx.fillStyle = "#aaa"; ctx.beginPath(); ctx.roundRect(-6, -4, 12, 7, 2); ctx.fill();
            ctx.fillStyle = "#555"; ctx.fillRect(-1, -16, 2, 4);
            ctx.restore();
            // Power indicator
            ctx.fillStyle = "#444"; ctx.beginPath(); ctx.arc(grdX + grdW - 10, grdY + grdH - 8, 5, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#ff6633"; ctx.beginPath(); ctx.arc(grdX + grdW - 10, grdY + grdH - 8, 2, 0, Math.PI * 2); ctx.fill();

            // -- Wire rack shelf --
            ctx.strokeStyle = "#999"; ctx.lineWidth = 1;
            const rackX = wW * 0.36, rackY = wH * 0.03, rackW = wW * 0.18, rackH = wH * 0.04;
            ctx.strokeRect(rackX, rackY, rackW, rackH);
            for (let w = 0; w < 5; w++) {
                const wx = rackX + w * rackW / 4;
                ctx.beginPath(); ctx.moveTo(wx, rackY); ctx.lineTo(wx, rackY + rackH); ctx.stroke();
            }
            // Items on rack
            ctx.fillStyle = "#ddd"; ctx.beginPath(); ctx.roundRect(rackX + 4, rackY + 2, 14, rackH - 4, 2); ctx.fill();
            ctx.fillStyle = "#ccc"; ctx.beginPath(); ctx.roundRect(rackX + 22, rackY + 4, 12, rackH - 6, 2); ctx.fill();

            // -- Refrigerator door --
            ctx.fillStyle = "#c0c0c0";
            ctx.beginPath(); ctx.roundRect(wW * 0.88, wH * 0.02, wW * 0.08, wH * 0.12, 3); ctx.fill();
            ctx.fillStyle = "#aaa";
            ctx.beginPath(); ctx.roundRect(wW * 0.895, wH * 0.04, 4, wH * 0.06, 2); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.08)";
            ctx.fillRect(wW * 0.882, wH * 0.022, wW * 0.076, 3);

            // -- Prep counter (center-low) --
            const prepX = wW * 0.34, prepY = wH * 0.09, prepW = wW * 0.20, prepH = wH * 0.06;
            ctx.fillStyle = "#b8b8b8";
            ctx.beginPath(); ctx.roundRect(prepX, prepY, prepW, prepH, 3); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.06)";
            ctx.fillRect(prepX + 2, prepY + 2, prepW - 4, 3);
            ctx.fillStyle = "#c4a060";
            ctx.beginPath(); ctx.roundRect(prepX + prepW * 0.15, prepY + prepH * 0.2, prepW * 0.35, prepH * 0.6, 2); ctx.fill();
            ctx.strokeStyle = "rgba(160,120,60,0.3)"; ctx.lineWidth = 0.5;
            for (let g = 0; g < 4; g++) {
                const gy = prepY + prepH * 0.25 + g * prepH * 0.12;
                ctx.beginPath(); ctx.moveTo(prepX + prepW * 0.17, gy); ctx.lineTo(prepX + prepW * 0.48, gy); ctx.stroke();
            }
            ctx.fillStyle = "#ddd"; ctx.beginPath(); ctx.roundRect(prepX + prepW * 0.58, prepY + prepH * 0.15, prepW * 0.16, prepH * 0.3, 2); ctx.fill();
            ctx.fillStyle = "#e44"; ctx.fillRect(prepX + prepW * 0.60, prepY + prepH * 0.20, prepW * 0.12, prepH * 0.1);
            ctx.fillStyle = "#ddd"; ctx.beginPath(); ctx.roundRect(prepX + prepW * 0.78, prepY + prepH * 0.15, prepW * 0.16, prepH * 0.3, 2); ctx.fill();
            ctx.fillStyle = "#4a4"; ctx.fillRect(prepX + prepW * 0.80, prepY + prepH * 0.20, prepW * 0.12, prepH * 0.1);

            // -- Sink (kitchen, below griddle) — box-style with dish stack + faucet --
            const snkX = wW * 0.60, snkY = wH * 0.16, snkW = wW * 0.18, snkH = wH * 0.04;
            const snkDepth = 6;
            // Front panel (3D)
            ctx.fillStyle = "#b0b0b0";
            ctx.beginPath(); ctx.moveTo(snkX, snkY + snkH); ctx.lineTo(snkX + snkDepth * 0.5, snkY + snkH + snkDepth);
            ctx.lineTo(snkX + snkW + snkDepth * 0.5, snkY + snkH + snkDepth); ctx.lineTo(snkX + snkW, snkY + snkH); ctx.closePath(); ctx.fill();
            // Cabinet door lines
            ctx.strokeStyle = "rgba(0,0,0,0.1)"; ctx.lineWidth = 0.5;
            ctx.beginPath(); ctx.moveTo(snkX + snkW * 0.33, snkY + snkH + 1); ctx.lineTo(snkX + snkW * 0.33 + 2, snkY + snkH + snkDepth); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(snkX + snkW * 0.66, snkY + snkH + 1); ctx.lineTo(snkX + snkW * 0.66 + 2, snkY + snkH + snkDepth); ctx.stroke();
            // Main body top
            ctx.fillStyle = "#c8c8c8";
            ctx.beginPath(); ctx.roundRect(snkX, snkY, snkW, snkH, 4); ctx.fill();
            // Two basins
            ctx.fillStyle = "#aaddee"; ctx.globalAlpha = 0.5;
            ctx.beginPath(); ctx.roundRect(snkX + 4, snkY + snkH * 0.15, snkW * 0.40, snkH * 0.6, 3); ctx.fill();
            ctx.beginPath(); ctx.roundRect(snkX + snkW * 0.50, snkY + snkH * 0.15, snkW * 0.40, snkH * 0.6, 3); ctx.fill();
            ctx.globalAlpha = 1;
            // Soap bubbles
            ctx.fillStyle = "rgba(200,230,255,0.35)";
            for (let sb = 0; sb < 5; sb++) {
                const sbx = snkX + 8 + Math.sin(Date.now() * 0.002 + sb * 1.3) * (snkW * 0.15) + snkW * 0.12;
                const sby = snkY + snkH * 0.25 + Math.cos(Date.now() * 0.003 + sb * 1.7) * snkH * 0.12;
                ctx.beginPath(); ctx.arc(sbx, sby, 2 + Math.sin(Date.now() * 0.004 + sb) * 1, 0, Math.PI * 2); ctx.fill();
            }
            // Dish stack (right side)
            ctx.fillStyle = "#e8e0d0";
            for (let ds = 0; ds < 5; ds++) {
                ctx.beginPath(); ctx.ellipse(snkX + snkW + 14, snkY + snkH * 0.7 - ds * 3, 10, 3, 0, 0, Math.PI * 2); ctx.fill();
                ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.5;
                ctx.beginPath(); ctx.ellipse(snkX + snkW + 14, snkY + snkH * 0.7 - ds * 3, 10, 3, 0, 0, Math.PI * 2); ctx.stroke();
            }
            // Dirty dish stack (left side)
            ctx.fillStyle = "#d8c8a8";
            for (let ds = 0; ds < 4; ds++) {
                ctx.beginPath(); ctx.ellipse(snkX - 12, snkY + snkH * 0.8 - ds * 3.5, 9, 3, 0.1, 0, Math.PI * 2); ctx.fill();
            }
            ctx.fillStyle = "#cc6633";
            ctx.beginPath(); ctx.ellipse(snkX - 12, snkY + snkH * 0.8 - 14, 7, 2.5, -0.1, 0, Math.PI * 2); ctx.fill();
            // Gooseneck faucet
            ctx.strokeStyle = "#999"; ctx.lineWidth = 3; ctx.lineCap = "round";
            const faucetCx = snkX + snkW * 0.5;
            ctx.beginPath();
            ctx.moveTo(faucetCx, snkY + snkH * 0.15);
            ctx.lineTo(faucetCx, snkY - 8);
            ctx.quadraticCurveTo(faucetCx + 8, snkY - 12, faucetCx + 10, snkY - 2);
            ctx.stroke();
            ctx.fillStyle = "#aaa";
            ctx.beginPath(); ctx.arc(faucetCx + 10, snkY - 1, 2, 0, Math.PI * 2); ctx.fill();
            ctx.lineCap = "butt";
            // Handles (hot/cold)
            ctx.fillStyle = "#cc3333";
            ctx.beginPath(); ctx.arc(faucetCx - 8, snkY + snkH * 0.12, 3, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#3366cc";
            ctx.beginPath(); ctx.arc(faucetCx + 8, snkY + snkH * 0.12, 3, 0, Math.PI * 2); ctx.fill();
            // Drying rack
            ctx.strokeStyle = "#aaa"; ctx.lineWidth = 1;
            const drX = snkX + snkW * 0.6, drY = snkY - 6, drW2 = snkW * 0.35, drH2 = 6;
            ctx.strokeRect(drX, drY, drW2, drH2);
            for (let dw = 0; dw < 4; dw++) {
                ctx.beginPath(); ctx.moveTo(drX + dw * drW2 / 3, drY); ctx.lineTo(drX + dw * drW2 / 3, drY + drH2); ctx.stroke();
            }

            // === Counter divider — clearly visible service counter ===
            // Counter top surface (thick wood grain)
            ctx.fillStyle = "#7a5e3c";
            ctx.fillRect(0, counterTop - 10, wW, 20);
            ctx.strokeStyle = "rgba(90,60,30,0.3)"; ctx.lineWidth = 0.6;
            for (let wl = 0; wl < 12; wl++) {
                const wy = counterTop - 9 + wl * 1.6;
                ctx.beginPath(); ctx.moveTo(0, wy); ctx.lineTo(wW, wy); ctx.stroke();
            }
            // Stainless steel serving rail
            ctx.fillStyle = "#d0d0d0";
            ctx.fillRect(0, counterTop - 12, wW, 3);
            ctx.fillStyle = "rgba(255,255,255,0.45)";
            ctx.fillRect(0, counterTop - 12, wW, 1);
            ctx.fillStyle = "#bbb";
            ctx.fillRect(0, counterTop + 10, wW, 2);
            // Glass sneeze guard
            ctx.fillStyle = "rgba(200,220,240,0.15)";
            ctx.fillRect(0, counterTop - 35, wW, 25);
            ctx.strokeStyle = "rgba(180,200,220,0.25)"; ctx.lineWidth = 0.5;
            ctx.strokeRect(0, counterTop - 35, wW, 25);
            // "ORDER HERE" sign
            ctx.save();
            ctx.fillStyle = "#cc3333";
            const signW = wW * 0.12, signH = wH * 0.018;
            const signX = wW * 0.5 - signW / 2, signY = counterTop - 33;
            ctx.beginPath(); ctx.roundRect(signX, signY, signW, signH, 3); ctx.fill();
            ctx.fillStyle = "#fff";
            ctx.font = `700 ${Math.round(wW * 0.012)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("ORDER HERE", wW * 0.5, signY + signH * 0.5);
            ctx.restore();
            // Down arrows
            ctx.fillStyle = "rgba(204,51,51,0.5)";
            for (let ar = 0; ar < 3; ar++) {
                const ax = wW * (0.42 + ar * 0.08);
                const ay = counterTop - 12 + Math.sin(Date.now() * 0.003 + ar) * 2;
                ctx.beginPath(); ctx.moveTo(ax - 4, ay); ctx.lineTo(ax + 4, ay); ctx.lineTo(ax, ay + 5); ctx.closePath(); ctx.fill();
            }
            // Pole lights at counter ends
            ctx.fillStyle = "#c8a848";
            ctx.beginPath(); ctx.roundRect(wW * 0.04, counterTop - 20, 4, 32, 2); ctx.fill();
            ctx.beginPath(); ctx.arc(wW * 0.04 + 2, counterTop - 22, 5, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "rgba(255,240,180,0.15)";
            ctx.beginPath(); ctx.arc(wW * 0.04 + 2, counterTop - 22, 14, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#c8a848";
            ctx.beginPath(); ctx.roundRect(wW * 0.94, counterTop - 20, 4, 32, 2); ctx.fill();
            ctx.beginPath(); ctx.arc(wW * 0.94 + 2, counterTop - 22, 5, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "rgba(255,240,180,0.15)";
            ctx.beginPath(); ctx.arc(wW * 0.94 + 2, counterTop - 22, 14, 0, Math.PI * 2); ctx.fill();

            // === Counter area ===
            ctx.fillStyle = "#e0d5c5";
            ctx.fillRect(0, counterTop + 12, wW, counterBottom - counterTop - 12);

            // -- Register (on counter) — compact with touch screen + card terminal --
            const regX = wW * 0.10, regY = wH * 0.215, regW = wW * 0.08, regH = wH * 0.035;
            // Base unit
            ctx.fillStyle = "#444";
            ctx.beginPath(); ctx.roundRect(regX, regY, regW, regH, 3); ctx.fill();
            ctx.fillStyle = "#555";
            ctx.beginPath(); ctx.roundRect(regX + 1, regY + 1, regW - 2, regH * 0.35, 2); ctx.fill();
            // Touch screen
            ctx.fillStyle = "#44aa66";
            ctx.beginPath(); ctx.roundRect(regX + 3, regY + 3, regW - 6, regH * 0.28, 1); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.15)";
            ctx.fillRect(regX + 4, regY + 4, (regW - 8) * 0.5, 2);
            // Number pad (small)
            for (let kr = 0; kr < 2; kr++) {
                for (let kc = 0; kc < 3; kc++) {
                    ctx.fillStyle = "#666";
                    ctx.beginPath(); ctx.roundRect(regX + 3 + kc * (regW * 0.25), regY + regH * 0.45 + kr * regH * 0.18, regW * 0.2, regH * 0.13, 1); ctx.fill();
                }
            }
            // Receipt printer
            ctx.fillStyle = "#f5f5e8";
            ctx.beginPath(); ctx.roundRect(regX + regW + 2, regY + 2, regW * 0.3, regH * 0.6, 1); ctx.fill();
            ctx.strokeStyle = "rgba(0,0,0,0.1)"; ctx.lineWidth = 0.3;
            for (let rl = 0; rl < 3; rl++) { ctx.beginPath(); ctx.moveTo(regX + regW + 3, regY + 4 + rl * 3); ctx.lineTo(regX + regW + regW * 0.28, regY + 4 + rl * 3); ctx.stroke(); }
            // Card terminal (beside register)
            ctx.fillStyle = "#333";
            ctx.beginPath(); ctx.roundRect(regX - regW * 0.35, regY + regH * 0.2, regW * 0.3, regH * 0.6, 2); ctx.fill();
            ctx.fillStyle = "#2266aa";
            ctx.beginPath(); ctx.roundRect(regX - regW * 0.32, regY + regH * 0.25, regW * 0.24, regH * 0.2, 1); ctx.fill();

            // -- Tray stack (on counter) --
            ctx.fillStyle = "#b06030";
            for (let ts = 0; ts < 4; ts++) {
                ctx.beginPath(); ctx.roundRect(wW * 0.24, wH * 0.222 + ts * 2.5, wW * 0.05, 2, 1); ctx.fill();
            }

            // -- Cup dispenser (on counter) --
            ctx.fillStyle = "#ddd";
            ctx.beginPath(); ctx.roundRect(wW * 0.32, wH * 0.215, 12, wH * 0.03, 3); ctx.fill();
            ctx.fillStyle = "#f8f0e0";
            for (let cu = 0; cu < 3; cu++) {
                ctx.beginPath(); ctx.arc(wW * 0.32 + 6, wH * 0.22 + cu * 5, 3.5, 0, Math.PI * 2); ctx.fill();
            }

            // -- Condiment station (on counter) --
            ctx.fillStyle = "#e8e0d0";
            ctx.beginPath(); ctx.roundRect(wW * 0.40, wH * 0.22, wW * 0.08, wH * 0.02, 2); ctx.fill();
            const condColors = ["#cc2222", "#ddaa00", "#228822"];
            for (let cd = 0; cd < 3; cd++) {
                ctx.fillStyle = condColors[cd];
                ctx.beginPath(); ctx.roundRect(wW * 0.41 + cd * wW * 0.025, wH * 0.222, 6, wH * 0.014, 2); ctx.fill();
            }

            // -- Drink machine (on counter) --
            const dmX = wW * 0.55, dmY = wH * 0.21, dmW = wW * 0.12, dmH = wH * 0.05;
            ctx.fillStyle = "#606060";
            ctx.beginPath(); ctx.roundRect(dmX, dmY, dmW, dmH, 4); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.05)";
            ctx.fillRect(dmX + 2, dmY + 2, dmW - 4, 4);
            const dColors = ["#cc3333", "#3366cc", "#33aa33"];
            for (let d = 0; d < 3; d++) {
                const dx = dmX + dmW * 0.12 + d * dmW * 0.28;
                ctx.fillStyle = dColors[d];
                ctx.beginPath(); ctx.roundRect(dx, dmY + dmH * 0.12, dmW * 0.22, dmH * 0.35, 2); ctx.fill();
                ctx.fillStyle = "#888";
                ctx.beginPath(); ctx.roundRect(dx + dmW * 0.07, dmY + dmH * 0.5, dmW * 0.08, dmH * 0.08, 1); ctx.fill();
            }
            ctx.fillStyle = "#555";
            ctx.beginPath(); ctx.roundRect(dmX + 4, dmY + dmH * 0.7, dmW - 8, dmH * 0.12, 2); ctx.fill();
            ctx.fillStyle = "#bbddee"; ctx.globalAlpha = 0.6;
            ctx.beginPath(); ctx.roundRect(dmX + dmW * 0.1, dmY + dmH * 0.85, dmW * 0.8, dmH * 0.12, 2); ctx.fill();
            ctx.globalAlpha = 1;

            // === Counter bottom divider ===
            ctx.fillStyle = "#8b7355";
            ctx.fillRect(0, counterBottom - 3, wW, 6);
            ctx.fillStyle = "#a08860";
            ctx.fillRect(0, counterBottom - 4, wW, 2);

            // -- Fluorescent lights (counter) --
            for (let li = 0; li < 3; li++) {
                const lx = wW * (0.2 + li * 0.3), ly = wH * 0.215;
                const lgr = ctx.createRadialGradient(lx, ly, 0, lx, ly, wH * 0.03);
                lgr.addColorStop(0, "rgba(255,255,240,0.08)"); lgr.addColorStop(1, "rgba(255,255,240,0)");
                ctx.fillStyle = lgr;
                ctx.fillRect(lx - wW * 0.05, ly, wW * 0.10, wH * 0.03);
                ctx.fillStyle = "#f8f8f0";
                ctx.beginPath(); ctx.roundRect(lx - wW * 0.025, ly, wW * 0.05, 3, 2); ctx.fill();
            }

            // === Menu board (illuminated/backlit) ===
            const mbX = wW * 0.30, mbY = wH * 0.002, mbW = wW * 0.40, mbH = wH * 0.025;
            // Backlight glow
            const mbGlow = ctx.createRadialGradient(wW * 0.5, mbY + mbH * 0.5, 0, wW * 0.5, mbY + mbH * 0.5, mbW * 0.6);
            mbGlow.addColorStop(0, "rgba(255,240,180,0.12)");
            mbGlow.addColorStop(1, "rgba(255,240,180,0)");
            ctx.fillStyle = mbGlow;
            ctx.fillRect(mbX - mbW * 0.1, mbY - 8, mbW * 1.2, mbH + 16);
            // Board frame
            ctx.fillStyle = "#3a2818";
            ctx.beginPath(); ctx.roundRect(mbX - 5, mbY - 5, mbW + 10, mbH + 10, 4); ctx.fill();
            // Backlit panel
            const mbBg = ctx.createLinearGradient(mbX, mbY, mbX, mbY + mbH);
            mbBg.addColorStop(0, "#1a1a1a"); mbBg.addColorStop(0.5, "#222"); mbBg.addColorStop(1, "#1a1a1a");
            ctx.fillStyle = mbBg;
            ctx.beginPath(); ctx.roundRect(mbX, mbY, mbW, mbH, 2); ctx.fill();
            // Light strip at top edge
            ctx.fillStyle = "rgba(255,240,200,0.25)";
            ctx.fillRect(mbX + 4, mbY + 1, mbW - 8, 2);
            // "MENU" title (glowing)
            ctx.save();
            ctx.shadowColor = "rgba(255,200,50,0.6)"; ctx.shadowBlur = 8;
            ctx.fillStyle = "#ffcc00";
            ctx.font = `700 ${Math.round(wW * 0.02)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("MENU", wW * 0.5, mbY + mbH * 0.32);
            ctx.restore();
            // Menu items (glowing white)
            ctx.save();
            ctx.shadowColor = "rgba(255,255,255,0.4)"; ctx.shadowBlur = 4;
            ctx.fillStyle = "rgba(255,255,255,0.85)";
            ctx.font = `600 ${Math.round(wW * 0.01)}px 'Zen Maru Gothic'`;
            const menuItems = ["SET A ¥500", "SET B ¥600", "SET C ¥700", "DRINK ¥200"];
            for (let mi = 0; mi < menuItems.length; mi++) {
                const mix = mbX + mbW * (0.13 + mi * 0.22);
                ctx.fillText(menuItems[mi], mix, mbY + mbH * 0.72);
            }
            ctx.restore();

            // === Customer waiting area (0.40~0.55) ===
            ctx.fillStyle = "#e5ddd2";
            ctx.fillRect(0, customerTop, wW, seatingTop - customerTop);

            // -- Stanchion poles + rope --
            ctx.fillStyle = "#c8a848";
            const stanchionH = (seatingTop - customerTop) * 0.7;
            for (let sp = 0; sp < 4; sp++) {
                const sx = wW * (0.20 + sp * 0.20), sy = customerTop + 5;
                ctx.beginPath(); ctx.arc(sx, sy, 4, 0, Math.PI * 2); ctx.fill();
                ctx.beginPath(); ctx.roundRect(sx - 2, sy, 4, stanchionH, 2); ctx.fill();
                ctx.fillStyle = "#b89838";
                ctx.beginPath(); ctx.ellipse(sx, sy + stanchionH + 2, 6, 3, 0, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "#c8a848";
            }
            ctx.strokeStyle = "rgba(180,140,80,0.35)"; ctx.lineWidth = 2; ctx.setLineDash([8, 4]);
            for (let rp = 0; rp < 3; rp++) {
                const rx1 = wW * (0.20 + rp * 0.20), rx2 = wW * (0.40 + rp * 0.20);
                ctx.beginPath(); ctx.moveTo(rx1, customerTop + 9); ctx.lineTo(rx2, customerTop + 9); ctx.stroke();
            }
            ctx.setLineDash([]);

            // === Seating area (0.55~0.80) ===
            ctx.fillStyle = "#d8c8b0";
            ctx.fillRect(0, seatingTop, wW, entranceTop - seatingTop);

            // -- Booth tables (4 booths) --
            const boothPositions = [
                { x: 0.12, y: 0.58 }, { x: 0.12, y: 0.68 },
                { x: 0.62, y: 0.58 }, { x: 0.62, y: 0.68 }
            ];
            boothPositions.forEach(bp => {
                const bx = wW * bp.x, by = wH * bp.y;
                const bw = wW * 0.24, bh = wH * 0.08;
                // Left bench
                ctx.fillStyle = "#cc4444";
                ctx.beginPath(); ctx.roundRect(bx, by + 2, 12, bh - 4, 3); ctx.fill();
                ctx.fillStyle = "#aa3333";
                ctx.beginPath(); ctx.roundRect(bx + 2, by + 4, 8, bh - 8, 2); ctx.fill();
                // Right bench
                ctx.fillStyle = "#cc4444";
                ctx.beginPath(); ctx.roundRect(bx + bw - 12, by + 2, 12, bh - 4, 3); ctx.fill();
                ctx.fillStyle = "#aa3333";
                ctx.beginPath(); ctx.roundRect(bx + bw - 10, by + 4, 8, bh - 8, 2); ctx.fill();
                // Table
                ctx.fillStyle = "#c4a060";
                ctx.beginPath(); ctx.roundRect(bx + 16, by + bh * 0.15, bw - 32, bh * 0.7, 3); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.08)";
                ctx.fillRect(bx + 18, by + bh * 0.17, bw - 36, 3);
                // Tray/food on some tables
                if (bp.y < 0.65) {
                    ctx.fillStyle = "#b06030";
                    ctx.beginPath(); ctx.roundRect(bx + bw * 0.35, by + bh * 0.3, bw * 0.2, bh * 0.3, 2); ctx.fill();
                    ctx.fillStyle = "#dd9933";
                    ctx.beginPath(); ctx.ellipse(bx + bw * 0.45, by + bh * 0.45, 6, 4, 0, 0, Math.PI * 2); ctx.fill();
                }
            });

            // -- Round tables (3) with chairs --
            const roundTablePositions = [
                { x: 0.42, y: 0.60 }, { x: 0.42, y: 0.72 }, { x: 0.88, y: 0.65 }
            ];
            roundTablePositions.forEach(rt => {
                const rx = wW * rt.x, ry = wH * rt.y;
                // Table
                ctx.fillStyle = "#c4a060";
                ctx.beginPath(); ctx.arc(rx, ry, 18, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.08)";
                ctx.beginPath(); ctx.arc(rx, ry, 16, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "#c4a060";
                ctx.beginPath(); ctx.arc(rx, ry, 14, 0, Math.PI * 2); ctx.fill();
                // Chairs
                for (let ch = 0; ch < 4; ch++) {
                    const ca = (Math.PI * 2 * ch) / 4 + 0.3;
                    const cx = rx + Math.cos(ca) * 28, cy = ry + Math.sin(ca) * 28;
                    ctx.fillStyle = "#8a7050";
                    ctx.beginPath(); ctx.arc(cx, cy, 8, 0, Math.PI * 2); ctx.fill();
                    ctx.fillStyle = "#7a6040";
                    ctx.beginPath(); ctx.arc(cx, cy, 6, 0, Math.PI * 2); ctx.fill();
                }
            });

            // -- Pendant lights over seating --
            const pendantPositions = [
                { x: 0.24, y: 0.57 }, { x: 0.24, y: 0.67 },
                { x: 0.74, y: 0.57 }, { x: 0.74, y: 0.67 },
                { x: 0.42, y: 0.59 }, { x: 0.42, y: 0.71 }
            ];
            pendantPositions.forEach(pp => {
                const px = wW * pp.x, py = wH * pp.y;
                const lgr = ctx.createRadialGradient(px, py, 0, px, py, 40);
                lgr.addColorStop(0, "rgba(255,240,200,0.12)");
                lgr.addColorStop(1, "rgba(255,240,200,0)");
                ctx.fillStyle = lgr;
                ctx.beginPath(); ctx.arc(px, py, 40, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "#d4a040";
                ctx.beginPath(); ctx.ellipse(px, py - 2, 6, 3, 0, 0, Math.PI * 2); ctx.fill();
            });

            // -- Wall windows in seating area --
            for (let wi = 0; wi < 3; wi++) {
                const wx = wW * (0.05 + wi * 0.35), wy = seatingTop + 8;
                const ww = wW * 0.14, wwh = wH * 0.04;
                // Window frame
                ctx.fillStyle = "#a09080";
                ctx.beginPath(); ctx.roundRect(wx - 2, wy - 2, ww + 4, wwh + 4, 2); ctx.fill();
                // Sky gradient
                const skyG = ctx.createLinearGradient(wx, wy, wx, wy + wwh);
                skyG.addColorStop(0, "#88bbee"); skyG.addColorStop(1, "#aaddff");
                ctx.fillStyle = skyG;
                ctx.beginPath(); ctx.roundRect(wx, wy, ww, wwh, 1); ctx.fill();
                // Window divider
                ctx.fillStyle = "#a09080";
                ctx.fillRect(wx + ww / 2 - 1, wy, 2, wwh);
                ctx.fillRect(wx, wy + wwh / 2 - 1, ww, 2);
            }

            // -- Wall paintings/posters in seating area --
            const seatingPosters = [
                { x: 0.50, y: 0.56, w: 0.06, h: 0.03, c: "#cc8844" },
                { x: 0.90, y: 0.57, w: 0.05, h: 0.04, c: "#4488cc" }
            ];
            seatingPosters.forEach(p => {
                ctx.fillStyle = "#f8f0e0";
                ctx.beginPath(); ctx.roundRect(wW * p.x - 1, wH * p.y - 1, wW * p.w + 2, wH * p.h + 2, 1); ctx.fill();
                ctx.fillStyle = p.c; ctx.globalAlpha = 0.6;
                ctx.fillRect(wW * p.x + 2, wH * p.y + 2, wW * p.w - 2, wH * p.h - 2);
                ctx.globalAlpha = 1;
            });

            // === Entrance area (0.80~1.0) ===
            ctx.fillStyle = "#c8b090";
            ctx.fillRect(0, entranceTop, wW, wH - entranceTop);

            // -- Welcome mat --
            ctx.fillStyle = "#556b2f";
            ctx.beginPath(); ctx.roundRect(wW * 0.38, wH * 0.92, wW * 0.24, wH * 0.04, 3); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.15)";
            ctx.font = `700 ${Math.round(wW * 0.018)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("WELCOME", wW * 0.5, wH * 0.94);

            // -- Glass double doors --
            const doorW = wW * 0.15, doorH = wH * 0.10;
            const doorLX = wW * 0.35, doorRX = wW * 0.52, doorY = wH * 0.82;
            // Left door
            ctx.fillStyle = "rgba(180,210,240,0.25)";
            ctx.beginPath(); ctx.roundRect(doorLX, doorY, doorW, doorH, 3); ctx.fill();
            ctx.strokeStyle = "#999"; ctx.lineWidth = 1.5;
            ctx.strokeRect(doorLX, doorY, doorW, doorH);
            // Door handle
            ctx.fillStyle = "#c0c0c0";
            ctx.beginPath(); ctx.roundRect(doorLX + doorW - 10, doorY + doorH * 0.35, 4, doorH * 0.3, 2); ctx.fill();
            // Right door
            ctx.fillStyle = "rgba(180,210,240,0.25)";
            ctx.beginPath(); ctx.roundRect(doorRX, doorY, doorW, doorH, 3); ctx.fill();
            ctx.strokeStyle = "#999"; ctx.lineWidth = 1.5;
            ctx.strokeRect(doorRX, doorY, doorW, doorH);
            ctx.fillStyle = "#c0c0c0";
            ctx.beginPath(); ctx.roundRect(doorRX + 6, doorY + doorH * 0.35, 4, doorH * 0.3, 2); ctx.fill();
            // Push bar
            ctx.fillStyle = "#aaa";
            ctx.beginPath(); ctx.roundRect(doorLX + 8, doorY + doorH * 0.45, doorW - 16, 3, 1); ctx.fill();
            ctx.beginPath(); ctx.roundRect(doorRX + 8, doorY + doorH * 0.45, doorW - 16, 3, 1); ctx.fill();

            // -- Umbrella stand --
            ctx.fillStyle = "#555";
            ctx.beginPath(); ctx.roundRect(wW * 0.28, wH * 0.84, 14, wH * 0.05, 3); ctx.fill();
            ctx.fillStyle = "#3366aa";
            ctx.beginPath(); ctx.roundRect(wW * 0.28 + 2, wH * 0.84, 3, wH * 0.04, 1); ctx.fill();
            ctx.fillStyle = "#cc4444";
            ctx.beginPath(); ctx.roundRect(wW * 0.28 + 8, wH * 0.84, 3, wH * 0.035, 1); ctx.fill();

            // -- Business hours sign --
            ctx.fillStyle = "#f8f0e0";
            ctx.beginPath(); ctx.roundRect(wW * 0.72, wH * 0.83, wW * 0.08, wH * 0.04, 2); ctx.fill();
            ctx.fillStyle = "#333";
            ctx.font = `${Math.round(wW * 0.008)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center";
            ctx.fillText("OPEN", wW * 0.76, wH * 0.845);
            ctx.fillText("10:00-22:00", wW * 0.76, wH * 0.86);

            // -- Trash/recycling bins --
            const binColors = ["#666", "#336699", "#996633"];
            for (let bi = 0; bi < 3; bi++) {
                const bx = wW * 0.82 + bi * 18, by = wH * 0.88;
                ctx.fillStyle = binColors[bi];
                ctx.beginPath(); ctx.roundRect(bx, by, 14, wH * 0.04, 2); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.15)";
                ctx.beginPath(); ctx.roundRect(bx + 2, by + 2, 10, 4, 1); ctx.fill();
            }

            // -- Takeout counter --
            ctx.fillStyle = "#b8a888";
            ctx.beginPath(); ctx.roundRect(wW * 0.08, wH * 0.84, wW * 0.14, wH * 0.05, 3); ctx.fill();
            ctx.fillStyle = "#f5f0e0";
            ctx.beginPath(); ctx.roundRect(wW * 0.10, wH * 0.85, wW * 0.04, wH * 0.02, 2); ctx.fill();
            ctx.fillStyle = "#f5f0e0";
            ctx.beginPath(); ctx.roundRect(wW * 0.15, wH * 0.85, wW * 0.04, wH * 0.025, 2); ctx.fill();

            // -- Potted plants (entrance) --
            const plantPositions = [{ x: 0.08, y: 0.92 }, { x: 0.92, y: 0.92 }];
            plantPositions.forEach(pp => {
                const px = wW * pp.x, py = wH * pp.y;
                ctx.fillStyle = "#b06030";
                ctx.beginPath(); ctx.moveTo(px - 8, py + 6); ctx.lineTo(px + 8, py + 6);
                ctx.lineTo(px + 6, py + 16); ctx.lineTo(px - 6, py + 16); ctx.closePath(); ctx.fill();
                ctx.fillStyle = "#338833";
                for (let lf = 0; lf < 5; lf++) {
                    const la = (Math.PI * 2 * lf) / 5 - Math.PI / 2;
                    ctx.beginPath(); ctx.ellipse(px + Math.cos(la) * 8, py + Math.sin(la) * 6 - 2, 7, 4, la, 0, Math.PI * 2); ctx.fill();
                }
            });

            // -- Fluorescent lights (seating + entrance) --
            for (let li = 0; li < 2; li++) {
                const lx = wW * (0.3 + li * 0.4), ly = wH * 0.56;
                ctx.fillStyle = "#f8f8f0";
                ctx.beginPath(); ctx.roundRect(lx - wW * 0.03, ly, wW * 0.06, 4, 2); ctx.fill();
            }
            {
                const lx = wW * 0.5, ly = wH * 0.81;
                ctx.fillStyle = "#f8f8f0";
                ctx.beginPath(); ctx.roundRect(lx - wW * 0.04, ly, wW * 0.08, 4, 2); ctx.fill();
            }

            // === Kitchen wall details ===
            ctx.fillStyle = "#a09080";
            ctx.fillRect(0, 0, wW, 3);
            ctx.fillRect(0, 0, 3, kitchenBottom);
            ctx.fillRect(wW - 3, 0, 3, kitchenBottom);

            // Wall posters (kitchen)
            const posterData = [{x: 0.03, y: 0.01, w: 0.06, h: 0.04, c: "#cc4444"}, {x: 0.90, y: 0.015, w: 0.05, h: 0.03, c: "#4488cc"}];
            posterData.forEach(p => {
                ctx.fillStyle = "#f8f0e0";
                ctx.beginPath(); ctx.roundRect(wW * p.x - 1, wH * p.y - 1, wW * p.w + 2, wH * p.h + 2, 1); ctx.fill();
                ctx.fillStyle = p.c; ctx.globalAlpha = 0.6;
                ctx.fillRect(wW * p.x + 2, wH * p.y + 2, wW * p.w - 2, wH * p.h - 2);
                ctx.globalAlpha = 1;
            });

            // Clock
            const clkX = wW * 0.94, clkY = wH * 0.025;
            ctx.fillStyle = "#fff"; ctx.beginPath(); ctx.arc(clkX, clkY, 10, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "#555"; ctx.lineWidth = 1; ctx.beginPath(); ctx.arc(clkX, clkY, 10, 0, Math.PI * 2); ctx.stroke();
            for (let h = 0; h < 12; h++) {
                const ha = (Math.PI * 2 * h) / 12 - Math.PI / 2;
                ctx.fillStyle = "#555";
                ctx.beginPath(); ctx.arc(clkX + Math.cos(ha) * 8, clkY + Math.sin(ha) * 8, 0.8, 0, Math.PI * 2); ctx.fill();
            }
            const now = Date.now();
            const minAngle = ((now / 60000) % 60) / 60 * Math.PI * 2 - Math.PI / 2;
            const hrAngle = ((now / 3600000) % 12) / 12 * Math.PI * 2 - Math.PI / 2;
            ctx.strokeStyle = "#333"; ctx.lineWidth = 1.2; ctx.lineCap = "round";
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(hrAngle) * 5, clkY + Math.sin(hrAngle) * 5); ctx.stroke();
            ctx.strokeStyle = "#333"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(minAngle) * 7, clkY + Math.sin(minAngle) * 7); ctx.stroke();
            ctx.lineCap = "butt";

            // Fire extinguisher
            ctx.fillStyle = "#cc2222";
            ctx.beginPath(); ctx.roundRect(wW * 0.02, wH * 0.10, 8, 16, 3); ctx.fill();
            ctx.fillStyle = "#222";
            ctx.beginPath(); ctx.roundRect(wW * 0.02 + 1, wH * 0.10 - 3, 6, 4, 2); ctx.fill();

            // Employee notice board
            ctx.fillStyle = "#c4a870";
            ctx.beginPath(); ctx.roundRect(wW * 0.86, wH * 0.10, wW * 0.08, wH * 0.05, 2); ctx.fill();
            ctx.fillStyle = "#f5f0e0";
            for (let n = 0; n < 3; n++) {
                ctx.beginPath(); ctx.roundRect(wW * 0.87 + n * wW * 0.02, wH * 0.105 + n * wH * 0.01, wW * 0.02, wH * 0.015, 1); ctx.fill();
            }
            ctx.fillStyle = "#cc4444";
            for (let n = 0; n < 3; n++) {
                ctx.beginPath(); ctx.arc(wW * 0.88 + n * wW * 0.02, wH * 0.105 + n * wH * 0.01, 1.5, 0, Math.PI * 2); ctx.fill();
            }

            // === NPCs ===
            updatePartTimeNpcs();
            partTimeNpcs.forEach(npc => drawTopDownNpc(npc, ctx));
        }

        function handlePartTimeChoice(clickedDrop) {
            if (!clickedDrop.activityLabels) return;
            playTitleToneConfirmSound();
            selectedToys.push({ id: clickedDrop.activityId, name: clickedDrop.activityName, labels: clickedDrop.activityLabels });
            // Save keyboard as Keys2 for carry into THIRTIES
            if (clickedDrop.pattern) {
                inheritedKeys2Pattern = clickedDrop.pattern.slice();
                inheritedKeys2Notes = clickedDrop.keyboardNotes ? clickedDrop.keyboardNotes.slice() : null;
                inheritedKeys2Attacks = clickedDrop.keyboardAttacks ? clickedDrop.keyboardAttacks.slice() : null;
                inheritedKeys2Durations = clickedDrop.keyboardDurations ? clickedDrop.keyboardDurations.slice() : null;
                inheritedKeys2SustainType = clickedDrop.keyboardSustainType ? clickedDrop.keyboardSustainType.slice() : null;
                inheritedKeys2SoundConfig = clickedDrop.partTimbre || clickedDrop.activityId || null;
            }
            addVolumeTrack('keys2');
            disposeToneDrops();
            toneDrops = [];
            partTimeObstacles = [];
            fadeScreenTo(1, 1200);
            setTimeout(() => {
                isTopDownScene = false;
                topDownCameraX = 0;
                topDownCameraY = 0;
                startThirtiesPhase();
                fadeScreenTo(0, 1000);
            }, 1200);
        }

        // ======== JOB HUNT PHASE (就活フェーズ) ========
        const JOBHUNT_TIMBRES = {
            "bright-chime":     { wave: "sine",     attack: 0.005, decay: 0.18, sustain: 0.15, release: 0.12 },
            "bright-sparkle":   { wave: "triangle", attack: 0.001, decay: 0.15, sustain: 0.10, release: 0.10, filterType: "highpass", filterFreq: 1500 },
            "bright-bell":      { wave: "sine",     attack: 0.001, decay: 0.20, sustain: 0.12, release: 0.12 },
            "polite-pad":       { wave: "triangle", attack: 0.02,  decay: 0.20, sustain: 0.18, release: 0.15, vibratoFreq: 2.0, vibratoDepth: 0.03 },
            "polite-piano":     { wave: "sine",     attack: 0.005, decay: 0.22, sustain: 0.12, release: 0.12 },
            "polite-soft":      { wave: "sine",     attack: 0.02,  decay: 0.18, sustain: 0.15, release: 0.12, filterType: "lowpass", filterFreq: 1200 },
            "passion-brass":    { wave: "sawtooth", attack: 0.01,  decay: 0.15, sustain: 0.15, release: 0.10, filterType: "lowpass", filterFreq: 1400 },
            "passion-drive":    { wave: "square",   attack: 0.005, decay: 0.12, sustain: 0.12, release: 0.08, filterType: "bandpass", filterFreq: 1000 },
            "passion-shout":    { wave: "sawtooth", attack: 0.001, decay: 0.10, sustain: 0.10, release: 0.08, filterType: "lowpass", filterFreq: 2000 }
        };
        const JOBHUNT_FACILITY_TIMBRES = {
            "bright":     ["bright-chime", "bright-sparkle", "bright-bell"],
            "polite":     ["polite-pad",   "polite-piano",   "polite-soft"],
            "passionate": ["passion-brass", "passion-drive",  "passion-shout"]
        };
        const JOBHUNT_PATTERN_STYLES = {
            "bright-chime": "formal-accent", "bright-sparkle": "crisp-staccato", "bright-bell": "formal-accent",
            "polite-pad": "dramatic-swell", "polite-piano": "formal-accent", "polite-soft": "dramatic-swell",
            "passion-brass": "dramatic-swell", "passion-drive": "crisp-staccato", "passion-shout": "crisp-staccato"
        };
        const JOBHUNT_DROPS = [
            { id: "bright",     name: "明るく話す",  nameEn: "Speak Brightly", color: "hsl(45, 60%, 60%)",  labels: { social: 4, optimistic: 3 },    xFrac: 0.25, yFrac: 0.42,
              requiredLabel: { key: "social", threshold: 8 } },
            { id: "polite",     name: "丁寧に話す",  nameEn: "Speak Politely", color: "hsl(210, 45%, 60%)", labels: { study: 4, focused: 3 },         xFrac: 0.50, yFrac: 0.38,
              requiredLabel: { key: "study", threshold: 8 } },
            { id: "passionate", name: "情熱的に話す", nameEn: "Speak Passionately", color: "hsl(0, 55%, 58%)",   labels: { expressive: 4, creative: 3 },  xFrac: 0.75, yFrac: 0.42,
              requiredLabel: { key: "expressive", threshold: 8 } }
        ];

        function createJobHuntSynth(timbreName) {
            const cfg = JOBHUNT_TIMBRES[timbreName];
            if (!cfg) return { synth: null, effects: [] };
            const effects = [];
            const synth = new Tone.PolySynth(Tone.Synth, {
                oscillator: { type: cfg.wave },
                envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
            });
            synth.volume.value = -100;
            if (cfg.filterType && cfg.vibratoFreq) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                effects.push(filter, vibrato);
                synth.chain(filter, vibrato, Tone.Destination);
            } else if (cfg.filterType) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                effects.push(filter);
                synth.chain(filter, Tone.Destination);
            } else if (cfg.vibratoFreq) {
                const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                effects.push(vibrato);
                synth.chain(vibrato, Tone.Destination);
            } else {
                synth.toDestination();
            }
            return { synth, effects };
        }

        function startJobHuntPhase() {
            currentScene = SCENE.JOB_HUNT;
            isTopDownScene = true;
            jobHuntInterviewRound = 1;
            jobHuntCameraZoom = 1.0;
            jobHuntViewMode = "topdown";
            jobHuntTransitioning = false;
            jobHuntSideScrollWorldW = 0;
            jobHuntDropTopDownPositions = [];
            worldWidth = Math.max(width * 1.3, 1000);
            worldHeight = Math.max(height * 1.8, 1000);
            baby = new Child(babyColorScheme);
            baby.isTopDown = true;
            baby.outfit = "suit";
            baby.x = worldWidth * 0.5;
            baby.y = worldHeight * 0.68;
            cameraX = 0;
            topDownCameraX = Math.max(0, Math.min(baby.x - width / 2, worldWidth - width));
            topDownCameraY = Math.max(0, Math.min(baby.y - height / 2, worldHeight - height));
            // Collision obstacles
            const wW = worldWidth, wH = worldHeight;
            const wallY = wH * 0.52, wallThick = 18;
            const doorX = wW * 0.38, doorW = wW * 0.24;
            const dskX = wW * 0.15, dskY = wH * 0.32, dskW = wW * 0.70, dskH = wH * 0.04;
            jobHuntObstacles = [
                { x: dskX, y: dskY, w: dskW, h: dskH },
                { x: 0, y: wallY - wallThick / 2, w: doorX, h: wallThick },
                { x: doorX + doorW, y: wallY - wallThick / 2, w: wW - doorX - doorW, h: wallThick },
            ];
            initJobHuntNpcs();
            initJobHuntDrops();
            initCarryHatLayer(); initCarrySnareLayer(); initCarryCymbalLayer();
            initCarryBassLayer(); initCarryKeyboardLayer();
            initCarryKeys2Layer();
            startBaseGroove(); buildScoreHud(); updateScoreToggleUi();
            orbWorldX = baby.x;
            orbWorldY = baby.y;
            orbParticles = [];
        }

        function initJobHuntNpcs() {
            jobHuntNpcs = [];
            // Interviewers (behind desk, top area — 3 interviewers, just above desk)
            for (let i = 0; i < 3; i++) {
                jobHuntNpcs.push({
                    x: worldWidth * (0.25 + i * 0.25),
                    y: worldHeight * 0.29,
                    targetX: 0, targetY: 0,
                    moveTimer: 0,
                    speed: 0,
                    walkCycle: Math.random() * Math.PI * 2,
                    bodyHue: 220 + randInt(-10, 10),
                    limbHue: 220 + randInt(-10, 10),
                    isInterviewer: true,
                    scale: 1.0,
                    skinTone: `hsl(25, ${58 + randInt(0, 20)}%, ${78 + randInt(0, 10)}%)`,
                    hairColor: `hsl(${randInt(15, 45)}, ${30 + randInt(0, 25)}%, ${35 + randInt(0, 25)}%)`,
                    faceType: randInt(0, 4),
                    isBoy: Math.random() < 0.5,
                    hairStyle: randInt(0, 2),
                    cheekColor: "hsl(350, 62%, 78%)"
                });
            }
            // Waiting job hunters in hallway (3 people) — seated on pipe chairs, tightly packed along wall
            const chairSpacing = 0.065;
            const chairStartX = 0.10;
            for (let i = 0; i < 3; i++) {
                jobHuntNpcs.push({
                    x: worldWidth * (chairStartX + i * chairSpacing),
                    y: worldHeight * 0.565,
                    targetX: 0, targetY: 0,
                    moveTimer: 0,
                    speed: 0,
                    walkCycle: Math.random() * Math.PI * 2,
                    bodyHue: 220 + randInt(-15, 15),
                    limbHue: 220 + randInt(-15, 15),
                    isInterviewer: false,
                    isWaiting: true,
                    fidgetSpeed: 0.02 + Math.random() * 0.03,
                    scale: 1.0,
                    skinTone: `hsl(25, ${58 + randInt(0, 20)}%, ${78 + randInt(0, 10)}%)`,
                    hairColor: `hsl(${randInt(15, 45)}, ${30 + randInt(0, 25)}%, ${35 + randInt(0, 25)}%)`,
                    faceType: randInt(0, 4),
                    isBoy: Math.random() < 0.5,
                    hairStyle: randInt(0, 2),
                    cheekColor: "hsl(350, 62%, 78%)"
                });
            }
        }

        function updateJobHuntNpcs() {
            jobHuntNpcs.forEach(npc => {
                if (npc.isInterviewer) {
                    npc.walkCycle += 0.01; // minimal movement
                } else {
                    // Fidgeting (leg bounce)
                    npc.walkCycle += npc.fidgetSpeed || 0.025;
                }
            });
        }

        function drawJobHuntNpc(npc, ctx) {
            // Soft ambient shadow beneath seated NPCs
            if (npc.isInterviewer || npc.isWaiting) {
                ctx.save();
                ctx.fillStyle = "rgba(0,0,0,0.045)";
                ctx.beginPath(); ctx.ellipse(npc.x, npc.y + 18, 14, 4, 0, 0, Math.PI * 2); ctx.fill();
                ctx.restore();
            }
            ctx.save();
            ctx.translate(npc.x, npc.y);

            const s = npc.scale || 0.7;
            const t = npc.walkCycle || 0;
            const isSeated = npc.isInterviewer || npc.isWaiting;
            const dir = -(npc.dir || 1);
            ctx.scale(dir * s, s);

            const skinColor = npc.skinTone || "hsl(25, 58%, 80%)";
            const hairColor = npc.hairColor || "#333";
            const cheekColor = npc.cheekColor || "hsl(350, 62%, 78%)";
            const faceType = npc.faceType != null ? npc.faceType : 0;
            const isBoy = npc.isBoy != null ? npc.isBoy : true;
            const hairStyle = npc.hairStyle != null ? npc.hairStyle : 0;
            const suitHue = npc.bodyHue || 220;
            const suitColor = `hsl(${suitHue}, 35%, 35%)`;
            const pantsColor = `hsl(${suitHue}, 30%, 28%)`;
            const tieColor = npc.isInterviewer ? "#883333" : "#333388";
            const tieKnotColor = npc.isInterviewer ? "#772828" : "#282877";
            const shoeColor = "#333";
            const soleColor = "#222";

            let legSwingL, legSwingR, kneeL, kneeR, armSwingL, armSwingR, headBobA, verticalBob;
            if (isSeated) {
                verticalBob = 0;
                // Seated pose: thighs forward, knees bent 90deg down
                legSwingL = 1.2; legSwingR = 1.2; kneeL = -1.5; kneeR = -1.5;
                armSwingL = npc.isInterviewer ? Math.sin(t * 2) * 0.15 - 0.1 : -0.05;
                armSwingR = -0.05;
                headBobA = npc.isInterviewer ? Math.sin(t * 2) * 0.03 : Math.sin(t * 3) * 0.01;
            } else {
                verticalBob = Math.abs(Math.sin(t)) * 2.5;
                legSwingL = Math.sin(t) * 0.26;
                legSwingR = Math.sin(t + Math.PI) * 0.26;
                kneeL = Math.max(0, -legSwingL) * 0.4;
                kneeR = Math.max(0, -legSwingR) * 0.4;
                armSwingL = Math.sin(t + Math.PI) * 0.22;
                armSwingR = Math.sin(t) * 0.22;
                headBobA = Math.sin(t * 2) * 0.02;
            }
            ctx.translate(0, -verticalBob);

            const dp = (x, y, ang, fn) => { ctx.save(); ctx.translate(x, y); ctx.rotate(ang); fn(ctx); ctx.restore(); };

            const drawLeg = (x, y, upperAng, kneeAng) => {
                dp(x, y, upperAng, c => {
                    c.fillStyle = pantsColor;
                    c.beginPath(); c.roundRect(-7, -3, 14, 25, 5); c.fill();
                    dp(0, 17, kneeAng, c2 => {
                        c2.fillStyle = pantsColor;
                        c2.beginPath(); c2.roundRect(-6, -4, 12, 22, 4); c2.fill();
                        c2.fillStyle = shoeColor;
                        c2.beginPath(); c2.ellipse(2, 20, 10, 5.5, 0, 0, Math.PI * 2); c2.fill();
                        c2.beginPath(); c2.roundRect(-5, 16, 12, 5, [3,3,0,0]); c2.fill();
                        c2.fillStyle = soleColor;
                        c2.beginPath(); c2.moveTo(-6, 21); c2.lineTo(12, 21); c2.lineTo(11, 24); c2.lineTo(-5, 24); c2.closePath(); c2.fill();
                    });
                });
            };
            const drawArm = (x, y, swingAng) => {
                dp(x, y, swingAng, c => {
                    // Upper arm (sleeve)
                    c.fillStyle = suitColor;
                    c.beginPath(); c.roundRect(-5.5, -2, 11, 10, 4); c.fill();
                    // Forearm (sleeve - long sleeve suit)
                    c.fillStyle = suitColor;
                    c.beginPath(); c.roundRect(-4.5, 8, 9, 12, 4); c.fill();
                    // Cuff shadow
                    c.fillStyle = "rgba(0,0,0,0.06)";
                    c.beginPath(); c.roundRect(-4.5, 17, 9, 3, [0,0,2,2]); c.fill();
                    dp(0, 20, 0.12, c2 => {
                        c2.fillStyle = skinColor;
                        c2.beginPath(); c2.roundRect(-3.5, 0, 7, 11, 3.5); c2.fill();
                        c2.beginPath(); c2.ellipse(0, 12, 4.5, 3.5, 0, 0, Math.PI * 2); c2.fill();
                    });
                });
            };

            // === Draw order: back-leg → back-arm → body → pants → front-leg → front-arm → head ===
            drawLeg(-8, -7, legSwingL, kneeL);
            drawArm(-15, -54, armSwingL);

            // Body — suit jacket
            ctx.fillStyle = suitColor;
            ctx.beginPath(); ctx.roundRect(-17, -58, 34, 32, 8); ctx.fill();
            // White shirt V
            ctx.fillStyle = "#e8e8e8";
            ctx.beginPath(); ctx.moveTo(-6, -58); ctx.lineTo(0, -48); ctx.lineTo(6, -58); ctx.closePath(); ctx.fill();
            // Lapel lines
            ctx.strokeStyle = "rgba(255,255,255,0.12)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.moveTo(-8, -58); ctx.lineTo(-4, -44); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(8, -58); ctx.lineTo(4, -44); ctx.stroke();
            // Tie
            ctx.fillStyle = tieColor;
            ctx.beginPath(); ctx.moveTo(-2, -56); ctx.lineTo(0, -40); ctx.lineTo(2, -56); ctx.closePath(); ctx.fill();
            ctx.fillStyle = tieKnotColor;
            ctx.beginPath(); ctx.ellipse(0, -56, 2.5, 1.8, 0, 0, Math.PI * 2); ctx.fill();
            // Pocket square (interviewers only)
            if (npc.isInterviewer) {
                ctx.fillStyle = "#e8e8e8";
                ctx.beginPath(); ctx.roundRect(4, -52, 6, 4, 1); ctx.fill();
            }

            // Pants
            ctx.fillStyle = pantsColor;
            ctx.beginPath(); ctx.roundRect(-16, -28, 32, 24, [0,0,6,6]); ctx.fill();
            ctx.beginPath(); ctx.ellipse(-8, -7, 10, 9, 0, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(8, -7, 10, 9, 0, 0, Math.PI * 2); ctx.fill();

            drawLeg(8, -7, legSwingR, kneeR);
            drawArm(15, -54, armSwingR);

            // Head
            dp(0, -72, headBobA, c => {
                c.scale(-1, 1);
                const HR = 21;
                // BACK HAIR
                c.fillStyle = hairColor;
                if (isBoy) {
                    if (hairStyle === 1) { c.beginPath(); c.arc(0, -1, HR + 5, Math.PI * 0.95, Math.PI * 0.05, false); c.closePath(); c.fill(); }
                    else if (hairStyle === 2) { c.beginPath(); c.arc(0, -1, HR + 2, Math.PI, 0, false); c.closePath(); c.fill(); }
                } else {
                    if (hairStyle === 0) {
                        c.beginPath(); c.arc(0, -1, HR + 4, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.roundRect(-HR - 5, -6, 9, 22, 4); c.fill();
                        c.beginPath(); c.roundRect(HR - 4, -6, 9, 22, 4); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.arc(0, -1, HR + 3, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.ellipse(-20, -8, 8, 14, -0.2, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.ellipse(20, -8, 8, 14, 0.2, 0, Math.PI * 2); c.fill();
                    } else {
                        c.beginPath(); c.arc(0, -1, HR + 4, Math.PI, 0, false); c.closePath(); c.fill();
                        c.beginPath(); c.ellipse(-18, -4, 7, 16, 0.25, 0, Math.PI * 2); c.fill();
                    }
                }
                // FACE BASE
                c.fillStyle = skinColor;
                c.beginPath(); c.arc(0, 0, HR, 0, Math.PI * 2); c.fill();
                // Ears
                c.beginPath(); c.arc(-18, 3, 5.5, 0, Math.PI * 2); c.fill();
                c.beginPath(); c.arc(18, 3, 5.5, 0, Math.PI * 2); c.fill();
                // FRONT HAIR
                c.fillStyle = hairColor;
                if (isBoy) {
                    if (hairStyle === 0) {
                        c.beginPath(); c.arc(0, -1, HR + 3, Math.PI, 0, false); c.closePath(); c.fill();
                        c.fillStyle = skinColor;
                        c.beginPath(); c.arc(0, 0, HR, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.arc(-18, 3, 5.5, 0, Math.PI * 2); c.fill();
                        c.beginPath(); c.arc(18, 3, 5.5, 0, Math.PI * 2); c.fill();
                        c.fillStyle = hairColor;
                        c.beginPath(); c.moveTo(-17, -21); c.lineTo(-17, -13);
                        c.quadraticCurveTo(-8, -16, 0, -13);
                        c.quadraticCurveTo(8, -16, 17, -13);
                        c.lineTo(17, -21); c.closePath(); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.moveTo(-19, -21); c.lineTo(-19, -10);
                        c.quadraticCurveTo(-10, -13, 0, -10); c.quadraticCurveTo(10, -13, 19, -10);
                        c.lineTo(19, -21); c.closePath(); c.fill();
                    } else {
                        c.globalAlpha = 0.45;
                        c.beginPath(); c.moveTo(-16, -21); c.lineTo(-16, -17); c.lineTo(16, -17); c.lineTo(16, -21); c.closePath(); c.fill();
                        c.globalAlpha = 1;
                    }
                } else {
                    if (hairStyle === 0) {
                        c.beginPath(); c.moveTo(-18, -21); c.lineTo(-18, -11); c.lineTo(18, -11); c.lineTo(18, -21); c.closePath(); c.fill();
                    } else if (hairStyle === 1) {
                        c.beginPath(); c.moveTo(-17, -21); c.lineTo(-17, -11); c.lineTo(17, -11); c.lineTo(17, -21); c.closePath(); c.fill();
                        c.fillStyle = "hsl(345, 65%, 65%)";
                        [[-20, -14], [20, -14]].forEach(([rx, ry]) => {
                            c.beginPath(); c.ellipse(rx - 4, ry, 4, 2.5, -0.3, 0, Math.PI * 2); c.fill();
                            c.beginPath(); c.ellipse(rx + 4, ry, 4, 2.5, 0.3, 0, Math.PI * 2); c.fill();
                            c.beginPath(); c.arc(rx, ry, 1.5, 0, Math.PI * 2); c.fill();
                        });
                    } else {
                        c.beginPath(); c.moveTo(-15, -21); c.lineTo(-15, -12);
                        c.quadraticCurveTo(0, -10, 17, -13); c.lineTo(17, -21); c.closePath(); c.fill();
                    }
                }
                // FEATURES
                drawBabyFace(c, faceType, skinColor, cheekColor, null, false);
            });

            ctx.restore();
        }

        function initJobHuntDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo || !inheritedChordProgression) return;
            for (let i = 0; i < JOBHUNT_DROPS.length; i++) {
                const fac = JOBHUNT_DROPS[i];
                const timbres = JOBHUNT_FACILITY_TIMBRES[fac.id] || ["bright-chime"];
                const pick = randInt(0, timbres.length - 1);
                const timbreName = timbres[pick];
                const patternStyle = JOBHUNT_PATTERN_STYLES[timbreName] || "formal-accent";
                const variant = randInt(0, 1);
                const kbBundle = buildKeyboardLine(baseRhythmInfo, patternStyle, inheritedChordProgression, variant);
                const kb = createJobHuntSynth(timbreName);
                toneDrops.push({
                    x: worldWidth * fac.xFrac,
                    y: worldHeight * fac.yFrac,
                    pattern: kbBundle.pattern,
                    velocityPattern: null,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "keyboard",
                    keyboardSynth: kb.synth,
                    keyboardEffects: kb.effects,
                    keyboardNotes: kbBundle.notes,
                    keyboardAttacks: kbBundle.attacks,
                    keyboardDurations: kbBundle.durations,
                    keyboardSustainType: kbBundle.sustainType,
                    activityId: fac.id,
                    activityName: fac.name,
                    activityNameEn: fac.nameEn || null,
                    dropColor: fac.color,
                    activityLabels: fac.labels,
                    requiredLabel: fac.requiredLabel || null,
                    jobHuntTimbre: timbreName,
                    ripples: []
                });
            }
            primeToneDrops();
        }

        function drawJobHuntBackground() {
            const wW = worldWidth, wH = worldHeight;
            const wallY = wH * 0.52;
            const wallThick = 18;
            const deskY = wH * 0.32;
            const dskX = wW * 0.15, dskW = wW * 0.70, dskH = wH * 0.04;

            // ======== INTERVIEW ROOM (top 52%) ========
            // Wall background — cream two-tone (upper lighter, lower wainscot)
            const wainscotY = wH * 0.38;
            ctx.fillStyle = "#f0ebe0";
            ctx.fillRect(0, 0, wW, wallY);
            // Lower wainscot area — slightly darker
            ctx.fillStyle = "#e8e0d0";
            ctx.fillRect(0, wainscotY, wW, wallY - wainscotY);
            // Wainscot rail
            ctx.fillStyle = "#c8b898";
            ctx.fillRect(0, wainscotY - 1, wW, 3);
            // Baseboard at wall/floor boundary (interview room side)
            ctx.fillStyle = "#8a7a60";
            ctx.fillRect(0, wallY - wallThick / 2 - 4, wW, 4);

            // Carpet
            const carpetG = ctx.createLinearGradient(0, wainscotY + 10, 0, wallY);
            carpetG.addColorStop(0, "#c4b090"); carpetG.addColorStop(1, "#bba880");
            ctx.fillStyle = carpetG;
            ctx.fillRect(0, wainscotY + 10, wW, wallY - wainscotY - 10);
            // Diamond pattern on carpet
            ctx.strokeStyle = "rgba(160,140,110,0.12)"; ctx.lineWidth = 0.5;
            const carpStep = 18;
            for (let ty = Math.floor(wainscotY + 10); ty < wallY; ty += carpStep) {
                for (let tx = 0; tx < wW; tx += carpStep) {
                    ctx.beginPath();
                    ctx.moveTo(tx + carpStep / 2, ty); ctx.lineTo(tx + carpStep, ty + carpStep / 2);
                    ctx.lineTo(tx + carpStep / 2, ty + carpStep); ctx.lineTo(tx, ty + carpStep / 2);
                    ctx.closePath(); ctx.stroke();
                }
            }

            // -- Downlights --
            for (let dl = 0; dl < 4; dl++) {
                const dlx = wW * (0.15 + dl * 0.23), dly = wH * 0.01;
                const dlg = ctx.createRadialGradient(dlx, dly, 0, dlx, dly, wH * 0.16);
                dlg.addColorStop(0, "rgba(255,250,230,0.10)"); dlg.addColorStop(1, "rgba(255,250,230,0)");
                ctx.fillStyle = dlg;
                ctx.fillRect(dlx - wW * 0.08, dly, wW * 0.16, wH * 0.16);
                ctx.fillStyle = "rgba(255,250,240,0.6)";
                ctx.beginPath(); ctx.arc(dlx, dly + 3, 4, 0, Math.PI * 2); ctx.fill();
            }

            // -- Interviewer chairs (behind desk — office chairs, drawn BEFORE desk so legs hidden) --
            for (let ic = 0; ic < 3; ic++) {
                const cx = wW * (0.25 + ic * 0.25), cy = wH * 0.29;
                // Star-base (5 casters)
                ctx.fillStyle = "#444";
                for (let cs = 0; cs < 5; cs++) {
                    const ca = (Math.PI * 2 * cs) / 5 - Math.PI / 2;
                    const bx = cx + Math.cos(ca) * 12, by = cy + 16 + Math.sin(ca) * 5;
                    ctx.beginPath(); ctx.arc(bx, by, 2.5, 0, Math.PI * 2); ctx.fill();
                    ctx.strokeStyle = "#555"; ctx.lineWidth = 1.2;
                    ctx.beginPath(); ctx.moveTo(cx, cy + 14); ctx.lineTo(bx, by); ctx.stroke();
                }
                // Stem
                ctx.fillStyle = "#555";
                ctx.fillRect(cx - 2.5, cy + 8, 5, 8);
                // Seat
                ctx.fillStyle = "#505050";
                ctx.beginPath(); ctx.roundRect(cx - 14, cy, 28, 10, 4); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.06)";
                ctx.fillRect(cx - 12, cy + 1, 24, 3);
                // Back (tall, curved)
                ctx.fillStyle = "#606060";
                ctx.beginPath(); ctx.roundRect(cx - 12, cy - 18, 24, 18, [6, 6, 0, 0]); ctx.fill();
                // Back mesh lines
                ctx.strokeStyle = "rgba(255,255,255,0.06)"; ctx.lineWidth = 0.5;
                for (let ml = 0; ml < 3; ml++) { ctx.beginPath(); ctx.moveTo(cx - 10, cy - 15 + ml * 5); ctx.lineTo(cx + 10, cy - 15 + ml * 5); ctx.stroke(); }
                // Armrests
                ctx.fillStyle = "#4a4a4a";
                ctx.beginPath(); ctx.roundRect(cx - 18, cy + 2, 6, 5, 2); ctx.fill();
                ctx.beginPath(); ctx.roundRect(cx + 12, cy + 2, 6, 5, 2); ctx.fill();
            }

            // -- Draw interviewer NPCs BEFORE desk (so desk covers their lower bodies) --
            updateJobHuntNpcs();
            jobHuntNpcs.forEach(npc => { if (npc.isInterviewer) drawJobHuntNpc(npc, ctx); });

            // -- Interview desk with wood grain + front face + desk LEGS --
            const dskDepth = 8;
            // Desk legs (4 legs, drawn first so top surface covers their tops)
            ctx.fillStyle = "#5a3c1a";
            const legW = 5, legH = 30;
            const legInset = 20;
            // Front left leg
            ctx.beginPath(); ctx.roundRect(dskX + legInset, deskY + dskH + dskDepth, legW, legH, 2); ctx.fill();
            // Front right leg
            ctx.beginPath(); ctx.roundRect(dskX + dskW - legInset - legW, deskY + dskH + dskDepth, legW, legH, 2); ctx.fill();
            // Back left leg (partially hidden)
            ctx.fillStyle = "#4a2c10";
            ctx.beginPath(); ctx.roundRect(dskX + legInset + 2, deskY - 2, legW - 1, 4, 1); ctx.fill();
            // Back right leg (partially hidden)
            ctx.beginPath(); ctx.roundRect(dskX + dskW - legInset - legW + 2, deskY - 2, legW - 1, 4, 1); ctx.fill();
            // Front face (desk thickness)
            ctx.fillStyle = "#6a4c2a";
            ctx.fillRect(dskX, deskY + dskH, dskW, dskDepth);
            // Bottom edge shadow
            ctx.fillStyle = "rgba(0,0,0,0.08)";
            ctx.fillRect(dskX + 2, deskY + dskH + dskDepth, dskW - 4, 3);
            // Top surface
            ctx.fillStyle = "#7a5c3a";
            ctx.beginPath(); ctx.roundRect(dskX, deskY, dskW, dskH, 3); ctx.fill();
            // Wood grain
            ctx.strokeStyle = "rgba(100,70,40,0.12)"; ctx.lineWidth = 0.5;
            for (let wl = 0; wl < 6; wl++) {
                const wy = deskY + 3 + wl * (dskH - 6) / 5;
                ctx.beginPath(); ctx.moveTo(dskX + 4, wy); ctx.lineTo(dskX + dskW - 4, wy); ctx.stroke();
            }
            // Front edge highlight
            ctx.fillStyle = "rgba(255,255,255,0.06)";
            ctx.fillRect(dskX + 2, deskY + 1, dskW - 4, 3);
            // Desk items: documents, cup, pen, name plate
            ctx.fillStyle = "#f0ece0";
            ctx.beginPath(); ctx.roundRect(dskX + dskW * 0.08, deskY + dskH * 0.15, dskW * 0.08, dskH * 0.7, 1); ctx.fill();
            ctx.beginPath(); ctx.roundRect(dskX + dskW * 0.18, deskY + dskH * 0.2, dskW * 0.08, dskH * 0.6, 1); ctx.fill();
            ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.3;
            for (let dl = 0; dl < 3; dl++) { ctx.beginPath(); ctx.moveTo(dskX + dskW * 0.09, deskY + dskH * 0.25 + dl * dskH * 0.15); ctx.lineTo(dskX + dskW * 0.15, deskY + dskH * 0.25 + dl * dskH * 0.15); ctx.stroke(); }
            // Coffee cup
            ctx.fillStyle = "#f8f4f0";
            ctx.beginPath(); ctx.ellipse(dskX + dskW * 0.42, deskY + dskH * 0.5, 6, 5, 0, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#8a5030"; ctx.globalAlpha = 0.5;
            ctx.beginPath(); ctx.ellipse(dskX + dskW * 0.42, deskY + dskH * 0.5, 4.5, 3.8, 0, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = 1;
            // Pen
            ctx.fillStyle = "#222";
            ctx.save(); ctx.translate(dskX + dskW * 0.55, deskY + dskH * 0.45); ctx.rotate(0.3);
            ctx.fillRect(-1, -10, 2.5, 20); ctx.restore();
            // Name plate
            ctx.fillStyle = "#c8a848";
            ctx.beginPath(); ctx.roundRect(dskX + dskW * 0.70, deskY + dskH * 0.2, dskW * 0.10, dskH * 0.55, 2); ctx.fill();
            ctx.fillStyle = "#333";
            ctx.font = `${Math.round(wW * 0.008)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("面接官", dskX + dskW * 0.75, deskY + dskH * 0.5);

            // -- Water pitcher and glasses on desk --
            const pitcherX = dskX + dskW * 0.88, pitcherY = deskY + dskH * 0.2;
            // Pitcher body
            ctx.fillStyle = "rgba(180,210,240,0.35)";
            ctx.beginPath(); ctx.roundRect(pitcherX - 5, pitcherY, 10, 14, 3); ctx.fill();
            ctx.strokeStyle = "rgba(140,180,220,0.4)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(pitcherX - 5, pitcherY, 10, 14, 3); ctx.stroke();
            // Water level
            ctx.fillStyle = "rgba(160,200,240,0.25)";
            ctx.fillRect(pitcherX - 4, pitcherY + 4, 8, 9);
            // Handle
            ctx.strokeStyle = "rgba(140,180,220,0.5)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.arc(pitcherX + 7, pitcherY + 7, 4, -Math.PI / 2, Math.PI / 2); ctx.stroke();
            // Glasses (2 small tumblers)
            for (let gi = 0; gi < 2; gi++) {
                const gx = pitcherX - 16 - gi * 12;
                ctx.fillStyle = "rgba(200,220,240,0.3)";
                ctx.beginPath(); ctx.roundRect(gx - 3, pitcherY + 4, 6, 8, 1); ctx.fill();
                ctx.strokeStyle = "rgba(160,190,220,0.35)"; ctx.lineWidth = 0.5;
                ctx.beginPath(); ctx.roundRect(gx - 3, pitcherY + 4, 6, 8, 1); ctx.stroke();
            }

            // -- Subtle shadow under desk --
            ctx.fillStyle = "rgba(0,0,0,0.06)";
            ctx.beginPath();
            ctx.ellipse(dskX + dskW / 2, deskY + dskH + dskDepth + legH + 4, dskW * 0.48, 6, 0, 0, Math.PI * 2);
            ctx.fill();

            // -- Shadow under interviewer chairs --
            for (let ic = 0; ic < 3; ic++) {
                const cx = wW * (0.25 + ic * 0.25), cy = wH * 0.29;
                ctx.fillStyle = "rgba(0,0,0,0.05)";
                ctx.beginPath(); ctx.ellipse(cx, cy + 22, 16, 4, 0, 0, Math.PI * 2); ctx.fill();
            }

            // -- Player chair (pipe chair style) --
            const pcx = wW * 0.50, pcy = wH * 0.42;
            // Metal legs
            ctx.strokeStyle = "#999"; ctx.lineWidth = 2; ctx.lineCap = "round";
            ctx.beginPath(); ctx.moveTo(pcx - 10, pcy + 12); ctx.lineTo(pcx - 12, pcy + 22); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(pcx + 10, pcy + 12); ctx.lineTo(pcx + 12, pcy + 22); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(pcx - 8, pcy - 4); ctx.lineTo(pcx - 10, pcy - 10); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(pcx + 8, pcy - 4); ctx.lineTo(pcx + 10, pcy - 10); ctx.stroke();
            ctx.lineCap = "butt";
            // Seat (cloth cushion)
            ctx.fillStyle = "#7090a8";
            ctx.beginPath(); ctx.roundRect(pcx - 11, pcy + 2, 22, 10, 3); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.08)";
            ctx.fillRect(pcx - 9, pcy + 3, 18, 3);
            // Back (cloth)
            ctx.fillStyle = "#6080a0";
            ctx.beginPath(); ctx.roundRect(pcx - 10, pcy - 8, 20, 10, [4, 4, 0, 0]); ctx.fill();

            // -- Wall paintings (framed) --
            const paintings = [
                { x: 0.05, y: 0.015, w: 0.06, h: 0.04, c1: "#6a8ab0", c2: "#88aad0" },
                { x: 0.88, y: 0.02, w: 0.07, h: 0.045, c1: "#a08860", c2: "#c0a880" },
                { x: 0.16, y: 0.02, w: 0.05, h: 0.035, c1: "#80a070", c2: "#a0c090" }
            ];
            paintings.forEach(p => {
                ctx.fillStyle = "#6a5a40";
                ctx.beginPath(); ctx.roundRect(wW * p.x - 2, wH * p.y - 2, wW * p.w + 4, wH * p.h + 4, 2); ctx.fill();
                const pg = ctx.createLinearGradient(wW * p.x, wH * p.y, wW * p.x + wW * p.w, wH * p.y + wH * p.h);
                pg.addColorStop(0, p.c1); pg.addColorStop(1, p.c2);
                ctx.fillStyle = pg;
                ctx.fillRect(wW * p.x, wH * p.y, wW * p.w, wH * p.h);
            });

            // -- Company logo on wall with name --
            ctx.fillStyle = "rgba(100,120,160,0.15)";
            ctx.beginPath(); ctx.arc(wW * 0.50, wH * 0.025, wW * 0.02, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "rgba(100,120,160,0.25)"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.arc(wW * 0.50, wH * 0.025, wW * 0.02, 0, Math.PI * 2); ctx.stroke();
            // Inner logo mark
            ctx.fillStyle = "rgba(100,120,160,0.2)";
            ctx.beginPath(); ctx.arc(wW * 0.50, wH * 0.025, wW * 0.012, 0, Math.PI * 2); ctx.fill();
            // Company name text below logo
            ctx.fillStyle = "rgba(80,100,140,0.3)";
            ctx.font = `600 ${Math.round(wW * 0.009)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "top";
            ctx.fillText("トーン株式会社", wW * 0.50, wH * 0.025 + wW * 0.022);

            // -- Wall-mounted AC unit --
            const acX = wW * 0.78, acY = wH * 0.005;
            ctx.fillStyle = "#eee";
            ctx.beginPath(); ctx.roundRect(acX, acY, wW * 0.12, wH * 0.018, 3); ctx.fill();
            ctx.strokeStyle = "rgba(200,200,200,0.6)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(acX, acY, wW * 0.12, wH * 0.018, 3); ctx.stroke();
            // Vent slats
            ctx.strokeStyle = "rgba(180,180,180,0.4)"; ctx.lineWidth = 0.5;
            for (let vs = 0; vs < 4; vs++) {
                const vy = acY + wH * 0.005 + vs * wH * 0.003;
                ctx.beginPath(); ctx.moveTo(acX + 4, vy); ctx.lineTo(acX + wW * 0.12 - 4, vy); ctx.stroke();
            }
            // LED indicator
            ctx.fillStyle = "#4a4"; ctx.beginPath(); ctx.arc(acX + 8, acY + 4, 1.5, 0, Math.PI * 2); ctx.fill();

            // -- Bookshelf / filing cabinet in corner --
            const bsX = wW * 0.02, bsY = wH * 0.08, bsW = wW * 0.04, bsH = wH * 0.28;
            // Cabinet body
            ctx.fillStyle = "#8a7a5a";
            ctx.beginPath(); ctx.roundRect(bsX, bsY, bsW, bsH, 2); ctx.fill();
            // Shelves
            ctx.fillStyle = "#7a6a4a";
            for (let sh = 0; sh < 4; sh++) {
                const sy = bsY + (sh + 1) * bsH / 5;
                ctx.fillRect(bsX + 1, sy, bsW - 2, 2);
            }
            // Books on shelves (colored spines)
            const bookColors = ["#4a6a8a", "#8a4a4a", "#4a8a4a", "#8a7a3a", "#6a4a8a", "#3a7a8a"];
            for (let sh = 0; sh < 4; sh++) {
                const shelfY = bsY + sh * bsH / 5 + 3;
                const shelfH = bsH / 5 - 5;
                let bx = bsX + 2;
                for (let b = 0; b < 4 + (sh % 2); b++) {
                    const bw = 3 + (b * 7 + sh * 3) % 4;
                    ctx.fillStyle = bookColors[(b + sh * 2) % bookColors.length];
                    ctx.fillRect(bx, shelfY, bw, shelfH);
                    bx += bw + 1;
                    if (bx > bsX + bsW - 4) break;
                }
            }

            // -- Potted plants --
            const drawPlant = (px, py) => {
                ctx.fillStyle = "#b06030";
                ctx.beginPath(); ctx.moveTo(px - 7, py + 4); ctx.lineTo(px + 7, py + 4);
                ctx.lineTo(px + 5, py + 14); ctx.lineTo(px - 5, py + 14); ctx.closePath(); ctx.fill();
                ctx.fillStyle = "#2d8833";
                for (let lf = 0; lf < 6; lf++) {
                    const la = (Math.PI * 2 * lf) / 6 - Math.PI / 2;
                    ctx.beginPath(); ctx.ellipse(px + Math.cos(la) * 8, py + Math.sin(la) * 6 - 2, 6, 3.5, la, 0, Math.PI * 2); ctx.fill();
                }
            };
            drawPlant(wW * 0.04, wH * 0.44);
            drawPlant(wW * 0.96, wH * 0.44);

            // -- Clock --
            const clkX = wW * 0.94, clkY = wH * 0.035, clkR = 12;
            ctx.fillStyle = "#fff"; ctx.beginPath(); ctx.arc(clkX, clkY, clkR, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "#666"; ctx.lineWidth = 1.2; ctx.beginPath(); ctx.arc(clkX, clkY, clkR, 0, Math.PI * 2); ctx.stroke();
            for (let h = 0; h < 12; h++) {
                const ha = (Math.PI * 2 * h) / 12 - Math.PI / 2;
                ctx.fillStyle = "#444";
                ctx.beginPath(); ctx.arc(clkX + Math.cos(ha) * (clkR - 2.5), clkY + Math.sin(ha) * (clkR - 2.5), 1, 0, Math.PI * 2); ctx.fill();
            }
            const now = Date.now();
            const secAngle = ((now / 1000) % 60) / 60 * Math.PI * 2 - Math.PI / 2;
            const minAngle = ((now / 60000) % 60) / 60 * Math.PI * 2 - Math.PI / 2;
            const hrAngle = ((now / 3600000) % 12) / 12 * Math.PI * 2 - Math.PI / 2;
            ctx.lineCap = "round";
            ctx.strokeStyle = "#333"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(hrAngle) * (clkR * 0.5), clkY + Math.sin(hrAngle) * (clkR * 0.5)); ctx.stroke();
            ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(minAngle) * (clkR * 0.7), clkY + Math.sin(minAngle) * (clkR * 0.7)); ctx.stroke();
            ctx.strokeStyle = "#cc3333"; ctx.lineWidth = 0.6;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(secAngle) * (clkR * 0.8), clkY + Math.sin(secAngle) * (clkR * 0.8)); ctx.stroke();
            ctx.lineCap = "butt";
            ctx.fillStyle = "#333"; ctx.beginPath(); ctx.arc(clkX, clkY, 1.5, 0, Math.PI * 2); ctx.fill();

            // -- Whiteboard --
            const wbX = wW * 0.72, wbY = wH * 0.015, wbW = wW * 0.10, wbH = wH * 0.05;
            ctx.fillStyle = "#f0f0f0";
            ctx.beginPath(); ctx.roundRect(wbX, wbY, wbW, wbH, 2); ctx.fill();
            ctx.strokeStyle = "#bbb"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.roundRect(wbX, wbY, wbW, wbH, 2); ctx.stroke();
            ctx.strokeStyle = "rgba(50,100,200,0.3)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(wbX + 6, wbY + wbH - 6); ctx.lineTo(wbX + wbW - 6, wbY + wbH - 6); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(wbX + 6, wbY + wbH - 6); ctx.lineTo(wbX + 6, wbY + 6); ctx.stroke();
            ctx.strokeStyle = "rgba(200,50,50,0.3)";
            ctx.beginPath();
            ctx.moveTo(wbX + 8, wbY + wbH - 10);
            ctx.lineTo(wbX + wbW * 0.35, wbY + wbH * 0.3);
            ctx.lineTo(wbX + wbW * 0.6, wbY + wbH * 0.5);
            ctx.lineTo(wbX + wbW - 8, wbY + 8);
            ctx.stroke();

            // ======== WALL + DOOR DIVIDER ========
            // Wall body
            ctx.fillStyle = "#605848";
            ctx.fillRect(0, wallY - wallThick / 2, wW, wallThick);
            // Top/bottom trim lines
            ctx.fillStyle = "#504838";
            ctx.fillRect(0, wallY - wallThick / 2, wW, 3);
            ctx.fillRect(0, wallY + wallThick / 2 - 3, wW, 3);
            // Wall texture — subtle vertical stripes
            ctx.strokeStyle = "rgba(255,255,255,0.03)"; ctx.lineWidth = 1;
            for (let ws = 0; ws < wW; ws += 12) {
                ctx.beginPath(); ctx.moveTo(ws, wallY - wallThick / 2); ctx.lineTo(ws, wallY + wallThick / 2); ctx.stroke();
            }
            // Door frame
            const doorX = wW * 0.38, doorW = wW * 0.24;
            ctx.fillStyle = "#8a7a58";
            ctx.beginPath(); ctx.roundRect(doorX - 4, wallY - wallThick / 2 - 3, doorW + 8, wallThick + 6, 2); ctx.fill();
            // Door opening (lighter floor visible through)
            ctx.fillStyle = "#c8c0a8";
            ctx.fillRect(doorX, wallY - wallThick / 2, doorW, wallThick);
            // Small transom window above door
            ctx.fillStyle = "rgba(180,210,240,0.35)";
            ctx.beginPath(); ctx.roundRect(doorX + doorW * 0.15, wallY - wallThick / 2 - 12, doorW * 0.7, 9, 2); ctx.fill();
            ctx.strokeStyle = "rgba(100,80,60,0.4)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(doorX + doorW * 0.15, wallY - wallThick / 2 - 12, doorW * 0.7, 9, 2); ctx.stroke();
            // Vertical divider in transom
            ctx.beginPath(); ctx.moveTo(doorX + doorW * 0.5, wallY - wallThick / 2 - 12); ctx.lineTo(doorX + doorW * 0.5, wallY - wallThick / 2 - 3); ctx.stroke();
            // 面接室 sign
            ctx.fillStyle = "#f0ece0";
            ctx.beginPath(); ctx.roundRect(doorX + doorW * 0.3, wallY - wallThick / 2 - 24, doorW * 0.4, 11, 2); ctx.fill();
            ctx.fillStyle = "#444";
            ctx.font = `600 ${Math.round(wW * 0.012)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("面接室", doorX + doorW * 0.5, wallY - wallThick / 2 - 18);

            // ======== HALLWAY (bottom 48%) ========
            const hallTop = wallY + wallThick / 2;
            // Floor with tile grid
            const hallG = ctx.createLinearGradient(0, hallTop, 0, wH);
            hallG.addColorStop(0, "#d0c8bb"); hallG.addColorStop(1, "#c4bba8");
            ctx.fillStyle = hallG;
            ctx.fillRect(0, hallTop, wW, wH - hallTop);
            // Tile grid lines
            ctx.strokeStyle = "rgba(180,170,150,0.18)"; ctx.lineWidth = 0.5;
            const tileSize = 24;
            for (let ty = hallTop; ty < wH; ty += tileSize) {
                ctx.beginPath(); ctx.moveTo(0, ty); ctx.lineTo(wW, ty); ctx.stroke();
            }
            for (let tx = 0; tx < wW; tx += tileSize) {
                ctx.beginPath(); ctx.moveTo(tx, hallTop); ctx.lineTo(tx, wH); ctx.stroke();
            }
            // Gloss streaks
            ctx.fillStyle = "rgba(255,255,255,0.04)";
            ctx.fillRect(wW * 0.1, hallTop, wW * 0.05, wH - hallTop);
            ctx.fillRect(wW * 0.5, hallTop, wW * 0.04, wH - hallTop);

            // -- Shoe scuff marks on hallway floor --
            ctx.fillStyle = "rgba(80,70,60,0.04)";
            const scuffs = [[0.30, 0.62], [0.45, 0.70], [0.55, 0.58], [0.65, 0.75], [0.20, 0.68], [0.75, 0.64], [0.40, 0.80]];
            scuffs.forEach(([sx, sy]) => {
                ctx.beginPath(); ctx.ellipse(wW * sx, wH * sy, 6 + Math.random() * 4, 2, (sx * 10) % 1.5, 0, Math.PI * 2); ctx.fill();
            });

            // -- Floor direction arrows leading to interview room door --
            ctx.fillStyle = "rgba(100,90,70,0.08)";
            const arrowCX = doorX + doorW / 2;
            for (let ai = 0; ai < 3; ai++) {
                const ay = wH * (0.72 - ai * 0.06);
                ctx.beginPath();
                ctx.moveTo(arrowCX, ay - 6);
                ctx.lineTo(arrowCX + 8, ay + 2);
                ctx.lineTo(arrowCX + 3, ay + 2);
                ctx.lineTo(arrowCX + 3, ay + 8);
                ctx.lineTo(arrowCX - 3, ay + 8);
                ctx.lineTo(arrowCX - 3, ay + 2);
                ctx.lineTo(arrowCX - 8, ay + 2);
                ctx.closePath(); ctx.fill();
            }

            // Hallway bottom wall
            ctx.fillStyle = "#d8d0c0";
            ctx.fillRect(0, wH - 6, wW, 6);
            ctx.fillStyle = "#8a7a60";
            ctx.fillRect(0, wH - 6, wW, 2);

            // -- Ceiling fluorescent lights for hallway (with subtle flicker) --
            for (let fl = 0; fl < 3; fl++) {
                const flx = wW * (0.15 + fl * 0.3), fly = hallTop + 2;
                // Slight flicker on middle light
                const flicker = (fl === 1) ? 0.92 + 0.08 * Math.sin(Date.now() * 0.005 + fl) : 1.0;
                ctx.globalAlpha = flicker;
                ctx.fillStyle = "#f0f0e8";
                ctx.beginPath(); ctx.roundRect(flx - wW * 0.06, fly, wW * 0.12, 5, 2); ctx.fill();
                const flg = ctx.createRadialGradient(flx, fly + 3, 0, flx, fly + 3, wH * 0.08);
                flg.addColorStop(0, "rgba(255,255,240,0.06)"); flg.addColorStop(1, "rgba(255,255,240,0)");
                ctx.fillStyle = flg;
                ctx.fillRect(flx - wW * 0.06, fly, wW * 0.12, wH * 0.08);
                ctx.globalAlpha = 1;
                // Light fixture housing detail
                ctx.strokeStyle = "rgba(180,180,170,0.3)"; ctx.lineWidth = 0.5;
                ctx.beginPath(); ctx.roundRect(flx - wW * 0.06, fly, wW * 0.12, 5, 2); ctx.stroke();
            }

            // -- Door handle detail on interview room door --
            const dhX = doorX + doorW - 12, dhY = wallY;
            ctx.fillStyle = "#b8a878";
            ctx.beginPath(); ctx.roundRect(dhX, dhY - 3, 8, 6, 2); ctx.fill();
            ctx.fillStyle = "#d4c49a";
            ctx.beginPath(); ctx.arc(dhX + 4, dhY, 2, 0, Math.PI * 2); ctx.fill();

            // -- Coat hooks on wall above waiting area --
            const hookWallY = hallTop + 3;
            for (let hi = 0; hi < 4; hi++) {
                const hx = wW * (0.08 + hi * 0.055);
                // Hook plate
                ctx.fillStyle = "#aaa";
                ctx.beginPath(); ctx.roundRect(hx - 2, hookWallY, 4, 6, 1); ctx.fill();
                // Hook
                ctx.strokeStyle = "#999"; ctx.lineWidth = 1.5; ctx.lineCap = "round";
                ctx.beginPath(); ctx.arc(hx, hookWallY + 8, 3, 0, Math.PI); ctx.stroke();
                ctx.lineCap = "butt";
            }

            // -- Side table with magazines near waiting chairs --
            const stX = wW * (0.10 + 3 * 0.065 + 0.03), stY = wH * 0.565;
            // Table legs
            ctx.fillStyle = "#8a7a5a";
            ctx.fillRect(stX - 8, stY + 10, 2, 12);
            ctx.fillRect(stX + 6, stY + 10, 2, 12);
            // Table top
            ctx.fillStyle = "#9a8a6a";
            ctx.beginPath(); ctx.roundRect(stX - 10, stY + 6, 20, 5, 2); ctx.fill();
            // Magazines
            ctx.fillStyle = "#d04040";
            ctx.beginPath(); ctx.roundRect(stX - 6, stY + 2, 8, 5, 1); ctx.fill();
            ctx.fillStyle = "#4060b0";
            ctx.beginPath(); ctx.roundRect(stX - 3, stY, 7, 5, 1); ctx.fill();

            // -- Fire extinguisher --
            const feX = wW * 0.92, feY = wH * 0.70;
            // Body (red cylinder)
            ctx.fillStyle = "#cc3333";
            ctx.beginPath(); ctx.roundRect(feX - 4, feY, 8, 18, 2); ctx.fill();
            // Top nozzle
            ctx.fillStyle = "#222";
            ctx.beginPath(); ctx.roundRect(feX - 2, feY - 3, 4, 4, 1); ctx.fill();
            // Pressure gauge
            ctx.fillStyle = "#eee";
            ctx.beginPath(); ctx.arc(feX, feY + 5, 2.5, 0, Math.PI * 2); ctx.fill();
            // Handle
            ctx.strokeStyle = "#222"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(feX + 2, feY - 1); ctx.lineTo(feX + 5, feY + 3); ctx.stroke();

            // -- Reception window/counter on opposite wall --
            const rcX = wW * 0.55, rcY = hallTop + 2, rcW = wW * 0.18, rcH = wH * 0.06;
            // Counter body
            ctx.fillStyle = "#b0a080";
            ctx.beginPath(); ctx.roundRect(rcX, rcY, rcW, rcH, 2); ctx.fill();
            // Window opening (frosted glass)
            ctx.fillStyle = "rgba(200,220,240,0.25)";
            ctx.beginPath(); ctx.roundRect(rcX + 4, rcY + 2, rcW - 8, rcH * 0.55, 2); ctx.fill();
            ctx.strokeStyle = "rgba(160,140,110,0.4)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(rcX + 4, rcY + 2, rcW - 8, rcH * 0.55, 2); ctx.stroke();
            // Counter ledge
            ctx.fillStyle = "#a09070";
            ctx.fillRect(rcX - 2, rcY + rcH - 4, rcW + 4, 4);
            // "受付" label
            ctx.fillStyle = "rgba(80,70,50,0.4)";
            ctx.font = `600 ${Math.round(wW * 0.008)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("受付", rcX + rcW / 2, rcY + rcH * 0.35);

            // -- Trash can near water cooler --
            const tcX = wW * 0.90, tcY = wH * 0.60;
            ctx.fillStyle = "#888";
            ctx.beginPath();
            ctx.moveTo(tcX - 5, tcY); ctx.lineTo(tcX + 5, tcY);
            ctx.lineTo(tcX + 4, tcY + 14); ctx.lineTo(tcX - 4, tcY + 14);
            ctx.closePath(); ctx.fill();
            // Rim
            ctx.fillStyle = "#999";
            ctx.fillRect(tcX - 6, tcY - 1, 12, 2);

            // -- Waiting pipe chairs (3 individual chairs, tightly packed along wall) --
            const chairSpacing = 0.065;
            const chairStartX = 0.10;
            for (let i = 0; i < 3; i++) {
                const cx = wW * (chairStartX + i * chairSpacing), cy = wH * 0.565;
                // Metal legs (pipe chair style)
                ctx.strokeStyle = "#999"; ctx.lineWidth = 2; ctx.lineCap = "round";
                // Front legs
                ctx.beginPath(); ctx.moveTo(cx - 10, cy + 12); ctx.lineTo(cx - 12, cy + 22); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(cx + 10, cy + 12); ctx.lineTo(cx + 12, cy + 22); ctx.stroke();
                // Back legs
                ctx.beginPath(); ctx.moveTo(cx - 8, cy - 4); ctx.lineTo(cx - 10, cy - 10); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(cx + 8, cy - 4); ctx.lineTo(cx + 10, cy - 10); ctx.stroke();
                ctx.lineCap = "butt";
                // Seat cushion
                ctx.fillStyle = "#7090a8";
                ctx.beginPath(); ctx.roundRect(cx - 12, cy + 2, 24, 10, 3); ctx.fill();
                ctx.fillStyle = "rgba(255,255,255,0.08)";
                ctx.fillRect(cx - 10, cy + 3, 20, 3);
                // Back cushion
                ctx.fillStyle = "#6080a0";
                ctx.beginPath(); ctx.roundRect(cx - 11, cy - 8, 22, 10, [4, 4, 0, 0]); ctx.fill();
            }

            // -- Water cooler --
            const wcX = wW * 0.94, wcY = wH * 0.58;
            ctx.fillStyle = "#e0e8f0";
            ctx.beginPath(); ctx.roundRect(wcX - 6, wcY, 12, 22, 3); ctx.fill();
            ctx.fillStyle = "#6090cc"; ctx.globalAlpha = 0.6;
            ctx.beginPath(); ctx.roundRect(wcX - 4, wcY - 12, 8, 14, [4, 4, 0, 0]); ctx.fill();
            ctx.globalAlpha = 1;
            ctx.fillStyle = "#cc4444"; ctx.beginPath(); ctx.arc(wcX - 2, wcY + 10, 2, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#4444cc"; ctx.beginPath(); ctx.arc(wcX + 2, wcY + 10, 2, 0, Math.PI * 2); ctx.fill();

            // -- Bulletin board --
            const bbX = wW * 0.04, bbY = hallTop + 5, bbW = wW * 0.08, bbH = wH * 0.07;
            ctx.fillStyle = "#c4a870";
            ctx.beginPath(); ctx.roundRect(bbX, bbY, bbW, bbH, 2); ctx.fill();
            ctx.fillStyle = "rgba(180,150,100,0.3)";
            for (let ci = 0; ci < 8; ci++) {
                ctx.beginPath(); ctx.arc(bbX + 3 + (ci * bbW / 8), bbY + 3 + (ci % 3) * bbH / 3, 2 + (ci % 2) * 1.5, 0, Math.PI * 2); ctx.fill();
            }
            const paperColors = ["#f0ece0", "#e8e0d0", "#f5f0e0"];
            for (let pp = 0; pp < 3; pp++) {
                ctx.fillStyle = paperColors[pp];
                ctx.beginPath(); ctx.roundRect(bbX + 4 + pp * bbW * 0.3, bbY + 3 + (pp % 2) * bbH * 0.25, bbW * 0.25, bbH * 0.5, 1); ctx.fill();
                ctx.fillStyle = pp === 0 ? "#cc4444" : pp === 1 ? "#44aa44" : "#4488cc";
                ctx.beginPath(); ctx.arc(bbX + 4 + pp * bbW * 0.3 + bbW * 0.12, bbY + 4 + (pp % 2) * bbH * 0.25, 2, 0, Math.PI * 2); ctx.fill();
            }

            // -- Emergency exit sign --
            ctx.fillStyle = "#228833";
            ctx.beginPath(); ctx.roundRect(wW * 0.88, hallTop + 3, wW * 0.05, wH * 0.02, 2); ctx.fill();
            ctx.fillStyle = "#fff";
            ctx.font = `600 ${Math.round(wW * 0.008)}px sans-serif`;
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("EXIT", wW * 0.905, hallTop + 3 + wH * 0.01);

            // ======== Waiting NPCs (hallway, drawn after hallway elements) ========
            jobHuntNpcs.forEach(npc => { if (!npc.isInterviewer) drawJobHuntNpc(npc, ctx); });

            // Interview round indicator
            if (currentScene === SCENE.JOB_HUNT2) {
                ctx.save();
                ctx.fillStyle = "rgba(200,180,100,0.85)";
                ctx.font = `700 ${Math.round(wW * 0.025)}px 'Zen Maru Gothic'`;
                ctx.textAlign = "center"; ctx.textBaseline = "middle";
                ctx.fillText("二次面接", wW * 0.5, wH * 0.50);
                ctx.restore();
            }
        }

        // ======== Side-scroll interview room transition ========

        function triggerJobHuntEnterInterview() {
            jobHuntTransitioning = true;
            // Save top-down state
            jobHuntSavedTopDownX = baby.x;
            jobHuntSavedTopDownY = baby.y;
            jobHuntSavedCamX = topDownCameraX;
            jobHuntSavedCamY = topDownCameraY;
            remapDropsToSideScroll();

            sceneFade.style.background = '#fff';
            fadeScreenTo(1, 400);
            setTimeout(() => {
                jobHuntViewMode = "sidescroll";
                jobHuntSideScrollWorldW = 2400;
                // Position baby near left door
                baby.x = 90;
                baby.y = height * ROOM_WALL_RATIO;
                baby.isTopDown = false;
                cameraX = 0;
                orbParticles = [];
                fadeScreenTo(0, 500);
                setTimeout(() => { jobHuntTransitioning = false; }, 500);
            }, 400);
        }

        function triggerJobHuntExitInterview() {
            jobHuntTransitioning = true;
            sceneFade.style.background = '#fff';
            fadeScreenTo(1, 400);
            setTimeout(() => {
                jobHuntViewMode = "topdown";
                baby.isTopDown = true;
                // Place baby just below the door in top-down
                const doorX = worldWidth * 0.38, doorW = worldWidth * 0.24;
                const wallY = worldHeight * 0.52;
                baby.x = doorX + doorW / 2;
                baby.y = wallY + 30;
                topDownCameraX = jobHuntSavedCamX;
                topDownCameraY = jobHuntSavedCamY;
                jobHuntCameraZoom = 1.0;
                restoreDropsToTopDown();
                orbParticles = [];
                fadeScreenTo(0, 500);
                setTimeout(() => { jobHuntTransitioning = false; }, 500);
            }, 400);
        }

        function remapDropsToSideScroll() {
            jobHuntDropTopDownPositions = toneDrops.map(d => ({ x: d.x, y: d.y }));
            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            // Fixed pixel positions — independent of window width (based on wW=2400)
            const xPositions = [1272, 1512, 1752];
            for (let i = 0; i < toneDrops.length; i++) {
                toneDrops[i].x = xPositions[i] || (1272 + i * 240);
                toneDrops[i].y = floorY;
            }
        }

        function restoreDropsToTopDown() {
            for (let i = 0; i < toneDrops.length && i < jobHuntDropTopDownPositions.length; i++) {
                toneDrops[i].x = jobHuntDropTopDownPositions[i].x;
                toneDrops[i].y = jobHuntDropTopDownPositions[i].y;
            }
        }

        function updateJobHuntSideScrollCamera() {
            if (!baby) return;
            const wW = jobHuntSideScrollWorldW;
            const chairX = wW * 0.40;
            // When baby reaches the chair area, lock camera to show interviewers + tones
            const interviewFocusX = wW * 0.65;  // center of the interview cluster
            const focusCamTarget = interviewFocusX - width * 0.55; // put cluster right-of-center

            if (baby.x >= chairX - 20) {
                // Smoothly pan to interview focus
                const target = Math.max(0, Math.min(focusCamTarget, wW - width));
                cameraX += (target - cameraX) * 0.06;
            } else {
                // Normal follow when walking around left side
                const leftTrigger = width * 0.3;
                const rightTrigger = width * 0.7;
                const babyScreenX = baby.x - cameraX;
                if (babyScreenX > rightTrigger) cameraX = baby.x - rightTrigger;
                if (babyScreenX < leftTrigger) cameraX = baby.x - leftTrigger;
            }
            const maxCamera = Math.max(0, wW - width);
            cameraX = Math.max(0, Math.min(cameraX, maxCamera));
        }

        function drawJobHuntSideScrollBg() {
            const wW = jobHuntSideScrollWorldW;
            const wallH = height * ROOM_WALL_RATIO;
            const floorY = wallH;

            // ======== WALL BACKGROUND ========
            // Upper wall — cream
            const wallG = ctx.createLinearGradient(0, 0, 0, wallH * 0.65);
            wallG.addColorStop(0, "#f0ebe0");
            wallG.addColorStop(1, "#ebe5d8");
            ctx.fillStyle = wallG;
            ctx.fillRect(0, 0, wW, wallH * 0.65);

            // Lower wainscoting — darker
            ctx.fillStyle = "#e0d8c8";
            ctx.fillRect(0, wallH * 0.65, wW, wallH * 0.35);
            // Wainscot rail
            ctx.fillStyle = "#c8b898";
            ctx.fillRect(0, wallH * 0.65 - 1, wW, 3);
            // Wainscot panel rectangles
            ctx.strokeStyle = "rgba(195,185,170,0.3)"; ctx.lineWidth = 1.5;
            for (let x = 20; x < wW; x += 140) {
                ctx.beginPath();
                ctx.roundRect(x, wallH * 0.65 + 10, 110, wallH * 0.35 - 22, 3);
                ctx.stroke();
            }

            // Crown molding
            ctx.fillStyle = "rgba(220,215,205,0.5)";
            ctx.fillRect(0, 0, wW, 5);
            ctx.fillStyle = "rgba(200,195,185,0.35)";
            ctx.fillRect(0, 5, wW, 2);

            // Baseboard
            ctx.fillStyle = "rgba(140,120,90,0.55)";
            ctx.fillRect(0, floorY - 8, wW, 8);
            ctx.fillStyle = "rgba(170,150,120,0.3)";
            ctx.fillRect(0, floorY - 10, wW, 3);

            // ======== FLOOR ========
            // Dark carpet
            const carpG = ctx.createLinearGradient(0, floorY, 0, height);
            carpG.addColorStop(0, "#6a6050");
            carpG.addColorStop(1, "#5a5040");
            ctx.fillStyle = carpG;
            ctx.fillRect(0, floorY, wW, height - floorY);
            // Diamond pattern
            ctx.strokeStyle = "rgba(100,90,70,0.12)"; ctx.lineWidth = 0.5;
            const cs = 22;
            for (let ty = floorY; ty < height; ty += cs) {
                for (let tx = 0; tx < wW; tx += cs) {
                    ctx.beginPath();
                    ctx.moveTo(tx + cs / 2, ty); ctx.lineTo(tx + cs, ty + cs / 2);
                    ctx.lineTo(tx + cs / 2, ty + cs); ctx.lineTo(tx, ty + cs / 2);
                    ctx.closePath(); ctx.stroke();
                }
            }

            // ======== DOWNLIGHTS ========
            for (let dl = 0; dl < 5; dl++) {
                const dlx = wW * (0.1 + dl * 0.2), dly = 2;
                const dlg = ctx.createRadialGradient(dlx, dly, 0, dlx, dly, wallH * 0.4);
                dlg.addColorStop(0, "rgba(255,250,230,0.10)"); dlg.addColorStop(1, "rgba(255,250,230,0)");
                ctx.fillStyle = dlg;
                ctx.fillRect(dlx - wallH * 0.3, dly, wallH * 0.6, wallH * 0.4);
                // Light fixture
                ctx.fillStyle = "rgba(255,250,240,0.6)";
                ctx.beginPath(); ctx.arc(dlx, dly + 3, 4, 0, Math.PI * 2); ctx.fill();
            }

            // ======== DOOR (left edge, x: 0–80) ========
            // Door frame
            ctx.fillStyle = "#8a7a58";
            ctx.beginPath(); ctx.roundRect(2, wallH * 0.12, 72, floorY - wallH * 0.12 + 4, 3); ctx.fill();
            // Door opening (hallway visible through)
            ctx.fillStyle = "#c8c0a8";
            ctx.fillRect(6, wallH * 0.15, 64, floorY - wallH * 0.15);
            // Hallway hint gradient
            const hallG = ctx.createLinearGradient(6, 0, 70, 0);
            hallG.addColorStop(0, "#d0c8bb"); hallG.addColorStop(1, "#c4bba8");
            ctx.fillStyle = hallG;
            ctx.fillRect(6, wallH * 0.15, 64, floorY - wallH * 0.15);
            // Door handle
            ctx.fillStyle = "#b8a878";
            ctx.beginPath(); ctx.roundRect(60, floorY * 0.55, 8, 12, 3); ctx.fill();
            ctx.fillStyle = "#d4c49a";
            ctx.beginPath(); ctx.arc(64, floorY * 0.55 + 6, 2, 0, Math.PI * 2); ctx.fill();
            // 面接室 sign above door
            ctx.fillStyle = "#f0ece0";
            ctx.beginPath(); ctx.roundRect(14, wallH * 0.08, 48, 16, 3); ctx.fill();
            ctx.fillStyle = "#444";
            ctx.font = "600 11px 'Zen Maru Gothic'";
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("面接室", 38, wallH * 0.08 + 8);

            // ======== POTTED PLANT & COAT RACK (left side) ========
            // Potted plant
            const ppx = 80, ppy = floorY - 8;
            ctx.fillStyle = "#b06030";
            ctx.beginPath();
            ctx.moveTo(ppx - 10, ppy + 6); ctx.lineTo(ppx + 10, ppy + 6);
            ctx.lineTo(ppx + 8, ppy + 20); ctx.lineTo(ppx - 8, ppy + 20);
            ctx.closePath(); ctx.fill();
            ctx.fillStyle = "#2d8833";
            for (let lf = 0; lf < 7; lf++) {
                const la = (Math.PI * 2 * lf) / 7 - Math.PI / 2;
                ctx.beginPath(); ctx.ellipse(ppx + Math.cos(la) * 12, ppy + Math.sin(la) * 8 - 4, 8, 5, la, 0, Math.PI * 2); ctx.fill();
            }
            // Coat rack
            const crx = 130, cry = floorY - 5;
            ctx.strokeStyle = "#555"; ctx.lineWidth = 3; ctx.lineCap = "round";
            ctx.beginPath(); ctx.moveTo(crx, cry); ctx.lineTo(crx, cry - 60); ctx.stroke();
            // Hooks
            ctx.lineWidth = 2;
            ctx.beginPath(); ctx.moveTo(crx - 12, cry - 55); ctx.lineTo(crx, cry - 50); ctx.lineTo(crx + 12, cry - 55); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(crx - 8, cry - 45); ctx.lineTo(crx, cry - 40); ctx.lineTo(crx + 8, cry - 45); ctx.stroke();
            // Base
            ctx.lineWidth = 2.5;
            ctx.beginPath(); ctx.moveTo(crx - 15, cry); ctx.lineTo(crx + 15, cry); ctx.stroke();
            ctx.lineCap = "butt";

            // ======== PLAYER'S PIPE CHAIR (x: ~40%, facing interviewers) ========
            const pcx = wW * 0.40, pcy = floorY - 5;
            // Metal legs
            ctx.strokeStyle = "#999"; ctx.lineWidth = 2; ctx.lineCap = "round";
            ctx.beginPath(); ctx.moveTo(pcx - 10, pcy); ctx.lineTo(pcx - 14, pcy + 15); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(pcx + 10, pcy); ctx.lineTo(pcx + 14, pcy + 15); ctx.stroke();
            ctx.lineCap = "butt";
            // Seat
            ctx.fillStyle = "#7090a8";
            ctx.beginPath(); ctx.roundRect(pcx - 14, pcy - 8, 28, 10, 3); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.08)";
            ctx.fillRect(pcx - 12, pcy - 7, 24, 3);
            // Back
            ctx.fillStyle = "#6080a0";
            ctx.beginPath(); ctx.roundRect(pcx - 12, pcy - 40, 24, 32, [4, 4, 0, 0]); ctx.fill();

            // ======== INTERVIEWERS (drawn BEFORE desk, aligned with tone drops) ========
            // Tone drops at 53%, 63%, 73% — interviewers sit at matching positions
            updateJobHuntNpcs();
            const interviewerXPositions = [wW * 0.53, wW * 0.63, wW * 0.73];
            const interviewerY = floorY - 5;
            const interviewerNpcs = jobHuntNpcs.filter(n => n.isInterviewer);
            for (let i = 0; i < interviewerNpcs.length && i < 3; i++) {
                const npc = interviewerNpcs[i];
                // Temporarily set position for side-scroll drawing
                const savedX = npc.x, savedY = npc.y;
                npc.x = interviewerXPositions[i];
                npc.y = interviewerY;
                drawJobHuntNpc(npc, ctx);
                npc.x = savedX; npc.y = savedY;
            }

            // ======== INTERVIEW DESK (spans tone cluster area: ~48%–78%) ========
            const dskX = wW * 0.48, dskW = wW * 0.30;
            const dskTopY = floorY - 30;
            const dskH = 12, dskDepth = 22;
            // Desk legs
            ctx.fillStyle = "#5a3c1a";
            const legW = 5, legH = 28;
            ctx.beginPath(); ctx.roundRect(dskX + 15, dskTopY + dskH, legW, legH, 2); ctx.fill();
            ctx.beginPath(); ctx.roundRect(dskX + dskW - 20, dskTopY + dskH, legW, legH, 2); ctx.fill();
            // Front face (desk thickness — visible from side)
            ctx.fillStyle = "#6a4c2a";
            ctx.fillRect(dskX, dskTopY + dskH, dskW, dskDepth);
            // Bottom edge shadow
            ctx.fillStyle = "rgba(0,0,0,0.08)";
            ctx.fillRect(dskX + 2, dskTopY + dskH + dskDepth, dskW - 4, 3);
            // Top surface
            ctx.fillStyle = "#7a5c3a";
            ctx.beginPath(); ctx.roundRect(dskX, dskTopY, dskW, dskH, 3); ctx.fill();
            // Wood grain
            ctx.strokeStyle = "rgba(100,70,40,0.12)"; ctx.lineWidth = 0.5;
            for (let wl = 0; wl < 5; wl++) {
                const wy = dskTopY + 2 + wl * (dskH - 4) / 4;
                ctx.beginPath(); ctx.moveTo(dskX + 4, wy); ctx.lineTo(dskX + dskW - 4, wy); ctx.stroke();
            }
            // Front edge highlight
            ctx.fillStyle = "rgba(255,255,255,0.06)";
            ctx.fillRect(dskX + 2, dskTopY + 1, dskW - 4, 3);
            // Desk items
            ctx.fillStyle = "#f0ece0";
            ctx.beginPath(); ctx.roundRect(dskX + 20, dskTopY + 2, 18, 8, 1); ctx.fill();
            ctx.beginPath(); ctx.roundRect(dskX + 45, dskTopY + 3, 16, 7, 1); ctx.fill();
            // Coffee cup
            ctx.fillStyle = "#f8f4f0";
            ctx.beginPath(); ctx.ellipse(dskX + dskW * 0.5, dskTopY + 5, 5, 4, 0, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#8a5030"; ctx.globalAlpha = 0.5;
            ctx.beginPath(); ctx.ellipse(dskX + dskW * 0.5, dskTopY + 5, 3.5, 2.8, 0, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = 1;
            // Name plate
            ctx.fillStyle = "#c8a848";
            ctx.beginPath(); ctx.roundRect(dskX + dskW * 0.75, dskTopY + 2, 22, 8, 2); ctx.fill();
            ctx.fillStyle = "#333";
            ctx.font = "600 7px 'Zen Maru Gothic'";
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("面接官", dskX + dskW * 0.75 + 11, dskTopY + 6);

            // ======== INTERVIEWER CHAIRS (behind desk, office-style) ========
            for (let ic = 0; ic < 3; ic++) {
                const cx = interviewerXPositions[ic], cy = floorY + 5;
                // Star base
                ctx.fillStyle = "#444";
                for (let cs = 0; cs < 5; cs++) {
                    const ca = (Math.PI * 2 * cs) / 5 - Math.PI / 2;
                    const bx = cx + Math.cos(ca) * 10, by = cy + Math.sin(ca) * 4;
                    ctx.beginPath(); ctx.arc(bx, by, 2, 0, Math.PI * 2); ctx.fill();
                }
            }

            // ======== WALL DECORATIONS ========
            // Whiteboard (behind interviewers on wall)
            const wbX = wW * 0.56, wbY = wallH * 0.12, wbW = wW * 0.18, wbH = wallH * 0.28;
            ctx.fillStyle = "#f0f0f0";
            ctx.beginPath(); ctx.roundRect(wbX, wbY, wbW, wbH, 2); ctx.fill();
            ctx.strokeStyle = "#bbb"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.roundRect(wbX, wbY, wbW, wbH, 2); ctx.stroke();
            // Whiteboard content sketch
            ctx.strokeStyle = "rgba(50,100,200,0.3)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(wbX + 8, wbY + wbH - 10); ctx.lineTo(wbX + wbW - 8, wbY + wbH - 10); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(wbX + 8, wbY + wbH - 10); ctx.lineTo(wbX + 8, wbY + 8); ctx.stroke();
            ctx.strokeStyle = "rgba(200,50,50,0.25)";
            ctx.beginPath();
            ctx.moveTo(wbX + 10, wbY + wbH - 14);
            ctx.lineTo(wbX + wbW * 0.4, wbY + wbH * 0.3);
            ctx.lineTo(wbX + wbW * 0.65, wbY + wbH * 0.5);
            ctx.lineTo(wbX + wbW - 10, wbY + 12);
            ctx.stroke();

            // Company logo plaque (above desk area)
            const lgX = wW * 0.65, lgY = wallH * 0.06;
            ctx.fillStyle = "rgba(100,120,160,0.15)";
            ctx.beginPath(); ctx.arc(lgX, lgY, 18, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "rgba(100,120,160,0.25)"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.arc(lgX, lgY, 18, 0, Math.PI * 2); ctx.stroke();
            ctx.fillStyle = "rgba(100,120,160,0.2)";
            ctx.beginPath(); ctx.arc(lgX, lgY, 10, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "rgba(80,100,140,0.3)";
            ctx.font = "600 8px 'Zen Maru Gothic'";
            ctx.textAlign = "center"; ctx.textBaseline = "top";
            ctx.fillText("トーン株式会社", lgX, lgY + 20);

            // Clock (right wall)
            const clkX = wW * 0.85, clkY = wallH * 0.18, clkR = 16;
            ctx.fillStyle = "#fff"; ctx.beginPath(); ctx.arc(clkX, clkY, clkR, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "#666"; ctx.lineWidth = 1.2; ctx.beginPath(); ctx.arc(clkX, clkY, clkR, 0, Math.PI * 2); ctx.stroke();
            for (let h = 0; h < 12; h++) {
                const ha = (Math.PI * 2 * h) / 12 - Math.PI / 2;
                ctx.fillStyle = "#444";
                ctx.beginPath(); ctx.arc(clkX + Math.cos(ha) * (clkR - 3), clkY + Math.sin(ha) * (clkR - 3), 1.2, 0, Math.PI * 2); ctx.fill();
            }
            const now = Date.now();
            const secAngle = ((now / 1000) % 60) / 60 * Math.PI * 2 - Math.PI / 2;
            const minAngle = ((now / 60000) % 60) / 60 * Math.PI * 2 - Math.PI / 2;
            const hrAngle = ((now / 3600000) % 12) / 12 * Math.PI * 2 - Math.PI / 2;
            ctx.lineCap = "round";
            ctx.strokeStyle = "#333"; ctx.lineWidth = 1.8;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(hrAngle) * (clkR * 0.5), clkY + Math.sin(hrAngle) * (clkR * 0.5)); ctx.stroke();
            ctx.lineWidth = 1.2;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(minAngle) * (clkR * 0.7), clkY + Math.sin(minAngle) * (clkR * 0.7)); ctx.stroke();
            ctx.strokeStyle = "#cc3333"; ctx.lineWidth = 0.6;
            ctx.beginPath(); ctx.moveTo(clkX, clkY); ctx.lineTo(clkX + Math.cos(secAngle) * (clkR * 0.8), clkY + Math.sin(secAngle) * (clkR * 0.8)); ctx.stroke();
            ctx.lineCap = "butt";
            ctx.fillStyle = "#333"; ctx.beginPath(); ctx.arc(clkX, clkY, 1.8, 0, Math.PI * 2); ctx.fill();

            // Wall paintings (left wall, near door)
            const paintings = [
                { x: wW * 0.12, y: wallH * 0.18, w: 40, h: 28, c1: "#6a8ab0", c2: "#88aad0" },
                { x: wW * 0.24, y: wallH * 0.22, w: 35, h: 24, c1: "#a08860", c2: "#c0a880" }
            ];
            paintings.forEach(p => {
                ctx.fillStyle = "#6a5a40";
                ctx.beginPath(); ctx.roundRect(p.x - 2, p.y - 2, p.w + 4, p.h + 4, 2); ctx.fill();
                const pg = ctx.createLinearGradient(p.x, p.y, p.x + p.w, p.y + p.h);
                pg.addColorStop(0, p.c1); pg.addColorStop(1, p.c2);
                ctx.fillStyle = pg;
                ctx.fillRect(p.x, p.y, p.w, p.h);
            });

            // AC unit on wall
            const acX = wW * 0.82, acY = wallH * 0.05;
            ctx.fillStyle = "#eee";
            ctx.beginPath(); ctx.roundRect(acX, acY, 80, 16, 3); ctx.fill();
            ctx.strokeStyle = "rgba(200,200,200,0.6)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(acX, acY, 80, 16, 3); ctx.stroke();
            ctx.strokeStyle = "rgba(180,180,180,0.4)"; ctx.lineWidth = 0.5;
            for (let vs = 0; vs < 4; vs++) {
                const vy = acY + 4 + vs * 3;
                ctx.beginPath(); ctx.moveTo(acX + 4, vy); ctx.lineTo(acX + 76, vy); ctx.stroke();
            }
            ctx.fillStyle = "#4a4"; ctx.beginPath(); ctx.arc(acX + 8, acY + 5, 1.5, 0, Math.PI * 2); ctx.fill();

            // ======== RIGHT CORNER (x: ~90%–100%): filing cabinet, plant ========
            // Filing cabinet
            const fcX = wW * 0.93, fcY = floorY - 55;
            ctx.fillStyle = "#8a8a8a";
            ctx.beginPath(); ctx.roundRect(fcX, fcY, 36, 55, 2); ctx.fill();
            // Drawers
            for (let dr = 0; dr < 3; dr++) {
                const dy = fcY + 3 + dr * 17;
                ctx.fillStyle = "#7a7a7a";
                ctx.beginPath(); ctx.roundRect(fcX + 3, dy, 30, 14, 1); ctx.fill();
                ctx.fillStyle = "#999";
                ctx.beginPath(); ctx.roundRect(fcX + 15, dy + 5, 6, 3, 1); ctx.fill();
            }
            // Potted plant in corner
            const rpx = wW * 0.97, rpy = floorY - 8;
            ctx.fillStyle = "#b06030";
            ctx.beginPath();
            ctx.moveTo(rpx - 8, rpy + 4); ctx.lineTo(rpx + 8, rpy + 4);
            ctx.lineTo(rpx + 6, rpy + 16); ctx.lineTo(rpx - 6, rpy + 16);
            ctx.closePath(); ctx.fill();
            ctx.fillStyle = "#2d8833";
            for (let lf = 0; lf < 6; lf++) {
                const la = (Math.PI * 2 * lf) / 6 - Math.PI / 2;
                ctx.beginPath(); ctx.ellipse(rpx + Math.cos(la) * 10, rpy + Math.sin(la) * 7 - 2, 7, 4, la, 0, Math.PI * 2); ctx.fill();
            }

            // ======== "← 廊下" exit hint near left door ========
            if (baby && baby.x < 140) {
                ctx.save();
                ctx.globalAlpha = 0.6 + 0.2 * Math.sin(Date.now() * 0.004);
                ctx.fillStyle = "#fff";
                ctx.font = "700 14px 'Zen Maru Gothic'";
                ctx.textAlign = "center"; ctx.textBaseline = "middle";
                ctx.fillText("← 廊下", 40, floorY + 35);
                ctx.restore();
            }

            // Interview round indicator for JOB_HUNT2
            if (currentScene === SCENE.JOB_HUNT2) {
                ctx.save();
                ctx.fillStyle = "rgba(200,180,100,0.6)";
                ctx.font = "700 18px 'Zen Maru Gothic'";
                ctx.textAlign = "center"; ctx.textBaseline = "middle";
                ctx.fillText("二次面接", wW * 0.5, wallH * 0.08);
                ctx.restore();
            }
        }

        function handleJobHuntChoice(clickedDrop) {
            if (jobHuntTransitioning) return;
            if (!clickedDrop.activityLabels) return;
            if (clickedDrop.consumed) return; // Already used modifier
            playTitleToneConfirmSound();
            selectedToys.push({ id: clickedDrop.activityId, name: clickedDrop.activityName, labels: clickedDrop.activityLabels });

            // Second interview condition check (round 1)
            if (jobHuntInterviewRound === 1 && clickedDrop.requiredLabel) {
                const totals = {};
                selectedToys.forEach(t => {
                    if (!t.labels) return;
                    Object.entries(t.labels).forEach(([k, v]) => {
                        totals[k] = (totals[k] || 0) + v;
                    });
                });
                const currentVal = totals[clickedDrop.requiredLabel.key] || 0;
                if (currentVal >= clickedDrop.requiredLabel.threshold) {
                    triggerSecondInterview(clickedDrop);
                    return;
                }
            }

            // Round 2: modifier tone — confirm the replacement permanently
            if (jobHuntInterviewRound === 2 && clickedDrop.instrument === "modifier" && !clickedDrop.consumed) {
                // Preview is already applied by hover → just make it permanent
                // If hover preview wasn't active, apply the replacement now
                if (modifierPreviewDrop !== clickedDrop) {
                    const stepsPerBar = baseRhythmInfo.beatsPerBar * STEPS_PER_BEAT;
                    const stepsPerPage = scoreHudState.stepsPerPage;
                    const absStart = stepsPerPage + clickedDrop.targetBarOnPage2 * stepsPerBar;
                    const d = clickedDrop;
                    for (let s = 0; s < stepsPerBar; s++) {
                        const idx = absStart + s;
                        // Keys (keyboard) is NOT replaced — only bass, drums, cymbal, keys2
                        if (inheritedBassPattern && d.replacementBassPattern) inheritedBassPattern[idx] = d.replacementBassPattern[s];
                        if (inheritedBassNotes && d.replacementBassNotes) inheritedBassNotes[idx] = d.replacementBassNotes[s];
                        if (inheritedBassAttacks && d.replacementBassAttacks) inheritedBassAttacks[idx] = d.replacementBassAttacks[s];
                        if (inheritedBassDurations && d.replacementBassDurations) inheritedBassDurations[idx] = d.replacementBassDurations[s];
                        if (baseRhythmInfo.kickPattern && d.replacementKick) baseRhythmInfo.kickPattern[idx] = d.replacementKick[s];
                        if (inheritedHatPattern && d.replacementHat) inheritedHatPattern[idx] = d.replacementHat[s];
                        if (inheritedSnarePattern && d.replacementSnare) inheritedSnarePattern[idx] = d.replacementSnare[s];
                        if (inheritedCymbalPattern && d.replacementCymbal) inheritedCymbalPattern[idx] = d.replacementCymbal[s];
                        if (inheritedCymbalVelocity && d.replacementCymbalVelocity) inheritedCymbalVelocity[idx] = d.replacementCymbalVelocity[s];
                        if (inheritedKeys2Pattern && d.replacementK2Pattern) inheritedKeys2Pattern[idx] = d.replacementK2Pattern[s];
                        if (inheritedKeys2Notes && d.replacementK2Notes) inheritedKeys2Notes[idx] = d.replacementK2Notes[s];
                        if (inheritedKeys2Attacks && d.replacementK2Attacks) inheritedKeys2Attacks[idx] = d.replacementK2Attacks[s];
                        if (inheritedKeys2Durations && d.replacementK2Durations) inheritedKeys2Durations[idx] = d.replacementK2Durations[s];
                        if (inheritedKeys2SustainType && d.replacementK2SustainType) inheritedKeys2SustainType[idx] = d.replacementK2SustainType[s];
                    }
                }
                // Clear preview state — the change is now permanent, no revert possible
                modifierPreviewDrop = null;
                modifierPreviewOriginal = null;

                // Mark consumed
                clickedDrop.consumed = true;

                // Add permanent bar highlight (page 1 = page2 in 0-indexed)
                scoreHudState.barHighlights.push({
                    page: 1,
                    barIndex: clickedDrop.targetBarOnPage2,
                    color: clickedDrop.dropColor
                });

                // Re-render score HUD
                renderScoreRows(null);

                // One modifier tone selected → advance to THIRTIES phase
                setTimeout(() => {
                    disposeToneDrops();
                    toneDrops = [];
                    jobHuntViewMode = "topdown";
                    if (baby) baby.isTopDown = true;
                    fadeScreenTo(1, 1200);
                    setTimeout(() => {
                        isTopDownScene = false;
                        startThirtiesPhase();
                        fadeScreenTo(0, 1000);
                    }, 1200);
                }, 1500);
                return;
            }

            // Condition not met (round 1) → preserve selected tone as Keys2, then next phase
            if (clickedDrop.instrument === "keyboard") {
                inheritedKeys2Pattern = clickedDrop.pattern ? clickedDrop.pattern.slice() : inheritedKeys2Pattern;
                inheritedKeys2Notes = clickedDrop.keyboardNotes ? clickedDrop.keyboardNotes.slice() : inheritedKeys2Notes;
                inheritedKeys2Attacks = clickedDrop.keyboardAttacks ? clickedDrop.keyboardAttacks.slice() : inheritedKeys2Attacks;
                inheritedKeys2Durations = clickedDrop.keyboardDurations ? clickedDrop.keyboardDurations.slice() : inheritedKeys2Durations;
                inheritedKeys2SustainType = clickedDrop.keyboardSustainType ? clickedDrop.keyboardSustainType.slice() : inheritedKeys2SustainType;
                inheritedKeys2SoundConfig = clickedDrop.jobHuntTimbre || inheritedKeys2SoundConfig;
            }
            disposeToneDrops();
            toneDrops = [];
            jobHuntViewMode = "topdown";
            if (baby) baby.isTopDown = true;
            fadeScreenTo(1, 1200);
            setTimeout(() => {
                isTopDownScene = false;
                startThirtiesPhase();
                fadeScreenTo(0, 1000);
            }, 1200);
        }

        function triggerSecondInterview(selectedDrop) {
            // Preserve the clicked tone's keyboard line as Keys2 (not main keyboard)
            if (selectedDrop && selectedDrop.instrument === "keyboard") {
                inheritedKeys2Pattern = selectedDrop.pattern ? selectedDrop.pattern.slice() : inheritedKeys2Pattern;
                inheritedKeys2Notes = selectedDrop.keyboardNotes ? selectedDrop.keyboardNotes.slice() : inheritedKeys2Notes;
                inheritedKeys2Attacks = selectedDrop.keyboardAttacks ? selectedDrop.keyboardAttacks.slice() : inheritedKeys2Attacks;
                inheritedKeys2Durations = selectedDrop.keyboardDurations ? selectedDrop.keyboardDurations.slice() : inheritedKeys2Durations;
                inheritedKeys2SustainType = selectedDrop.keyboardSustainType ? selectedDrop.keyboardSustainType.slice() : inheritedKeys2SustainType;
                inheritedKeys2SoundConfig = selectedDrop.jobHuntTimbre || inheritedKeys2SoundConfig;
                // Recreate carry Keys2 synth with JOB_HUNT timbre
                disposeCarryKeys2Layer();
                const kb = createJobHuntSynth(selectedDrop.jobHuntTimbre || "bright-chime");
                carryKeys2Synth = kb.synth;
                carryKeys2Effects = kb.effects;
                if (carryKeys2Synth) carryKeys2Synth.volume.value = -18;
            }
            disposeToneDrops();
            toneDrops = [];

            // Celebratory sparkle particles
            const sparkles = [];
            for (let i = 0; i < 40; i++) {
                sparkles.push({
                    x: width * 0.5 + (Math.random() - 0.5) * width * 0.6,
                    y: height * 0.5 + (Math.random() - 0.5) * height * 0.3,
                    vx: (Math.random() - 0.5) * 3,
                    vy: -Math.random() * 2.5 - 0.5,
                    size: Math.random() * 4 + 2,
                    hue: Math.random() * 60 + 30, // gold-yellow range
                    life: 1.0,
                    decay: 0.003 + Math.random() * 0.004
                });
            }

            // Flash + text animation
            secondInterviewText = {
                textJa: "一次面接通過！",
                textEn: "First Interview Passed!",
                alpha: 0, scale: 0.5, sparkles: sparkles,
                shimmer: 0
            };
            let frame = 0;
            const animateText = () => {
                frame++;
                if (secondInterviewText) secondInterviewText.shimmer = frame;
                if (frame < 40) {
                    // Zoom in with easing
                    const t = frame / 40;
                    const ease = 1 - Math.pow(1 - t, 3);
                    secondInterviewText.alpha = ease;
                    secondInterviewText.scale = 0.3 + ease * 0.9;
                } else if (frame < 120) {
                    // Hold with gentle pulse
                    secondInterviewText.alpha = 1;
                    secondInterviewText.scale = 1.2 + Math.sin(frame * 0.08) * 0.04;
                } else if (frame < 160) {
                    secondInterviewText.alpha = Math.max(0, secondInterviewText.alpha - 0.03);
                } else {
                    secondInterviewText = null;
                    fadeScreenTo(1, 800);
                    setTimeout(() => {
                        startJobHunt2Phase();
                        fadeScreenTo(0, 800);
                    }, 800);
                    return;
                }
                // Update sparkles
                if (secondInterviewText && secondInterviewText.sparkles) {
                    secondInterviewText.sparkles.forEach(s => {
                        s.x += s.vx;
                        s.y += s.vy;
                        s.vy += 0.02;
                        s.life -= s.decay;
                    });
                }
                requestAnimationFrame(animateText);
            };
            // White flash
            sceneFade.style.background = '#fff';
            fadeScreenTo(0.7, 200);
            setTimeout(() => {
                fadeScreenTo(0, 400);
                sceneFade.style.background = '#fff';
                animateText();
            }, 300);
        }

        function startJobHunt2Phase() {
            currentScene = SCENE.JOB_HUNT2;
            isTopDownScene = true;
            jobHuntInterviewRound = 2;
            jobHuntViewMode = "topdown";
            jobHuntTransitioning = false;
            jobHuntDropTopDownPositions = [];
            modifierPreviewDrop = null;
            modifierPreviewOriginal = null;
            worldWidth = Math.max(width * 1.3, 1000);
            worldHeight = Math.max(height * 1.8, 1000);
            // Recompute obstacles for new world size
            const wW = worldWidth, wH = worldHeight;
            const wallY = wH * 0.52, wallThick = 18;
            const doorX = wW * 0.38, doorW = wW * 0.24;
            const dskX = wW * 0.15, dskY = wH * 0.32, dskW = wW * 0.70, dskH = wH * 0.04;
            jobHuntObstacles = [
                { x: dskX, y: dskY, w: dskW, h: dskH },
                { x: 0, y: wallY - wallThick / 2, w: doorX, h: wallThick },
                { x: doorX + doorW, y: wallY - wallThick / 2, w: wW - doorX - doorW, h: wallThick },
            ];
            // Reset baby to hallway for second interview
            if (baby) {
                baby.isTopDown = true;
                baby.x = worldWidth * 0.5;
                baby.y = worldHeight * 0.68;
            }
            initJobHunt2Drops();
            buildScoreHud();
            updateScoreToggleUi();
        }

        function initJobHunt2Drops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo || !inheritedChordProgression) return;

            const stepsPerPage = baseRhythmInfo.beatsPerBar * baseRhythmInfo.bars * STEPS_PER_BEAT;
            const stepsPerBar = baseRhythmInfo.beatsPerBar * STEPS_PER_BEAT;
            scoreHudState.pageCount = 2;
            scoreHudState.currentPage = 0;
            scoreHudState.stepsPerPage = stepsPerPage;
            scoreHudState.barHighlights = [];

            // Double the base patterns for pagination (page1 = original, page2 = copy)
            if (baseRhythmInfo.kickPattern) {
                baseRhythmInfo._originalKick = baseRhythmInfo._originalKick || baseRhythmInfo.kickPattern.slice();
                baseRhythmInfo.kickPattern = [...baseRhythmInfo._originalKick, ...baseRhythmInfo._originalKick];
            }
            if (inheritedHatPattern) {
                inheritedHatPattern = [...inheritedHatPattern.slice(0, stepsPerPage), ...inheritedHatPattern.slice(0, stepsPerPage)];
            }
            if (inheritedSnarePattern) {
                inheritedSnarePattern = [...inheritedSnarePattern.slice(0, stepsPerPage), ...inheritedSnarePattern.slice(0, stepsPerPage)];
            }
            if (inheritedSnareVelocity) {
                inheritedSnareVelocity = [...inheritedSnareVelocity.slice(0, stepsPerPage), ...inheritedSnareVelocity.slice(0, stepsPerPage)];
            }
            if (inheritedBassPattern) {
                inheritedBassPattern = [...inheritedBassPattern.slice(0, stepsPerPage), ...inheritedBassPattern.slice(0, stepsPerPage)];
                if (inheritedBassNotes) inheritedBassNotes = [...inheritedBassNotes.slice(0, stepsPerPage), ...inheritedBassNotes.slice(0, stepsPerPage)];
                if (inheritedBassAttacks) inheritedBassAttacks = [...inheritedBassAttacks.slice(0, stepsPerPage), ...inheritedBassAttacks.slice(0, stepsPerPage)];
                if (inheritedBassDurations) inheritedBassDurations = [...inheritedBassDurations.slice(0, stepsPerPage), ...inheritedBassDurations.slice(0, stepsPerPage)];
                if (inheritedBassSustainType) inheritedBassSustainType = [...inheritedBassSustainType.slice(0, stepsPerPage), ...inheritedBassSustainType.slice(0, stepsPerPage)];
            }
            if (inheritedKeyboardPattern) {
                inheritedKeyboardPattern = [...inheritedKeyboardPattern.slice(0, stepsPerPage), ...inheritedKeyboardPattern.slice(0, stepsPerPage)];
                if (inheritedKeyboardNotes) inheritedKeyboardNotes = [...inheritedKeyboardNotes.slice(0, stepsPerPage), ...inheritedKeyboardNotes.slice(0, stepsPerPage)];
                if (inheritedKeyboardAttacks) inheritedKeyboardAttacks = [...inheritedKeyboardAttacks.slice(0, stepsPerPage), ...inheritedKeyboardAttacks.slice(0, stepsPerPage)];
                if (inheritedKeyboardDurations) inheritedKeyboardDurations = [...inheritedKeyboardDurations.slice(0, stepsPerPage), ...inheritedKeyboardDurations.slice(0, stepsPerPage)];
                if (inheritedKeyboardSustainType) inheritedKeyboardSustainType = [...inheritedKeyboardSustainType.slice(0, stepsPerPage), ...inheritedKeyboardSustainType.slice(0, stepsPerPage)];
            }
            if (inheritedKeys2Pattern) {
                inheritedKeys2Pattern = [...inheritedKeys2Pattern.slice(0, stepsPerPage), ...inheritedKeys2Pattern.slice(0, stepsPerPage)];
                if (inheritedKeys2Notes) inheritedKeys2Notes = [...inheritedKeys2Notes.slice(0, stepsPerPage), ...inheritedKeys2Notes.slice(0, stepsPerPage)];
                if (inheritedKeys2Attacks) inheritedKeys2Attacks = [...inheritedKeys2Attacks.slice(0, stepsPerPage), ...inheritedKeys2Attacks.slice(0, stepsPerPage)];
                if (inheritedKeys2Durations) inheritedKeys2Durations = [...inheritedKeys2Durations.slice(0, stepsPerPage), ...inheritedKeys2Durations.slice(0, stepsPerPage)];
                if (inheritedKeys2SustainType) inheritedKeys2SustainType = [...inheritedKeys2SustainType.slice(0, stepsPerPage), ...inheritedKeys2SustainType.slice(0, stepsPerPage)];
            }
            if (inheritedCymbalPattern) {
                inheritedCymbalPattern = [...inheritedCymbalPattern.slice(0, stepsPerPage), ...inheritedCymbalPattern.slice(0, stepsPerPage)];
                if (inheritedCymbalVelocity) inheritedCymbalVelocity = [...inheritedCymbalVelocity.slice(0, stepsPerPage), ...inheritedCymbalVelocity.slice(0, stepsPerPage)];
            }

            // 3 modifier tones — each replaces bar 3 or bar 4 of page 2
            const drops2 = [
                { id: "bright2",     name: "自信を持って", nameEn: "With Confidence",  color: "hsl(50, 65%, 58%)",  labels: { social: 5, optimistic: 4 },   xFrac: 0.25, yFrac: 0.42 },
                { id: "polite2",     name: "論理的に",    nameEn: "Logically",        color: "hsl(215, 50%, 58%)", labels: { study: 5, focused: 4 },        xFrac: 0.50, yFrac: 0.38 },
                { id: "passionate2", name: "熱意を込めて", nameEn: "With Passion",     color: "hsl(5, 60%, 56%)",   labels: { expressive: 5, creative: 4 }, xFrac: 0.75, yFrac: 0.42 }
            ];
            const styleMap = { "bright2": "formal-accent", "polite2": "dramatic-swell", "passionate2": "crisp-staccato" };

            // Assign each tone to bar index 2 or 3 (= bar 3 or 4 of page 2)
            // Ensure at least one targets each bar for variety
            const barPool = [2, 3, randInt(0, 1) ? 2 : 3];
            // Shuffle
            for (let i = barPool.length - 1; i > 0; i--) {
                const j = randInt(0, i);
                [barPool[i], barPool[j]] = [barPool[j], barPool[i]];
            }

            // Bass style mapping per mood
            const bassStyleMap = { "bright2": "energetic", "polite2": "soft", "passionate2": "groovy" };

            for (let i = 0; i < drops2.length; i++) {
                const fac = drops2[i];
                const targetBar = barPool[i]; // 0-indexed bar on page 2 (2 = bar3, 3 = bar4)
                const barStart = targetBar * stepsPerBar;
                const barEnd = barStart + stepsPerBar;
                const variant = randInt(0, 1);

                // Generate replacement for instruments EXCEPT Keys (keyboard stays unchanged)
                // Keys2 (different variant for variety)
                const k2Bundle = inheritedKeys2Pattern ? buildKeyboardLine(baseRhythmInfo, styleMap[fac.id], inheritedChordProgression, 1 - variant) : null;
                // Bass
                const bassBundle = inheritedBassPattern ? buildBassLine(baseRhythmInfo, bassStyleMap[fac.id] || "energetic", inheritedChordProgression, variant) : null;
                // Drums — generate new hat/snare patterns, extract the target bar
                const hatBar = buildHiHatPattern(baseRhythmInfo, randInt(0, 3));
                const snareBundle = buildSnarePattern(baseRhythmInfo, randInt(0, 3));

                // Build kick variation for the bar (flip some hits)
                let kickBar = null;
                if (baseRhythmInfo.kickPattern) {
                    kickBar = baseRhythmInfo.kickPattern.slice(barStart, barEnd);
                    // Vary: toggle 1-2 hits to create an accent feel
                    const flipCount = randInt(1, 2);
                    for (let f = 0; f < flipCount; f++) {
                        const idx = randInt(0, kickBar.length - 1);
                        kickBar[idx] = !kickBar[idx];
                    }
                }
                // Cymbal variation
                const cymbalBundle = inheritedCymbalPattern ? buildCymbalPattern(baseRhythmInfo, randInt(0, 3)) : null;

                toneDrops.push({
                    x: worldWidth * fac.xFrac,
                    y: worldHeight * fac.yFrac,
                    instrument: "modifier",
                    targetBarOnPage2: targetBar,
                    // Bass replacement
                    replacementBassPattern: bassBundle ? bassBundle.pattern.slice(barStart, barEnd) : null,
                    replacementBassNotes: bassBundle && bassBundle.notes ? bassBundle.notes.slice(barStart, barEnd) : null,
                    replacementBassAttacks: bassBundle && bassBundle.attacks ? bassBundle.attacks.slice(barStart, barEnd) : null,
                    replacementBassDurations: bassBundle && bassBundle.durations ? bassBundle.durations.slice(barStart, barEnd) : null,
                    replacementBassSustainType: bassBundle && bassBundle.sustainType ? bassBundle.sustainType.slice(barStart, barEnd) : null,
                    // Drum replacements
                    replacementKick: kickBar,
                    replacementHat: hatBar ? hatBar.slice(barStart, barEnd) : null,
                    replacementSnare: snareBundle ? snareBundle.pattern.slice(barStart, barEnd) : null,
                    // Cymbal replacement
                    replacementCymbal: cymbalBundle ? cymbalBundle.pattern.slice(barStart, barEnd) : null,
                    replacementCymbalVelocity: cymbalBundle ? cymbalBundle.velocity.slice(barStart, barEnd) : null,
                    // Keys2 replacement
                    replacementK2Pattern: k2Bundle ? k2Bundle.pattern.slice(barStart, barEnd) : null,
                    replacementK2Notes: k2Bundle && k2Bundle.notes ? k2Bundle.notes.slice(barStart, barEnd) : null,
                    replacementK2Attacks: k2Bundle && k2Bundle.attacks ? k2Bundle.attacks.slice(barStart, barEnd) : null,
                    replacementK2Durations: k2Bundle && k2Bundle.durations ? k2Bundle.durations.slice(barStart, barEnd) : null,
                    replacementK2SustainType: k2Bundle && k2Bundle.sustainType ? k2Bundle.sustainType.slice(barStart, barEnd) : null,
                    consumed: false,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    activityId: fac.id,
                    activityName: fac.name,
                    activityNameEn: fac.nameEn || null,
                    dropColor: fac.color,
                    activityLabels: fac.labels,
                    ripples: [],
                    pattern: null,
                    keyboardSynth: null,
                    keyboardEffects: null
                });
            }

            primeToneDrops();
        }

        // Modifier tone hover preview: temporarily swap bar data so player can audition
        function updateModifierTonePreview() {
            if (currentScene !== SCENE.JOB_HUNT2 || jobHuntInterviewRound !== 2) return;
            if (!baseRhythmInfo) return;

            // Find the hovered unconsumed modifier
            let hoveredMod = null;
            toneDrops.forEach(d => {
                if (d.instrument === "modifier" && d.isHovered && !d.consumed) hoveredMod = d;
            });

            // Same drop still hovered — nothing to do
            if (hoveredMod === modifierPreviewDrop) return;

            const stepsPerBar = baseRhythmInfo.beatsPerBar * STEPS_PER_BEAT;
            const stepsPerPage = scoreHudState.stepsPerPage;

            // Revert previous preview if any
            if (modifierPreviewDrop && modifierPreviewOriginal) {
                const prev = modifierPreviewDrop;
                const orig = modifierPreviewOriginal;
                const absStart = stepsPerPage + prev.targetBarOnPage2 * stepsPerBar;
                for (let s = 0; s < stepsPerBar; s++) {
                    const idx = absStart + s;
                    // Keys (keyboard) is NOT reverted — it was never changed
                    if (orig.bassPattern) inheritedBassPattern[idx] = orig.bassPattern[s];
                    if (orig.bassNotes) inheritedBassNotes[idx] = orig.bassNotes[s];
                    if (orig.bassAttacks) inheritedBassAttacks[idx] = orig.bassAttacks[s];
                    if (orig.bassDurations) inheritedBassDurations[idx] = orig.bassDurations[s];
                    if (orig.kick) baseRhythmInfo.kickPattern[idx] = orig.kick[s];
                    if (orig.hat) inheritedHatPattern[idx] = orig.hat[s];
                    if (orig.snare) inheritedSnarePattern[idx] = orig.snare[s];
                    if (orig.cymbal) inheritedCymbalPattern[idx] = orig.cymbal[s];
                    if (orig.cymbalVelocity) inheritedCymbalVelocity[idx] = orig.cymbalVelocity[s];
                    if (orig.k2Pattern) inheritedKeys2Pattern[idx] = orig.k2Pattern[s];
                    if (orig.k2Notes) inheritedKeys2Notes[idx] = orig.k2Notes[s];
                    if (orig.k2Attacks) inheritedKeys2Attacks[idx] = orig.k2Attacks[s];
                    if (orig.k2Durations) inheritedKeys2Durations[idx] = orig.k2Durations[s];
                    if (orig.k2SustainType) inheritedKeys2SustainType[idx] = orig.k2SustainType[s];
                }
                modifierPreviewDrop = null;
                modifierPreviewOriginal = null;
            }

            // Apply new preview
            if (hoveredMod) {
                const d = hoveredMod;
                const absStart = stepsPerPage + d.targetBarOnPage2 * stepsPerBar;
                // Save originals (Keys excluded — not modified)
                const slice = (arr) => arr ? arr.slice(absStart, absStart + stepsPerBar) : null;
                modifierPreviewOriginal = {
                    bassPattern: slice(inheritedBassPattern),
                    bassNotes: slice(inheritedBassNotes),
                    bassAttacks: slice(inheritedBassAttacks),
                    bassDurations: slice(inheritedBassDurations),
                    kick: slice(baseRhythmInfo.kickPattern),
                    hat: slice(inheritedHatPattern),
                    snare: slice(inheritedSnarePattern),
                    cymbal: slice(inheritedCymbalPattern),
                    cymbalVelocity: slice(inheritedCymbalVelocity),
                    k2Pattern: slice(inheritedKeys2Pattern),
                    k2Notes: slice(inheritedKeys2Notes),
                    k2Attacks: slice(inheritedKeys2Attacks),
                    k2Durations: slice(inheritedKeys2Durations),
                    k2SustainType: slice(inheritedKeys2SustainType)
                };
                // Apply replacement (Keys excluded)
                for (let s = 0; s < stepsPerBar; s++) {
                    const idx = absStart + s;
                    if (inheritedBassPattern && d.replacementBassPattern) inheritedBassPattern[idx] = d.replacementBassPattern[s];
                    if (inheritedBassNotes && d.replacementBassNotes) inheritedBassNotes[idx] = d.replacementBassNotes[s];
                    if (inheritedBassAttacks && d.replacementBassAttacks) inheritedBassAttacks[idx] = d.replacementBassAttacks[s];
                    if (inheritedBassDurations && d.replacementBassDurations) inheritedBassDurations[idx] = d.replacementBassDurations[s];
                    if (baseRhythmInfo.kickPattern && d.replacementKick) baseRhythmInfo.kickPattern[idx] = d.replacementKick[s];
                    if (inheritedHatPattern && d.replacementHat) inheritedHatPattern[idx] = d.replacementHat[s];
                    if (inheritedSnarePattern && d.replacementSnare) inheritedSnarePattern[idx] = d.replacementSnare[s];
                    if (inheritedCymbalPattern && d.replacementCymbal) inheritedCymbalPattern[idx] = d.replacementCymbal[s];
                    if (inheritedCymbalVelocity && d.replacementCymbalVelocity) inheritedCymbalVelocity[idx] = d.replacementCymbalVelocity[s];
                    if (inheritedKeys2Pattern && d.replacementK2Pattern) inheritedKeys2Pattern[idx] = d.replacementK2Pattern[s];
                    if (inheritedKeys2Notes && d.replacementK2Notes) inheritedKeys2Notes[idx] = d.replacementK2Notes[s];
                    if (inheritedKeys2Attacks && d.replacementK2Attacks) inheritedKeys2Attacks[idx] = d.replacementK2Attacks[s];
                    if (inheritedKeys2Durations && d.replacementK2Durations) inheritedKeys2Durations[idx] = d.replacementK2Durations[s];
                    if (inheritedKeys2SustainType && d.replacementK2SustainType) inheritedKeys2SustainType[idx] = d.replacementK2SustainType[s];
                }
                modifierPreviewDrop = d;
            }
        }

        // ======== CARRY KEYS2 LAYER (大学→アルバイト/就活) ========
        function disposeCarryKeys2Layer() {
            if (carryKeys2Synth) { carryKeys2Synth.dispose(); carryKeys2Synth = null; }
            if (carryKeys2Effects) { carryKeys2Effects.forEach(e => e.dispose()); carryKeys2Effects = []; }
        }

        function initCarryKeys2Layer() {
            disposeCarryKeys2Layer();
            if (!inheritedKeys2Pattern || !inheritedKeys2Notes) return;

            // Check if the sound config is a PART_TIME timbre name directly (e.g., "register-beep")
            const ptCfg = PARTTIME_TIMBRES[inheritedKeys2SoundConfig];
            if (ptCfg) {
                const kb = createPartTimeSynth(inheritedKeys2SoundConfig);
                carryKeys2Synth = kb.synth;
                carryKeys2Effects = kb.effects;
                if (carryKeys2Synth) carryKeys2Synth.volume.value = -22;
                return;
            }

            // Check if the sound config is a JOB_HUNT timbre name directly
            const jhCfg = JOBHUNT_TIMBRES[inheritedKeys2SoundConfig];
            if (jhCfg) {
                const kb = createJobHuntSynth(inheritedKeys2SoundConfig);
                carryKeys2Synth = kb.synth;
                carryKeys2Effects = kb.effects;
                if (carryKeys2Synth) carryKeys2Synth.volume.value = -22;
                return;
            }

            // Check if the sound config is a KEYBOARD timbre name directly (e.g., travel K2: "staccato-bounce", "syncopated")
            const kbCfg = KEYBOARD_TIMBRES[inheritedKeys2SoundConfig];
            if (kbCfg) {
                const kb = createKeyboardSynth(inheritedKeys2SoundConfig);
                carryKeys2Synth = kb.synth;
                carryKeys2Effects = kb.effects;
                if (carryKeys2Synth) carryKeys2Synth.volume.value = -22;
                return;
            }

            // Otherwise use university facility mapping
            const styleMap = {
                "gate": "bells", "field": "xylophone", "building": "piano-gentle",
                "gym": "marimba", "art_hall": "glass-pad"
            };
            const timbreName = styleMap[inheritedKeys2SoundConfig] || "piano-gentle";
            const cfg = UNIVERSITY_TIMBRES[timbreName] || KEYBOARD_TIMBRES[timbreName];
            if (!cfg) return;
            const synth = new Tone.PolySynth(Tone.Synth, {
                oscillator: { type: cfg.wave },
                envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
            });
            synth.volume.value = -24;
            if (cfg.filterType) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                carryKeys2Effects.push(filter);
                synth.chain(filter, Tone.Destination);
            } else {
                synth.toDestination();
            }
            carryKeys2Synth = synth;
        }

        function drawUniversityBuildings(wallH) {
            for (let i = 0; i < UNIVERSITY_FACILITIES.length; i++) {
                const fac = UNIVERSITY_FACILITIES[i];
                const cx = worldWidth * (fac.worldFraction[0] + fac.worldFraction[1]) / 2;
                const zoneW = worldWidth * (fac.worldFraction[1] - fac.worldFraction[0]);
                const bw = zoneW * 0.80;
                const bx = cx - bw / 2;

                if (fac.id === "gate") {
                    drawGateBuilding(cx, bx, bw, wallH);
                } else if (fac.id === "field") {
                    drawFieldBuilding(cx, bx, bw, wallH);
                } else if (fac.id === "building") {
                    drawMainBuilding(cx, bx, bw, wallH);
                } else if (fac.id === "gym") {
                    drawGymBuilding(cx, bx, bw, wallH);
                } else if (fac.id === "art_hall") {
                    drawArtHallBuilding(cx, bx, bw, wallH);
                }
            }
        }

        // === 校門 (Gate) ===
        function drawGateBuilding(cx, bx, bw, wallH) {
            const groundY = wallH;
            const pillarH = wallH * 0.45;
            const pillarW = bw * 0.08;
            const gateW = bw * 0.35;

            // Brick wall extending left and right
            ctx.fillStyle = "#b88860";
            ctx.fillRect(bx, groundY - pillarH * 0.4, bw * 0.25, pillarH * 0.4);
            ctx.fillRect(bx + bw * 0.75, groundY - pillarH * 0.4, bw * 0.25, pillarH * 0.4);
            // Brick pattern
            ctx.strokeStyle = "rgba(140,100,60,0.2)";
            ctx.lineWidth = 1;
            for (let r = 0; r < 6; r++) {
                const ry = groundY - r * 8 - 4;
                ctx.beginPath(); ctx.moveTo(bx, ry); ctx.lineTo(bx + bw * 0.25, ry); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(bx + bw * 0.75, ry); ctx.lineTo(bx + bw, ry); ctx.stroke();
            }

            // Left pillar
            ctx.fillStyle = "#8a8078";
            ctx.fillRect(cx - gateW / 2 - pillarW, groundY - pillarH, pillarW, pillarH);
            // Pillar cap
            ctx.fillStyle = "#9a9088";
            ctx.fillRect(cx - gateW / 2 - pillarW - 3, groundY - pillarH - 6, pillarW + 6, 8);

            // Right pillar
            ctx.fillStyle = "#8a8078";
            ctx.fillRect(cx + gateW / 2, groundY - pillarH, pillarW, pillarH);
            ctx.fillStyle = "#9a9088";
            ctx.fillRect(cx + gateW / 2 - 3, groundY - pillarH - 6, pillarW + 6, 8);

            // Iron arch gate
            ctx.strokeStyle = "#3a3a3a";
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.arc(cx, groundY - pillarH * 0.55, gateW / 2, Math.PI, 0);
            ctx.stroke();
            // Gate bars
            ctx.lineWidth = 2;
            const barCount = 8;
            for (let b = 1; b < barCount; b++) {
                const barX = cx - gateW / 2 + (gateW / barCount) * b;
                const arcY = groundY - pillarH * 0.55 - Math.sqrt(Math.max(0, (gateW / 2) ** 2 - (barX - cx) ** 2));
                ctx.beginPath();
                ctx.moveTo(barX, groundY);
                ctx.lineTo(barX, arcY);
                ctx.stroke();
            }

            // Name plate
            ctx.fillStyle = "#f0e8d8";
            ctx.beginPath();
            ctx.roundRect(cx - gateW / 2 - pillarW - 2, groundY - pillarH * 0.7, pillarW + 4, pillarH * 0.22, 3);
            ctx.fill();
            ctx.strokeStyle = "#888";
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.roundRect(cx - gateW / 2 - pillarW - 2, groundY - pillarH * 0.7, pillarW + 4, pillarH * 0.22, 3);
            ctx.stroke();
            ctx.fillStyle = "#333";
            ctx.font = `700 ${Math.max(8, pillarW * 0.6)}px 'Zen Maru Gothic'`;
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            // Write vertically
            const nameChars = "大学".split("");
            nameChars.forEach((ch, ci) => {
                ctx.fillText(ch, cx - gateW / 2 - pillarW / 2, groundY - pillarH * 0.7 + pillarH * 0.06 + ci * (pillarH * 0.08));
            });

            // Cherry trees on both sides of the gate
            const treeH = pillarH * 0.7;
            // Left cherry tree
            drawCherryTree(cx - gateW / 2 - pillarW - bw * 0.12, groundY, treeH);
            // Right cherry tree
            drawCherryTree(cx + gateW / 2 + pillarW + bw * 0.12, groundY, treeH);

            // Bulletin board
            const bbX = cx + gateW / 2 + pillarW + bw * 0.06;
            const bbW = 30;
            const bbH = 22;
            ctx.fillStyle = "#d0c0a0";
            ctx.fillRect(bbX - bbW / 2, groundY - 40, bbW, bbH);
            ctx.strokeStyle = "#8a7a60";
            ctx.lineWidth = 1.5;
            ctx.strokeRect(bbX - bbW / 2, groundY - 40, bbW, bbH);
            // Post
            ctx.fillStyle = "#8a7a60";
            ctx.fillRect(bbX - 2, groundY - 18, 4, 18);
            // Notes on board
            ctx.fillStyle = "#fff";
            ctx.fillRect(bbX - 10, groundY - 37, 8, 6);
            ctx.fillStyle = "#fdd";
            ctx.fillRect(bbX + 2, groundY - 36, 7, 5);
            ctx.fillStyle = "#ddf";
            ctx.fillRect(bbX - 8, groundY - 28, 6, 5);
        }

        function drawCherryTree(x, groundY, treeH) {
            const trunkW = 8;
            const trunkH = treeH * 0.4;
            ctx.fillStyle = "hsl(15, 25%, 35%)";
            ctx.fillRect(x - trunkW / 2, groundY - trunkH, trunkW, trunkH);
            // Cherry blossom crown (pink)
            const crownY = groundY - trunkH;
            const crownR = treeH * 0.35;
            ctx.fillStyle = "hsl(340, 60%, 78%)";
            ctx.beginPath(); ctx.arc(x, crownY - crownR * 0.5, crownR, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "hsl(345, 55%, 82%)";
            ctx.beginPath(); ctx.arc(x - crownR * 0.5, crownY - crownR * 0.15, crownR * 0.7, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "hsl(335, 65%, 75%)";
            ctx.beginPath(); ctx.arc(x + crownR * 0.55, crownY - crownR * 0.3, crownR * 0.65, 0, Math.PI * 2); ctx.fill();
        }

        // === 運動場 (Field) ===
        function drawFieldBuilding(cx, bx, bw, wallH) {
            const groundY = wallH;
            const fieldW = bw * 0.92;
            const fieldX = cx - fieldW / 2;

            // The field is drawn as an open ground-level area with perspective
            // It extends from just above ground line, tapering inward at the top (depth)

            // Perspective trapezoid: wider at bottom (near), narrower at top (far)
            const nearY = groundY;                    // bottom edge (closest to viewer)
            const farY = groundY - wallH * 0.52;      // top edge (far side of field)
            const nearHalfW = fieldW * 0.50;           // wide at bottom
            const farHalfW = fieldW * 0.36;            // narrower at top

            // Field grass (trapezoid with depth)
            const fieldGrass = ctx.createLinearGradient(0, farY, 0, nearY);
            fieldGrass.addColorStop(0, "#5a9030");    // darker far
            fieldGrass.addColorStop(0.4, "#68a838");
            fieldGrass.addColorStop(1, "#72b848");    // brighter near
            ctx.fillStyle = fieldGrass;
            ctx.beginPath();
            ctx.moveTo(cx - nearHalfW, nearY);
            ctx.lineTo(cx - farHalfW, farY);
            ctx.lineTo(cx + farHalfW, farY);
            ctx.lineTo(cx + nearHalfW, nearY);
            ctx.closePath();
            ctx.fill();

            // Mowing stripes (horizontal lines that follow perspective)
            ctx.strokeStyle = "rgba(80,160,50,0.18)";
            ctx.lineWidth = 1;
            const stripes = 8;
            for (let s = 1; s < stripes; s++) {
                const frac = s / stripes;
                const y = farY + (nearY - farY) * frac;
                const hw = farHalfW + (nearHalfW - farHalfW) * frac;
                ctx.beginPath();
                ctx.moveTo(cx - hw, y);
                ctx.lineTo(cx + hw, y);
                ctx.stroke();
            }

            // Track (perspective ellipse — wider at bottom)
            const trackCY = farY + (nearY - farY) * 0.52;
            const trackHW = farHalfW + (nearHalfW - farHalfW) * 0.52;
            const trackRX = trackHW * 0.82;
            const trackRY = (nearY - farY) * 0.32;
            ctx.strokeStyle = "hsl(15, 50%, 52%)";
            ctx.lineWidth = 4;
            ctx.beginPath();
            ctx.ellipse(cx, trackCY, trackRX, trackRY, 0, 0, Math.PI * 2);
            ctx.stroke();
            // Inner lane
            ctx.strokeStyle = "rgba(255,255,255,0.3)";
            ctx.lineWidth = 1.5;
            ctx.beginPath();
            ctx.ellipse(cx, trackCY, trackRX * 0.88, trackRY * 0.88, 0, 0, Math.PI * 2);
            ctx.stroke();

            // Center line and circle
            ctx.strokeStyle = "rgba(255,255,255,0.35)";
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(cx, farY + (nearY - farY) * 0.15);
            ctx.lineTo(cx, nearY - (nearY - farY) * 0.05);
            ctx.stroke();
            ctx.beginPath();
            ctx.arc(cx, trackCY, trackRY * 0.3, 0, Math.PI * 2);
            ctx.stroke();

            // Goal posts (left and right, with perspective size)
            const drawGoal = (gx, gy, scale) => {
                const gw = 24 * scale;
                const gh = 20 * scale;
                ctx.strokeStyle = "#fff";
                ctx.lineWidth = 2.5 * scale;
                ctx.beginPath();
                ctx.moveTo(gx - gw / 2, gy);
                ctx.lineTo(gx - gw / 2, gy - gh);
                ctx.lineTo(gx + gw / 2, gy - gh);
                ctx.lineTo(gx + gw / 2, gy);
                ctx.stroke();
                // Net lines
                ctx.strokeStyle = "rgba(255,255,255,0.2)";
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.moveTo(gx, gy - gh);
                ctx.lineTo(gx, gy);
                ctx.stroke();
            };
            // Far goal (smaller)
            drawGoal(cx, farY + (nearY - farY) * 0.12, 0.65);
            // Near goal (larger)
            drawGoal(cx, nearY - (nearY - farY) * 0.02, 1.0);

            // Fence around perimeter (chain-link style)
            ctx.strokeStyle = "rgba(140,140,140,0.6)";
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(cx - nearHalfW, nearY);
            ctx.lineTo(cx - farHalfW, farY);
            ctx.lineTo(cx + farHalfW, farY);
            ctx.lineTo(cx + nearHalfW, nearY);
            ctx.stroke();
            // Fence posts
            const postCount = 8;
            for (let p = 0; p <= postCount; p++) {
                const frac = p / postCount;
                // Left side posts
                const lpx = cx - nearHalfW + (nearHalfW - farHalfW) * frac;
                const lpy = nearY - (nearY - farY) * frac;
                const postH = 12 + frac * 6;
                ctx.fillStyle = "#888";
                ctx.fillRect(lpx - 1.5, lpy - postH, 3, postH);
                // Right side posts
                const rpx = cx + nearHalfW - (nearHalfW - farHalfW) * frac;
                ctx.fillRect(rpx - 1.5, lpy - postH, 3, postH);
            }
            // Horizontal wires
            ctx.strokeStyle = "rgba(160,160,160,0.35)";
            ctx.lineWidth = 1;
            for (let w = 0; w < 3; w++) {
                const wireYFrac = 0.3 + w * 0.25;
                ctx.beginPath();
                const wy = nearY - (nearY - farY) * wireYFrac;
                const whw = farHalfW + (nearHalfW - farHalfW) * (1 - wireYFrac);
                ctx.moveTo(cx - whw, wy);
                ctx.lineTo(cx - farHalfW, farY);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(cx + whw, wy);
                ctx.lineTo(cx + farHalfW, farY);
                ctx.stroke();
            }

            // Scoreboard (small structure on the far side)
            const sbX = cx + farHalfW * 0.6;
            const sbY = farY - 2;
            ctx.fillStyle = "#555";
            ctx.fillRect(sbX - 1.5, sbY - 22, 3, 22);
            ctx.fillStyle = "#333";
            ctx.fillRect(sbX - 12, sbY - 28, 24, 10);
            ctx.fillStyle = "#181818";
            ctx.fillRect(sbX - 10, sbY - 26, 20, 6);
            ctx.fillStyle = "#ff4444";
            ctx.font = "700 5px monospace";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            ctx.fillText("0 - 0", sbX, sbY - 23);

            // Equipment shed (small building at the side)
            const shedX = cx - nearHalfW - 18;
            const shedY = groundY;
            const shedW = 28;
            const shedH = 24;
            ctx.fillStyle = "#8a8070";
            ctx.fillRect(shedX, shedY - shedH, shedW, shedH);
            ctx.fillStyle = "#6a6058";
            ctx.beginPath();
            ctx.moveTo(shedX - 2, shedY - shedH);
            ctx.lineTo(shedX + shedW / 2, shedY - shedH - 8);
            ctx.lineTo(shedX + shedW + 2, shedY - shedH);
            ctx.closePath();
            ctx.fill();
            ctx.fillStyle = "#555";
            ctx.fillRect(shedX + shedW * 0.35, shedY - 14, 8, 14);
        }

        // === 校舎 (Main Building) ===
        function drawMainBuilding(cx, bx, bw, wallH) {
            const groundY = wallH;
            const floors = 4;
            const bh = wallH * 0.72;
            const buildX = cx - bw * 0.45;
            const buildW = bw * 0.90;
            const buildY = groundY - bh;

            // Building body (concrete)
            ctx.fillStyle = "#c8c4b8";
            ctx.fillRect(buildX, buildY, buildW, bh);

            // Building edge highlights
            ctx.fillStyle = "rgba(255,255,255,0.08)";
            ctx.fillRect(buildX, buildY, buildW * 0.05, bh);
            ctx.fillStyle = "rgba(0,0,0,0.06)";
            ctx.fillRect(buildX + buildW * 0.95, buildY, buildW * 0.05, bh);

            // Stairwell protrusions (left and right)
            const stairW = buildW * 0.08;
            const stairH = bh * 0.95;
            ctx.fillStyle = "#bab6aa";
            ctx.fillRect(buildX - stairW, groundY - stairH, stairW, stairH);
            ctx.fillRect(buildX + buildW, groundY - stairH, stairW, stairH);

            // Floor lines
            const floorH = bh / floors;
            for (let f = 1; f < floors; f++) {
                const fy = buildY + f * floorH;
                ctx.fillStyle = "rgba(0,0,0,0.08)";
                ctx.fillRect(buildX, fy - 1, buildW, 3);
            }

            // Windows (10 per floor)
            const winCols = 10;
            const winMarginX = buildW * 0.06;
            const winAreaW = buildW - winMarginX * 2;
            const winW = winAreaW / winCols * 0.65;
            const winH = floorH * 0.45;
            for (let f = 0; f < floors; f++) {
                for (let c = 0; c < winCols; c++) {
                    const wx = buildX + winMarginX + (c / winCols) * winAreaW + (winAreaW / winCols - winW) / 2;
                    const wy = buildY + f * floorH + floorH * 0.2;
                    ctx.fillStyle = `rgba(140,180,210,${0.4 + Math.random() * 0.2})`;
                    ctx.fillRect(wx, wy, winW, winH);
                    // Window frame
                    ctx.strokeStyle = "rgba(100,100,100,0.3)";
                    ctx.lineWidth = 1;
                    ctx.strokeRect(wx, wy, winW, winH);
                    // Window divider
                    ctx.beginPath();
                    ctx.moveTo(wx + winW / 2, wy);
                    ctx.lineTo(wx + winW / 2, wy + winH);
                    ctx.stroke();
                }
            }

            // Main entrance (glass door + canopy)
            const entranceW = buildW * 0.15;
            const entranceH = floorH * 0.7;
            ctx.fillStyle = "#666";
            ctx.fillRect(cx - entranceW / 2, groundY - entranceH, entranceW, entranceH);
            // Glass panels
            ctx.fillStyle = "rgba(160,200,220,0.5)";
            ctx.fillRect(cx - entranceW / 2 + 3, groundY - entranceH + 3, entranceW / 2 - 5, entranceH - 3);
            ctx.fillRect(cx + 2, groundY - entranceH + 3, entranceW / 2 - 5, entranceH - 3);
            // Canopy (awning)
            ctx.fillStyle = "#999";
            ctx.fillRect(cx - entranceW * 0.7, groundY - entranceH - 5, entranceW * 1.4, 6);

            // Clock tower on roof
            const towerW = buildW * 0.06;
            const towerH = bh * 0.18;
            ctx.fillStyle = "#aaa8a0";
            ctx.fillRect(cx - towerW / 2, buildY - towerH, towerW, towerH);
            // Clock face
            ctx.fillStyle = "#f0f0e8";
            ctx.beginPath();
            ctx.arc(cx, buildY - towerH * 0.5, towerW * 0.35, 0, Math.PI * 2);
            ctx.fill();
            ctx.strokeStyle = "#555";
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.arc(cx, buildY - towerH * 0.5, towerW * 0.35, 0, Math.PI * 2);
            ctx.stroke();
            // Clock hands
            const clockCY = buildY - towerH * 0.5;
            const handLen = towerW * 0.25;
            ctx.strokeStyle = "#333";
            ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.moveTo(cx, clockCY); ctx.lineTo(cx, clockCY - handLen); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(cx, clockCY); ctx.lineTo(cx + handLen * 0.6, clockCY); ctx.stroke();

            // Tower cap
            ctx.fillStyle = "#888";
            ctx.beginPath();
            ctx.moveTo(cx - towerW / 2 - 2, buildY - towerH);
            ctx.lineTo(cx, buildY - towerH - 10);
            ctx.lineTo(cx + towerW / 2 + 2, buildY - towerH);
            ctx.closePath();
            ctx.fill();

            // Bicycle parking (in front)
            for (let b = 0; b < 5; b++) {
                const bikeX = cx - buildW * 0.2 + b * 16;
                ctx.strokeStyle = "#777";
                ctx.lineWidth = 1.5;
                // Simple bike rack silhouette
                ctx.beginPath();
                ctx.arc(bikeX, groundY - 4, 5, 0, Math.PI * 2);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(bikeX, groundY - 9);
                ctx.lineTo(bikeX + 3, groundY - 16);
                ctx.stroke();
            }

            // "1号館" sign
            ctx.fillStyle = "rgba(60,60,80,0.8)";
            ctx.beginPath();
            ctx.roundRect(cx - 28, buildY + 8, 56, 18, 3);
            ctx.fill();
            ctx.fillStyle = "#fff";
            ctx.font = "700 10px 'Zen Maru Gothic'";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            ctx.fillText("1号館", cx, buildY + 17);
        }

        // === 体育館 (Gym) ===
        function drawGymBuilding(cx, bx, bw, wallH) {
            const groundY = wallH;
            const bh = wallH * 0.58;
            const buildX = cx - bw * 0.42;
            const buildW = bw * 0.84;
            const buildY = groundY - bh;

            // Walls (side)
            ctx.fillStyle = "#c0b8a8";
            ctx.fillRect(buildX, buildY + bh * 0.2, buildW, bh * 0.8);

            // Arch roof (kamaboko/barrel shape)
            ctx.fillStyle = "#8a8680";
            ctx.beginPath();
            ctx.moveTo(buildX, buildY + bh * 0.2);
            ctx.quadraticCurveTo(cx, buildY - bh * 0.15, buildX + buildW, buildY + bh * 0.2);
            ctx.lineTo(buildX + buildW, buildY + bh * 0.2);
            ctx.lineTo(buildX, buildY + bh * 0.2);
            ctx.closePath();
            ctx.fill();
            // Roof highlights
            ctx.strokeStyle = "rgba(255,255,255,0.12)";
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.quadraticCurveTo(cx, buildY - bh * 0.15, buildX + buildW, buildY + bh * 0.2);
            ctx.stroke();

            // Louver windows (side ventilation)
            const louverCount = 8;
            for (let l = 0; l < louverCount; l++) {
                const lx = buildX + buildW * 0.08 + (l / louverCount) * buildW * 0.84;
                const ly = buildY + bh * 0.3;
                const lh = bh * 0.15;
                ctx.fillStyle = "rgba(160,200,220,0.35)";
                ctx.fillRect(lx, ly, buildW * 0.06, lh);
                // Louver slats
                ctx.strokeStyle = "rgba(100,100,100,0.3)";
                ctx.lineWidth = 1;
                for (let s = 0; s < 4; s++) {
                    const sy = ly + (s / 4) * lh + lh * 0.1;
                    ctx.beginPath();
                    ctx.moveTo(lx, sy);
                    ctx.lineTo(lx + buildW * 0.06, sy);
                    ctx.stroke();
                }
            }

            // Main entrance (large sliding doors)
            const doorW = buildW * 0.2;
            const doorH = bh * 0.5;
            ctx.fillStyle = "#888";
            ctx.fillRect(cx - doorW / 2, groundY - doorH, doorW, doorH);
            // Door panels
            ctx.fillStyle = "rgba(160,190,210,0.4)";
            ctx.fillRect(cx - doorW / 2 + 3, groundY - doorH + 3, doorW / 2 - 4, doorH - 6);
            ctx.fillRect(cx + 1, groundY - doorH + 3, doorW / 2 - 4, doorH - 6);
            // Door handles
            ctx.fillStyle = "#666";
            ctx.fillRect(cx - 4, groundY - doorH * 0.5, 3, 12);
            ctx.fillRect(cx + 1, groundY - doorH * 0.5, 3, 12);

            // Basketball hoop silhouette (visible through window)
            ctx.strokeStyle = "rgba(180,100,50,0.3)";
            ctx.lineWidth = 2;
            const hoopX = cx + buildW * 0.15;
            const hoopY = buildY + bh * 0.35;
            ctx.beginPath();
            ctx.rect(hoopX - 8, hoopY, 16, 12);
            ctx.stroke();
            ctx.beginPath();
            ctx.arc(hoopX, hoopY + 16, 6, 0, Math.PI * 2);
            ctx.stroke();

            // "体育館" sign
            ctx.fillStyle = "rgba(60,60,80,0.8)";
            ctx.beginPath();
            ctx.roundRect(cx - 30, groundY - doorH - 16, 60, 14, 3);
            ctx.fill();
            ctx.fillStyle = "#fff";
            ctx.font = "700 9px 'Zen Maru Gothic'";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            ctx.fillText("体育館", cx, groundY - doorH - 9);

            // Trophy case decoration (side of entrance)
            ctx.fillStyle = "rgba(200,180,120,0.4)";
            ctx.fillRect(cx + doorW / 2 + 8, groundY - 28, 18, 24);
            ctx.strokeStyle = "rgba(180,160,100,0.5)";
            ctx.lineWidth = 1;
            ctx.strokeRect(cx + doorW / 2 + 8, groundY - 28, 18, 24);
            // Trophy silhouette
            ctx.fillStyle = "rgba(220,180,60,0.6)";
            ctx.beginPath();
            ctx.moveTo(cx + doorW / 2 + 14, groundY - 22);
            ctx.lineTo(cx + doorW / 2 + 20, groundY - 22);
            ctx.lineTo(cx + doorW / 2 + 19, groundY - 14);
            ctx.lineTo(cx + doorW / 2 + 15, groundY - 14);
            ctx.closePath();
            ctx.fill();
            ctx.fillRect(cx + doorW / 2 + 15, groundY - 14, 4, 4);
            ctx.fillRect(cx + doorW / 2 + 13, groundY - 10, 8, 2);
        }

        // === 制作館 (Art Hall) ===
        function drawArtHallBuilding(cx, bx, bw, wallH) {
            const groundY = wallH;
            const bh = wallH * 0.60;
            const buildX = cx - bw * 0.42;
            const buildW = bw * 0.84;
            const buildY = groundY - bh;

            // Modern concrete building body
            ctx.fillStyle = "#bbb8b0";
            ctx.fillRect(buildX, buildY, buildW, bh);

            // Glass section (large atelier window — angled skylight look)
            const glassW = buildW * 0.35;
            const glassH = bh * 0.55;
            const glassX = buildX + buildW * 0.55;
            const glassY = buildY + bh * 0.08;
            // Window background
            ctx.fillStyle = "rgba(140,190,220,0.5)";
            ctx.beginPath();
            ctx.moveTo(glassX, glassY + glassH);
            ctx.lineTo(glassX, glassY);
            ctx.lineTo(glassX + glassW, glassY - glassH * 0.15);
            ctx.lineTo(glassX + glassW, glassY + glassH);
            ctx.closePath();
            ctx.fill();
            // Window frame
            ctx.strokeStyle = "#888";
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(glassX, glassY + glassH);
            ctx.lineTo(glassX, glassY);
            ctx.lineTo(glassX + glassW, glassY - glassH * 0.15);
            ctx.lineTo(glassX + glassW, glassY + glassH);
            ctx.closePath();
            ctx.stroke();
            // Window dividers
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(glassX + glassW * 0.33, glassY + glassH);
            ctx.lineTo(glassX + glassW * 0.33, glassY - glassH * 0.05);
            ctx.stroke();
            ctx.beginPath();
            ctx.moveTo(glassX + glassW * 0.66, glassY + glassH);
            ctx.lineTo(glassX + glassW * 0.66, glassY - glassH * 0.1);
            ctx.stroke();

            // Regular windows on left side
            for (let r = 0; r < 2; r++) {
                for (let c = 0; c < 3; c++) {
                    const wx = buildX + buildW * 0.06 + c * buildW * 0.14;
                    const wy = buildY + bh * 0.15 + r * bh * 0.35;
                    ctx.fillStyle = "rgba(140,180,210,0.4)";
                    ctx.fillRect(wx, wy, buildW * 0.10, bh * 0.2);
                    ctx.strokeStyle = "rgba(100,100,100,0.3)";
                    ctx.lineWidth = 1;
                    ctx.strokeRect(wx, wy, buildW * 0.10, bh * 0.2);
                }
            }

            // Colorful wall mural/mosaic (on front face)
            const muralX = buildX + buildW * 0.08;
            const muralY = buildY + bh * 0.7;
            const muralW = buildW * 0.38;
            const muralH = bh * 0.22;
            const mosaicColors = [
                "rgba(220,80,80,0.5)", "rgba(80,160,220,0.5)", "rgba(220,200,60,0.5)",
                "rgba(80,200,120,0.5)", "rgba(200,100,220,0.5)", "rgba(240,140,60,0.5)"
            ];
            const tileSize = 8;
            let colorIdx = 0;
            for (let my = muralY; my < muralY + muralH; my += tileSize) {
                for (let mx = muralX; mx < muralX + muralW; mx += tileSize) {
                    ctx.fillStyle = mosaicColors[colorIdx % mosaicColors.length];
                    ctx.fillRect(mx, my, tileSize - 1, tileSize - 1);
                    colorIdx++;
                }
            }

            // Entrance
            const doorW = buildW * 0.14;
            const doorH = bh * 0.4;
            ctx.fillStyle = "#555";
            ctx.fillRect(cx - doorW / 2, groundY - doorH, doorW, doorH);
            ctx.fillStyle = "rgba(160,200,220,0.4)";
            ctx.fillRect(cx - doorW / 2 + 2, groundY - doorH + 2, doorW - 4, doorH - 4);

            // Sculpture in front of entrance
            ctx.fillStyle = "#888";
            // Base
            ctx.fillRect(cx + buildW * 0.22, groundY - 12, 16, 12);
            // Abstract shape
            ctx.beginPath();
            ctx.moveTo(cx + buildW * 0.22 + 4, groundY - 12);
            ctx.lineTo(cx + buildW * 0.22 + 8, groundY - 36);
            ctx.lineTo(cx + buildW * 0.22 + 12, groundY - 12);
            ctx.closePath();
            ctx.fill();
            ctx.fillStyle = "#999";
            ctx.beginPath();
            ctx.arc(cx + buildW * 0.22 + 8, groundY - 32, 5, 0, Math.PI * 2);
            ctx.fill();

            // Chimney (kiln exhaust)
            const chimneyX = buildX + buildW * 0.85;
            ctx.fillStyle = "#8a8480";
            ctx.fillRect(chimneyX - 5, buildY - 14, 10, 14 + bh * 0.1);
            // Chimney cap
            ctx.fillStyle = "#777";
            ctx.fillRect(chimneyX - 7, buildY - 17, 14, 4);

            // "制作館" sign
            ctx.fillStyle = "rgba(60,60,80,0.8)";
            ctx.beginPath();
            ctx.roundRect(cx - 30, groundY - doorH - 16, 60, 14, 3);
            ctx.fill();
            ctx.fillStyle = "#fff";
            ctx.font = "700 9px 'Zen Maru Gothic'";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            ctx.fillText("制作館", cx, groundY - doorH - 9);
        }

        function drawSchoolBackground() {
            ensureSchoolBgObjects();
            updateSchoolNpcs();
            const wallH = height * ROOM_WALL_RATIO;
            const hallEnd = worldWidth * 0.60;
            const classStart = hallEnd;
            const charH = 120;
            const doorH = charH;
            const doorW = 58;
            const deskH = 8;
            const deskTopFromFloor = 48;
            const deskW = 55;
            const lockerH = charH * 0.85;
            const lockerW = 40;
            const hov = hoveredSchoolActivity;
            const t = performance.now() * 0.001;

            // Helper: activity glow overlay
            const glowFor = (actId, cx, cy, radius) => {
                if (hov !== actId) return;
                const pulse = 0.5 + Math.sin(t * 4) * 0.2;
                const act = SCHOOL_ACTIVITIES.find(a => a.id === actId);
                const col = act ? act.color : "hsl(50,80%,70%)";
                const g = ctx.createRadialGradient(cx, cy, radius * 0.1, cx, cy, radius);
                g.addColorStop(0, col.replace(')', `, ${0.35 * pulse})`).replace('hsl(', 'hsla('));
                g.addColorStop(0.6, col.replace(')', `, ${0.15 * pulse})`).replace('hsl(', 'hsla('));
                g.addColorStop(1, "rgba(255,255,255,0)");
                ctx.fillStyle = g;
                ctx.beginPath(); ctx.arc(cx, cy, radius, 0, Math.PI * 2); ctx.fill();
            };
            // Helper: hover border glow on rect
            const glowRectFor = (actId, rx, ry, rw, rh, rad) => {
                if (hov !== actId) return;
                const pulse = 0.6 + Math.sin(t * 4) * 0.25;
                const act = SCHOOL_ACTIVITIES.find(a => a.id === actId);
                const col = act ? act.color : "hsl(50,80%,70%)";
                ctx.save();
                ctx.shadowColor = col;
                ctx.shadowBlur = 18 + pulse * 14;
                ctx.strokeStyle = col.replace(')', `, ${0.7 * pulse})`).replace('hsl(', 'hsla(');
                ctx.lineWidth = 3;
                ctx.beginPath(); ctx.roundRect(rx - 2, ry - 2, rw + 4, rh + 4, rad || 6); ctx.stroke();
                ctx.restore();
            };

            // ========== HALLWAY (left 48%) ==========
            // Wall gradient
            const hallWallG = ctx.createLinearGradient(0, 0, 0, wallH);
            hallWallG.addColorStop(0, "#f5f3ef");
            hallWallG.addColorStop(0.4, "#f0ebe3");
            hallWallG.addColorStop(1, "#e8e0d5");
            ctx.fillStyle = hallWallG;
            ctx.fillRect(0, 0, hallEnd, wallH);

            // Wainscoting (more detailed)
            const wainH = wallH * 0.38;
            const wainY = wallH - wainH;
            const wainG = ctx.createLinearGradient(0, wainY, 0, wallH);
            wainG.addColorStop(0, "rgba(210, 200, 185, 0.55)");
            wainG.addColorStop(0.5, "rgba(218, 210, 195, 0.5)");
            wainG.addColorStop(1, "rgba(200, 190, 175, 0.6)");
            ctx.fillStyle = wainG;
            ctx.fillRect(0, wainY, hallEnd, wainH);
            // Wainscot top molding
            ctx.fillStyle = "rgba(185, 175, 158, 0.55)";
            ctx.fillRect(0, wainY, hallEnd, 5);
            ctx.fillStyle = "rgba(225, 218, 205, 0.4)";
            ctx.fillRect(0, wainY + 5, hallEnd, 2);
            // Wainscot panel lines
            ctx.strokeStyle = "rgba(180, 170, 155, 0.15)";
            ctx.lineWidth = 1;
            for (let px = 80; px < hallEnd; px += 120) {
                ctx.beginPath(); ctx.moveTo(px, wainY + 12); ctx.lineTo(px, wallH - 14); ctx.stroke();
            }
            // Baseboard
            ctx.fillStyle = "rgba(160, 150, 135, 0.65)";
            ctx.fillRect(0, wallH - 12, hallEnd, 12);
            ctx.fillStyle = "rgba(175, 165, 148, 0.5)";
            ctx.fillRect(0, wallH - 14, hallEnd, 3);

            // Crown molding (top)
            ctx.fillStyle = "rgba(230, 225, 215, 0.5)";
            ctx.fillRect(0, 0, hallEnd, 6);
            ctx.fillStyle = "rgba(200, 192, 180, 0.3)";
            ctx.fillRect(0, 6, hallEnd, 3);

            // Ceiling fluorescent lights
            for (let lx = 120; lx < hallEnd; lx += 280) {
                // Light fixture body
                ctx.fillStyle = "rgba(220, 225, 230, 0.6)";
                ctx.beginPath(); ctx.roundRect(lx - 55, 2, 110, 8, 2); ctx.fill();
                // Light tube
                ctx.fillStyle = "rgba(245, 248, 255, 0.75)";
                ctx.beginPath(); ctx.roundRect(lx - 48, 6, 96, 12, 3); ctx.fill();
                ctx.strokeStyle = "rgba(200, 205, 215, 0.4)";
                ctx.lineWidth = 1;
                ctx.beginPath(); ctx.roundRect(lx - 48, 6, 96, 12, 3); ctx.stroke();
                // Glow cone
                const glow = ctx.createRadialGradient(lx, 16, 8, lx, 50, 150);
                glow.addColorStop(0, "rgba(255, 255, 248, 0.16)");
                glow.addColorStop(0.5, "rgba(255, 255, 248, 0.05)");
                glow.addColorStop(1, "rgba(255, 255, 248, 0)");
                ctx.fillStyle = glow;
                ctx.fillRect(lx - 150, 10, 300, 150);
            }

            // === 3 Hallway Doors (improved with through-window scenes) ===
            const drawDoor = (cx, label, doorColor, windowColor, actId, windowScene) => {
                const dY = wallH - doorH;
                const isGlowing = hov === actId;

                // Glow behind door when hovered
                if (isGlowing) glowFor(actId, cx, wallH - doorH / 2, 90);

                // Door shadow
                ctx.fillStyle = "rgba(0,0,0,0.06)";
                ctx.beginPath(); ctx.roundRect(cx - doorW / 2 + 3, dY + 4, doorW, doorH, [6,6,0,0]); ctx.fill();

                // Door body
                const dG = ctx.createLinearGradient(cx - doorW / 2, 0, cx + doorW / 2, 0);
                dG.addColorStop(0, doorColor);
                dG.addColorStop(0.5, doorColor.replace(/\)/, ', 0.9)').replace('rgb(', 'rgba('));
                dG.addColorStop(1, doorColor);
                ctx.fillStyle = doorColor;
                ctx.beginPath(); ctx.roundRect(cx - doorW / 2, dY, doorW, doorH, [6,6,0,0]); ctx.fill();

                // Door panels (raised panel effect)
                ctx.strokeStyle = "rgba(255,255,255,0.12)";
                ctx.lineWidth = 1;
                ctx.beginPath(); ctx.roundRect(cx - doorW / 2 + 5, dY + 58, doorW - 10, doorH - 66, 3); ctx.stroke();

                // Door frame
                ctx.strokeStyle = "rgba(80, 70, 55, 0.5)";
                ctx.lineWidth = 4;
                ctx.beginPath(); ctx.roundRect(cx - doorW / 2 - 2, dY - 2, doorW + 4, doorH + 2, [7,7,0,0]); ctx.stroke();
                ctx.strokeStyle = "rgba(140, 125, 105, 0.35)";
                ctx.lineWidth = 2;
                ctx.beginPath(); ctx.roundRect(cx - doorW / 2 + 1, dY + 1, doorW - 2, doorH - 1, [5,5,0,0]); ctx.stroke();

                // Window on door (larger, with scene inside)
                const winX = cx - 16, winY = dY + 12, winW = 32, winH = 40;
                ctx.fillStyle = windowColor;
                ctx.beginPath(); ctx.roundRect(winX, winY, winW, winH, 4); ctx.fill();
                // Window scene
                if (windowScene === "sports") {
                    // Green field & blue sky
                    ctx.fillStyle = "rgba(130, 200, 240, 0.6)";
                    ctx.beginPath(); ctx.roundRect(winX + 2, winY + 2, winW - 4, winH * 0.4, [3,3,0,0]); ctx.fill();
                    ctx.fillStyle = "rgba(80, 170, 80, 0.5)";
                    ctx.beginPath(); ctx.roundRect(winX + 2, winY + winH * 0.4, winW - 4, winH * 0.6 - 2, [0,0,3,3]); ctx.fill();
                    // Goal post
                    ctx.strokeStyle = "rgba(255,255,255,0.5)";
                    ctx.lineWidth = 1.5;
                    ctx.beginPath(); ctx.moveTo(winX + 10, winY + winH * 0.35);
                    ctx.lineTo(winX + 10, winY + winH * 0.6);
                    ctx.lineTo(winX + 22, winY + winH * 0.6);
                    ctx.lineTo(winX + 22, winY + winH * 0.35);
                    ctx.lineTo(winX + 10, winY + winH * 0.35); ctx.stroke();
                } else if (windowScene === "library") {
                    // Warm light & bookshelves
                    ctx.fillStyle = "rgba(245, 235, 210, 0.5)";
                    ctx.beginPath(); ctx.roundRect(winX + 2, winY + 2, winW - 4, winH - 4, 3); ctx.fill();
                    for (let sh = 0; sh < 3; sh++) {
                        const sy = winY + 8 + sh * 12;
                        ctx.fillStyle = "rgba(140, 100, 60, 0.4)";
                        ctx.fillRect(winX + 5, sy, winW - 10, 2);
                        // Mini books
                        const bkCols = ["rgba(180,60,60,0.5)", "rgba(60,100,180,0.5)", "rgba(60,150,60,0.5)", "rgba(180,150,60,0.5)"];
                        for (let b = 0; b < 4; b++) {
                            ctx.fillStyle = bkCols[b];
                            ctx.fillRect(winX + 7 + b * 6, sy - 7, 4, 7);
                        }
                    }
                } else if (windowScene === "science") {
                    // Beakers & flasks
                    ctx.fillStyle = "rgba(220, 235, 245, 0.5)";
                    ctx.beginPath(); ctx.roundRect(winX + 2, winY + 2, winW - 4, winH - 4, 3); ctx.fill();
                    // Flask
                    ctx.strokeStyle = "rgba(100, 150, 200, 0.6)";
                    ctx.lineWidth = 1.5;
                    ctx.beginPath();
                    ctx.moveTo(winX + 12, winY + 14); ctx.lineTo(winX + 12, winY + 24);
                    ctx.lineTo(winX + 7, winY + 34); ctx.lineTo(winX + 17, winY + 34);
                    ctx.lineTo(winX + 12, winY + 24); ctx.stroke();
                    ctx.fillStyle = "rgba(100, 200, 150, 0.35)";
                    ctx.beginPath(); ctx.moveTo(winX + 8, winY + 30);
                    ctx.lineTo(winX + 16, winY + 30); ctx.lineTo(winX + 17, winY + 34);
                    ctx.lineTo(winX + 7, winY + 34); ctx.closePath(); ctx.fill();
                    // Test tube
                    ctx.strokeStyle = "rgba(100, 150, 200, 0.5)";
                    ctx.beginPath(); ctx.roundRect(winX + 20, winY + 16, 5, 18, [0,0,2,2]); ctx.stroke();
                    ctx.fillStyle = "rgba(200, 100, 150, 0.3)";
                    ctx.beginPath(); ctx.roundRect(winX + 20, winY + 24, 5, 10, [0,0,2,2]); ctx.fill();
                }
                // Window frame
                ctx.strokeStyle = "rgba(80, 70, 55, 0.35)";
                ctx.lineWidth = 2;
                ctx.beginPath(); ctx.roundRect(winX, winY, winW, winH, 4); ctx.stroke();
                // Window cross bar
                ctx.strokeStyle = "rgba(80, 70, 55, 0.2)";
                ctx.lineWidth = 1.5;
                ctx.beginPath(); ctx.moveTo(winX, winY + winH / 2); ctx.lineTo(winX + winW, winY + winH / 2); ctx.stroke();

                // Handle (brass)
                ctx.fillStyle = "#c8b878";
                ctx.beginPath(); ctx.roundRect(cx + doorW / 2 - 14, wallH - doorH * 0.44, 6, 14, 3); ctx.fill();
                ctx.fillStyle = "#b0a060";
                ctx.beginPath(); ctx.arc(cx + doorW / 2 - 11, wallH - doorH * 0.44, 3.5, 0, Math.PI * 2); ctx.fill();

                // Label plate above door
                ctx.fillStyle = "rgba(255,255,255,0.95)";
                const labelW = Math.max(68, label.length * 14 + 16);
                ctx.beginPath(); ctx.roundRect(cx - labelW / 2, dY - 26, labelW, 22, 4); ctx.fill();
                ctx.strokeStyle = "rgba(130, 120, 105, 0.35)";
                ctx.lineWidth = 1.5;
                ctx.beginPath(); ctx.roundRect(cx - labelW / 2, dY - 26, labelW, 22, 4); ctx.stroke();
                ctx.fillStyle = "#3a2e22";
                ctx.font = "700 13px 'Zen Maru Gothic', sans-serif";
                ctx.textAlign = "center"; ctx.textBaseline = "middle";
                ctx.fillText(label, cx, dY - 15);

                // Glow rect when hovered
                glowRectFor(actId, cx - doorW / 2 - 4, dY - 28, doorW + 8, doorH + 30, 8);
            };

            // 3 Doors
            drawDoor(worldWidth * 0.06, "運動場", "#8a7060", "#a0d0e8", "sports_field", "sports");
            drawDoor(worldWidth * 0.22, "図書館", "#907858", "#d8c8a0", "library", "library");
            drawDoor(worldWidth * 0.42, "理科室", "#687870", "#b8d0d8", "science_room", "science");

            // === Shoe box (下駄箱) near sports door ===
            const sbX = worldWidth * 0.11;
            const sbW = 50, sbH = 45;
            const sbY = wallH - sbH;
            ctx.fillStyle = "#b0a890";
            ctx.beginPath(); ctx.roundRect(sbX, sbY, sbW, sbH, 3); ctx.fill();
            ctx.strokeStyle = "rgba(0,0,0,0.1)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.roundRect(sbX, sbY, sbW, sbH, 3); ctx.stroke();
            for (let r = 0; r < 3; r++) {
                ctx.strokeStyle = "rgba(0,0,0,0.06)"; ctx.lineWidth = 0.8;
                ctx.beginPath(); ctx.moveTo(sbX, sbY + 15 * (r + 1)); ctx.lineTo(sbX + sbW, sbY + 15 * (r + 1)); ctx.stroke();
            }

            // === Lockers (improved) ===
            schoolBgObjects.lockers.forEach(locker => {
                const ly = wallH - lockerH;
                // Locker body gradient
                const lg = ctx.createLinearGradient(locker.x, 0, locker.x + lockerW, 0);
                lg.addColorStop(0, `hsl(${locker.hue}, 24%, 72%)`);
                lg.addColorStop(0.4, `hsl(${locker.hue}, 26%, 76%)`);
                lg.addColorStop(1, `hsl(${locker.hue}, 22%, 68%)`);
                ctx.fillStyle = lg;
                ctx.beginPath(); ctx.roundRect(locker.x, ly, lockerW, lockerH, 3); ctx.fill();
                ctx.strokeStyle = "rgba(0,0,0,0.12)"; ctx.lineWidth = 1.2;
                ctx.beginPath(); ctx.roundRect(locker.x, ly, lockerW, lockerH, 3); ctx.stroke();
                // Divider
                ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 1;
                ctx.beginPath(); ctx.moveTo(locker.x, ly + lockerH * 0.5);
                ctx.lineTo(locker.x + lockerW, ly + lockerH * 0.5); ctx.stroke();
                // Handles
                ctx.fillStyle = "rgba(100,95,88,0.6)";
                ctx.beginPath(); ctx.roundRect(locker.x + lockerW - 11, ly + lockerH * 0.22, 6, 13, 2.5); ctx.fill();
                ctx.beginPath(); ctx.roundRect(locker.x + lockerW - 11, ly + lockerH * 0.72, 6, 13, 2.5); ctx.fill();
                // Vents
                ctx.strokeStyle = "rgba(0,0,0,0.06)"; ctx.lineWidth = 0.7;
                for (let s = 0; s < 4; s++) {
                    ctx.beginPath();
                    ctx.moveTo(locker.x + 6, ly + 8 + s * 5);
                    ctx.lineTo(locker.x + lockerW - 14, ly + 8 + s * 5);
                    ctx.stroke();
                }
                // Number label
                ctx.fillStyle = "rgba(0,0,0,0.12)";
                ctx.font = "600 9px sans-serif";
                ctx.textAlign = "center"; ctx.textBaseline = "middle";
            });

            // Fire extinguisher near lockers
            const feX = worldWidth * 0.39, feY = wallH - 42;
            ctx.fillStyle = "#cc3030";
            ctx.beginPath(); ctx.roundRect(feX, feY, 12, 36, [3,3,1,1]); ctx.fill();
            ctx.fillStyle = "#222";
            ctx.beginPath(); ctx.roundRect(feX + 2, feY - 4, 8, 6, 2); ctx.fill();
            ctx.fillStyle = "#888";
            ctx.beginPath(); ctx.roundRect(feX + 8, feY - 2, 7, 3, 1); ctx.fill();

            // Hallway windows (improved with curtains)
            for (let wx = worldWidth * 0.48; wx < hallEnd - 40; wx += 200) {
                const ww = 110, wh = wallH * 0.38;
                const wy = wallH * 0.05;
                // Sky through window
                const skyG = ctx.createLinearGradient(0, wy, 0, wy + wh);
                skyG.addColorStop(0, "#b8d8f0");
                skyG.addColorStop(0.6, "#d0e8f8");
                skyG.addColorStop(1, "#c8e0c8");
                ctx.fillStyle = skyG;
                ctx.beginPath(); ctx.roundRect(wx + 3, wy + 3, ww - 6, wh - 6, 2); ctx.fill();
                // Clouds
                ctx.fillStyle = "rgba(255,255,255,0.4)";
                ctx.beginPath(); ctx.arc(wx + 30, wy + 18, 10, 0, Math.PI * 2); ctx.fill();
                ctx.beginPath(); ctx.arc(wx + 42, wy + 16, 12, 0, Math.PI * 2); ctx.fill();
                ctx.beginPath(); ctx.arc(wx + 70, wy + 22, 8, 0, Math.PI * 2); ctx.fill();
                // Window frame
                ctx.strokeStyle = "rgba(130, 120, 105, 0.6)";
                ctx.lineWidth = 6;
                ctx.beginPath(); ctx.roundRect(wx, wy, ww, wh, 3); ctx.stroke();
                // Cross bars
                ctx.lineWidth = 3;
                ctx.beginPath(); ctx.moveTo(wx + ww / 2, wy); ctx.lineTo(wx + ww / 2, wy + wh); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(wx, wy + wh / 2); ctx.lineTo(wx + ww, wy + wh / 2); ctx.stroke();
                // Inner frame
                ctx.strokeStyle = "rgba(160, 150, 135, 0.35)";
                ctx.lineWidth = 1.5;
                ctx.beginPath(); ctx.roundRect(wx + 3, wy + 3, ww - 6, wh - 6, 2); ctx.stroke();
                // Window sill
                ctx.fillStyle = "rgba(190, 180, 165, 0.6)";
                ctx.beginPath(); ctx.roundRect(wx - 5, wy + wh - 1, ww + 10, 7, 2); ctx.fill();
            }

            // Hall floor (linoleum tiles - improved)
            const floorG = ctx.createLinearGradient(0, wallH, 0, height);
            floorG.addColorStop(0, "#ddd5c8");
            floorG.addColorStop(0.3, "#d8d0c4");
            floorG.addColorStop(1, "#cfc6b8");
            ctx.fillStyle = floorG;
            ctx.fillRect(0, wallH, hallEnd, height - wallH);
            // Tile grid
            ctx.strokeStyle = "rgba(175, 165, 150, 0.14)";
            ctx.lineWidth = 0.8;
            for (let gx = 0; gx < hallEnd; gx += 65) {
                ctx.beginPath(); ctx.moveTo(gx, wallH); ctx.lineTo(gx, height); ctx.stroke();
            }
            for (let gy = wallH; gy < height; gy += 65) {
                ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(hallEnd, gy); ctx.stroke();
            }
            // Floor reflection
            const fglow = ctx.createLinearGradient(0, wallH, 0, wallH + 40);
            fglow.addColorStop(0, "rgba(255, 255, 255, 0.12)");
            fglow.addColorStop(1, "rgba(255, 255, 255, 0)");
            ctx.fillStyle = fglow;
            ctx.fillRect(0, wallH, hallEnd, 40);

            // ========== DIVIDING WALL (hallway ↔ classroom) ==========
            const divW = 18;
            const divX = hallEnd - divW / 2;
            // Wall body
            const divG = ctx.createLinearGradient(divX, 0, divX + divW, 0);
            divG.addColorStop(0, "rgba(185, 178, 168, 0.85)");
            divG.addColorStop(0.3, "rgba(195, 188, 178, 0.9)");
            divG.addColorStop(0.7, "rgba(190, 183, 173, 0.88)");
            divG.addColorStop(1, "rgba(180, 173, 163, 0.82)");
            ctx.fillStyle = divG;
            ctx.fillRect(divX, 0, divW, height);
            // Wall edge highlights
            ctx.fillStyle = "rgba(210, 205, 195, 0.4)";
            ctx.fillRect(divX, 0, 2, height);
            ctx.fillStyle = "rgba(160, 155, 145, 0.3)";
            ctx.fillRect(divX + divW - 2, 0, 2, height);

            // Classroom sliding door (open)
            const sdoorW = 60, sdoorH = doorH;
            const sdoorY = wallH - sdoorH;
            // Door opening (dark gap)
            ctx.fillStyle = "rgba(60, 55, 48, 0.15)";
            ctx.fillRect(divX + 1, sdoorY, divW - 2, sdoorH);
            // Slid-open door (partially visible, tucked to right side of wall)
            const slidX = divX + divW - 4;
            ctx.fillStyle = "rgba(180, 170, 155, 0.7)";
            ctx.beginPath(); ctx.roundRect(slidX, sdoorY, sdoorW * 0.55, sdoorH, [0,3,3,0]); ctx.fill();
            // Door handle groove
            ctx.fillStyle = "rgba(120, 115, 105, 0.5)";
            ctx.beginPath(); ctx.roundRect(slidX + 3, sdoorY + sdoorH * 0.4, 4, 22, 2); ctx.fill();
            // Glass panel on sliding door
            ctx.fillStyle = "rgba(210, 225, 235, 0.5)";
            ctx.beginPath(); ctx.roundRect(slidX + 10, sdoorY + 14, sdoorW * 0.55 - 16, sdoorH * 0.35, 3); ctx.fill();
            // Door rail (top)
            ctx.fillStyle = "rgba(140, 130, 118, 0.6)";
            ctx.fillRect(divX - 4, sdoorY - 5, divW + sdoorW * 0.6 + 4, 5);
            // Door rail (bottom)
            ctx.fillStyle = "rgba(140, 130, 118, 0.45)";
            ctx.fillRect(divX - 2, wallH - 3, divW + sdoorW * 0.6, 3);
            // Class sign plate (wider, mounted on wall above door)
            const signW = 72, signH = 28;
            const signX = divX + divW / 2 - signW / 2;
            const signY = sdoorY - 40;
            ctx.fillStyle = "#f8f5ee";
            ctx.beginPath(); ctx.roundRect(signX, signY, signW, signH, 5); ctx.fill();
            ctx.strokeStyle = "rgba(100, 90, 75, 0.4)"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.roundRect(signX, signY, signW, signH, 5); ctx.stroke();
            // Blue banner stripe
            ctx.fillStyle = "rgba(70, 120, 180, 0.7)";
            ctx.beginPath(); ctx.roundRect(signX + 3, signY + 3, signW - 6, 7, 2); ctx.fill();
            ctx.fillStyle = "#2a2018";
            ctx.font = "700 14px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("2年1組", signX + signW / 2, signY + signH / 2 + 3);

            // ========== CLASSROOM (right 52%) ==========
            // Classroom wall gradient
            const classWallG = ctx.createLinearGradient(0, 0, 0, wallH);
            classWallG.addColorStop(0, "#faf8f3");
            classWallG.addColorStop(0.3, "#f5f0e8");
            classWallG.addColorStop(1, "#ede5da");
            ctx.fillStyle = classWallG;
            ctx.fillRect(classStart, 0, worldWidth - classStart, wallH);
            // Crown molding
            ctx.fillStyle = "rgba(228, 222, 212, 0.5)";
            ctx.fillRect(classStart, 0, worldWidth - classStart, 6);
            ctx.fillStyle = "rgba(200, 192, 180, 0.3)";
            ctx.fillRect(classStart, 6, worldWidth - classStart, 3);
            // Baseboard
            ctx.fillStyle = "rgba(160, 150, 135, 0.65)";
            ctx.fillRect(classStart, wallH - 12, worldWidth - classStart, 12);
            ctx.fillStyle = "rgba(175, 165, 148, 0.45)";
            ctx.fillRect(classStart, wallH - 14, worldWidth - classStart, 3);

            // Classroom ceiling lights (improved)
            for (let lx = classStart + 140; lx < worldWidth - 50; lx += 260) {
                ctx.fillStyle = "rgba(220, 225, 230, 0.55)";
                ctx.beginPath(); ctx.roundRect(lx - 50, 2, 100, 7, 2); ctx.fill();
                ctx.fillStyle = "rgba(245, 248, 255, 0.72)";
                ctx.beginPath(); ctx.roundRect(lx - 44, 5, 88, 11, 3); ctx.fill();
                const glow = ctx.createRadialGradient(lx, 14, 6, lx, 45, 130);
                glow.addColorStop(0, "rgba(255, 255, 248, 0.14)");
                glow.addColorStop(0.5, "rgba(255, 255, 248, 0.04)");
                glow.addColorStop(1, "rgba(255, 255, 248, 0)");
                ctx.fillStyle = glow;
                ctx.fillRect(lx - 130, 8, 260, 140);
            }

            // Classroom floor (wood - drawn early so furniture appears on top)
            const woodG = ctx.createLinearGradient(0, wallH, 0, height);
            woodG.addColorStop(0, "#dccca8");
            woodG.addColorStop(0.3, "#d8c8a8");
            woodG.addColorStop(1, "#cebea0");
            ctx.fillStyle = woodG;
            ctx.fillRect(classStart, wallH, worldWidth - classStart, height - wallH);
            // Wood plank pattern
            ctx.strokeStyle = "rgba(80, 60, 40, 0.05)";
            ctx.lineWidth = 0.8;
            for (let wx = classStart; wx < worldWidth; wx += 65) {
                ctx.beginPath(); ctx.moveTo(wx, wallH); ctx.lineTo(wx, height); ctx.stroke();
            }
            for (let wy = wallH; wy < height; wy += 22) {
                const offset = (Math.floor((wy - wallH) / 22) % 2) * 32;
                ctx.beginPath(); ctx.moveTo(classStart + offset, wy); ctx.lineTo(worldWidth, wy); ctx.stroke();
            }
            // Floor reflection near wall
            const woodGlow = ctx.createLinearGradient(0, wallH, 0, wallH + 35);
            woodGlow.addColorStop(0, "rgba(255, 255, 255, 0.08)");
            woodGlow.addColorStop(1, "rgba(255, 255, 255, 0)");
            ctx.fillStyle = woodGlow;
            ctx.fillRect(classStart, wallH, worldWidth - classStart, 35);

            // === Classroom windows (back wall, with curtains) ===
            for (let wx = classStart + 20; wx < classStart + 200; wx += 130) {
                const ww = 90, wh = wallH * 0.45;
                const wy = wallH * 0.04;
                // Sky
                const skyG = ctx.createLinearGradient(0, wy, 0, wy + wh);
                skyG.addColorStop(0, "#b0d4f0");
                skyG.addColorStop(0.7, "#d0e4f8");
                skyG.addColorStop(1, "#c0dcc0");
                ctx.fillStyle = skyG;
                ctx.beginPath(); ctx.roundRect(wx + 3, wy + 3, ww - 6, wh - 6, 2); ctx.fill();
                // Tree outside
                ctx.fillStyle = "rgba(80, 140, 60, 0.35)";
                ctx.beginPath(); ctx.arc(wx + ww * 0.3, wy + wh * 0.65, 18, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "rgba(90, 65, 40, 0.3)";
                ctx.fillRect(wx + ww * 0.3 - 2, wy + wh * 0.75, 4, 14);
                // Frame
                ctx.strokeStyle = "rgba(130, 120, 105, 0.55)";
                ctx.lineWidth = 5;
                ctx.beginPath(); ctx.roundRect(wx, wy, ww, wh, 3); ctx.stroke();
                ctx.lineWidth = 2.5;
                ctx.beginPath(); ctx.moveTo(wx + ww / 2, wy); ctx.lineTo(wx + ww / 2, wy + wh); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(wx, wy + wh * 0.45); ctx.lineTo(wx + ww, wy + wh * 0.45); ctx.stroke();
                // Window sill
                ctx.fillStyle = "rgba(185, 175, 160, 0.6)";
                ctx.beginPath(); ctx.roundRect(wx - 4, wy + wh, ww + 8, 6, 2); ctx.fill();
                // Curtains
                ctx.fillStyle = "rgba(180, 140, 100, 0.2)";
                ctx.beginPath(); ctx.roundRect(wx + 1, wy + 1, 12, wh - 2, 1); ctx.fill();
                ctx.beginPath(); ctx.roundRect(wx + ww - 13, wy + 1, 12, wh - 2, 1); ctx.fill();
                // Curtain folds
                ctx.strokeStyle = "rgba(160, 120, 80, 0.12)";
                ctx.lineWidth = 0.8;
                for (let f = 0; f < 3; f++) {
                    ctx.beginPath(); ctx.moveTo(wx + 3 + f * 4, wy + 4); ctx.lineTo(wx + 3 + f * 4, wy + wh - 4); ctx.stroke();
                    ctx.beginPath(); ctx.moveTo(wx + ww - 12 + f * 4, wy + 4); ctx.lineTo(wx + ww - 12 + f * 4, wy + wh - 4); ctx.stroke();
                }
            }

            // === Posters/notices on wall ===
            const posterX = classStart + 180;
            // Poster 1: class schedule
            ctx.fillStyle = "#f8f0d8";
            ctx.beginPath(); ctx.roundRect(posterX, wallH * 0.08, 72, 95, 4); ctx.fill();
            ctx.strokeStyle = "rgba(160, 140, 100, 0.35)"; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.roundRect(posterX, wallH * 0.08, 72, 95, 4); ctx.stroke();
            // Pin
            ctx.fillStyle = "#cc3030";
            ctx.beginPath(); ctx.arc(posterX + 36, wallH * 0.08 - 1, 3, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#c04040";
            ctx.font = "700 10px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "center"; ctx.textBaseline = "top";
            ctx.fillText("時間割", posterX + 36, wallH * 0.08 + 6);
            ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.5;
            for (let r = 0; r < 5; r++) {
                const ry = wallH * 0.08 + 24 + r * 14;
                ctx.beginPath(); ctx.moveTo(posterX + 4, ry); ctx.lineTo(posterX + 68, ry); ctx.stroke();
            }

            // Poster 2: student art
            ctx.fillStyle = "#e8f0d8";
            ctx.beginPath(); ctx.roundRect(posterX + 86, wallH * 0.06, 62, 72, 4); ctx.fill();
            ctx.strokeStyle = "rgba(100, 140, 80, 0.3)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.roundRect(posterX + 86, wallH * 0.06, 62, 72, 4); ctx.stroke();
            ctx.fillStyle = "#cc3030";
            ctx.beginPath(); ctx.arc(posterX + 117, wallH * 0.06 - 1, 3, 0, Math.PI * 2); ctx.fill();
            // Rainbow
            const rcx = posterX + 117, rcy = wallH * 0.06 + 48;
            ["#e04040","#e08040","#e0d040","#40b040","#4080d0","#8040c0"].forEach((col, i) => {
                ctx.strokeStyle = col; ctx.lineWidth = 2;
                ctx.beginPath(); ctx.arc(rcx, rcy, 22 - i * 3, Math.PI, 0); ctx.stroke();
            });

            // Poster 3: class motto
            ctx.fillStyle = "#f0e8f0";
            ctx.beginPath(); ctx.roundRect(posterX + 162, wallH * 0.10, 58, 55, 4); ctx.fill();
            ctx.fillStyle = "#cc3030";
            ctx.beginPath(); ctx.arc(posterX + 191, wallH * 0.10 - 1, 3, 0, Math.PI * 2); ctx.fill();
            ctx.fillStyle = "#604080";
            ctx.font = "700 9px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "center";
            ctx.fillText("学級目標", posterX + 191, wallH * 0.10 + 10);
            ctx.font = "600 8px 'Zen Maru Gothic', sans-serif";
            ctx.fillText("なかよく", posterX + 191, wallH * 0.10 + 28);
            ctx.fillText("たのしく", posterX + 191, wallH * 0.10 + 40);

            // === BLACKBOARD (large, highly detailed) ===
            const bbX = worldWidth * 0.82;
            const bbW = worldWidth * 0.14;
            const bbY = wallH * 0.06;
            const bbH = wallH * 0.58;
            // Shadow
            ctx.fillStyle = "rgba(0,0,0,0.06)";
            ctx.beginPath(); ctx.roundRect(bbX + 4, bbY + 4, bbW, bbH, 4); ctx.fill();
            // Board surface gradient
            const bbG = ctx.createLinearGradient(bbX, bbY, bbX, bbY + bbH);
            bbG.addColorStop(0, "#2c5040");
            bbG.addColorStop(0.3, "#284a38");
            bbG.addColorStop(0.7, "#264535");
            bbG.addColorStop(1, "#2a4a3a");
            ctx.fillStyle = bbG;
            ctx.beginPath(); ctx.roundRect(bbX, bbY, bbW, bbH, 4); ctx.fill();
            // Chalk dust texture
            ctx.fillStyle = "rgba(255,255,255,0.03)";
            for (let dx = 0; dx < bbW; dx += 12) {
                for (let dy = 0; dy < bbH; dy += 12) {
                    if (Math.random() > 0.6) {
                        ctx.beginPath();
                        ctx.arc(bbX + dx + Math.random() * 10, bbY + dy + Math.random() * 10, Math.random() * 3, 0, Math.PI * 2);
                        ctx.fill();
                    }
                }
            }
            // Frame (wooden, detailed)
            ctx.strokeStyle = "#9a8a68";
            ctx.lineWidth = 6;
            ctx.beginPath(); ctx.roundRect(bbX - 4, bbY - 4, bbW + 8, bbH + 8, 5); ctx.stroke();
            ctx.strokeStyle = "#a89870";
            ctx.lineWidth = 2;
            ctx.beginPath(); ctx.roundRect(bbX - 1, bbY - 1, bbW + 2, bbH + 2, 3); ctx.stroke();
            // Chalk tray (3D effect)
            ctx.fillStyle = "#b8ad98";
            ctx.beginPath(); ctx.roundRect(bbX - 8, bbY + bbH + 3, bbW + 16, 12, [0,0,3,3]); ctx.fill();
            ctx.fillStyle = "#a89880";
            ctx.fillRect(bbX - 8, bbY + bbH + 3, bbW + 16, 3);
            ctx.fillStyle = "rgba(0,0,0,0.06)";
            ctx.fillRect(bbX - 6, bbY + bbH + 5, bbW + 12, 2);
            // Chalk pieces
            ctx.fillStyle = "#f8f8f5";
            ctx.beginPath(); ctx.roundRect(bbX + 14, bbY + bbH + 6, 22, 5, 1.5); ctx.fill();
            ctx.fillStyle = "#e8d060";
            ctx.beginPath(); ctx.roundRect(bbX + 42, bbY + bbH + 6, 18, 5, 1.5); ctx.fill();
            ctx.fillStyle = "#e87070";
            ctx.beginPath(); ctx.roundRect(bbX + 66, bbY + bbH + 7, 15, 4, 1.5); ctx.fill();
            ctx.fillStyle = "#70a0e0";
            ctx.beginPath(); ctx.roundRect(bbX + 86, bbY + bbH + 6, 12, 5, 1.5); ctx.fill();

            // Chalk writing on blackboard
            ctx.font = "500 13px 'Zen Maru Gothic', sans-serif";
            ctx.fillStyle = "rgba(255,255,255,0.35)";
            ctx.textAlign = "left"; ctx.textBaseline = "top";
            ctx.fillText("今日のめあて", bbX + 18, bbY + 16);
            ctx.strokeStyle = "rgba(255,255,255,0.22)";
            ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.moveTo(bbX + 18, bbY + 35); ctx.lineTo(bbX + bbW - 30, bbY + 35); ctx.stroke();
            ctx.font = "400 11px 'Zen Maru Gothic', sans-serif";
            ctx.fillStyle = "rgba(255,255,255,0.25)";
            ctx.fillText("みんなで たすけあおう", bbX + 24, bbY + 44);

            // Doodle art on blackboard (linked to 落書き activity)
            const doodleGlow = hov === "doodle";
            if (doodleGlow) glowFor("doodle", bbX + bbW * 0.6, bbY + bbH * 0.65, bbH * 0.5);
            const dAlpha = doodleGlow ? 0.65 + Math.sin(t * 3) * 0.15 : 0.3;
            ctx.save();
            ctx.globalAlpha = dAlpha;
            // Star
            const drawStar = (sx, sy, r, col) => {
                ctx.fillStyle = col;
                ctx.beginPath();
                for (let i = 0; i < 5; i++) {
                    const a1 = (i * 72 - 90) * Math.PI / 180;
                    const a2 = ((i * 72) + 36 - 90) * Math.PI / 180;
                    ctx.lineTo(sx + Math.cos(a1) * r, sy + Math.sin(a1) * r);
                    ctx.lineTo(sx + Math.cos(a2) * r * 0.45, sy + Math.sin(a2) * r * 0.45);
                }
                ctx.closePath(); ctx.fill();
            };
            drawStar(bbX + bbW * 0.7, bbY + bbH * 0.55, 14, "rgba(230, 210, 80, 0.9)");
            drawStar(bbX + bbW * 0.85, bbY + bbH * 0.45, 9, "rgba(230, 130, 180, 0.85)");
            // Smiley face
            const smX = bbX + bbW * 0.55, smY = bbY + bbH * 0.72;
            ctx.strokeStyle = "rgba(255, 255, 100, 0.85)";
            ctx.lineWidth = 2;
            ctx.beginPath(); ctx.arc(smX, smY, 13, 0, Math.PI * 2); ctx.stroke();
            ctx.fillStyle = "rgba(255, 255, 100, 0.8)";
            ctx.beginPath(); ctx.arc(smX - 5, smY - 3, 2, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.arc(smX + 5, smY - 3, 2, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.arc(smX, smY + 2, 7, 0.15 * Math.PI, 0.85 * Math.PI); ctx.stroke();
            // Flower
            const flX = bbX + bbW * 0.78, flY = bbY + bbH * 0.78;
            ctx.fillStyle = "rgba(255, 150, 150, 0.85)";
            for (let p = 0; p < 5; p++) {
                const pa = (p / 5) * Math.PI * 2;
                ctx.beginPath(); ctx.arc(flX + Math.cos(pa) * 7, flY + Math.sin(pa) * 7, 5, 0, Math.PI * 2); ctx.fill();
            }
            ctx.fillStyle = "rgba(255, 220, 80, 0.9)";
            ctx.beginPath(); ctx.arc(flX, flY, 4, 0, Math.PI * 2); ctx.fill();
            // Cat face
            const catX = bbX + bbW * 0.4, catY = bbY + bbH * 0.8;
            ctx.strokeStyle = "rgba(255, 200, 150, 0.8)"; ctx.lineWidth = 1.8;
            ctx.beginPath(); ctx.arc(catX, catY, 10, 0, Math.PI * 2); ctx.stroke();
            // Ears
            ctx.beginPath(); ctx.moveTo(catX - 8, catY - 8); ctx.lineTo(catX - 12, catY - 18); ctx.lineTo(catX - 3, catY - 10); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(catX + 8, catY - 8); ctx.lineTo(catX + 12, catY - 18); ctx.lineTo(catX + 3, catY - 10); ctx.stroke();
            // Eyes & whiskers
            ctx.fillStyle = "rgba(255, 200, 150, 0.8)";
            ctx.beginPath(); ctx.arc(catX - 4, catY - 2, 1.5, 0, Math.PI * 2); ctx.fill();
            ctx.beginPath(); ctx.arc(catX + 4, catY - 2, 1.5, 0, Math.PI * 2); ctx.fill();
            ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(catX - 8, catY + 1); ctx.lineTo(catX - 16, catY - 1); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(catX - 8, catY + 3); ctx.lineTo(catX - 16, catY + 4); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(catX + 8, catY + 1); ctx.lineTo(catX + 16, catY - 1); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(catX + 8, catY + 3); ctx.lineTo(catX + 16, catY + 4); ctx.stroke();
            ctx.restore();

            // Doodle glow rect
            if (doodleGlow) {
                glowRectFor("doodle", bbX + bbW * 0.3, bbY + bbH * 0.4, bbW * 0.6, bbH * 0.55, 6);
            }

            // Date in corner
            ctx.fillStyle = "rgba(255,255,255,0.3)";
            ctx.font = "500 12px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "right"; ctx.textBaseline = "top";
            ctx.fillText("2/20", bbX + bbW - 14, bbY + 12);

            // === Clock (improved) ===
            const clockX = bbX + bbW + 35;
            const clockY = wallH * 0.14;
            const clockR = 24;
            // Clock shadow
            ctx.fillStyle = "rgba(0,0,0,0.05)";
            ctx.beginPath(); ctx.arc(clockX + 2, clockY + 2, clockR + 2, 0, Math.PI * 2); ctx.fill();
            // Clock body
            ctx.fillStyle = "#fafafa";
            ctx.beginPath(); ctx.arc(clockX, clockY, clockR, 0, Math.PI * 2); ctx.fill();
            ctx.strokeStyle = "#4a4a4a";
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.arc(clockX, clockY, clockR, 0, Math.PI * 2); ctx.stroke();
            // Inner ring
            ctx.strokeStyle = "rgba(0,0,0,0.06)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.arc(clockX, clockY, clockR - 3, 0, Math.PI * 2); ctx.stroke();
            // Hour marks
            for (let h = 0; h < 12; h++) {
                const a = (h / 12) * Math.PI * 2 - Math.PI / 2;
                const isMain = h % 3 === 0;
                ctx.strokeStyle = isMain ? "#333" : "#888";
                ctx.lineWidth = isMain ? 2 : 1;
                ctx.beginPath();
                ctx.moveTo(clockX + Math.cos(a) * (clockR - (isMain ? 8 : 6)), clockY + Math.sin(a) * (clockR - (isMain ? 8 : 6)));
                ctx.lineTo(clockX + Math.cos(a) * (clockR - 3), clockY + Math.sin(a) * (clockR - 3));
                ctx.stroke();
            }
            // Hands (10:10 position)
            ctx.strokeStyle = "#222"; ctx.lineWidth = 2.5; ctx.lineCap = "round";
            ctx.beginPath(); ctx.moveTo(clockX, clockY);
            ctx.lineTo(clockX + Math.cos(-Math.PI * 0.42) * 13, clockY + Math.sin(-Math.PI * 0.42) * 13); ctx.stroke();
            ctx.lineWidth = 1.8;
            ctx.beginPath(); ctx.moveTo(clockX, clockY);
            ctx.lineTo(clockX + Math.cos(Math.PI * 0.17) * 17, clockY + Math.sin(Math.PI * 0.17) * 17); ctx.stroke();
            ctx.lineCap = "butt";
            // Second hand
            const secAngle = (t * 0.5) % (Math.PI * 2) - Math.PI / 2;
            ctx.strokeStyle = "#cc0000"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(clockX, clockY);
            ctx.lineTo(clockX + Math.cos(secAngle) * 18, clockY + Math.sin(secAngle) * 18); ctx.stroke();
            // Center dot
            ctx.fillStyle = "#222";
            ctx.beginPath(); ctx.arc(clockX, clockY, 2.5, 0, Math.PI * 2); ctx.fill();

            // === ORGAN (highly detailed, linked to organ activity) ===
            const organX = worldWidth * 0.95 - 44;
            const organW = 88;
            const organH = 68;
            const organY = wallH - organH;
            const organGlow = hov === "organ";
            if (organGlow) glowFor("organ", organX + organW / 2, organY + organH / 2, 80);
            // Main body (wood grain)
            const oG = ctx.createLinearGradient(organX, organY, organX, organY + organH);
            oG.addColorStop(0, "#7a5838");
            oG.addColorStop(0.4, "#6a4830");
            oG.addColorStop(1, "#5a3820");
            ctx.fillStyle = oG;
            ctx.beginPath(); ctx.roundRect(organX, organY, organW, organH, [5,5,2,2]); ctx.fill();
            // Wood grain lines
            ctx.strokeStyle = "rgba(0,0,0,0.06)"; ctx.lineWidth = 0.5;
            for (let gy = organY + 8; gy < organY + organH; gy += 7) {
                ctx.beginPath(); ctx.moveTo(organX + 3, gy); ctx.lineTo(organX + organW - 3, gy); ctx.stroke();
            }
            // Keyboard area (recessed)
            ctx.fillStyle = "rgba(0,0,0,0.15)";
            ctx.beginPath(); ctx.roundRect(organX + 4, organY + 10, organW - 8, 22, 2); ctx.fill();
            // White keys
            const keyStartX = organX + 6, keyW = (organW - 12) / 14;
            for (let k = 0; k < 14; k++) {
                ctx.fillStyle = k % 2 === 0 ? "#f5f2e8" : "#f0ede4";
                ctx.beginPath(); ctx.roundRect(keyStartX + k * keyW, organY + 11, keyW - 0.8, 19, [0,0,1.5,1.5]); ctx.fill();
                ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.5;
                ctx.beginPath(); ctx.roundRect(keyStartX + k * keyW, organY + 11, keyW - 0.8, 19, [0,0,1.5,1.5]); ctx.stroke();
            }
            // Black keys
            ctx.fillStyle = "#1a1a1a";
            [1,2,4,5,6,8,9,11,12].forEach(k => {
                if (k < 14) {
                    ctx.beginPath(); ctx.roundRect(keyStartX + k * keyW - 1.5, organY + 11, keyW * 0.65, 12, [0,0,1,1]); ctx.fill();
                }
            });
            // Control knobs
            for (let kn = 0; kn < 4; kn++) {
                ctx.fillStyle = "#4a3a28";
                ctx.beginPath(); ctx.arc(organX + 14 + kn * 18, organY + 40, 4, 0, Math.PI * 2); ctx.fill();
                ctx.fillStyle = "#f0e8d0";
                ctx.beginPath(); ctx.arc(organX + 14 + kn * 18, organY + 40, 2, 0, Math.PI * 2); ctx.fill();
            }
            // Music stand
            const msY = organY - 20;
            ctx.fillStyle = "#7a5838";
            ctx.beginPath(); ctx.roundRect(organX + 8, msY, organW - 16, 22, [5,5,0,0]); ctx.fill();
            ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.roundRect(organX + 8, msY, organW - 16, 22, [5,5,0,0]); ctx.stroke();
            // Sheet music on stand
            ctx.fillStyle = "#f8f4e8";
            ctx.beginPath(); ctx.roundRect(organX + 14, msY + 3, organW - 28, 16, 2); ctx.fill();
            ctx.strokeStyle = "rgba(0,0,0,0.08)"; ctx.lineWidth = 0.5;
            // Staff lines on sheet music
            for (let sl = 0; sl < 5; sl++) {
                ctx.beginPath();
                ctx.moveTo(organX + 18, msY + 6 + sl * 2.5);
                ctx.lineTo(organX + organW - 18, msY + 6 + sl * 2.5);
                ctx.stroke();
            }
            // Notes on sheet
            ctx.fillStyle = "rgba(0,0,0,0.2)";
            [22, 30, 38, 46, 54].forEach((nx, i) => {
                ctx.beginPath(); ctx.ellipse(organX + nx, msY + 7 + (i % 3) * 2.5, 2, 1.5, 0.3, 0, Math.PI * 2); ctx.fill();
            });
            // Pedals
            ctx.fillStyle = "#4a3a28";
            ctx.beginPath(); ctx.roundRect(organX + 15, wallH + 2, 20, 8, 2); ctx.fill();
            ctx.beginPath(); ctx.roundRect(organX + organW - 35, wallH + 2, 20, 8, 2); ctx.fill();
            // Legs
            ctx.fillStyle = "#5a3828";
            ctx.fillRect(organX + 6, wallH - 2, 6, 18);
            ctx.fillRect(organX + organW - 12, wallH - 2, 6, 18);
            // Stool
            const stoolX = organX + organW / 2 - 22;
            ctx.fillStyle = "#5a3820";
            ctx.beginPath(); ctx.roundRect(stoolX, wallH - 2, 44, 6, 3); ctx.fill();
            ctx.fillStyle = "rgba(0,0,0,0.08)";
            ctx.beginPath(); ctx.roundRect(stoolX + 2, wallH - 1, 40, 4, 2); ctx.fill();
            ctx.fillStyle = "#4a2818";
            ctx.fillRect(stoolX + 6, wallH + 4, 5, 14);
            ctx.fillRect(stoolX + 33, wallH + 4, 5, 14);
            // Organ glow
            if (organGlow) glowRectFor("organ", organX - 4, msY - 4, organW + 8, organH + 24 + 4, 6);

            // === BOOKS for 読書 activity (worldFraction 0.52-0.60) ===
            const booksX = worldWidth * 0.67;
            const booksFloorY = wallH + 22;
            const readGlow = hov === "reading";
            if (readGlow) glowFor("reading", booksX, booksFloorY + 12, 70);
            // Find the desk closest to the reading area and put books on it
            const readDesk = schoolBgObjects.desks.find(d => Math.abs(d.x - booksX) < 40);
            const bookBaseY = readDesk ? readDesk.y - 1 : booksFloorY;
            // Stack of closed books
            const bookAlpha = readGlow ? 1.0 : 0.85;
            ctx.save();
            ctx.globalAlpha = bookAlpha;
            schoolBgObjects.books.forEach((book, bi) => {
                const bx = booksX - 18 + bi * 7;
                const by = bookBaseY - book.h;
                ctx.save();
                ctx.translate(bx, by + book.h / 2);
                ctx.rotate(book.tilt);
                // Book cover
                ctx.fillStyle = book.color;
                ctx.beginPath(); ctx.roundRect(-book.w / 2, -book.h / 2, book.w, book.h, 1.5); ctx.fill();
                // Spine highlight
                ctx.fillStyle = "rgba(255,255,255,0.2)";
                ctx.fillRect(-book.w / 2, -book.h / 2, 1.5, book.h);
                // Page edges
                ctx.fillStyle = "rgba(255,250,235,0.8)";
                ctx.fillRect(-book.w / 2 + 1.5, -book.h / 2 + 1, book.w - 3, 1);
                ctx.restore();
            });
            // Open book (lying flat)
            const obX = booksX + 28, obY = bookBaseY - 6;
            ctx.fillStyle = "#f5f0e0";
            ctx.beginPath();
            ctx.moveTo(obX - 20, obY); ctx.lineTo(obX, obY + 4); ctx.lineTo(obX + 20, obY);
            ctx.lineTo(obX + 20, obY - 14); ctx.lineTo(obX, obY - 10); ctx.lineTo(obX - 20, obY - 14);
            ctx.closePath(); ctx.fill();
            // Book spine
            ctx.strokeStyle = "rgba(0,0,0,0.12)"; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(obX, obY + 4); ctx.lineTo(obX, obY - 10); ctx.stroke();
            // Text lines
            ctx.strokeStyle = "rgba(0,0,0,0.1)"; ctx.lineWidth = 0.5;
            for (let tl = 0; tl < 3; tl++) {
                ctx.beginPath();
                ctx.moveTo(obX - 17, obY - 12 + tl * 4);
                ctx.lineTo(obX - 4, obY - 10 + tl * 4);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(obX + 4, obY - 10 + tl * 4);
                ctx.lineTo(obX + 17, obY - 12 + tl * 4);
                ctx.stroke();
            }
            // Book cover (closed book beside open one)
            ctx.fillStyle = "hsl(25, 55%, 48%)";
            ctx.beginPath(); ctx.roundRect(obX + 24, obY - 14, 14, 18, 2); ctx.fill();
            ctx.fillStyle = "rgba(255,255,255,0.15)";
            ctx.fillRect(obX + 24, obY - 14, 2, 18);
            ctx.restore();
            if (readGlow) glowRectFor("reading", booksX - 24, bookBaseY - 32, 74, 36, 5);

            // === CHATTING STUDENTS for おしゃべり activity (worldFraction 0.62-0.72) ===
            const chatX = worldWidth * 0.76;
            const chatGlow = hov === "chatting";
            if (chatGlow) glowFor("chatting", chatX, wallH - 10, 80);
            if (schoolBgObjects.chattingPair) {
                const pair = schoolBgObjects.chattingPair;
                // Draw both students using full Child rig in standing pose
                drawSchoolNpc(pair.student1, { standing: true, gesturePhase: t, facing: 1 });
                drawSchoolNpc(pair.student2, { standing: true, gesturePhase: t + Math.PI, facing: -1 });
                // Speech bubbles (drawn separately on top)
                const drawBubble = (sx, facing, bobOffset) => {
                    ctx.save();
                    ctx.translate(sx, wallH);
                    ctx.fillStyle = `rgba(255,255,255,${0.55 + Math.sin(t * 4 + bobOffset) * 0.2})`;
                    const bubX = facing > 0 ? 22 : -44;
                    ctx.beginPath(); ctx.roundRect(bubX, -85, 22, 14, 5); ctx.fill();
                    // Bubble tail
                    ctx.beginPath();
                    ctx.moveTo(bubX + (facing > 0 ? 0 : 22), -73);
                    ctx.lineTo(bubX + (facing > 0 ? -4 : 26), -69);
                    ctx.lineTo(bubX + (facing > 0 ? 6 : 16), -73);
                    ctx.closePath(); ctx.fill();
                    // Speech dots
                    ctx.fillStyle = "rgba(0,0,0,0.25)";
                    for (let d = 0; d < 3; d++) {
                        const da = 0.35 + Math.sin(t * 5 + d * 0.8 + bobOffset) * 0.15;
                        ctx.globalAlpha = da;
                        ctx.beginPath(); ctx.arc(bubX + 5 + d * 5, -78, 1.5, 0, Math.PI * 2); ctx.fill();
                    }
                    ctx.globalAlpha = 1;
                    ctx.restore();
                };
                drawBubble(pair.student1.x, 1, 0);
                drawBubble(pair.student2.x, -1, Math.PI);
            }
            if (chatGlow) glowRectFor("chatting", chatX - 55, wallH - 100, 110, 120, 8);

            // === Desks and chairs (drawn on top of floor) ===
            schoolBgObjects.desks.forEach(desk => {
                const dtop = desk.y;
                // Desk shadow
                ctx.fillStyle = "rgba(0,0,0,0.03)";
                ctx.beginPath(); ctx.roundRect(desk.x - deskW / 2 + 3, dtop + 3, deskW, deskH + 20, 2); ctx.fill();
                // Desk surface
                const dG = ctx.createLinearGradient(desk.x - deskW / 2, dtop, desk.x + deskW / 2, dtop);
                dG.addColorStop(0, "rgba(200, 180, 148, 0.85)");
                dG.addColorStop(0.5, "rgba(210, 190, 158, 0.9)");
                dG.addColorStop(1, "rgba(195, 175, 145, 0.85)");
                ctx.fillStyle = dG;
                ctx.beginPath(); ctx.roundRect(desk.x - deskW / 2, dtop, deskW, deskH, 2); ctx.fill();
                ctx.strokeStyle = "rgba(0,0,0,0.07)"; ctx.lineWidth = 1;
                ctx.beginPath(); ctx.roundRect(desk.x - deskW / 2, dtop, deskW, deskH, 2); ctx.stroke();
                // Desk edge highlight
                ctx.fillStyle = "rgba(255,255,255,0.12)";
                ctx.fillRect(desk.x - deskW / 2, dtop, deskW, 1.5);
                // Desk front panel
                ctx.fillStyle = "rgba(180, 160, 130, 0.55)";
                ctx.beginPath(); ctx.roundRect(desk.x - deskW / 2, dtop + deskH, deskW, 18, [0,0,2,2]); ctx.fill();
                // Legs
                ctx.fillStyle = "rgba(110, 108, 100, 0.5)";
                const legLen = deskTopFromFloor - deskH;
                ctx.fillRect(desk.x - deskW / 2 + 2, dtop + deskH, 3, legLen);
                ctx.fillRect(desk.x + deskW / 2 - 5, dtop + deskH, 3, legLen);
                // Chair
                const chairY = dtop + deskH + legLen;
                ctx.fillStyle = "rgba(170, 155, 125, 0.55)";
                ctx.beginPath(); ctx.roundRect(desk.x - 14, chairY - 6, 28, 5, 2); ctx.fill();
                ctx.fillStyle = "rgba(125, 120, 110, 0.4)";
                ctx.fillRect(desk.x - 12, chairY - 1, 2, 10);
                ctx.fillRect(desk.x + 10, chairY - 1, 2, 10);
                // Backrest
                ctx.fillStyle = "rgba(155, 140, 115, 0.5)";
                ctx.beginPath(); ctx.roundRect(desk.x - 12, chairY - 28, 24, 10, [3,3,0,0]); ctx.fill();
                ctx.fillRect(desk.x - 11, chairY - 18, 2, 14);
                ctx.fillRect(desk.x + 9, chairY - 18, 2, 14);
            });

            // NPC students in hallway
            if (schoolBgNpcs) {
                schoolBgNpcs.forEach(npc => drawSchoolNpc(npc));
            }

            ctx.textAlign = "left";
        }

        function drawToneDrops() {
            const dropColor = (drop) => {
                if (drop.dropColor) return drop.dropColor;
                if (drop.instrument === "snare") return "hsl(24, 82%, 58%)";
                if (drop.instrument === "cymbal") return "hsl(202, 58%, 64%)";
                if (drop.instrument === "hat") return palette.btnColor;
                return palette.btnColor;
            };
            toneDrops.forEach(drop => {
                const active = drop.proximityVol > -62;
                const glow = Math.max(0, (drop.proximityVol + 100) / 100);
                const fillLevel = clamp01(drop.fillLevel || 0);
                const toneColor = dropColor(drop);
                if (drop.toy && toySystem.drawToy) {
                    const toyScale = (currentScene === SCENE.TODDLE1 || currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2) ? 1.5 : 1.84;
                    toySystem.drawToy(ctx, drop.toy, drop.x, drop.y - 92, toyScale, drop.toySeed);
                }
                if (drop.toy && drop.overlapAlpha > 0.01) {
                    const a = Math.min(1, drop.overlapAlpha);
                    ctx.save();
                    ctx.globalAlpha = a;
                    ctx.textAlign = "center";
                    ctx.textBaseline = "middle";
                    ctx.shadowColor = "rgba(255,255,255,0.85)";
                    ctx.shadowBlur = 12;
                    ctx.fillStyle = "rgba(46, 51, 66, 0.95)";
                    ctx.font = "700 18px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.toy.name, drop.x, drop.y - 176);
                    ctx.shadowBlur = 8;
                    ctx.fillStyle = "rgba(75, 84, 106, 0.9)";
                    ctx.font = "600 12px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.toy.nameJa || "", drop.x, drop.y - 154);
                    ctx.restore();
                }
                ctx.save();
                ctx.translate(drop.x, drop.y);

                // Beat-synced ripples (kept subtle to match choice-button style)
                if (drop.ripples) {
                    drop.ripples = drop.ripples.filter(r => r.t < 1);
                    drop.ripples.forEach(r => {
                        r.t += 0.02;
                        const radius = 52 + r.t * 56;
                        const alpha = (1 - r.t) * 0.18 * (r.accent || 0.7);
                        ctx.strokeStyle = `rgba(255, 255, 255, ${alpha})`;
                        ctx.lineWidth = 2.2 * (1 - r.t * 0.55);
                        ctx.beginPath();
                        ctx.arc(0, 0, radius, 0, Math.PI * 2);
                        ctx.stroke();
                    });
                }

                // Consumed modifier: dim the entire drop
                if (drop.consumed) {
                    ctx.globalAlpha = 0.3;
                }

                // Base style: close to initial choice buttons (solid fill + white border + modest shadow)
                const baseR = 50;
                ctx.shadowColor = "rgba(0,0,0,0.14)";
                ctx.shadowBlur = 14;
                ctx.shadowOffsetY = 8;
                ctx.fillStyle = toneColor;
                ctx.beginPath();
                ctx.arc(0, 0, baseR, 0, Math.PI * 2);
                ctx.fill();
                ctx.shadowBlur = 0;
                ctx.shadowOffsetY = 0;

                // Subtle top highlight instead of strong glow
                const hi = ctx.createRadialGradient(-14, -18, 2, -8, -10, 42);
                hi.addColorStop(0, "rgba(255,255,255,0.30)");
                hi.addColorStop(1, "rgba(255,255,255,0)");
                ctx.fillStyle = hi;
                ctx.beginPath();
                ctx.arc(0, 0, baseR - 2, 0, Math.PI * 2);
                ctx.fill();

                // White border like choice buttons
                ctx.strokeStyle = "rgba(255,255,255,0.96)";
                ctx.lineWidth = 4;
                ctx.beginPath();
                ctx.arc(0, 0, baseR, 0, Math.PI * 2);
                ctx.stroke();

                // Hovered tone gets a restrained accent ring
                if (active) {
                    ctx.strokeStyle = `rgba(255,255,255,${0.14 + glow * 0.14})`;
                    ctx.lineWidth = 2;
                    ctx.beginPath();
                    ctx.arc(0, 0, baseR + 8 + glow * 2, 0, Math.PI * 2);
                    ctx.stroke();
                }

                ctx.fillStyle = fillLevel >= 0.985 ? "rgba(255,255,255,0.98)" : "rgba(255,255,255,0.72)";
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";
                if (drop.instrument === "modifier") {
                    ctx.font = "700 13px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.activityName || "", 0, -12);
                    if (drop.activityNameEn) {
                        ctx.font = "500 10px 'Zen Maru Gothic', sans-serif";
                        ctx.fillText(drop.activityNameEn, 0, 2);
                    }
                    // Show which bar it targets
                    ctx.font = "500 9px 'Zen Maru Gothic', sans-serif";
                    ctx.globalAlpha = drop.consumed ? 0.3 : 0.6;
                    const barLabel = drop.targetBarOnPage2 === 2 ? "Bar 3" : "Bar 4";
                    ctx.fillText(barLabel, 0, 16);
                    if (drop.consumed) {
                        // Checkmark
                        ctx.globalAlpha = 0.8;
                        ctx.font = "700 22px sans-serif";
                        ctx.fillText("\u2713", 0, 32);
                    }
                } else if (drop.instrument === "keyboard" || drop.instrument === "timbre" || drop.instrument === "melody") {
                    ctx.font = "700 14px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.activityName || "", 0, -6);
                    if (drop.activityNameEn) {
                        ctx.font = "500 10px 'Zen Maru Gothic', sans-serif";
                        ctx.fillText(drop.activityNameEn, 0, 10);
                    }
                } else if (drop.instrument === "bass") {
                    ctx.font = "700 14px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.activityName || "", 0, -2);
                    ctx.font = "500 9px 'Zen Maru Gothic', sans-serif";
                    ctx.globalAlpha = 0.7;
                    ctx.fillText(drop.bassStyle || "", 0, 14);
                    ctx.globalAlpha = 1;
                } else if (drop.chordProgression) {
                    ctx.font = "700 18px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(drop.chordProgression.chords[0], 0, -5);
                    ctx.font = "500 9px 'Zen Maru Gothic', sans-serif";
                    ctx.globalAlpha = 0.7;
                    ctx.fillText(drop.chordProgression.chords.join(" - "), 0, 10);
                    ctx.globalAlpha = 1;
                    if (drop.facilityName || drop.chordSide) {
                        ctx.fillStyle = "rgba(255,255,255,0.82)";
                        ctx.font = "600 11px 'Zen Maru Gothic', sans-serif";
                        ctx.textBaseline = "bottom";
                        ctx.fillText(drop.facilityName || drop.chordSide, 0, -54);
                        ctx.textBaseline = "middle";
                    }
                } else {
                    ctx.font = "700 27px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText("tone.", 0, 1.5);
                }
                ctx.restore();
            });
        }

        // Hovered toy stats HUD (top-left, screen space)
        let hoveredToyHudAlpha = 0;
        let lastHoveredToy = null;
        function drawToyStatsHud() {
            if (currentScene !== SCENE.CRAWL && currentScene !== SCENE.CRAWL2 && currentScene !== SCENE.TODDLE1 && currentScene !== SCENE.CHILD1 && currentScene !== SCENE.CHILD2 && currentScene !== SCENE.ADULT && currentScene !== SCENE.UNIVERSITY && currentScene !== SCENE.PART_TIME && currentScene !== SCENE.JOB_HUNT && currentScene !== SCENE.JOB_HUNT2 && currentScene !== SCENE.TRAVEL && currentScene !== SCENE.THIRTIES && currentScene !== SCENE.CITY) {
                hoveredToyHudAlpha = 0;
                return;
            }
            // Find the hovered toy (or post-adult drop with activity labels)
            let hovToy = null;
            toneDrops.forEach(drop => {
                if (drop.isHovered && drop.toy) hovToy = drop.toy;
                if (drop.isHovered && drop.activityLabels && (currentScene === SCENE.CHILD1 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY)) {
                    hovToy = { name: drop.activityNameEn ? `${drop.activityName} / ${drop.activityNameEn}` : drop.activityName, labels: drop.activityLabels };
                }
            });
            if (hovToy) {
                lastHoveredToy = hovToy;
                hoveredToyHudAlpha = Math.min(1, hoveredToyHudAlpha + 0.08);
            } else {
                hoveredToyHudAlpha = Math.max(0, hoveredToyHudAlpha - 0.06);
            }
            if (hoveredToyHudAlpha < 0.01 || !lastHoveredToy) return;
            const toy = lastHoveredToy;

            ctx.save();
            ctx.globalAlpha = hoveredToyHudAlpha;

            const px = 18, py = 18;
            // Collect non-zero labels
            const entries = [];
            if (toy.labels) {
                Object.entries(toy.labels).forEach(([k, v]) => {
                    if (v > 0) entries.push({ label: k, value: v });
                });
            }
            entries.sort((a, b) => b.value - a.value);

            // Audio profile
            const audio = toy.audio;
            const audioEntries = [];
            if (audio) {
                audioEntries.push({ label: "density", value: audio.density.join("-") });
                audioEntries.push({ label: "pitch", value: audio.pitchMotion.join("-") });
                audioEntries.push({ label: "rhythm", value: audio.rhythmMotion.join("-") });
                audioEntries.push({ label: "openness", value: audio.openness.join("-") });
            }

            const totalScore = entries.reduce((s, e) => s + e.value, 0);
            const lineH = 22;
            const panelH = 48 + entries.length * lineH + (audioEntries.length ? 14 + audioEntries.length * 18 : 0) + 28;
            const panelW = 200;

            // Panel background
            ctx.fillStyle = "rgba(30, 32, 42, 0.72)";
            ctx.beginPath();
            ctx.roundRect(px, py, panelW, panelH, 10);
            ctx.fill();
            // Panel border
            ctx.strokeStyle = "rgba(255,255,255,0.15)";
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.roundRect(px, py, panelW, panelH, 10);
            ctx.stroke();

            let cy = py + 16;

            // Toy name (English)
            ctx.fillStyle = "rgba(255,255,255,0.95)";
            ctx.font = "700 14px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "left";
            ctx.textBaseline = "middle";
            ctx.fillText(toy.name, px + 14, cy);
            // Japanese name (separate line below)
            if (toy.nameJa) {
                cy += 14;
                ctx.fillStyle = "rgba(255,255,255,0.55)";
                ctx.font = "500 10px 'Zen Maru Gothic', sans-serif";
                ctx.fillText(toy.nameJa, px + 14, cy);
            }
            cy += 22;

            // Life labels header
            ctx.fillStyle = "rgba(229, 142, 170, 0.9)";
            ctx.font = "600 11px 'Zen Maru Gothic', sans-serif";
            ctx.fillText(`Life Labels (total: ${totalScore})`, px + 14, cy);
            cy += 16;

            // Label bars
            entries.forEach(e => {
                // Bar background
                ctx.fillStyle = "rgba(255,255,255,0.1)";
                ctx.beginPath(); ctx.roundRect(px + 14, cy - 6, 140, 14, 3); ctx.fill();
                // Bar fill
                const barMax = (currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2) ? 5 : 3;
                const barW = Math.min(e.value / barMax, 1) * 140;
                const barG = ctx.createLinearGradient(px + 14, 0, px + 14 + barW, 0);
                barG.addColorStop(0, "rgba(229, 142, 170, 0.7)");
                barG.addColorStop(1, "rgba(198, 128, 219, 0.7)");
                ctx.fillStyle = barG;
                ctx.beginPath(); ctx.roundRect(px + 14, cy - 6, barW, 14, 3); ctx.fill();
                // Label text
                ctx.fillStyle = "rgba(255,255,255,0.9)";
                ctx.font = "500 10px 'Zen Maru Gothic', sans-serif";
                ctx.fillText(labelDisplay(e.label), px + 18, cy + 1);
                // Value
                ctx.textAlign = "right";
                ctx.fillText(`+${e.value}`, px + 14 + 136, cy + 1);
                ctx.textAlign = "left";
                cy += lineH;
            });

            // Audio profile section
            if (audioEntries.length) {
                cy += 4;
                ctx.fillStyle = "rgba(160, 200, 230, 0.8)";
                ctx.font = "600 11px 'Zen Maru Gothic', sans-serif";
                ctx.fillText("Sound Profile", px + 14, cy);
                cy += 14;
                audioEntries.forEach(e => {
                    ctx.fillStyle = "rgba(255,255,255,0.6)";
                    ctx.font = "400 10px 'Zen Maru Gothic', sans-serif";
                    ctx.fillText(e.label, px + 18, cy);
                    ctx.textAlign = "right";
                    ctx.fillStyle = "rgba(255,255,255,0.8)";
                    ctx.fillText(e.value, px + 14 + 136, cy);
                    ctx.textAlign = "left";
                    cy += 18;
                });
            }

            ctx.restore();
        }

        // Cumulative life labels HUD (top-right, screen space)
        let cumulHudAlpha = 0;
        let lastCumulToy = null;
        function drawCumulativeStatsHud() {
            if (currentScene !== SCENE.CRAWL && currentScene !== SCENE.CRAWL2 && currentScene !== SCENE.TODDLE1 && currentScene !== SCENE.CHILD1 && currentScene !== SCENE.CHILD2 && currentScene !== SCENE.ADULT && currentScene !== SCENE.UNIVERSITY && currentScene !== SCENE.PART_TIME && currentScene !== SCENE.JOB_HUNT && currentScene !== SCENE.JOB_HUNT2 && currentScene !== SCENE.TRAVEL && currentScene !== SCENE.THIRTIES && currentScene !== SCENE.CITY) {
                cumulHudAlpha = 0;
                return;
            }
            let hovToy = null;
            toneDrops.forEach(drop => {
                if (drop.isHovered && drop.toy) hovToy = drop.toy;
                if (drop.isHovered && drop.activityLabels && (currentScene === SCENE.CHILD1 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY)) {
                    hovToy = { name: drop.activityNameEn ? `${drop.activityName} / ${drop.activityNameEn}` : drop.activityName, labels: drop.activityLabels };
                }
            });
            if (hovToy) {
                lastCumulToy = hovToy;
                cumulHudAlpha = Math.min(1, cumulHudAlpha + 0.08);
            } else {
                cumulHudAlpha = Math.max(0, cumulHudAlpha - 0.06);
            }
            if (cumulHudAlpha < 0.01 || !lastCumulToy) return;

            // Accumulate: all previously selected toys + hovered toy (avoid double-counting)
            const totals = {};
            const alreadySelected = lastCumulToy && selectedToys.some(t => t.id === lastCumulToy.id || t.name === lastCumulToy.name);
            const allToys = alreadySelected ? selectedToys : [...selectedToys, lastCumulToy];
            allToys.forEach(t => {
                if (!t.labels) return;
                Object.entries(t.labels).forEach(([k, v]) => {
                    totals[k] = (totals[k] || 0) + v;
                });
            });

            // Sort by value descending, filter out zero
            const entries = Object.entries(totals)
                .filter(([, v]) => v > 0)
                .map(([label, value]) => ({ label, value }))
                .sort((a, b) => b.value - a.value);

            if (!entries.length) return;

            const grandTotal = entries.reduce((s, e) => s + e.value, 0);
            const maxVal = entries[0].value;

            ctx.save();
            ctx.globalAlpha = cumulHudAlpha;

            const panelW = 220;
            const lineH = 22;
            const panelH = 48 + entries.length * lineH + 10;
            const px = width - panelW - 18;
            const py = 18;

            // Panel background
            ctx.fillStyle = "rgba(30, 32, 42, 0.72)";
            ctx.beginPath(); ctx.roundRect(px, py, panelW, panelH, 10); ctx.fill();
            ctx.strokeStyle = "rgba(255,255,255,0.15)";
            ctx.lineWidth = 1;
            ctx.beginPath(); ctx.roundRect(px, py, panelW, panelH, 10); ctx.stroke();

            let cy = py + 16;

            // Header
            ctx.fillStyle = "rgba(255,255,255,0.95)";
            ctx.font = "700 13px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "left";
            ctx.textBaseline = "middle";
            ctx.fillText("Life Labels Total", px + 14, cy);
            // Grand total badge
            ctx.fillStyle = "rgba(229, 142, 170, 0.85)";
            ctx.font = "700 12px 'Zen Maru Gothic', sans-serif";
            ctx.textAlign = "right";
            ctx.fillText(`${grandTotal} pts`, px + panelW - 14, cy);
            ctx.textAlign = "left";
            cy += 10;

            // Selected toys count
            ctx.fillStyle = "rgba(255,255,255,0.45)";
            ctx.font = "400 10px 'Zen Maru Gothic', sans-serif";
            ctx.fillText(alreadySelected ? `${selectedToys.length} selected` : `${selectedToys.length} selected + 1 preview`, px + 14, cy);
            cy += 18;

            // Label bars (sorted by value)
            const barMaxW = panelW - 62;
            entries.forEach(e => {
                // Bar background
                ctx.fillStyle = "rgba(255,255,255,0.08)";
                ctx.beginPath(); ctx.roundRect(px + 14, cy - 6, barMaxW, 14, 3); ctx.fill();
                // Bar fill
                const barW = (e.value / maxVal) * barMaxW;
                const barG = ctx.createLinearGradient(px + 14, 0, px + 14 + barW, 0);
                barG.addColorStop(0, "rgba(229, 142, 170, 0.65)");
                barG.addColorStop(1, "rgba(198, 128, 219, 0.65)");
                ctx.fillStyle = barG;
                ctx.beginPath(); ctx.roundRect(px + 14, cy - 6, barW, 14, 3); ctx.fill();
                // Label text
                ctx.fillStyle = "rgba(255,255,255,0.9)";
                ctx.font = "500 10px 'Zen Maru Gothic', sans-serif";
                ctx.textAlign = "left";
                ctx.fillText(labelDisplay(e.label), px + 18, cy + 1);
                // Value
                ctx.textAlign = "right";
                ctx.font = "700 11px 'Zen Maru Gothic', sans-serif";
                ctx.fillText(String(e.value), px + panelW - 14, cy + 1);
                ctx.textAlign = "left";
                cy += lineH;
            });

            ctx.restore();
        }

        // ======== Label Change Animation System ========
        const labelChangeAnimations = [];

        function spawnLabelAnimation(labels, isPositive) {
            const startTime = Date.now();
            const entries = Object.entries(labels).filter(([, v]) => v > 0);
            entries.forEach(([key, value], i) => {
                labelChangeAnimations.push({
                    label: key,
                    value: value,
                    isPositive: isPositive,
                    startTime: startTime,
                    delay: i * 200,
                    x: width * 0.5 + (Math.random() - 0.5) * 80,
                    y: height * 0.35 + i * 32,
                });
            });
        }

        function drawLabelAnimations(ctx) {
            const now = Date.now();
            for (let i = labelChangeAnimations.length - 1; i >= 0; i--) {
                const anim = labelChangeAnimations[i];
                const elapsed = now - anim.startTime - anim.delay;
                if (elapsed < 0) continue;
                const duration = 2000;
                if (elapsed > duration) {
                    labelChangeAnimations.splice(i, 1);
                    continue;
                }
                const t = elapsed / duration;
                const fadeIn = Math.min(1, t * 5);
                const fadeOut = t > 0.6 ? 1 - (t - 0.6) / 0.4 : 1;
                const alpha = fadeIn * fadeOut;
                const rise = t * 60;
                const scale = 1 + Math.sin(t * Math.PI) * 0.15;

                ctx.save();
                ctx.globalAlpha = alpha;
                const x = anim.x;
                const y = anim.y - rise;

                ctx.translate(x, y);
                ctx.scale(scale, scale);

                const sign = anim.isPositive ? "+" : "-";
                const color = anim.isPositive ? "rgba(100, 230, 140, " : "rgba(255, 100, 100, ";
                const glowColor = anim.isPositive ? "rgba(100, 230, 140, 0.4)" : "rgba(255, 100, 100, 0.4)";
                const text = `${sign}${anim.value} ${labelDisplay(anim.label)}`;

                // Glow
                ctx.shadowColor = glowColor;
                ctx.shadowBlur = 12;

                // Text
                ctx.font = "700 16px 'Zen Maru Gothic', sans-serif";
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";
                ctx.fillStyle = color + "1)";
                ctx.fillText(text, 0, 0);

                // Outline
                ctx.strokeStyle = "rgba(0,0,0,0.3)";
                ctx.lineWidth = 2;
                ctx.strokeText(text, 0, 0);

                ctx.restore();
            }
        }

        // ======== Pachinko-style FLASHY Slot Label Animation ========
        const slotLabelAnimations = [];
        const slotLabelParticles = [];
        let slotScreenShake = { intensity: 0, startTime: 0, duration: 0 };
        let slotFlashOverlay = { alpha: 0, color: "#fff", startTime: 0, duration: 0 };
        let slotRainbowBurst = { active: false, startTime: 0, duration: 0, x: 0, y: 0 };

        function spawnSlotLabelAnimation(labels, tier) {
            const startTime = Date.now();
            const entries = Object.entries(labels).filter(([, v]) => v > 0);
            const isMiss = tier === "miss";
            const isJackpot = tier === "jackpot";
            const isBig = tier === "big";

            // Screen shake
            if (!isMiss) {
                slotScreenShake.intensity = isJackpot ? 18 : isBig ? 10 : 5;
                slotScreenShake.startTime = startTime;
                slotScreenShake.duration = isJackpot ? 1200 : isBig ? 800 : 400;
            }

            // Flash overlay
            if (!isMiss) {
                slotFlashOverlay.alpha = isJackpot ? 0.8 : isBig ? 0.5 : 0.25;
                slotFlashOverlay.color = isJackpot ? "#FFD700" : isBig ? "#FF4488" : "#FFFFFF";
                slotFlashOverlay.startTime = startTime;
                slotFlashOverlay.duration = isJackpot ? 600 : 400;
            }

            // Rainbow burst for jackpot/big
            if (isJackpot || isBig) {
                slotRainbowBurst.active = true;
                slotRainbowBurst.startTime = startTime;
                slotRainbowBurst.duration = isJackpot ? 3000 : 2000;
                slotRainbowBurst.x = width / 2;
                slotRainbowBurst.y = height * 0.35;
            }

            // Explosion particles
            const particleCount = isJackpot ? 80 : isBig ? 40 : isMiss ? 0 : 15;
            const hues = isJackpot ? [0, 30, 60, 120, 200, 280, 330] : isBig ? [340, 20, 50] : [45, 60];
            for (let p = 0; p < particleCount; p++) {
                const angle = (Math.PI * 2 / particleCount) * p + (Math.random() - 0.5) * 0.5;
                const speed = (isJackpot ? 6 : 4) + Math.random() * 4;
                const hue = hues[Math.floor(Math.random() * hues.length)];
                slotLabelParticles.push({
                    x: width / 2, y: height * 0.35,
                    vx: Math.cos(angle) * speed,
                    vy: Math.sin(angle) * speed - 2,
                    size: 3 + Math.random() * (isJackpot ? 8 : 5),
                    hue: hue,
                    life: 1,
                    decay: 0.008 + Math.random() * 0.012,
                    type: Math.random() > 0.5 ? "star" : "circle",
                    sparkle: Math.random(),
                });
            }

            // Label text entries with staggered timing
            entries.forEach(([key, value], i) => {
                slotLabelAnimations.push({
                    label: key,
                    value: value,
                    tier: tier,
                    startTime: startTime,
                    delay: isMiss ? 0 : i * 350,
                    x: width / 2,
                    y: height * 0.28 + i * 50,
                    baseScale: isJackpot ? 2.5 : isBig ? 2.0 : isMiss ? 1.0 : 1.4,
                    angle: 0,
                });
            });
        }

        function drawSlotLabelAnimations(ctx) {
            const now = Date.now();

            // 1. Screen shake
            let shakeX = 0, shakeY = 0;
            if (slotScreenShake.intensity > 0) {
                const elapsed = now - slotScreenShake.startTime;
                if (elapsed < slotScreenShake.duration) {
                    const decay = 1 - elapsed / slotScreenShake.duration;
                    const intensity = slotScreenShake.intensity * decay;
                    shakeX = (Math.random() - 0.5) * intensity * 2;
                    shakeY = (Math.random() - 0.5) * intensity * 2;
                    ctx.save();
                    ctx.translate(shakeX, shakeY);
                } else {
                    slotScreenShake.intensity = 0;
                }
            }

            // 2. Flash overlay
            if (slotFlashOverlay.alpha > 0) {
                const elapsed = now - slotFlashOverlay.startTime;
                if (elapsed < slotFlashOverlay.duration) {
                    const t = elapsed / slotFlashOverlay.duration;
                    const a = slotFlashOverlay.alpha * (1 - t * t);
                    ctx.save();
                    ctx.globalAlpha = a;
                    ctx.fillStyle = slotFlashOverlay.color;
                    ctx.fillRect(-20, -20, width + 40, height + 40);
                    ctx.restore();
                } else {
                    slotFlashOverlay.alpha = 0;
                }
            }

            // 3. Rainbow burst rings
            if (slotRainbowBurst.active) {
                const elapsed = now - slotRainbowBurst.startTime;
                if (elapsed < slotRainbowBurst.duration) {
                    const t = elapsed / slotRainbowBurst.duration;
                    ctx.save();
                    const ringCount = 5;
                    for (let r = 0; r < ringCount; r++) {
                        const rt = Math.max(0, t - r * 0.08);
                        if (rt <= 0) continue;
                        const radius = rt * Math.max(width, height) * 0.6;
                        const alpha = Math.max(0, 1 - rt * 1.3) * 0.6;
                        const hue = (r * 72 + elapsed * 0.3) % 360;
                        ctx.beginPath();
                        ctx.arc(slotRainbowBurst.x, slotRainbowBurst.y, radius, 0, Math.PI * 2);
                        ctx.strokeStyle = `hsla(${hue}, 100%, 65%, ${alpha})`;
                        ctx.lineWidth = 6 - r;
                        ctx.stroke();
                    }
                    // Center starburst
                    if (t < 0.5) {
                        const burstAlpha = (1 - t * 2) * 0.7;
                        const burstSize = 40 + t * 200;
                        const rayCount = 12;
                        ctx.globalAlpha = burstAlpha;
                        for (let ray = 0; ray < rayCount; ray++) {
                            const angle = (Math.PI * 2 / rayCount) * ray + elapsed * 0.003;
                            const hue = (ray * 30 + elapsed * 0.5) % 360;
                            ctx.strokeStyle = `hsl(${hue}, 100%, 70%)`;
                            ctx.lineWidth = 3;
                            ctx.beginPath();
                            ctx.moveTo(
                                slotRainbowBurst.x + Math.cos(angle) * 10,
                                slotRainbowBurst.y + Math.sin(angle) * 10
                            );
                            ctx.lineTo(
                                slotRainbowBurst.x + Math.cos(angle) * burstSize,
                                slotRainbowBurst.y + Math.sin(angle) * burstSize
                            );
                            ctx.stroke();
                        }
                    }
                    ctx.restore();
                } else {
                    slotRainbowBurst.active = false;
                }
            }

            // 4. Explosion particles
            for (let i = slotLabelParticles.length - 1; i >= 0; i--) {
                const p = slotLabelParticles[i];
                p.x += p.vx;
                p.y += p.vy;
                p.vy += 0.08;
                p.vx *= 0.99;
                p.life -= p.decay;
                if (p.life <= 0) {
                    slotLabelParticles.splice(i, 1);
                    continue;
                }
                ctx.save();
                ctx.globalAlpha = p.life;
                const sparkle = 0.6 + Math.sin(now * 0.02 + p.sparkle * 100) * 0.4;
                ctx.fillStyle = `hsl(${p.hue}, 100%, ${55 + sparkle * 25}%)`;
                ctx.shadowColor = `hsl(${p.hue}, 100%, 70%)`;
                ctx.shadowBlur = 8;
                if (p.type === "star") {
                    // Draw star shape
                    ctx.translate(p.x, p.y);
                    ctx.rotate(now * 0.005 + p.sparkle * 10);
                    ctx.beginPath();
                    for (let s = 0; s < 5; s++) {
                        const a1 = (s * 2 * Math.PI / 5) - Math.PI / 2;
                        const a2 = a1 + Math.PI / 5;
                        ctx.lineTo(Math.cos(a1) * p.size, Math.sin(a1) * p.size);
                        ctx.lineTo(Math.cos(a2) * p.size * 0.4, Math.sin(a2) * p.size * 0.4);
                    }
                    ctx.closePath();
                    ctx.fill();
                } else {
                    ctx.beginPath();
                    ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                    ctx.fill();
                }
                ctx.restore();
            }

            // 5. Label text with dramatic entrance
            for (let i = slotLabelAnimations.length - 1; i >= 0; i--) {
                const anim = slotLabelAnimations[i];
                const elapsed = now - anim.startTime - anim.delay;
                if (elapsed < 0) continue;
                const duration = anim.tier === "jackpot" ? 3500 : anim.tier === "big" ? 2800 : anim.tier === "miss" ? 1500 : 2200;
                if (elapsed > duration) {
                    slotLabelAnimations.splice(i, 1);
                    continue;
                }
                const t = elapsed / duration;
                const isMiss = anim.tier === "miss";
                const isJackpot = anim.tier === "jackpot";
                const isBig = anim.tier === "big";

                // Dramatic entrance: slam in from large, bounce, settle
                let scale, alpha, offsetY;
                if (t < 0.08) {
                    // Slam in from 3x size
                    const st = t / 0.08;
                    scale = anim.baseScale * (3.0 - 2.0 * st);
                    alpha = st;
                    offsetY = 0;
                } else if (t < 0.15) {
                    // Bounce up
                    const st = (t - 0.08) / 0.07;
                    scale = anim.baseScale * (1.0 + 0.3 * Math.sin(st * Math.PI));
                    alpha = 1;
                    offsetY = -10 * Math.sin(st * Math.PI);
                } else if (t < 0.22) {
                    // Second smaller bounce
                    const st = (t - 0.15) / 0.07;
                    scale = anim.baseScale * (1.0 + 0.12 * Math.sin(st * Math.PI));
                    alpha = 1;
                    offsetY = -4 * Math.sin(st * Math.PI);
                } else if (t < 0.65) {
                    // Hold steady with pulsing glow
                    scale = anim.baseScale * (1.0 + Math.sin(elapsed * 0.008) * 0.06);
                    alpha = 1;
                    offsetY = 0;
                } else {
                    // Fade out and rise
                    const ft = (t - 0.65) / 0.35;
                    scale = anim.baseScale * (1.0 + ft * 0.3);
                    alpha = 1 - ft;
                    offsetY = -ft * 50;
                }

                ctx.save();
                ctx.globalAlpha = alpha;
                const x = anim.x;
                const y = anim.y + offsetY;
                ctx.translate(x, y);

                // Wobble for jackpot
                if (isJackpot && t > 0.08 && t < 0.65) {
                    ctx.rotate(Math.sin(elapsed * 0.012) * 0.05);
                }

                ctx.scale(scale, scale);

                const sign = isMiss ? "+" : "+";
                const text = `${sign}${anim.value} ${labelDisplay(anim.label)}`;

                // Color cycling for jackpot, solid for others
                let fillColor, glowColor;
                if (isJackpot) {
                    const hue = (elapsed * 0.4 + i * 60) % 360;
                    fillColor = `hsl(${hue}, 100%, 65%)`;
                    glowColor = `hsl(${hue}, 100%, 50%)`;
                } else if (isBig) {
                    fillColor = "#FF66AA";
                    glowColor = "#FF2277";
                } else if (isMiss) {
                    fillColor = "rgba(180, 180, 200, 0.8)";
                    glowColor = "rgba(100, 100, 120, 0.4)";
                } else {
                    fillColor = "#FFD700";
                    glowColor = "#FF8800";
                }

                // Multi-layer glow for emphasis
                if (!isMiss) {
                    ctx.shadowColor = glowColor;
                    ctx.shadowBlur = isJackpot ? 30 : isBig ? 20 : 12;
                }

                // Background banner for non-miss
                if (!isMiss) {
                    const metrics = (function() {
                        ctx.font = `900 ${isJackpot ? 26 : isBig ? 22 : 18}px 'Zen Maru Gothic', sans-serif`;
                        return ctx.measureText(text);
                    })();
                    const bannerW = metrics.width + 40;
                    const bannerH = isJackpot ? 46 : isBig ? 40 : 34;
                    const bannerGrad = ctx.createLinearGradient(-bannerW/2, 0, bannerW/2, 0);
                    if (isJackpot) {
                        const hue = (elapsed * 0.3) % 360;
                        bannerGrad.addColorStop(0, `hsla(${hue}, 100%, 20%, 0.85)`);
                        bannerGrad.addColorStop(0.5, `hsla(${(hue + 30) % 360}, 100%, 15%, 0.9)`);
                        bannerGrad.addColorStop(1, `hsla(${(hue + 60) % 360}, 100%, 20%, 0.85)`);
                    } else if (isBig) {
                        bannerGrad.addColorStop(0, "rgba(80, 10, 40, 0.85)");
                        bannerGrad.addColorStop(0.5, "rgba(60, 5, 30, 0.9)");
                        bannerGrad.addColorStop(1, "rgba(80, 10, 40, 0.85)");
                    } else {
                        bannerGrad.addColorStop(0, "rgba(60, 40, 0, 0.8)");
                        bannerGrad.addColorStop(1, "rgba(40, 25, 0, 0.85)");
                    }
                    ctx.fillStyle = bannerGrad;
                    ctx.beginPath();
                    ctx.roundRect(-bannerW/2, -bannerH/2, bannerW, bannerH, 8);
                    ctx.fill();

                    // Banner border with glow
                    ctx.strokeStyle = isJackpot ? `hsl(${(elapsed * 0.4) % 360}, 100%, 70%)` : isBig ? "#FF66AA" : "#FFD700";
                    ctx.lineWidth = 2;
                    ctx.beginPath();
                    ctx.roundRect(-bannerW/2, -bannerH/2, bannerW, bannerH, 8);
                    ctx.stroke();
                }

                // Main text
                const fontSize = isJackpot ? 26 : isBig ? 22 : isMiss ? 14 : 18;
                ctx.font = `900 ${fontSize}px 'Zen Maru Gothic', sans-serif`;
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";

                // Text outline
                ctx.strokeStyle = "rgba(0,0,0,0.6)";
                ctx.lineWidth = isJackpot ? 4 : 3;
                ctx.strokeText(text, 0, 0);

                // Fill text
                ctx.fillStyle = fillColor;
                ctx.fillText(text, 0, 0);

                // Extra shine highlight for jackpot
                if (isJackpot && t > 0.1 && t < 0.65) {
                    const shineX = ((elapsed * 0.15) % 300) - 150;
                    ctx.save();
                    ctx.globalAlpha = 0.4;
                    ctx.beginPath();
                    ctx.rect(shineX - 20, -20, 40, 40);
                    ctx.clip();
                    ctx.fillStyle = "rgba(255,255,255,0.8)";
                    ctx.fillText(text, 0, 0);
                    ctx.restore();
                }

                ctx.restore();
            }

            // Restore from screen shake
            if (slotScreenShake.intensity > 0 && (now - slotScreenShake.startTime) < slotScreenShake.duration) {
                ctx.restore();
            }
        }

        // Chord hover preview system — independent of groove loop
        let chordPreviewSynth = null;
        let chordPreviewDrop = null;
        let chordPreviewBarIndex = 0;

        function startChordPreview(drop) {
            stopChordPreview();
            if (!drop.chordProgression || !baseGroove || !baseRhythmInfo) return;
            // Create a dedicated preview synth
            try {
                chordPreviewSynth = new Tone.PolySynth(Tone.Synth, {
                    oscillator: { type: "triangle4" },
                    envelope: { attack: 0.04, decay: 0.5, sustain: 0.25, release: 0.6 },
                    volume: -14
                }).toDestination();
            } catch (e) { return; }
            chordPreviewDrop = drop;
            const barSteps = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
            const totalSteps = barSteps * baseRhythmInfo.bars;
            const currentStep = ((baseGroove.step % totalSteps) + totalSteps) % totalSteps;
            const currentBar = Math.floor(currentStep / barSteps) % drop.chordProgression.notes.length;
            const isBarHead = (currentStep % barSteps) === 0;

            // If hovered mid-bar, wait for the next bar head.
            chordPreviewBarIndex = isBarHead
                ? currentBar
                : ((currentBar + 1) % drop.chordProgression.notes.length);
            if (isBarHead) playChordPreviewNote();
        }

        function playChordPreviewNote() {
            if (!chordPreviewSynth || !chordPreviewDrop || !chordPreviewDrop.chordProgression) return;
            const notes = chordPreviewDrop.chordProgression.notes;
            const chord = notes[chordPreviewBarIndex % notes.length];
            try {
                chordPreviewSynth.triggerAttackRelease(chord, "2n");
                chordPreviewDrop.ripples.push({ t: 0, accent: 0.85 });
            } catch (e) { /* ignore */ }
            chordPreviewBarIndex++;
        }

        function stopChordPreview() {
            if (chordPreviewSynth) {
                try { chordPreviewSynth.dispose(); } catch (e) {}
                chordPreviewSynth = null;
            }
            chordPreviewDrop = null;
            chordPreviewBarIndex = 0;
        }

        function updateToneDropProximity() {
            if ((currentScene !== SCENE.CRAWL && currentScene !== SCENE.CRAWL2 && currentScene !== SCENE.TODDLE1 && currentScene !== SCENE.CHILD1 && currentScene !== SCENE.CHILD2 && currentScene !== SCENE.ADULT && currentScene !== SCENE.UNIVERSITY && currentScene !== SCENE.PART_TIME && currentScene !== SCENE.JOB_HUNT && currentScene !== SCENE.JOB_HUNT2 && currentScene !== SCENE.TRAVEL && currentScene !== SCENE.THIRTIES && currentScene !== SCENE.CITY) || !toneDrops.length) {
                return;
            }

            if (isMinigameActive && minigameTriggerDrop) {
                toneDrops.forEach(drop => {
                    const isTrigger = (drop === minigameTriggerDrop);
                    drop.isHovered = isTrigger;
                    const targetAlpha = isTrigger ? 1 : 0;
                    drop.overlapAlpha += (targetAlpha - drop.overlapAlpha) * 0.18;

                    if (drop.instrument === "chord") {
                        if (isTrigger && !chordPreviewDrop) {
                            startChordPreview(drop);
                        } else if (!isTrigger && chordPreviewDrop === drop) {
                            stopChordPreview();
                        }
                    }
                });
                if (currentScene === SCENE.CHILD2) {
                    hoveredSchoolActivity = minigameTriggerDrop.activityId;
                }
                return;
            }

            toneDrops.forEach(drop => {
                const dist = Math.hypot(orbWorldX - drop.x, orbWorldY - drop.y);
                const hoverR = (drop.instrument === "chord" || drop.instrument === "bass" || drop.instrument === "keyboard" || drop.instrument === "modifier" || drop.instrument === "timbre" || drop.instrument === "melody") ? 60 : 50;
                const wasHovered = drop.isHovered;
                // Keep drop hovered while confirmation dialog is open for it
                drop.isHovered = dist <= hoverR || (adultConfirmation.active && adultConfirmation.drop === drop);
                drop.proximityVol = drop.isHovered ? -12 : -100;
                const target = drop.isHovered ? 1 : 0;
                drop.overlapAlpha += (target - drop.overlapAlpha) * 0.18;

                // Chord preview: start when hover begins, stop when hover ends
                if (drop.instrument === "chord") {
                    if (drop.isHovered && !wasHovered) {
                        startChordPreview(drop);
                    } else if (!drop.isHovered && wasHovered && chordPreviewDrop === drop) {
                        stopChordPreview();
                    }
                }

                // TRAVEL: swap drum/bass patterns for page2 last 2 bars on hover
                if (currentScene === SCENE.TRAVEL && drop.travelAltKick) {
                    const stepsPerBar = baseRhythmInfo.beatsPerBar * STEPS_PER_BEAT;
                    const spp = scoreHudState.stepsPerPage || (baseRhythmInfo.beatsPerBar * baseRhythmInfo.bars * STEPS_PER_BEAT);
                    const absStart = spp + (spp - stepsPerBar * 2); // page2 offset + last-2-bars offset
                    const altLen = stepsPerBar * 2;

                    if (drop.isHovered && !wasHovered) {
                        // Save originals, apply alt patterns
                        drop._origKick = baseRhythmInfo.kickPattern ? baseRhythmInfo.kickPattern.slice(absStart, absStart + altLen) : null;
                        drop._origHat = inheritedHatPattern ? inheritedHatPattern.slice(absStart, absStart + altLen) : null;
                        drop._origSnare = inheritedSnarePattern ? inheritedSnarePattern.slice(absStart, absStart + altLen) : null;
                        drop._origBassPattern = inheritedBassPattern ? inheritedBassPattern.slice(absStart, absStart + altLen) : null;
                        drop._origBassNotes = inheritedBassNotes ? inheritedBassNotes.slice(absStart, absStart + altLen) : null;
                        drop._origBassAttacks = inheritedBassAttacks ? inheritedBassAttacks.slice(absStart, absStart + altLen) : null;
                        drop._origBassDurations = inheritedBassDurations ? inheritedBassDurations.slice(absStart, absStart + altLen) : null;

                        for (let s = 0; s < altLen; s++) {
                            const idx = absStart + s;
                            if (baseRhythmInfo.kickPattern && drop.travelAltKick) baseRhythmInfo.kickPattern[idx] = drop.travelAltKick[s];
                            if (inheritedHatPattern && drop.travelAltHat) inheritedHatPattern[idx] = drop.travelAltHat[s];
                            if (inheritedSnarePattern && drop.travelAltSnare) inheritedSnarePattern[idx] = drop.travelAltSnare[s];
                            if (inheritedBassPattern && drop.travelAltBassPattern) inheritedBassPattern[idx] = drop.travelAltBassPattern[s];
                            if (inheritedBassNotes && drop.travelAltBassNotes) inheritedBassNotes[idx] = drop.travelAltBassNotes[s];
                            if (inheritedBassAttacks && drop.travelAltBassAttacks) inheritedBassAttacks[idx] = drop.travelAltBassAttacks[s];
                            if (inheritedBassDurations && drop.travelAltBassDurations) inheritedBassDurations[idx] = drop.travelAltBassDurations[s];
                        }
                    } else if (!drop.isHovered && wasHovered) {
                        // Restore originals
                        if (drop._origKick || drop._origHat || drop._origSnare || drop._origBassPattern) {
                            for (let s = 0; s < altLen; s++) {
                                const idx = absStart + s;
                                if (baseRhythmInfo.kickPattern && drop._origKick) baseRhythmInfo.kickPattern[idx] = drop._origKick[s];
                                if (inheritedHatPattern && drop._origHat) inheritedHatPattern[idx] = drop._origHat[s];
                                if (inheritedSnarePattern && drop._origSnare) inheritedSnarePattern[idx] = drop._origSnare[s];
                                if (inheritedBassPattern && drop._origBassPattern) inheritedBassPattern[idx] = drop._origBassPattern[s];
                                if (inheritedBassNotes && drop._origBassNotes) inheritedBassNotes[idx] = drop._origBassNotes[s];
                                if (inheritedBassAttacks && drop._origBassAttacks) inheritedBassAttacks[idx] = drop._origBassAttacks[s];
                                if (inheritedBassDurations && drop._origBassDurations) inheritedBassDurations[idx] = drop._origBassDurations[s];
                            }
                            drop._origKick = null;
                            drop._origHat = null;
                            drop._origSnare = null;
                            drop._origBassPattern = null;
                            drop._origBassNotes = null;
                            drop._origBassAttacks = null;
                            drop._origBassDurations = null;
                        }
                    }
                }
            });
            // Track hovered bass activity for school background glow
            if (currentScene === SCENE.CHILD2) {
                const hov = toneDrops.find(d => d.instrument === "bass" && d.isHovered);
                hoveredSchoolActivity = hov ? hov.activityId : null;
            }
            // THIRTIES: melody preview on hover
            if (currentScene === SCENE.THIRTIES && !thirtiesMelodyConfirmed) {
                const hov = toneDrops.find(d => d.instrument === "melody" && d.isHovered);
                const newRoom = hov ? hov.activityId : null;

                if (newRoom !== thirtiesHoveredRoom) {
                    if (thirtiesHoveredRoom && !newRoom) {
                        restoreOriginalMelody();
                    }
                    if (newRoom && thirtiesRoomMelodies && thirtiesRoomMelodies[newRoom]) {
                        previewRoomMelody(newRoom);
                    }
                    thirtiesHoveredRoom = newRoom;
                    renderScoreRows();
                }
            }
        }

        function buildHiHatPattern(baseInfo, variant) {
            const totalBeats = baseInfo.beatsPerBar * baseInfo.bars;
            const pattern = new Array(totalBeats * STEPS_PER_BEAT).fill(false);
            const put = (beatIndex, mode = 'on') => {
                if (beatIndex < 0 || beatIndex >= totalBeats) return;
                const base = beatIndex * STEPS_PER_BEAT;
                const set = (offset) => {
                    const idx = base + offset;
                    if (idx >= 0 && idx < pattern.length) pattern[idx] = true;
                };
                if (mode === 'on') set(0);           // 表
                else if (mode === 'off') set(2);     // 裏
                else if (mode === 'push') set(1);    // 前ノリ
                else if (mode === 'late') set(3);    // 後ノリ
                else if (mode === 'double') { set(0); set(2); }
                else if (mode === 'split') { set(1); set(3); }
                else set(0);
            };

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * baseInfo.beatsPerBar;

                // 4 clearly separated archetypes with multiple A-style placements.
                if (variant === 0) {
                    // Anchor: clear pulse, occasional offbeat decoration.
                    put(b, 'on');
                    if (baseInfo.beatsPerBar >= 3) put(b + 2, bar % 2 === 0 ? 'on' : 'off');
                    if (baseInfo.beatsPerBar >= 4 && bar % 2 === 1) put(b + 3, 'off');
                    continue;
                }

                if (variant === 1) {
                    // Backbeat: beat 2/4 core with push/late alternatives.
                    if (baseInfo.beatsPerBar >= 2) put(b + 1, bar % 2 === 0 ? 'on' : 'push');
                    if (baseInfo.beatsPerBar >= 4) put(b + 3, bar % 2 === 0 ? 'on' : 'late');
                    else if (baseInfo.beatsPerBar === 3) put(b + 2, 'off');
                    continue;
                }

                if (variant === 2) {
                    // Dense: line-up with mixed A variants.
                    for (let i = 0; i < baseInfo.beatsPerBar; i++) {
                        const mode = (i + bar) % 3 === 0 ? 'double' : ((i + bar) % 2 === 0 ? 'off' : 'on');
                        put(b + i, mode);
                    }
                    if (baseInfo.beatsPerBar >= 4) put(b + 1, 'push');
                    continue;
                }

                // v3: syncopated-phrase with late accents.
                for (let i = 0; i < baseInfo.beatsPerBar; i++) {
                    if ((i + bar) % 2 === 0) put(b + i, 'split');
                }
                put(b + baseInfo.beatsPerBar - 1, 'late');
                if (baseInfo.beatsPerBar >= 4) put(b + 1, bar % 2 === 0 ? 'off' : 'push');
            }

            return pattern;
        }

        function createSpacedDropXs(count, minGap, minX, maxX) {
            for (let attempt = 0; attempt < 120; attempt++) {
                const xs = [];
                for (let i = 0; i < count; i++) xs.push(randInt(minX, maxX));
                xs.sort((a, b) => a - b);
                let ok = true;
                for (let i = 1; i < xs.length; i++) {
                    if (xs[i] - xs[i - 1] < minGap) {
                        ok = false;
                        break;
                    }
                }
                if (ok) return xs;
            }
            const span = maxX - minX;
            const step = Math.max(minGap, Math.floor(span / Math.max(1, count - 1)));
            const xs = [];
            for (let i = 0; i < count; i++) xs.push(minX + i * step);
            return xs;
        }

        function primeToneDrops() {
            toneDrops.forEach(drop => {
                drop.isFilled = true;
                drop.fillLevel = 1;
                drop.jellyPulse = 0;
                drop.jellyDrain = false;
                drop.fillOriginX = 0;
                drop.fillOriginY = 0;
            });
        }

        function disposeToneDrops() {
            stopChordPreview();
            toneDrops.forEach(d => {
                if (d.hatClosedSynth) d.hatClosedSynth.dispose();
                if (d.hatOpenSynth) d.hatOpenSynth.dispose();
                if (d.hatFilter) d.hatFilter.dispose();
                if (d.snareSynth) d.snareSynth.dispose();
                if (d.snareFilter) d.snareFilter.dispose();
                if (d.snareBody) d.snareBody.dispose();
                if (d.cymbalSynth) d.cymbalSynth.dispose();
                if (d.chordSynth) d.chordSynth.dispose();
                if (d.bassSynth) d.bassSynth.dispose();
                if (d.guitarSynth) d.guitarSynth.dispose();
                if (d.guitarEffects) d.guitarEffects.forEach(e => e.dispose());
                if (d.keyboardSynth) d.keyboardSynth.dispose();
                if (d.keyboardEffects) d.keyboardEffects.forEach(e => e.dispose());
                if (d.keys2Synth) d.keys2Synth.dispose();
                if (d.keys2Effects) d.keys2Effects.forEach(e => e.dispose());
            });
        }

        function disposeCarryHatLayer() {
            if (carryHatSynth) {
                carryHatSynth.dispose();
                carryHatSynth = null;
            }
            if (carryHatFilter) {
                carryHatFilter.dispose();
                carryHatFilter = null;
            }
        }

        function initCarryHatLayer() {
            disposeCarryHatLayer();
            const pattern = inheritedHatPattern || (baseRhythmInfo ? baseRhythmInfo.baseHatPattern : null);
            if (!pattern) return;
            const cfg = inheritedHatSoundConfig || { noise: "white", hp: 7600, q: 0.55, decay: 0.05, release: 0.016 };
            carryHatFilter = new Tone.Filter({
                type: "highpass",
                frequency: cfg.hp,
                Q: cfg.q
            }).toDestination();
            carryHatSynth = new Tone.NoiseSynth({
                noise: { type: cfg.noise },
                envelope: { attack: 0.001, decay: cfg.decay, sustain: 0, release: cfg.release },
                volume: inheritedHatVolumeDb
            }).connect(carryHatFilter);
        }

        function disposeCarrySnareLayer() {
            if (carrySnareSynth) {
                carrySnareSynth.dispose();
                carrySnareSynth = null;
            }
            if (carrySnareFilter) {
                carrySnareFilter.dispose();
                carrySnareFilter = null;
            }
            if (carrySnareBody) {
                carrySnareBody.dispose();
                carrySnareBody = null;
            }
        }

        function initCarrySnareLayer() {
            disposeCarrySnareLayer();
            if (!inheritedSnarePattern) return;
            const cfg = inheritedSnareSoundConfig || { noise: "white", bp: 1800, q: 0.7, decay: 0.12, release: 0.08, body: true };
            carrySnareFilter = new Tone.Filter({
                type: "bandpass",
                frequency: cfg.bp,
                Q: cfg.q
            }).toDestination();
            carrySnareSynth = new Tone.NoiseSynth({
                noise: { type: cfg.noise },
                envelope: { attack: 0.001, decay: cfg.decay, sustain: 0, release: cfg.release },
                volume: inheritedSnareVolumeDb
            }).connect(carrySnareFilter);
            carrySnareBody = cfg.body ? new Tone.MembraneSynth({
                pitchDecay: 0.025,
                octaves: 2.5,
                oscillator: { type: "triangle" },
                envelope: { attack: 0.001, decay: 0.1, sustain: 0, release: 0.06 },
                volume: inheritedSnareBodyVolumeDb
            }).toDestination() : null;
        }

        function disposeCarryCymbalLayer() {
            if (carryCymbalSynth) {
                carryCymbalSynth.dispose();
                carryCymbalSynth = null;
            }
        }

        function initCarryCymbalLayer() {
            disposeCarryCymbalLayer();
            if (!inheritedCymbalPattern) return;
            const cfg = inheritedCymbalSoundConfig || { freq: 280, harmonicity: 5.1, modulationIndex: 30, resonance: 4000, decay: 0.8 };
            carryCymbalSynth = new Tone.MetalSynth({
                frequency: cfg.freq,
                harmonicity: cfg.harmonicity,
                modulationIndex: cfg.modulationIndex,
                resonance: cfg.resonance,
                envelope: { attack: 0.001, decay: cfg.decay, release: 0.05 },
                volume: inheritedCymbalVolumeDb
            }).toDestination();
        }

        function disposeCarryChordLayer() {
            if (carryChordSynth) {
                carryChordSynth.dispose();
                carryChordSynth = null;
            }
            carryChordPattern = null;
        }

        function initCarryChordLayer() {
            disposeCarryChordLayer();
            if (!inheritedChordProgression || !baseRhythmInfo) return;
            const chosenFac = CHILD_FACILITIES.find(f => f.id === childLifeChoice);
            const oscType = chosenFac ? chosenFac.oscType : "triangle4";
            carryChordSynth = new Tone.PolySynth(Tone.Synth, {
                oscillator: { type: oscType },
                envelope: { attack: 0.05, decay: 0.6, sustain: 0.3, release: 0.8 },
                volume: -14
            }).toDestination();
            // Store chord notes for playback in tick
            carryChordPattern = inheritedChordProgression.notes;
        }

        let carryBassSynth = null;
        let carryBassFilter = null;
        const inheritedBassVolumeDb = -16;

        function disposeCarryBassLayer() {
            if (carryBassSynth) { carryBassSynth.dispose(); carryBassSynth = null; }
            if (carryBassFilter) { carryBassFilter.dispose(); carryBassFilter = null; }
        }

        function initCarryBassLayer() {
            disposeCarryBassLayer();
            if (!inheritedBassPattern || !inheritedBassNotes) return;
            const BASS_TIMBRES = {
                energetic:     { osc: "sawtooth", attack: 0.01, decay: 0.15, sustain: 0.35, release: 0.25, filterBase: 150, filterOct: 3 },
                soft:          { osc: "sine",     attack: 0.06, decay: 0.5,  sustain: 0.5,  release: 0.8,  filterBase: 80,  filterOct: 1.5 },
                quirky:        { osc: "square",   attack: 0.01, decay: 0.2,  sustain: 0.25, release: 0.3,  filterBase: 120, filterOct: 2.8 },
                contemplative: { osc: "sine",     attack: 0.08, decay: 0.6,  sustain: 0.6,  release: 1.2,  filterBase: 60,  filterOct: 1.2 },
                groovy:        { osc: "triangle", attack: 0.01, decay: 0.2,  sustain: 0.3,  release: 0.3,  filterBase: 130, filterOct: 2.5 },
                playful:       { osc: "triangle", attack: 0.01, decay: 0.12, sustain: 0.2,  release: 0.2,  filterBase: 160, filterOct: 3.2 },
                melodic:       { osc: "sine",     attack: 0.03, decay: 0.35, sustain: 0.45, release: 0.6,  filterBase: 100, filterOct: 2 }
            };
            const timbre = BASS_TIMBRES[inheritedBassSoundConfig] || BASS_TIMBRES.soft;
            carryBassSynth = new Tone.MonoSynth({
                oscillator: { type: timbre.osc },
                envelope: { attack: timbre.attack, decay: timbre.decay, sustain: timbre.sustain, release: timbre.release },
                filterEnvelope: {
                    attack: timbre.attack * 0.5, decay: timbre.decay, sustain: timbre.sustain, release: timbre.release,
                    baseFrequency: timbre.filterBase, octaves: timbre.filterOct
                },
                volume: inheritedBassVolumeDb
            }).toDestination();
        }

        function initChordDrops() {
            disposeToneDrops();
            toneDrops = [];
            childFacilityLayouts = [];
            if (!baseRhythmInfo) return;

            // Select 4 facilities based on player's life labels
            childFacilities = selectChildFacilities();

            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            const groundY = height * ROOM_WALL_RATIO;
            const count = 4;
            const startX = worldWidth * 0.06;
            const endX = worldWidth * 0.94;
            const totalSpan = endX - startX;

            // Calculate weighted widths for each facility
            const baseSlotW = totalSpan / count;
            const rawWidths = childFacilities.slice(0, count).map(f => baseSlotW * (f.sizeW || 1));
            const totalRawW = rawWidths.reduce((a, b) => a + b, 0);
            // Normalize so total fits in totalSpan
            const slotWidths = rawWidths.map(w => w * totalSpan / totalRawW);

            // Compute center positions with jitter
            const positions = [];
            let cursor = startX;
            for (let i = 0; i < count; i++) {
                const slotW = slotWidths[i];
                const jitter = (Math.random() - 0.5) * slotW * 0.12;
                const cx = cursor + slotW * 0.5 + jitter;
                positions.push(cx);
                // Building size from facility properties
                const bW = Math.min(slotW * 0.72, 220) * (childFacilities[i].sizeW || 1);
                const bH = groundY * (childFacilities[i].sizeH || 0.50);
                childFacilityLayouts.push({ cx, bW, bH });
                cursor += slotW;
            }

            for (let i = 0; i < count; i++) {
                const fac = childFacilities[i];
                const mode = fac.chordMode === "minor" ? "home" : "kindergarten";
                const prog = generateChordProgression(mode);
                const bundle = buildChordPattern(baseRhythmInfo);
                const chordSynth = new Tone.PolySynth(Tone.Synth, {
                    oscillator: { type: fac.oscType },
                    envelope: { attack: 0.05, decay: 0.6, sustain: 0.3, release: 0.8 },
                    volume: -100
                }).toDestination();
                toneDrops.push({
                    x: positions[i],
                    y: floorY + (i % 2 === 0 ? -8 : 8),
                    pattern: bundle.pattern,
                    velocityPattern: bundle.velocity,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "chord",
                    chordSynth,
                    chordProgression: prog,
                    chordSide: fac.id,
                    facilityName: fac.name,
                    dropColor: fac.color,
                    activityId: fac.id,
                    activityName: fac.name,
                    activityNameEn: fac.nameEn || "",
                    activityLabels: fac.affinity || {},
                    ripples: []
                });
            }
            primeToneDrops();
        }

        // Build bass note sequence from chord progression root notes
        // Most notes are 1 step; some styles sprinkle in 2-step or 4-step sustained notes.
        // Returns { pattern, notes, attacks, durations, sustainType }
        //   sustainType[i]: 'single' | 'start' | 'mid' | 'end' | null (for HUD visuals)
        function buildBassLine(baseInfo, style, chordProg, variant = 0) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const barSteps = baseInfo.beatsPerBar * STEPS_PER_BEAT;

            const rootNotes = chordProg.notes.map(triad => triad[0].replace(/\d+$/, '') + '2');
            const fifthNotes = chordProg.notes.map(triad => triad[2].replace(/\d+$/, '') + '2');
            const thirdNotes = chordProg.notes.map(triad => triad[1].replace(/\d+$/, '') + '2');

            const events = []; // { step, note, len }
            const add = (si, note, len) => {
                if (si >= 0 && si < totalSteps && note) {
                    events.push({ step: si, note, len: Math.min(len, totalSteps - si) });
                }
            };
            const S = STEPS_PER_BEAT; // 4

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * barSteps;
                const root = rootNotes[bar % rootNotes.length];
                const fifth = fifthNotes[bar % fifthNotes.length];
                const third = thirdNotes[bar % thirdNotes.length];
                const nextRoot = rootNotes[(bar + 1) % rootNotes.length];

                if (style === "energetic") {
                    if (variant === 0) {
                        // Driving syncopation with end-of-bar push (sports_field cool groove)
                        add(b, root, 1);
                        add(b + 2, fifth, 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 1, root, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, fifth, 1);
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S + 1, third, 1);
                            add(b + 3 * S + 3, nextRoot, 1);
                        }
                    } else {
                        // Four-on-the-floor backbone plus offbeat stab
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                            const isLong = (beat === 0 && bar % 2 === 0);
                            add(b + beat * S, beat % 2 === 0 ? root : fifth, isLong ? 2 : 1);
                            add(b + beat * S + 2, beat % 2 === 0 ? fifth : root, 1);
                        }
                    }
                } else if (style === "soft") {
                    if (variant === 0) {
                        // Long, settled tones with minimal motion
                        add(b, root, 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, fifth, 1);
                    } else {
                        // Calm pulse with a gentle pickup
                        add(b, root, 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 2, third, 1);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, root, 2);
                    }
                } else if (style === "quirky") {
                    if (variant === 0) {
                        // Offbeat-heavy with one 2-step wobble
                        add(b + 2, root, 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 1, fifth, 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 3, root, 1);
                        if (baseInfo.beatsPerBar >= 4 && bar % 2 === 1) add(b + 3 * S, third, 1);
                    } else {
                        // Crooked accents and displaced downbeat
                        add(b + 1, third, 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 3, root, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 1, fifth, 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + (bar % 2 === 0 ? 0 : 2), root, 1);
                    }
                } else if (style === "contemplative") {
                    if (variant === 0) {
                        // Spacious sustained notes
                        add(b, root, 4);
                        if (bar % 2 === 1 && baseInfo.beatsPerBar >= 3) add(b + 2 * S, fifth, 1);
                    } else {
                        // Even more minimal, late-bar breath
                        add(b, root, 5);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 1, third, 1);
                    }
                } else if (style === "groovy") {
                    if (variant === 0) {
                        // Pocket groove: downbeat anchor + offbeat pops
                        add(b, root, 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 2, root, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, fifth, 1);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 2, third, 1);
                    } else {
                        // Talkative syncopation, still danceable
                        add(b, root, 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 1, fifth, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 2, root, 1);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 3, nextRoot, 1);
                    }
                } else if (style === "playful") {
                    if (variant === 0) {
                        // Bouncy alternating pulse with a 16th fill
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                            add(b + beat * S, beat % 2 === 0 ? root : fifth, 1);
                        }
                        if (baseInfo.beatsPerBar >= 2) {
                            const lb = b + (baseInfo.beatsPerBar - 1) * S;
                            for (let s = 0; s < S; s++) add(lb + s, s % 2 === 0 ? root : fifth, 1);
                        }
                    } else {
                        // Playful call-and-response stabs
                        add(b, root, 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 2, third, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 1, fifth, 1);
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S, root, 1);
                            add(b + 3 * S + 2, fifth, 1);
                        }
                    }
                } else if (style === "melodic") {
                    if (variant === 0) {
                        // Walking contour
                        const walk = [root, third, fifth, nextRoot];
                        for (let beat = 0; beat < Math.min(baseInfo.beatsPerBar, 4); beat++) {
                            const isLong = (beat === 0);
                            add(b + beat * S, walk[beat % walk.length], isLong ? 2 : 1);
                        }
                    } else {
                        // Arpeggio-like rise with soft resolution
                        add(b, root, 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S, third, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, fifth, 1);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 1, nextRoot, 2);
                    }
                }
            }

            // Convert events into arrays
            const pattern = new Array(totalSteps).fill(false);
            const notes = new Array(totalSteps).fill(null);
            const attacks = new Array(totalSteps).fill(false);
            const durations = new Array(totalSteps).fill(null);
            const sustainType = new Array(totalSteps).fill(null); // for HUD visuals

            const stepToDur = (len) => {
                if (len <= 1) return "16n";
                if (len <= 2) return "8n";
                if (len <= 3) return "8n.";
                if (len <= 4) return "4n";
                if (len <= 6) return "4n.";
                if (len <= 8) return "2n";
                return "1n";
            };

            // Prevent note overlap: clip durations so no note extends past the next note's start
            events.sort((a, b) => a.step - b.step);
            for (let i = 0; i < events.length - 1; i++) {
                const endStep = events[i].step + events[i].len;
                if (endStep > events[i + 1].step) {
                    events[i].len = events[i + 1].step - events[i].step;
                    if (events[i].len < 1) events[i].len = 1;
                }
            }

            events.forEach(ev => {
                attacks[ev.step] = true;
                notes[ev.step] = ev.note;
                durations[ev.step] = stepToDur(ev.len);
                for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                    pattern[s] = true;
                    if (!notes[s]) notes[s] = ev.note;
                }
                // Mark sustain type for visual display
                if (ev.len === 1) {
                    sustainType[ev.step] = 'single';
                } else {
                    for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                        if (s === ev.step) sustainType[s] = 'start';
                        else if (s === ev.step + ev.len - 1) sustainType[s] = 'end';
                        else sustainType[s] = 'mid';
                    }
                }
            });

            return { pattern, notes, attacks, durations, sustainType };
        }

        // Guitar timbres — all PolySynth (chords) only (no PluckSynth/Reverb/Chorus — AudioWorklet breaks on file://)
        const GUITAR_TIMBRES = {
            "fingerpicking": { type: "poly",  wave: "triangle", attack: 0.003, decay: 0.5,  sustain: 0.08, release: 0.4 },
            "cutting":       { type: "poly",  wave: "square",   attack: 0.001, decay: 0.08, sustain: 0.0,  release: 0.05, filterFreq: 2000, filterType: "bandpass" },
            "clean-electric":{ type: "poly",  wave: "triangle", attack: 0.01,  decay: 0.6,  sustain: 0.4,  release: 0.8, vibratoFreq: 1.5, vibratoDepth: 0.08 },
            "acoustic-arpeggio": { type: "poly", wave: "triangle", attack: 0.002, decay: 0.4, sustain: 0.1, release: 0.35 },
            "rock":          { type: "polyDist", wave: "sawtooth", attack: 0.003, decay: 0.2, sustain: 0.35, release: 0.3, distortion: 0.5 }
        };

        function buildGuitarLine(baseInfo, style, chordProg, variant) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const barSteps = baseInfo.beatsPerBar * STEPS_PER_BEAT;
            const S = STEPS_PER_BEAT; // 4

            // Extract chord tones — all chords in octave 4 (clearly audible guitar range)
            const chordRoots = chordProg.notes.map(triad => triad[0].replace(/\d+$/, ''));
            const chordThirds = chordProg.notes.map(triad => triad[1].replace(/\d+$/, ''));
            const chordFifths = chordProg.notes.map(triad => triad[2].replace(/\d+$/, ''));

            const events = []; // { step, note, len }  note is always an array (chord)
            const add = (si, note, len) => {
                if (si >= 0 && si < totalSteps && note) {
                    events.push({ step: si, note, len: Math.min(len, totalSteps - si) });
                }
            };

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * barSteps;
                const R = chordRoots[bar % chordRoots.length];
                const T = chordThirds[bar % chordThirds.length];
                const F = chordFifths[bar % chordFifths.length];
                // Full triad chord in octave 4
                const chord4 = [R + "4", T + "4", F + "4"];
                // Wider voicing: root3 + third4 + fifth4
                const chordWide = [R + "3", T + "4", F + "4"];

                if (style === "fingerpicking") {
                    // Gentle arpeggiated chords — strum-like with slight spread
                    // Beat 1: full chord, Beat 3: root+fifth, occasional fills
                    if (variant === 0) {
                        add(b, chord4, 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [R + "4", F + "4"], 3);
                        if (baseInfo.beatsPerBar >= 4 && Math.random() > 0.3) {
                            add(b + 3 * S, [T + "4", F + "4"], 2);
                        }
                    } else {
                        // Every other beat gets a chord
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat += 2) {
                            add(b + beat * S, beat === 0 ? chord4 : [R + "4", F + "4"], 3);
                        }
                        if (baseInfo.beatsPerBar >= 4 && Math.random() > 0.4) {
                            add(b + 3 * S + 2, [T + "4", F + "4", R + "5"], 1);
                        }
                    }

                } else if (style === "cutting") {
                    // カッティング — staccato chord stabs on offbeats, funky rhythm
                    const offbeats = variant === 0 ? [2, 6, 10, 14] : [2, 6, 10];
                    for (const step of offbeats) {
                        if (step < barSteps) {
                            add(b + step, chord4, 1); // very short stab
                        }
                    }
                    // Accent hit on beat 1 every other bar
                    if (bar % 2 === 0) {
                        add(b, chord4, 1);
                    }
                    // Variant: extra syncopated ghost stab
                    if (variant === 1 && baseInfo.beatsPerBar >= 3 && Math.random() > 0.3) {
                        add(b + 2 * S + 3, [R + "4", F + "4"], 1);
                    }

                } else if (style === "clean-electric") {
                    // しっとり — sustained smooth chord, held across the bar
                    if (variant === 0) {
                        add(b, chordWide, barSteps);  // hold full bar
                    } else {
                        add(b, chordWide, Math.floor(barSteps * 0.6));
                        if (baseInfo.beatsPerBar >= 3) {
                            // Re-strum on beat 3
                            add(b + 2 * S, chord4, Math.floor(barSteps * 0.4));
                        }
                    }

                } else if (style === "acoustic-arpeggio") {
                    // Flowing chord arpeggios — chord hit then broken chord fills
                    if (variant === 0) {
                        add(b, chord4, 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S, [T + "4", F + "4"], 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [R + "4", F + "4", R + "5"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, chordWide, 2);
                    } else {
                        // 8th-note chord rhythm
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                            const ch = beat % 2 === 0 ? chord4 : [R + "4", F + "4"];
                            add(b + beat * S, ch, 2);
                            if (Math.random() > 0.4) {
                                add(b + beat * S + 2, [T + "4", F + "4"], 2);
                            }
                        }
                    }

                } else if (style === "rock") {
                    // パワーコード — driving power chords (root+5th+octave)
                    const power = [R + "4", F + "4", R + "5"];
                    if (variant === 0) {
                        add(b, power, 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, power, 3);
                        if (baseInfo.beatsPerBar >= 4 && Math.random() > 0.4) {
                            add(b + 3 * S + 2, [R + "4", F + "4"], 1);
                            add(b + 3 * S + 3, power, 1);
                        }
                    } else {
                        // Heavy 8th note chug
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                            add(b + beat * S, power, 2);
                            if (Math.random() > 0.25) {
                                add(b + beat * S + 2, [R + "4", F + "4"], 2);
                            }
                        }
                    }
                }
            }

            // Convert events into arrays
            const pattern = new Array(totalSteps).fill(false);
            const notes = new Array(totalSteps).fill(null);
            const attacks = new Array(totalSteps).fill(false);
            const durations = new Array(totalSteps).fill(null);
            const sustainType = new Array(totalSteps).fill(null);

            const stepToDur = (len) => {
                if (len <= 1) return "16n";
                if (len <= 2) return "8n";
                if (len <= 3) return "8n.";
                if (len <= 4) return "4n";
                if (len <= 6) return "4n.";
                if (len <= 8) return "2n";
                return "1n";
            };

            // Prevent note overlap: clip durations so no note extends past the next note's start
            events.sort((a, b) => a.step - b.step);
            for (let i = 0; i < events.length - 1; i++) {
                const endStep = events[i].step + events[i].len;
                if (endStep > events[i + 1].step) {
                    events[i].len = events[i + 1].step - events[i].step;
                    if (events[i].len < 1) events[i].len = 1;
                }
            }

            events.forEach(ev => {
                attacks[ev.step] = true;
                notes[ev.step] = ev.note;
                durations[ev.step] = stepToDur(ev.len);
                for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                    pattern[s] = true;
                    if (!notes[s]) notes[s] = ev.note;
                }
                if (ev.len === 1) {
                    sustainType[ev.step] = 'single';
                } else {
                    for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                        if (s === ev.step) sustainType[s] = 'start';
                        else if (s === ev.step + ev.len - 1) sustainType[s] = 'end';
                        else sustainType[s] = 'mid';
                    }
                }
            });

            return { pattern, notes, attacks, durations, sustainType };
        }

        function createGuitarSynth(style) {
            const cfg = GUITAR_TIMBRES[style];
            if (!cfg) return { synth: null, effects: [] };

            const effects = [];
            let synth;

            if (cfg.type === "poly") {
                synth = new Tone.PolySynth(Tone.Synth, {
                    oscillator: { type: cfg.wave },
                    envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
                });
                synth.volume.value = -100;
                if (cfg.filterType) {
                    const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                    effects.push(filter);
                    synth.chain(filter, Tone.Destination);
                } else if (cfg.vibratoFreq) {
                    const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                    effects.push(vibrato);
                    synth.chain(vibrato, Tone.Destination);
                } else {
                    synth.toDestination();
                }

            } else if (cfg.type === "polyDist") {
                synth = new Tone.PolySynth(Tone.Synth, {
                    oscillator: { type: cfg.wave },
                    envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
                });
                synth.volume.value = -100;
                const dist = new Tone.Distortion(cfg.distortion);
                effects.push(dist);
                synth.chain(dist, Tone.Destination);
            }

            return { synth, effects };
        }

        // Keyboard timbres for ADULT phase — all PolySynth (no AudioWorklet issues)
        const KEYBOARD_TIMBRES = {
            "piano-gentle":   { wave: "sine",     attack: 0.005, decay: 0.8,  sustain: 0.1,  release: 0.6 },
            "organ-funky":    { wave: "square",   attack: 0.001, decay: 0.1,  sustain: 0.0,  release: 0.05, filterType: "bandpass", filterFreq: 1800 },
            "piano-chord":    { wave: "triangle", attack: 0.01,  decay: 1.0,  sustain: 0.35, release: 1.0,  vibratoFreq: 1.5, vibratoDepth: 0.06 },
            "piano-arpeggio": { wave: "sine",     attack: 0.003, decay: 0.25, sustain: 0.0,  release: 0.2 },
            "organ-power":    { wave: "sawtooth", attack: 0.005, decay: 0.3,  sustain: 0.5,  release: 0.4 },
            "pachinko-bells": { wave: "square",   attack: 0.001, decay: 0.12, sustain: 0.0,  release: 0.08, filterType: "bandpass", filterFreq: 2400 },
            "piano-sparse":   { wave: "triangle", attack: 0.02,  decay: 1.2,  sustain: 0.08, release: 0.8 },
            "syncopated":     { wave: "sine",     attack: 0.008, decay: 0.35, sustain: 0.15, release: 0.3 },
            "staccato-bounce":{ wave: "triangle", attack: 0.003, decay: 0.2,  sustain: 0.0,  release: 0.15 }
        };

        // University-specific timbres: diverse beyond keyboard (xylophone, flute, bells, etc.)
        const UNIVERSITY_TIMBRES = {
            "xylophone":      { wave: "sine",     attack: 0.001, decay: 0.25, sustain: 0.0,  release: 0.15, filterType: "highpass", filterFreq: 800 },
            "flute":          { wave: "sine",     attack: 0.04,  decay: 0.3,  sustain: 0.6,  release: 0.5,  vibratoFreq: 4.5, vibratoDepth: 0.04 },
            "bells":          { wave: "sine",     attack: 0.001, decay: 1.2,  sustain: 0.0,  release: 1.0 },
            "marimba":        { wave: "triangle", attack: 0.001, decay: 0.4,  sustain: 0.0,  release: 0.2 },
            "music-box":      { wave: "sine",     attack: 0.001, decay: 0.6,  sustain: 0.0,  release: 0.4, filterType: "lowpass", filterFreq: 3500 },
            "kalimba":        { wave: "triangle", attack: 0.001, decay: 0.5,  sustain: 0.02, release: 0.3, filterType: "bandpass", filterFreq: 1200 },
            "reed-organ":     { wave: "sawtooth", attack: 0.02,  decay: 0.2,  sustain: 0.55, release: 0.3, filterType: "lowpass", filterFreq: 1400 },
            "glass-pad":      { wave: "sine",     attack: 0.08,  decay: 0.5,  sustain: 0.4,  release: 0.8,  vibratoFreq: 2.0, vibratoDepth: 0.08 },
            "pluck-synth":    { wave: "triangle", attack: 0.001, decay: 0.18, sustain: 0.0,  release: 0.12, filterType: "lowpass", filterFreq: 2200 },
            "warm-strings":   { wave: "sawtooth", attack: 0.06,  decay: 0.4,  sustain: 0.5,  release: 0.6, filterType: "lowpass", filterFreq: 1000, vibratoFreq: 3.0, vibratoDepth: 0.05 },
            "steel-drum":     { wave: "sine",     attack: 0.001, decay: 0.35, sustain: 0.0,  release: 0.2, filterType: "bandpass", filterFreq: 2000 },
            "celesta":        { wave: "sine",     attack: 0.001, decay: 0.8,  sustain: 0.0,  release: 0.5, filterType: "lowpass", filterFreq: 4000 },
            "whistle":        { wave: "sine",     attack: 0.03,  decay: 0.15, sustain: 0.7,  release: 0.3,  vibratoFreq: 5.0, vibratoDepth: 0.03 },
            "choir-pad":      { wave: "triangle", attack: 0.1,   decay: 0.3,  sustain: 0.6,  release: 0.8,  vibratoFreq: 2.5, vibratoDepth: 0.06 },
            "harpsichord":    { wave: "sawtooth", attack: 0.001, decay: 0.15, sustain: 0.0,  release: 0.08, filterType: "lowpass", filterFreq: 2500 }
        };

        // 3 timbre sets per university facility (for variety)
        const UNIVERSITY_FACILITY_TIMBRES = {
            "gate":     ["bells",        "flute",       "music-box"],
            "field":    ["xylophone",    "steel-drum",  "whistle"],
            "building": ["piano-gentle", "reed-organ",  "harpsichord"],
            "gym":      ["marimba",      "pluck-synth", "kalimba"],
            "art_hall": ["glass-pad",    "celesta",     "choir-pad"]
        };

        // Pattern style mappings for university timbres
        const UNIVERSITY_PATTERN_STYLES = {
            "bells":        "piano-gentle",
            "flute":        "piano-chord",
            "music-box":    "piano-arpeggio",
            "xylophone":    "organ-funky",
            "steel-drum":   "organ-funky",
            "whistle":      "piano-chord",
            "piano-gentle": "piano-gentle",
            "reed-organ":   "syncopated",
            "harpsichord":  "staccato-bounce",
            "marimba":      "organ-funky",
            "pluck-synth":  "piano-arpeggio",
            "kalimba":      "piano-arpeggio",
            "glass-pad":    "melodic-run",
            "celesta":      "staccato-bounce",
            "choir-pad":    "syncopated"
        };

        function createUniversitySynth(timbreName) {
            const cfg = UNIVERSITY_TIMBRES[timbreName] || KEYBOARD_TIMBRES[timbreName];
            if (!cfg) return { synth: null, effects: [] };
            const effects = [];
            const synth = new Tone.PolySynth(Tone.Synth, {
                oscillator: { type: cfg.wave },
                envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
            });
            synth.volume.value = -100;
            if (cfg.filterType && cfg.vibratoFreq) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                effects.push(filter, vibrato);
                synth.chain(filter, vibrato, Tone.Destination);
            } else if (cfg.filterType) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                effects.push(filter);
                synth.chain(filter, Tone.Destination);
            } else if (cfg.vibratoFreq) {
                const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                effects.push(vibrato);
                synth.chain(vibrato, Tone.Destination);
            } else {
                synth.toDestination();
            }
            return { synth, effects };
        }

        function buildKeyboardLine(baseInfo, style, chordProg, variant) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const barSteps = baseInfo.beatsPerBar * STEPS_PER_BEAT;
            const S = STEPS_PER_BEAT; // 4

            const chordRoots = chordProg.notes.map(triad => triad[0].replace(/\d+$/, ''));
            const chordThirds = chordProg.notes.map(triad => triad[1].replace(/\d+$/, ''));
            const chordFifths = chordProg.notes.map(triad => triad[2].replace(/\d+$/, ''));

            const events = [];
            const add = (si, note, len) => {
                if (si >= 0 && si < totalSteps && note) {
                    events.push({ step: si, note, len: Math.min(len, totalSteps - si) });
                }
            };

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * barSteps;
                const R = chordRoots[bar % chordRoots.length];
                const T = chordThirds[bar % chordThirds.length];
                const F = chordFifths[bar % chordFifths.length];
                const chord4 = [R + "4", T + "4", F + "4"];
                const chordWide = [R + "3", T + "4", F + "4"];

                if (style === "piano-gentle") {
                    // Beat 1 full chord, beat 3 partial chord
                    add(b, chord4, 3);
                    if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [R + "4", F + "4"], 3);
                    if (baseInfo.beatsPerBar >= 4 && variant === 1 && Math.random() > 0.4) {
                        add(b + 3 * S, [T + "4", F + "4"], 2);
                    }

                } else if (style === "organ-funky") {
                    // Offbeat staccato chord stabs
                    const offbeats = variant === 0 ? [2, 6, 10, 14] : [2, 6, 10];
                    for (const step of offbeats) {
                        if (step < barSteps) add(b + step, chord4, 1);
                    }
                    // Accent on beat 1 every other bar
                    if (bar % 2 === 0) add(b, chord4, 1);
                    if (variant === 1 && baseInfo.beatsPerBar >= 3 && Math.random() > 0.3) {
                        add(b + 2 * S + 3, [R + "4", F + "4"], 1);
                    }

                } else if (style === "piano-chord") {
                    // Sustained chords with occasional short stabs mixed in
                    if (variant === 0) {
                        if (bar % 3 === 2) {
                            // Every 3rd bar: ファーーファファファーー pattern
                            add(b, chordWide, S * 2);                              // ファーー
                            add(b + S * 2, chord4, 3);                             // ファ
                            add(b + S * 2 + 3, [R + "4", F + "4"], 3);             // ファ
                            if (baseInfo.beatsPerBar >= 4) add(b + S * 3 + 2, chordWide, S); // ファーー
                        } else {
                            add(b, chordWide, barSteps);                            // ファーーーー
                        }
                    } else {
                        if (bar % 2 === 1) {
                            // Every other bar: short stabs before sustained
                            add(b, chord4, 3);                                      // ファ
                            add(b + 3, [R + "4", F + "4"], 3);                      // ファ
                            if (baseInfo.beatsPerBar >= 3) add(b + S + 2, chordWide, barSteps - S - 2); // ファーーー
                        } else {
                            add(b, chordWide, Math.floor(barSteps * 0.6));
                            if (baseInfo.beatsPerBar >= 3) {
                                add(b + 2 * S, chord4, Math.floor(barSteps * 0.4));
                            }
                        }
                    }

                } else if (style === "piano-sparse") {
                    // Sparse, monotone single notes — slightly melancholic, understated
                    if (variant === 0) {
                        add(b, [R + "4"], 4);                                           // beat 1: root only
                        if (baseInfo.beatsPerBar >= 3 && bar % 2 === 0) {
                            add(b + 2 * S, [T + "4"], 3);                              // every other bar: minor third
                        }
                        if (baseInfo.beatsPerBar >= 4 && bar % 2 === 1) {
                            add(b + 3 * S, [F + "3"], 4);                              // alternating bars: low fifth
                        }
                    } else {
                        add(b, [R + "3"], 4);                                           // beat 1: low root
                        if (baseInfo.beatsPerBar >= 2 && bar % 3 === 0) {
                            add(b + S + 2, [T + "4"], 3);                              // sparse third
                        }
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S, [R + "4"], 3);                              // beat 4: octave root
                        }
                    }

                } else if (style === "piano-arpeggio") {
                    // Staccato arpeggio — single-step taps through chord tones
                    if (variant === 0) {
                        add(b, [R + "4"], 1);                                           // beat 1: root
                        if (baseInfo.beatsPerBar >= 2) add(b + S, [T + "4"], 1);       // beat 2: third
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [R + "5"], 1);   // beat 3: octave root
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [F + "4"], 1);   // beat 4: fifth
                        if (baseInfo.beatsPerBar >= 4 && bar % 2 === 1) {
                            add(b + 3 * S + 2, [T + "4"], 1);                          // every other bar: passing note
                        }
                    } else {
                        // Variant 1: descending contour
                        add(b, [R + "5"], 1);                                           // beat 1: high root
                        if (baseInfo.beatsPerBar >= 2) add(b + S, [F + "4"], 1);       // beat 2: fifth
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [T + "4"], 1);   // beat 3: third
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [R + "4"], 1);   // beat 4: root
                        if (baseInfo.beatsPerBar >= 4 && bar % 2 === 0) {
                            add(b + 3 * S + 2, [F + "4"], 1);                          // pickup into next bar
                        }
                    }

                } else if (style === "organ-power") {
                    // Strong chord on beats 1 and 3, 8th-note fills on beat 4
                    const power = [R + "4", F + "4", R + "5"];
                    add(b, power, 3);
                    if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, power, 3);
                    if (baseInfo.beatsPerBar >= 4) {
                        if (variant === 0 && Math.random() > 0.3) {
                            add(b + 3 * S, [R + "4", F + "4"], 2);
                            add(b + 3 * S + 2, power, 2);
                        } else {
                            add(b + 3 * S, power, 2);
                            if (Math.random() > 0.25) {
                                add(b + 3 * S + 2, [R + "4", F + "4"], 2);
                            }
                        }
                    }

                } else if (style === "pachinko-bells") {
                    // Rapid, flashy arpeggiated bells — pachinko parlor feel
                    // Busy 16th-note cascades with high octave sparkle
                    const hi = [R + "5", F + "5"];
                    const mid = [R + "4", T + "4", F + "4"];
                    const spark = [R + "6"];
                    if (variant === 0) {
                        add(b, mid, 1); add(b + 1, hi, 1); add(b + 2, spark, 1); add(b + 3, hi, 1);
                        if (baseInfo.beatsPerBar >= 2) { add(b + S, mid, 1); add(b + S + 1, spark, 1); add(b + S + 2, hi, 1); add(b + S + 3, mid, 1); }
                        if (baseInfo.beatsPerBar >= 3) { add(b + 2*S, spark, 1); add(b + 2*S + 1, mid, 1); add(b + 2*S + 2, hi, 1); add(b + 2*S + 3, spark, 1); }
                        if (baseInfo.beatsPerBar >= 4) { add(b + 3*S, hi, 1); add(b + 3*S + 1, spark, 1); add(b + 3*S + 2, mid, 1); add(b + 3*S + 3, hi, 1); }
                    } else {
                        add(b, spark, 1); add(b + 2, mid, 1);
                        if (baseInfo.beatsPerBar >= 2) { add(b + S, hi, 1); add(b + S + 1, spark, 1); add(b + S + 3, mid, 1); }
                        if (baseInfo.beatsPerBar >= 3) { add(b + 2*S, mid, 1); add(b + 2*S + 2, spark, 1); add(b + 2*S + 3, hi, 1); }
                        if (baseInfo.beatsPerBar >= 4) { add(b + 3*S, spark, 1); add(b + 3*S + 1, hi, 1); add(b + 3*S + 2, spark, 1); add(b + 3*S + 3, mid, 1); }
                    }

                } else if (style === "syncopated") {
                    // Syncopated hits — accents on offbeats with varying chord voicings
                    if (variant === 0) {
                        add(b, [R + "4"], 1);
                        add(b + 3, chord4, 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 1, [T + "4", F + "4"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 2, chordWide, 2);
                    } else {
                        add(b + 1, [R + "4", F + "4"], 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 3, chord4, 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [T + "5"], 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 2, chordWide, 3);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 1, [R + "4", T + "4"], 2);
                    }

                } else if (style === "melodic-run") {
                    // Single-note melodic runs through chord tones at different octaves
                    const tones = [R, T, F];
                    if (variant === 0) {
                        // Ascending run
                        add(b, [tones[0] + "4"], 2);
                        add(b + 2, [tones[1] + "4"], 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S, [tones[2] + "4"], 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 2, [tones[0] + "5"], 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [tones[1] + "5"], 3);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [tones[2] + "5"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 2, [tones[0] + "4"], 2);
                    } else {
                        // Descending run with leaps
                        add(b, [tones[2] + "5"], 2);
                        add(b + 2, [tones[0] + "5"], 1);
                        add(b + 3, [tones[1] + "4"], 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 1, [tones[2] + "4"], 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [tones[0] + "4"], 4);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [tones[1] + "5"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 2, [tones[2] + "4"], 2);
                    }

                } else if (style === "staccato-bounce") {
                    // Quick bouncing single notes — rhythmic and playful
                    const bounce = [R + "5", T + "4", F + "4", R + "4"];
                    if (variant === 0) {
                        for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                            add(b + beat * S, [bounce[beat % bounce.length]], 1);
                            if (Math.random() > 0.3) add(b + beat * S + 2, [bounce[(beat + 1) % bounce.length]], 1);
                        }
                    } else {
                        add(b, [R + "5"], 1);
                        add(b + 1, [F + "4"], 1);
                        add(b + 3, [T + "4"], 1);
                        if (baseInfo.beatsPerBar >= 2) { add(b + S, [R + "4"], 1); add(b + S + 2, [F + "5"], 1); }
                        if (baseInfo.beatsPerBar >= 3) { add(b + 2 * S + 1, [T + "5"], 1); add(b + 2 * S + 3, [R + "4"], 1); }
                        if (baseInfo.beatsPerBar >= 4) { add(b + 3 * S, [F + "4"], 1); add(b + 3 * S + 2, [T + "4", R + "5"], 1); }
                    }

                // === Part-Time (アルバイト) pattern styles ===
                } else if (style === "staccato-burst") {
                    // 16th-note burst clusters (2-3 notes) → rest → burst
                    if (variant === 0) {
                        add(b, [R + "5"], 1);
                        add(b + 1, [T + "5"], 1);
                        add(b + 2, [F + "5"], 1);
                        // Rest on beat 2
                        if (baseInfo.beatsPerBar >= 3) {
                            add(b + 2 * S, [R + "4"], 1);
                            add(b + 2 * S + 1, [F + "4"], 1);
                        }
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S + 2, [T + "5"], 1);
                            add(b + 3 * S + 3, [R + "5"], 1);
                        }
                    } else {
                        add(b + 1, [F + "5"], 1);
                        add(b + 2, [R + "5"], 1);
                        if (baseInfo.beatsPerBar >= 2) {
                            add(b + S + 1, [T + "4"], 1);
                            add(b + S + 2, [F + "4"], 1);
                            add(b + S + 3, [R + "4"], 1);
                        }
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S, [T + "5"], 1);
                            add(b + 3 * S + 1, [F + "5"], 1);
                        }
                    }

                } else if (style === "synco-punch") {
                    // Off-beat accented short hits, irregular placement
                    if (variant === 0) {
                        add(b + 2, [R + "5", F + "5"], 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 3, [T + "4"], 1);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S + 1, [F + "4", R + "5"], 1);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 2, [T + "5"], 1);
                    } else {
                        add(b + 3, [F + "5"], 1);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 1, [R + "4", T + "4"], 1);
                        if (baseInfo.beatsPerBar >= 3) {
                            add(b + 2 * S + 2, [T + "5"], 1);
                            add(b + 2 * S + 3, [F + "4"], 1);
                        }
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [R + "5"], 1);
                    }

                } else if (style === "rapid-tap") {
                    // Fast consecutive taps for 1-2 beats then rest
                    if (variant === 0) {
                        for (let s = 0; s < Math.min(S * 2, barSteps); s++) {
                            add(b + s, [s % 2 === 0 ? R + "5" : T + "5"], 1);
                        }
                        // Rest for remaining beats
                    } else {
                        // Start after a rest
                        if (baseInfo.beatsPerBar >= 2) {
                            for (let s = 0; s < Math.min(S, barSteps - S); s++) {
                                add(b + S + s, [s % 3 === 0 ? R + "5" : (s % 3 === 1 ? T + "4" : F + "4")], 1);
                            }
                        }
                        if (baseInfo.beatsPerBar >= 4) {
                            add(b + 3 * S, [R + "4", F + "4"], 1);
                            add(b + 3 * S + 2, [T + "5"], 1);
                        }
                    }

                // === Job Hunt (就活) pattern styles ===
                } else if (style === "formal-accent") {
                    // ファーー、、ファー、ファーーー rhythm — mid-length notes with gaps
                    if (variant === 0) {
                        add(b, chord4, 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [R + "4"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [R + "4", F + "4"], 3);
                    } else {
                        add(b + 1, [T + "4"], 2);
                        if (baseInfo.beatsPerBar >= 3) add(b + S + 3, chord4, 3);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [F + "4"], 2);
                    }

                } else if (style === "crisp-staccato") {
                    // ファー、ファーー、、ファー rhythm — punchy with space
                    const crisp = [R + "5", T + "4", F + "5"];
                    if (variant === 0) {
                        add(b, [crisp[0]], 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S + 2, [crisp[1]], 3);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [crisp[2]], 2);
                    } else {
                        add(b + 1, [crisp[2]], 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + 2 * S, [crisp[0]], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S + 1, [crisp[1]], 2);
                    }

                } else if (style === "dramatic-swell") {
                    // ファーーー、、ファー、ファーー rhythm — passionate swells with breath
                    if (variant === 0) {
                        add(b, [R + "4"], 3);
                        if (baseInfo.beatsPerBar >= 3) add(b + S + 3, [R + "5", F + "5"], 2);
                        if (baseInfo.beatsPerBar >= 4) add(b + 2 * S + 2, chord4, 3);
                    } else {
                        add(b, chord4, 2);
                        if (baseInfo.beatsPerBar >= 2) add(b + S, [T + "5", F + "5"], 3);
                        if (baseInfo.beatsPerBar >= 4) add(b + 3 * S, [R + "4"], 2);
                    }
                }
            }

            // Convert events into arrays
            const pattern = new Array(totalSteps).fill(false);
            const notes = new Array(totalSteps).fill(null);
            const attacks = new Array(totalSteps).fill(false);
            const durations = new Array(totalSteps).fill(null);
            const sustainType = new Array(totalSteps).fill(null);

            const stepToDur = (len) => {
                if (len <= 1) return "16n";
                if (len <= 2) return "8n";
                if (len <= 3) return "8n.";
                if (len <= 4) return "4n";
                if (len <= 6) return "4n.";
                if (len <= 8) return "2n";
                return "1n";
            };

            // Prevent note overlap: clip durations so no note extends past the next note's start
            events.sort((a, b) => a.step - b.step);
            for (let i = 0; i < events.length - 1; i++) {
                const endStep = events[i].step + events[i].len;
                if (endStep > events[i + 1].step) {
                    events[i].len = events[i + 1].step - events[i].step;
                    if (events[i].len < 1) events[i].len = 1;
                }
            }

            events.forEach(ev => {
                attacks[ev.step] = true;
                notes[ev.step] = ev.note;
                durations[ev.step] = stepToDur(ev.len);
                for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                    pattern[s] = true;
                    if (!notes[s]) notes[s] = ev.note;
                }
                if (ev.len === 1) {
                    sustainType[ev.step] = 'single';
                } else {
                    for (let s = ev.step; s < ev.step + ev.len && s < totalSteps; s++) {
                        if (s === ev.step) sustainType[s] = 'start';
                        else if (s === ev.step + ev.len - 1) sustainType[s] = 'end';
                        else sustainType[s] = 'mid';
                    }
                }
            });

            return { pattern, notes, attacks, durations, sustainType };
        }

        function createKeyboardSynth(style) {
            const cfg = KEYBOARD_TIMBRES[style];
            if (!cfg) return { synth: null, effects: [] };

            const effects = [];
            // NOTE: Do NOT put volume in the PolySynth constructor options — Tone.js v14
            // passes all second-arg properties as inner voice options, so volume:-100 would
            // set each inner Synth to -100dB (making total output ~silent).
            // Instead, set PolySynth.volume.value after creation.
            const synth = new Tone.PolySynth(Tone.Synth, {
                oscillator: { type: cfg.wave },
                envelope: { attack: cfg.attack, decay: cfg.decay, sustain: cfg.sustain, release: cfg.release }
            });
            synth.volume.value = -100;

            if (cfg.filterType) {
                const filter = new Tone.Filter({ type: cfg.filterType, frequency: cfg.filterFreq, Q: 1.5 });
                effects.push(filter);
                synth.chain(filter, Tone.Destination);
            } else if (cfg.vibratoFreq) {
                const vibrato = new Tone.Vibrato({ frequency: cfg.vibratoFreq, depth: cfg.vibratoDepth });
                effects.push(vibrato);
                synth.chain(vibrato, Tone.Destination);
            } else {
                synth.toDestination();
            }

            return { synth, effects };
        }

        function initBassDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo || !inheritedChordProgression) return;

            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;

            // Per-style synth timbres
            const BASS_TIMBRES = {
                energetic:     { osc: "sawtooth", attack: 0.01, decay: 0.15, sustain: 0.35, release: 0.25, filterBase: 150, filterOct: 3 },
                soft:          { osc: "sine",     attack: 0.06, decay: 0.5,  sustain: 0.5,  release: 0.8,  filterBase: 80,  filterOct: 1.5 },
                quirky:        { osc: "square",   attack: 0.01, decay: 0.2,  sustain: 0.25, release: 0.3,  filterBase: 120, filterOct: 2.8 },
                contemplative: { osc: "sine",     attack: 0.08, decay: 0.6,  sustain: 0.6,  release: 1.2,  filterBase: 60,  filterOct: 1.2 },
                groovy:        { osc: "triangle", attack: 0.01, decay: 0.2,  sustain: 0.3,  release: 0.3,  filterBase: 130, filterOct: 2.5 },
                playful:       { osc: "triangle", attack: 0.01, decay: 0.12, sustain: 0.2,  release: 0.2,  filterBase: 160, filterOct: 3.2 },
                melodic:       { osc: "sine",     attack: 0.03, decay: 0.35, sustain: 0.45, release: 0.6,  filterBase: 100, filterOct: 2 }
            };

            for (let i = 0; i < SCHOOL_ACTIVITIES.length; i++) {
                const act = SCHOOL_ACTIVITIES[i];
                const bassVariant = randInt(0, 1);
                const bassBundle = buildBassLine(baseRhythmInfo, act.bassStyle, inheritedChordProgression, bassVariant);

                const timbre = BASS_TIMBRES[act.bassStyle] || BASS_TIMBRES.soft;
                const bassSynth = new Tone.MonoSynth({
                    oscillator: { type: timbre.osc },
                    envelope: { attack: timbre.attack, decay: timbre.decay, sustain: timbre.sustain, release: timbre.release },
                    filterEnvelope: {
                        attack: timbre.attack * 0.5, decay: timbre.decay, sustain: timbre.sustain, release: timbre.release,
                        baseFrequency: timbre.filterBase, octaves: timbre.filterOct
                    },
                    volume: -100
                }).toDestination();

                // Place drop within the activity's worldFraction range
                const minX = worldWidth * act.worldFraction[0];
                const maxX = worldWidth * act.worldFraction[1];
                const cx = minX + (maxX - minX) * 0.5;

                toneDrops.push({
                    x: cx,
                    y: floorY + (i % 2 === 0 ? -8 : 8),
                    pattern: bassBundle.pattern,
                    bassNotes: bassBundle.notes,
                    bassAttacks: bassBundle.attacks,
                    bassDurations: bassBundle.durations,
                    bassSustainType: bassBundle.sustainType,
                    velocityPattern: null,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "bass",
                    bassSynth,
                    bassStyle: act.bassStyle,
                    bassVariant,
                    activityId: act.id,
                    activityName: act.name,
                    dropColor: act.color,
                    activityLabels: act.labels,
                    ripples: []
                });
            }
            primeToneDrops();
        }

        function initToneDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo) return;

            const count = 4;
            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            const xs = createSpacedDropXs(count, 200, 180, worldWidth - 180);
            const toyPool = toySystem.TOY_LIBRARY.slice();
            for (let i = toyPool.length - 1; i > 0; i--) {
                const j = randInt(0, i);
                [toyPool[i], toyPool[j]] = [toyPool[j], toyPool[i]];
            }
            const hatTimbres = [
                { noise: "white", hp: 7600, q: 0.5, decay: 0.04, mode: "closed" },
                { noise: "pink", hp: 6800, q: 0.7, decay: 0.055, mode: "closed" },
                { noise: "white", hp: 9200, q: 0.4, decay: 0.03, mode: "closed" },
                { noise: "brown", hp: 6200, q: 0.8, decay: 0.05, mode: "mixed-open" }
            ];

            for (let i = 0; i < count; i++) {
                const timbre = hatTimbres[i % hatTimbres.length];
                const hatSoundConfig = { noise: timbre.noise, hp: timbre.hp, q: timbre.q, decay: timbre.decay, release: 0.015 };
                const hatFilter = new Tone.Filter({
                    type: "highpass",
                    frequency: timbre.hp,
                    Q: timbre.q
                }).toDestination();
                const hatClosedSynth = new Tone.NoiseSynth({
                    noise: { type: timbre.noise },
                    envelope: { attack: 0.001, decay: timbre.decay, sustain: 0, release: 0.015 },
                    volume: -100
                }).connect(hatFilter);
                const hatOpenSynth = new Tone.NoiseSynth({
                    noise: { type: timbre.noise },
                    envelope: { attack: 0.001, decay: timbre.decay * 3.4, sustain: 0, release: 0.12 },
                    volume: -100
                }).connect(hatFilter);
                const pattern = buildHiHatPattern(baseRhythmInfo, i);
                const toy = toyPool.length ? toyPool[i % toyPool.length] : null;
                const audioProfile = toy ? toy.audio : { density:[1,2], pitchMotion:[1,2], rhythmMotion:[1,1], openness:[0,1] };
                toneDrops.push({
                    x: xs[i],
                    y: floorY + (i % 2 === 0 ? -8 : 8),
                    pattern: applyToyPatternProfile(pattern, audioProfile),
                    velocityPattern: null,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    hatClosedSynth,
                    hatOpenSynth,
                    hatFilter,
                    hatMode: timbre.mode,
                    hatSoundConfig,
                    instrument: "hat",
                    toy,
                    toySeed: Math.random() * 10000,
                    audioProfile,
                    ripples: []
                });
            }
            phaseOneToyIds = toneDrops.map(d => d.toy?.id).filter(Boolean);
            primeToneDrops();
        }

        function buildSnarePattern(baseInfo, variant) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const totalBeats = baseInfo.beatsPerBar * baseInfo.bars;
            const pattern = new Array(totalSteps).fill(false);
            const velocity = new Array(totalSteps).fill(0);
            const put = (beatIndex, mode = "on", vel = 0.88) => {
                if (beatIndex < 0 || beatIndex >= totalBeats) return;
                const base = beatIndex * STEPS_PER_BEAT;
                const slot = mode === "off" ? 2 : (mode === "push" ? 1 : (mode === "late" ? 3 : 0));
                const idx = base + slot;
                if (idx < 0 || idx >= totalSteps) return;
                pattern[idx] = true;
                velocity[idx] = Math.max(velocity[idx], vel);
            };

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * baseInfo.beatsPerBar;
                if (variant === 0) {
                    // Classic backbeat
                    if (baseInfo.beatsPerBar >= 2) put(b + 1, "on", 0.98);
                    put(b + baseInfo.beatsPerBar - 1, "on", 0.86);
                    if (bar % 2 === 1) put(b, "off", 0.55);
                    continue;
                }
                if (variant === 1) {
                    // Push groove
                    if (baseInfo.beatsPerBar >= 2) put(b + 1, "push", 0.84);
                    put(b + baseInfo.beatsPerBar - 1, "late", 0.92);
                    if (bar % 2 === 0) put(b, "on", 0.62);
                    continue;
                }
                if (variant === 2) {
                    // Sparse heavy accents
                    put(b, "on", 0.95);
                    if (baseInfo.beatsPerBar >= 3) put(b + 2, "off", 0.72);
                    if (bar % 2 === 1) put(b + baseInfo.beatsPerBar - 1, "on", 0.78);
                    continue;
                }
                if (variant === 3) {
                    // Ghost-note forward motion
                    if (baseInfo.beatsPerBar >= 2) put(b + 1, "on", 0.86);
                    if (baseInfo.beatsPerBar >= 3) put(b + 2, "push", 0.58);
                    put(b + baseInfo.beatsPerBar - 1, "late", 0.74);
                    continue;
                }
                // Variant 4: denser but controlled
                for (let i = 0; i < baseInfo.beatsPerBar; i++) {
                    if (i % 2 === 1) put(b + i, "on", 0.8 + (i === baseInfo.beatsPerBar - 1 ? 0.1 : 0));
                }
                put(b, bar % 2 === 0 ? "off" : "push", 0.52);
                put(b + baseInfo.beatsPerBar - 1, "on", 0.96);
            }
            return { pattern, velocity };
        }

        function buildCymbalPattern(baseInfo, variant) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const totalBeats = baseInfo.beatsPerBar * baseInfo.bars;
            const pattern = new Array(totalSteps).fill(false);
            const velocity = new Array(totalSteps).fill(0);
            const put = (beatIndex, mode = "on", vel = 0.88) => {
                if (beatIndex < 0 || beatIndex >= totalBeats) return;
                const base = beatIndex * STEPS_PER_BEAT;
                const slot = mode === "off" ? 2 : (mode === "push" ? 1 : (mode === "late" ? 3 : 0));
                const idx = base + slot;
                if (idx < 0 || idx >= totalSteps) return;
                pattern[idx] = true;
                velocity[idx] = Math.max(velocity[idx], vel);
            };

            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const b = bar * baseInfo.beatsPerBar;
                if (variant === 0) {
                    // v0 "ride": beat 1 each bar, occasional beat 3
                    put(b, "on", 0.92);
                    if (baseInfo.beatsPerBar >= 3 && bar % 2 === 0) put(b + 2, "on", 0.68);
                    continue;
                }
                if (variant === 1) {
                    // v1 "crash": only bar 1 & bar 3, accent build-up
                    if (bar === 0) put(b, "on", 0.98);
                    if (bar === 2) put(b, "on", 0.90);
                    if (bar === baseInfo.bars - 1) put(b + baseInfo.beatsPerBar - 1, "on", 0.78);
                    continue;
                }
                if (variant === 2) {
                    // v2 "splash": offbeat accents, very sparse
                    if (bar % 2 === 1 && baseInfo.beatsPerBar >= 2) put(b + 1, "off", 0.82);
                    if (bar === baseInfo.bars - 1) put(b, "push", 0.72);
                    continue;
                }
                // v3 "china": syncopated, irregular push/late placements
                if (bar % 2 === 0) put(b, "push", 0.86);
                else if (baseInfo.beatsPerBar >= 2) put(b + 1, "late", 0.80);
                if (bar === baseInfo.bars - 1 && baseInfo.beatsPerBar >= 3) put(b + 2, "on", 0.74);
            }
            return { pattern, velocity };
        }

        // Procedural Chord Progression Generator (CHILD1)
        // Uses music theory: diatonic chords + weighted Markov transitions
        function generateChordProgression(mode) {
            const TONE_NAMES = ['C','C#','D','D#','E','F','F#','G','G#','A','A#','B'];

            // Key definitions with proper enharmonic note names
            const MAJOR_KEYS = [
                { root: 0,  notes: ['C','D','E','F','G','A','B'] },
                { root: 7,  notes: ['G','A','B','C','D','E','F#'] },
                { root: 2,  notes: ['D','E','F#','G','A','B','C#'] },
                { root: 5,  notes: ['F','G','A','Bb','C','D','E'] },
                { root: 10, notes: ['Bb','C','D','Eb','F','G','A'] },
                { root: 3,  notes: ['Eb','F','G','Ab','Bb','C','D'] },
                { root: 9,  notes: ['A','B','C#','D','E','F#','G#'] },
            ];
            const MINOR_KEYS = [
                { root: 9,  notes: ['A','B','C','D','E','F','G'] },
                { root: 4,  notes: ['E','F#','G','A','B','C','D'] },
                { root: 2,  notes: ['D','E','F','G','A','Bb','C'] },
                { root: 11, notes: ['B','C#','D','E','F#','G','A'] },
                { root: 0,  notes: ['C','D','Eb','F','G','Ab','Bb'] },
                { root: 7,  notes: ['G','A','Bb','C','D','Eb','F'] },
            ];

            const MAJOR_INTERVALS = [0, 2, 4, 5, 7, 9, 11];
            const MINOR_INTERVALS = [0, 2, 3, 5, 7, 8, 10];
            const MAJOR_QUALITIES = ['major','minor','minor','major','major','minor','dim'];
            const MINOR_QUALITIES = ['minor','dim','major','minor','minor','major','major'];
            const MAJOR_SUFFIXES = ['','m','m','','','m','\u00B0'];
            const MINOR_SUFFIXES = ['m','\u00B0','','m','m','',''];

            const isMajor = mode === 'kindergarten';
            const keys = isMajor ? MAJOR_KEYS : MINOR_KEYS;
            const key = keys[randInt(0, keys.length - 1)];
            const intervals = isMajor ? MAJOR_INTERVALS : MINOR_INTERVALS;
            const qualities = isMajor ? MAJOR_QUALITIES : MINOR_QUALITIES;
            const suffixes = isMajor ? MAJOR_SUFFIXES : MINOR_SUFFIXES;

            function triadMidi(degree) {
                const rootMidi = 48 + ((key.root + intervals[degree]) % 12);
                const q = qualities[degree];
                if (q === 'major') return [rootMidi, rootMidi + 4, rootMidi + 7];
                if (q === 'minor') return [rootMidi, rootMidi + 3, rootMidi + 7];
                return [rootMidi, rootMidi + 3, rootMidi + 6];
            }
            function midiToTone(midi) {
                return TONE_NAMES[midi % 12] + (Math.floor(midi / 12) - 1);
            }
            function chordName(degree) {
                return key.notes[degree] + suffixes[degree];
            }

            // Weighted Markov transitions: [targetDegree, weight]
            // Common = high weight, rare-but-valid = low weight
            const MAJOR_TRANS = {
                0: [[1,3],[2,1],[3,5],[4,5],[5,4]],
                1: [[4,5],[2,2],[6,1]],
                2: [[5,4],[3,3],[1,2]],
                3: [[4,5],[0,4],[1,2],[5,2],[6,1]],
                4: [[0,6],[5,3],[3,1]],
                5: [[3,5],[1,4],[4,3],[2,1]],
                6: [[0,5],[2,2]]
            };
            const MINOR_TRANS = {
                0: [[1,1],[2,2],[3,4],[4,3],[5,3],[6,3]],
                1: [[4,5],[6,3]],
                2: [[5,4],[3,3],[6,3]],
                3: [[4,5],[0,4],[6,2]],
                4: [[0,6],[5,3]],
                5: [[2,4],[3,3],[1,2],[6,2]],
                6: [[2,4],[0,3],[5,2],[4,2],[3,1]]
            };

            const trans = isMajor ? MAJOR_TRANS : MINOR_TRANS;
            const startW = isMajor
                ? [[0,5],[5,3],[3,2],[2,1]]
                : [[0,5],[5,3],[2,2],[3,1]];

            function weightedPick(options) {
                const total = options.reduce((s, o) => s + o[1], 0);
                let r = Math.random() * total;
                for (const [deg, w] of options) {
                    r -= w;
                    if (r <= 0) return deg;
                }
                return options[options.length - 1][0];
            }

            const degrees = [];
            let cur = weightedPick(startW);
            degrees.push(cur);
            for (let i = 1; i < 4; i++) {
                const opts = trans[cur];
                cur = (opts && opts.length) ? weightedPick(opts) : 0;
                degrees.push(cur);
            }

            return {
                name: degrees.map(d => chordName(d)).join('-'),
                chords: degrees.map(d => chordName(d)),
                notes: degrees.map(d => triadMidi(d).map(midiToTone))
            };
        }

        function buildChordPattern(baseInfo) {
            const totalSteps = baseInfo.beatsPerBar * baseInfo.bars * STEPS_PER_BEAT;
            const barSteps = baseInfo.beatsPerBar * STEPS_PER_BEAT;
            const pattern = new Array(totalSteps).fill(false);
            const velocity = new Array(totalSteps).fill(0);
            for (let bar = 0; bar < baseInfo.bars; bar++) {
                const idx = bar * barSteps;
                // Trigger on every beat in the bar for responsive hover preview
                for (let beat = 0; beat < baseInfo.beatsPerBar; beat++) {
                    const si = idx + beat * STEPS_PER_BEAT;
                    pattern[si] = true;
                    velocity[si] = beat === 0 ? 0.95 : 0.7;
                }
            }
            return { pattern, velocity };
        }

        function initSnareDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo) return;

            const count = 5;
            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            const xs = createSpacedDropXs(count, 165, 180, worldWidth - 180);
            const excluded = new Set(phaseOneToyIds);
            const uniquePool = toySystem.TOY_LIBRARY.filter(t => !excluded.has(t.id));
            const poolBase = uniquePool.length >= count ? uniquePool : toySystem.TOY_LIBRARY.slice();
            const toyPool = poolBase.slice();
            for (let i = toyPool.length - 1; i > 0; i--) {
                const j = randInt(0, i);
                [toyPool[i], toyPool[j]] = [toyPool[j], toyPool[i]];
            }

            const timbres = [
                { noise: "white", bp: 2050, q: 0.7, decay: 0.11, release: 0.08, body: true },
                { noise: "pink", bp: 1650, q: 1.0, decay: 0.16, release: 0.1, body: false },
                { noise: "brown", bp: 1280, q: 0.8, decay: 0.2, release: 0.12, body: true },
                { noise: "white", bp: 2520, q: 1.2, decay: 0.08, release: 0.06, body: false },
                { noise: "pink", bp: 1880, q: 0.9, decay: 0.13, release: 0.09, body: true }
            ];

            for (let i = 0; i < count; i++) {
                const timbre = timbres[i];
                const bundle = buildSnarePattern(baseRhythmInfo, i);
                const snareGainBoostDb = (i === 1 || i === 4) ? 6 : 0;
                const snareBodyBoostDb = (i === 1 || i === 4) ? 5 : 0;
                const snareSoundConfig = {
                    noise: timbre.noise,
                    bp: timbre.bp,
                    q: timbre.q,
                    decay: timbre.decay,
                    release: timbre.release,
                    body: timbre.body
                };
                const snareFilter = new Tone.Filter({
                    type: "bandpass",
                    frequency: timbre.bp,
                    Q: timbre.q
                }).toDestination();
                const snareSynth = new Tone.NoiseSynth({
                    noise: { type: timbre.noise },
                    envelope: { attack: 0.001, decay: timbre.decay, sustain: 0, release: timbre.release },
                    volume: -100
                }).connect(snareFilter);
                const snareBody = timbre.body ? new Tone.MembraneSynth({
                    pitchDecay: 0.025,
                    octaves: 2.5,
                    oscillator: { type: "triangle" },
                    envelope: { attack: 0.001, decay: 0.1, sustain: 0, release: 0.06 },
                    volume: -22
                }).toDestination() : null;
                const toy = toyPool.length ? toyPool[i % toyPool.length] : null;
                toneDrops.push({
                    x: xs[i],
                    y: floorY + (i % 2 === 0 ? -10 : 10),
                    pattern: bundle.pattern,
                    velocityPattern: bundle.velocity,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "snare",
                    snareSynth,
                    snareFilter,
                    snareBody,
                    snareSoundConfig,
                    snareGainBoostDb,
                    snareBodyBoostDb,
                    toy,
                    toySeed: Math.random() * 10000,
                    hudStyleClass: i % 2 === 0 ? "snare" : "snare-alt",
                    ripples: []
                });
            }
            phaseTwoToyIds = toneDrops.map(d => d.toy?.id).filter(Boolean);
            primeToneDrops();
        }

        function initCymbalDrops() {
            disposeToneDrops();
            toneDrops = [];
            if (!baseRhythmInfo) return;

            const count = 4;
            const floorY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            const xs = createSpacedDropXs(count, 200, 180, worldWidth - 180);
            const excluded = new Set([...phaseOneToyIds, ...phaseTwoToyIds]);
            const uniquePool = toySystem.TOY_LIBRARY.filter(t => !excluded.has(t.id));
            const poolBase = uniquePool.length >= count ? uniquePool : toySystem.TOY_LIBRARY.slice();
            const toyPool = poolBase.slice();
            for (let i = toyPool.length - 1; i > 0; i--) {
                const j = randInt(0, i);
                [toyPool[i], toyPool[j]] = [toyPool[j], toyPool[i]];
            }

            const timbres = [
                { freq: 300, harmonicity: 5.1, modulationIndex: 32, resonance: 4000, decay: 1.2, label: "ride" },
                { freq: 250, harmonicity: 5.4, modulationIndex: 40, resonance: 5000, decay: 0.8, label: "crash" },
                { freq: 400, harmonicity: 4.6, modulationIndex: 24, resonance: 5500, decay: 0.3, label: "splash" },
                { freq: 180, harmonicity: 3.8, modulationIndex: 48, resonance: 2800, decay: 0.6, label: "china" }
            ];

            for (let i = 0; i < count; i++) {
                const timbre = timbres[i];
                const bundle = buildCymbalPattern(baseRhythmInfo, i);
                const cymbalSoundConfig = {
                    freq: timbre.freq,
                    harmonicity: timbre.harmonicity,
                    modulationIndex: timbre.modulationIndex,
                    resonance: timbre.resonance,
                    decay: timbre.decay
                };
                const cymbalSynth = new Tone.MetalSynth({
                    frequency: timbre.freq,
                    harmonicity: timbre.harmonicity,
                    modulationIndex: timbre.modulationIndex,
                    resonance: timbre.resonance,
                    envelope: { attack: 0.001, decay: timbre.decay, release: 0.05 },
                    volume: -100
                }).toDestination();
                const toy = toyPool.length ? toyPool[i % toyPool.length] : null;
                toneDrops.push({
                    x: xs[i],
                    y: floorY + (i % 2 === 0 ? -10 : 10),
                    pattern: bundle.pattern,
                    velocityPattern: bundle.velocity,
                    proximityVol: -100,
                    isHovered: false,
                    overlapAlpha: 0,
                    instrument: "cymbal",
                    cymbalSynth,
                    cymbalSoundConfig,
                    toy,
                    toySeed: Math.random() * 10000,
                    hudStyleClass: i % 2 === 0 ? "cymbal" : "cymbal-alt",
                    ripples: []
                });
            }
            primeToneDrops();
        }

        function applyToyPatternProfile(pattern, profile) {
            const out = pattern.slice();
            const densityLevel = randInt(profile.density[0], profile.density[1]);
            if (densityLevel <= 1) return out;
            for (let i = 0; i < out.length; i += STEPS_PER_BEAT) {
                if (out[i]) {
                    if (densityLevel >= 2 && Math.random() < 0.35) out[i + 2] = true;
                    if (densityLevel >= 3 && Math.random() < 0.22) out[i + 1] = true;
                }
            }
            return out;
        }

        function startBaseGroove() {
            if (!baseRhythmInfo) return;
            if (baseGroove && baseGroove.timer) clearTimeout(baseGroove.timer);
            if (baseGroove && baseGroove.kickSynth) baseGroove.kickSynth.dispose();

            const kickSynth = new Tone.MembraneSynth({
                pitchDecay: 0.06,
                octaves: 5,
                oscillator: { type: "sine" },
                envelope: { attack: 0.001, decay: 0.45, sustain: 0, release: 0.2 },
                volume: -8
            }).toDestination();

            const stepMs = 60000 / baseRhythmInfo.bpm / STEPS_PER_BEAT;
            baseGroove = {
                step: 0,
                stepMs,
                nextTick: performance.now() + stepMs,
                timer: null,
                kickSynth
            };

            const tick = () => {
                if (!baseGroove || minigameMuteGroove || travelStill.active) return;
                const now = performance.now();
                while (baseGroove.nextTick <= now + 4) {
                    const step = baseGroove.step;
                    if (baseRhythmInfo.kickPattern[step]) {
                        baseGroove.kickSynth.triggerAttackRelease("C1", "8n");
                    }
                    if (
                        (currentScene === SCENE.CRAWL2 || currentScene === SCENE.TODDLE1 || currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryHatSynth &&
                        carryHatFilter &&
                        inheritedHatPattern &&
                        inheritedHatPattern[step]
                    ) {
                        carryHatFilter.frequency.value = 7000 + Math.random() * 1800;
                        carryHatSynth.triggerAttackRelease("32n");
                    }
                    if (
                        (currentScene === SCENE.TODDLE1 || currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carrySnareSynth &&
                        carrySnareFilter &&
                        inheritedSnarePattern &&
                        inheritedSnarePattern[step]
                    ) {
                        const snareVel = inheritedSnareVelocity ? (inheritedSnareVelocity[step] || 0.72) : 0.72;
                        carrySnareFilter.frequency.value = 1400 + snareVel * 800 + Math.random() * 200;
                        carrySnareSynth.triggerAttackRelease("16n");
                        if (carrySnareBody && snareVel >= 0.85) {
                            carrySnareBody.triggerAttackRelease("G2", "32n");
                        }
                    }
                    if (
                        (currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryCymbalSynth &&
                        inheritedCymbalPattern &&
                        inheritedCymbalPattern[step]
                    ) {
                        carryCymbalSynth.triggerAttackRelease("16n");
                    }
                    // Carry chord playback removed from ADULT (bass + guitar only)
                    // Carry bass playback (ADULT+: play inherited bass line)
                    if (
                        (currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryBassSynth &&
                        inheritedBassAttacks &&
                        inheritedBassAttacks[step]
                    ) {
                        const note = inheritedBassNotes ? inheritedBassNotes[step] : null;
                        const dur = inheritedBassDurations ? inheritedBassDurations[step] : "8n";
                        if (note) {
                            try { carryBassSynth.triggerAttackRelease(note, dur); } catch (e) { /* ignore */ }
                        }
                    }
                    // Carry keyboard playback (UNIVERSITY+: play inherited keyboard line)
                    if (
                        (currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryKeyboardSynth &&
                        inheritedKeyboardAttacks &&
                        inheritedKeyboardAttacks[step]
                    ) {
                        const kNote = inheritedKeyboardNotes ? inheritedKeyboardNotes[step] : null;
                        const kDur = inheritedKeyboardDurations ? inheritedKeyboardDurations[step] : "8n";
                        if (kNote) {
                            try { carryKeyboardSynth.releaseAll(); } catch (e) {}
                            try { carryKeyboardSynth.triggerAttackRelease(kNote, kDur); } catch (e) { /* ignore */ }
                        }
                    }
                    // Carry Keys2 playback (PART_TIME onwards)
                    if (
                        (currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.ENTERTAINMENT || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryKeys2Synth &&
                        inheritedKeys2Attacks &&
                        inheritedKeys2Attacks[step]
                    ) {
                        const k2Note = inheritedKeys2Notes ? inheritedKeys2Notes[step] : null;
                        const k2Dur = inheritedKeys2Durations ? inheritedKeys2Durations[step] : "8n";
                        if (k2Note) {
                            try { carryKeys2Synth.releaseAll(); } catch (e) {}
                            try { carryKeys2Synth.triggerAttackRelease(k2Note, k2Dur); } catch (e) { /* ignore */ }
                        }
                    }
                    // Carry Lead playback (THIRTIES)
                    if (
                        (currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) &&
                        carryLeadSynth &&
                        leadAttacks &&
                        leadAttacks[step]
                    ) {
                        const lNote = leadNotes ? leadNotes[step] : null;
                        const lDur = leadDurations ? leadDurations[step] : "8n";
                        if (lNote) {
                            try { carryLeadSynth.releaseAll(); } catch (e) {}
                            try { carryLeadSynth.triggerAttackRelease(lNote, lDur); } catch (e) { /* ignore */ }
                        }
                    }
                    updateScoreHudPlayhead(step);

                    // Chord hover preview: play next chord in progression on each beat 1
                    if (chordPreviewSynth && chordPreviewDrop) {
                        const barSteps = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
                        if (step % barSteps === 0) {
                            playChordPreviewNote();
                        }
                    }

                    toneDrops.forEach(drop => {
                        const hasNote = (drop.pattern && drop.pattern[step]) || (drop.keys2Pattern && drop.keys2Pattern[step]);
                        if (!hasNote) return;
                        if (drop.proximityVol <= -68) return;
                        const accent = drop.velocityPattern ? (drop.velocityPattern[step] || 0.72) : 0.9;
                        const baseVol = Math.min(-12, drop.proximityVol - 12) + (accent - 0.8) * 9;
                        if (drop.instrument === "chord") {
                            // While hovered, chord preview synth is authoritative (bar-head aligned).
                            if (drop.isHovered && chordPreviewDrop === drop) return;
                            // Chord sound via proximity (non-hover) — original behavior
                            const barSteps2 = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
                            const barIndex = Math.floor(step / barSteps2) % drop.chordProgression.notes.length;
                            drop.chordSynth.volume.value = baseVol - 8;
                            drop.chordSynth.triggerAttackRelease(drop.chordProgression.notes[barIndex], "2n");
                            if (drop.isHovered) drop.ripples.push({ t: 0, accent });
                            return;
                        }
                        if (drop.instrument === "keyboard") {
                            // If drop has Keys2, only play Keys2 (Keys is handled by carry layer)
                            if (drop.keys2Synth) {
                                if (drop.keys2Pattern && drop.keys2Pattern[step] &&
                                    drop.keys2Attacks && drop.keys2Attacks[step]) {
                                    const k2Note = drop.keys2Notes[step];
                                    const k2Dur = drop.keys2Durations[step];
                                    if (k2Note) {
                                        drop.keys2Synth.volume.value = baseVol + 8;
                                        try { drop.keys2Synth.releaseAll(); } catch(e) {}
                                        try { drop.keys2Synth.triggerAttackRelease(k2Note, k2Dur); } catch(e) {}
                                    }
                                }
                                if (drop.isHovered && drop.keys2Attacks && drop.keys2Attacks[step]) {
                                    drop.ripples.push({ t: 0, accent });
                                }
                            } else {
                                // Standard keyboard drop (no Keys2): play Keys directly
                                if (drop.keyboardAttacks && drop.keyboardAttacks[step] && drop.keyboardSynth) {
                                    const kNote = drop.keyboardNotes[step];
                                    const kDur = drop.keyboardDurations[step];
                                    if (kNote) {
                                        drop.keyboardSynth.volume.value = baseVol + 8;
                                        try { drop.keyboardSynth.releaseAll(); } catch(e) {}
                                        try { drop.keyboardSynth.triggerAttackRelease(kNote, kDur); } catch(e) {}
                                    }
                                }
                                if (drop.isHovered && drop.keyboardAttacks && drop.keyboardAttacks[step]) {
                                    drop.ripples.push({ t: 0, accent });
                                }
                            }
                            return;
                        }
                        if (drop.instrument === "bass") {
                            // Bass: supporting role (quieter)
                            if (drop.bassAttacks && drop.bassAttacks[step]) {
                                const note = drop.bassNotes ? drop.bassNotes[step] : null;
                                const dur = drop.bassDurations ? drop.bassDurations[step] : "8n";
                                if (note && drop.bassSynth) {
                                    drop.bassSynth.volume.value = drop.guitarSynth ? baseVol - 2 : baseVol + 8;
                                    try {
                                        drop.bassSynth.triggerAttackRelease(note, dur);
                                    } catch (e) { /* ignore */ }
                                }
                            }
                            // Guitar trigger (primary instrument in ADULT)
                            if (drop.guitarAttacks && drop.guitarAttacks[step] && drop.guitarSynth) {
                                const gNote = drop.guitarNotes[step];
                                const gDur = drop.guitarDurations[step];
                                if (gNote) {
                                    drop.guitarSynth.volume.value = baseVol + 10;
                                    try {
                                        if (Array.isArray(gNote)) {
                                            drop.guitarSynth.triggerAttackRelease(gNote, gDur);
                                        } else {
                                            drop.guitarSynth.triggerAttackRelease(gNote, gDur);
                                        }
                                    } catch (e) { /* ignore */ }
                                }
                            }
                            if (drop.isHovered && ((drop.bassAttacks && drop.bassAttacks[step]) || (drop.guitarAttacks && drop.guitarAttacks[step]))) {
                                drop.ripples.push({ t: 0, accent });
                            }
                            return;
                        }
                        if (drop.instrument === "cymbal") {
                            drop.cymbalSynth.volume.value = baseVol - 4;
                            drop.cymbalSynth.triggerAttackRelease("16n");
                            if (drop.isHovered) drop.ripples.push({ t: 0, accent });
                            return;
                        }
                        if (drop.instrument === "snare") {
                            if (drop.snareFilter) {
                                drop.snareFilter.frequency.value = 1200 + accent * 1800 + Math.random() * 260;
                            }
                            // Beat-position boost: louder on beat 1 & 3
                            const beatInBar = Math.floor((step % (baseRhythmInfo.beatsPerBar * STEPS_PER_BEAT)) / STEPS_PER_BEAT);
                            const beatBoostDb = (beatInBar === 0 || beatInBar === 2) ? 7 : 0;
                            drop.snareSynth.volume.value = baseVol + 6 + (drop.snareGainBoostDb || 0) + beatBoostDb;
                            const jitter = (Math.random() * 0.008).toFixed(3);
                            drop.snareSynth.triggerAttackRelease("16n", `+${jitter}`);
                            if (drop.snareBody && (accent >= 0.85 || beatBoostDb > 0)) {
                                drop.snareBody.volume.value = baseVol - 2 + (drop.snareBodyBoostDb || 0) + beatBoostDb;
                                drop.snareBody.triggerAttackRelease("G2", "32n");
                            }
                            if (drop.isHovered) drop.ripples.push({ t: 0, accent });
                            return;
                        }

                        const profile = drop.audioProfile || { pitchMotion:[1,1], rhythmMotion:[1,1], openness:[0,0] };
                        const pitchL = randInt(profile.pitchMotion[0], profile.pitchMotion[1]);
                        const rhythmL = randInt(profile.rhythmMotion[0], profile.rhythmMotion[1]);
                        const opennessL = randInt(profile.openness[0], profile.openness[1]);
                        const freq = 6200 + pitchL * 1200 + Math.random() * 700;
                        drop.hatFilter.frequency.value = freq;
                        const barSteps = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
                        const stepInBar = step % barSteps;
                        const isOpenAccent = (
                            (drop.hatMode === "mixed-open" || opennessL >= 2) &&
                            (stepInBar === barSteps - 2 || stepInBar === barSteps - 1 || (rhythmL >= 2 && stepInBar === 1))
                        );
                        const jitter = rhythmL >= 2 ? (Math.random() * 0.01) : 0;
                        if (isOpenAccent) {
                            drop.hatOpenSynth.volume.value = baseVol - 3;
                            drop.hatOpenSynth.triggerAttackRelease("8n", `+${jitter.toFixed(3)}`);
                        } else {
                            drop.hatClosedSynth.volume.value = baseVol;
                            const dur = rhythmL >= 3 ? "16n" : "32n";
                            drop.hatClosedSynth.triggerAttackRelease(dur, `+${jitter.toFixed(3)}`);
                        }
                        if (drop.isHovered) drop.ripples.push({ t: 0, accent: isOpenAccent ? 1 : 0.7 });
                    });

                    baseGroove.step = (step + 1) % baseRhythmInfo.kickPattern.length;
                    baseGroove.nextTick += baseGroove.stepMs;
                }
                baseGroove.timer = setTimeout(tick, 20);
            };
            tick();
        }

        // 画面外トーン方向インジケーター（マリカ風くの字矢印）
        function drawOffscreenToneArrows() {
            if (!toneDrops.length) return;
            if (currentScene < SCENE.CRAWL || currentScene === SCENE.LESSON) return;

            let hasLeft = false, hasRight = false;
            for (const drop of toneDrops) {
                const sx = drop.x - cameraX;
                if (sx < -20) hasLeft = true;
                if (sx > width + 20) hasRight = true;
                if (hasLeft && hasRight) break;
            }
            if (!hasLeft && !hasRight) return;

            const t = Date.now() * 0.002;
            const pulse = 0.7 + 0.3 * Math.sin(t);
            const drift = Math.sin(t * 1.1) * 3;
            const yCenter = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            const btnC = palette.btnColor;
            const toHsla = (a) => btnC.replace('hsl(', 'hsla(').replace(')', ', ' + a + ')');

            ctx.save();
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';

            // くの字1個を描く（太いストローク、枠線なし）
            const armLen = 28;
            const halfAng = 58 * Math.PI / 180; // 開き約116°
            const adx = armLen * Math.cos(halfAng);
            const ady = armLen * Math.sin(halfAng);

            const drawChevron = (tipX, tipY, dir, alpha) => {
                const ax = tipX + dir * adx;
                const ay1 = tipY - ady;
                const ay2 = tipY + ady;
                // グロー
                ctx.shadowColor = toHsla(alpha * 0.5);
                ctx.shadowBlur = 18;
                ctx.strokeStyle = toHsla(alpha);
                ctx.lineWidth = 7;
                ctx.beginPath();
                ctx.moveTo(ax, ay1);
                ctx.lineTo(tipX, tipY);
                ctx.lineTo(ax, ay2);
                ctx.stroke();
                ctx.shadowBlur = 0;
            };

            // マリカ風: 2個並べる（手前が濃く、奥が薄い）
            const gap = 22;
            const drawSide = (baseX, dir) => {
                drawChevron(baseX,       yCenter, dir, pulse * 0.9);
                drawChevron(baseX + dir * -gap, yCenter, dir, pulse * 0.45);
            };

            if (hasLeft) drawSide(38 - drift, 1);
            if (hasRight) drawSide(width - 38 + drift, -1);

            ctx.restore();
        }

        // === Shared Confirmation Overlay ===
        function drawConfirmationOverlay() {
            if (!adultConfirmation.active) return;
            adultConfirmation.fade += (1 - adultConfirmation.fade) * 0.12;
            const f = adultConfirmation.fade;
            const t = Date.now() * 0.001;

            const drop = adultConfirmation.drop;
            const toneName = drop.activityName || drop.facilityName || "tone";
            const activity = ADULT_ACTIVITIES.find(a => a.name === toneName || a.id === drop.activityId) || getThirtiesActivities(thirtiesHasMarriage).find(a => a.name === toneName || a.id === drop.activityId);
            const toneNameEn = activity ? activity.nameEn : (drop.activityNameEn || drop.facilityName || "tone");
            const toneColor = drop.dropColor || (activity ? activity.color : palette.btnColor);

            // Soft frosted overlay
            ctx.fillStyle = `rgba(245, 243, 238, ${0.55 * f})`;
            ctx.fillRect(0, 0, width, height);

            // Always center the confirmation dialog on screen
            const bx = width / 2;
            const centerY = height * 0.38;

            // Soft radial glow (tone-colored)
            ctx.save();
            ctx.globalAlpha = f * 0.25;
            const auraR = 160 + Math.sin(t * 1.5) * 8;
            const aura = ctx.createRadialGradient(bx, centerY, 0, bx, centerY, auraR);
            aura.addColorStop(0, toneColor);
            aura.addColorStop(1, "rgba(255,255,255,0)");
            ctx.fillStyle = aura;
            ctx.beginPath();
            ctx.arc(bx, centerY, auraR, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();

            // Tone name
            ctx.save();
            ctx.globalAlpha = f;
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";

            ctx.shadowColor = "rgba(255,255,255,0.9)";
            ctx.shadowBlur = 14;
            ctx.fillStyle = "rgba(60, 55, 48, 0.92)";
            ctx.font = "700 22px 'Zen Maru Gothic', sans-serif";
            ctx.fillText(`「${toneName}」`, bx, centerY - 52);

            ctx.shadowBlur = 10;
            ctx.fillStyle = "rgba(100, 95, 85, 0.7)";
            ctx.font = "500 13px 'Zen Maru Gothic', sans-serif";
            ctx.fillText(toneNameEn, bx, centerY - 30);

            ctx.shadowBlur = 8;
            ctx.fillStyle = "rgba(80, 75, 65, 0.85)";
            ctx.font = "500 15px 'Zen Maru Gothic', sans-serif";
            ctx.fillText("このtoneを選びますか？", bx, centerY - 4);
            ctx.fillStyle = "rgba(120, 115, 105, 0.6)";
            ctx.font = "400 11px 'Zen Maru Gothic', sans-serif";
            ctx.fillText("Choose this tone?", bx, centerY + 14);
            ctx.restore();

            // Circular buttons
            const btnR = 30;
            const btnSpacing = 44;
            const yesCenter = { x: bx - btnSpacing, y: centerY + 52 };
            const noCenter = { x: bx + btnSpacing, y: centerY + 52 };

            const drawCircleBtn = (cx, cy, r, label, isYes) => {
                const dx = mouseX - cx, dy = mouseY - cy;
                const isHover = (dx * dx + dy * dy) <= (r + 4) * (r + 4);
                const scale = isHover ? 1.08 + Math.sin(t * 4) * 0.02 : 1.0;
                const sr = r * scale;

                ctx.save();
                ctx.globalAlpha = f;
                ctx.shadowColor = "rgba(0,0,0,0.10)";
                ctx.shadowBlur = 12;
                ctx.shadowOffsetY = 4;
                ctx.fillStyle = isYes ? toneColor : "hsl(30, 10%, 78%)";
                ctx.beginPath();
                ctx.arc(cx, cy, sr, 0, Math.PI * 2);
                ctx.fill();

                ctx.shadowBlur = 0;
                ctx.shadowOffsetY = 0;
                const hi = ctx.createRadialGradient(cx - sr * 0.28, cy - sr * 0.32, 1, cx - sr * 0.16, cy - sr * 0.18, sr * 0.85);
                hi.addColorStop(0, "rgba(255,255,255,0.35)");
                hi.addColorStop(1, "rgba(255,255,255,0)");
                ctx.fillStyle = hi;
                ctx.beginPath();
                ctx.arc(cx, cy, sr - 1, 0, Math.PI * 2);
                ctx.fill();

                ctx.strokeStyle = isHover ? "rgba(255,255,255,1)" : "rgba(255,255,255,0.88)";
                ctx.lineWidth = isHover ? 3.5 : 3;
                ctx.beginPath();
                ctx.arc(cx, cy, sr, 0, Math.PI * 2);
                ctx.stroke();

                ctx.fillStyle = "rgba(255,255,255,0.95)";
                ctx.font = "700 14px 'Zen Maru Gothic', sans-serif";
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";
                ctx.fillText(label, cx, cy + 1);
                ctx.restore();

                return { x: cx - r - 4, y: cy - r - 4, w: (r + 4) * 2, h: (r + 4) * 2 };
            };

            adultConfirmation.yesRect = drawCircleBtn(yesCenter.x, yesCenter.y, btnR, "はい", true);
            adultConfirmation.noRect = drawCircleBtn(noCenter.x, noCenter.y, btnR, "いいえ", false);
        }

        // Render Loop
        function animate() {
            ctx.clearRect(0, 0, width, height);
            // Keep pointer-linked world coordinates in sync even while camera scrolls.
            const isJobHuntSideScroll = (currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2) && jobHuntViewMode === "sidescroll";
            if (isTopDownScene && isJobHuntSideScroll) {
                // Side-scroll mode uses cameraX like normal side-scroll scenes
                orbWorldX = mouseX + cameraX;
                orbWorldY = mouseY;
            } else if (isTopDownScene) {
                if (currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.CITY) {
                    updateTopDownCamera();
                    topDownOffsetX = worldWidth <= width ? (width - worldWidth) / 2 : -topDownCameraX;
                    topDownOffsetY = worldHeight <= height ? (height - worldHeight) / 2 : -topDownCameraY;
                } else {
                    topDownOffsetX = (width - worldWidth) / 2;
                    topDownOffsetY = (height - worldHeight) / 2;
                }
                // Account for camera zoom when converting mouse to world coords
                if ((currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2) && jobHuntCameraZoom !== 1.0 && baby) {
                    const z = jobHuntCameraZoom;
                    const bsx = baby.x + topDownOffsetX;
                    const bsy = baby.y + topDownOffsetY;
                    orbWorldX = (mouseX - bsx) / z + bsx - topDownOffsetX;
                    orbWorldY = (mouseY - bsy) / z + bsy - topDownOffsetY;
                } else {
                    orbWorldX = mouseX - topDownOffsetX;
                    orbWorldY = mouseY - topDownOffsetY;
                }
            } else if (currentScene >= SCENE.CRAWL) {
                orbWorldX = mouseX + cameraX;
                orbWorldY = mouseY;
            } else {
                orbWorldX = mouseX;
                orbWorldY = mouseY;
            }
            updateScoreToggleUi();

            // 1. Draw Background (Different per scene)
            if (currentScene === SCENE.LESSON) {
                // 授業フェーズ: toneなし、選択肢なし、HUDなし
                drawLessonScene();
            } else if (currentScene === SCENE.ENTERTAINMENT && slotMachine.active) {
                updateSlotMachineReels();
                drawSlotMachineScene(ctx);
                drawSlotLabelAnimations(ctx);
            } else if (isTopDownScene) {
                // 見下ろし型2D scenes (PART_TIME, JOB_HUNT, JOB_HUNT2)
                updateToneDropProximity();
                updateModifierTonePreview();
                updateScoreHudPreviewRow();

                if (baby && !isMinigameActive) {
                    if (isJobHuntSideScroll) {
                        baby.update(orbWorldX);
                        // Check exit trigger: walk to left door to leave
                        if (!jobHuntTransitioning && baby.x < 30) {
                            triggerJobHuntExitInterview();
                        }
                    } else {
                        baby.updateTopDown(orbWorldX, orbWorldY);
                        // CITY: family followers updateTopDown
                        if (currentScene === SCENE.CITY) {
                            if (thirtiesSpouse) {
                                thirtiesSpouse.updateTopDown(baby.x - 40, baby.y);
                            }
                            if (thirtiesKid) {
                                const kidTargetX = thirtiesSpouse ? thirtiesSpouse.x - 35 : baby.x - 70;
                                thirtiesKid.updateTopDown(kidTargetX, baby.y);
                            }
                        }
                    }
                }

                if (isJobHuntSideScroll) {
                    // === SIDE-SCROLL RENDERING ===
                    updateJobHuntSideScrollCamera();
                    ctx.save();
                    ctx.translate(-cameraX, 0);
                    drawJobHuntSideScrollBg();
                    drawToneDrops();
                    if (baby) baby.draw(ctx);
                    ctx.restore();
                } else {
                    // === EXISTING TOP-DOWN RENDERING ===
                    // Dark grey margins
                    ctx.fillStyle = "#2a2a2a";
                    ctx.fillRect(0, 0, width, height);

                    ctx.save();
                    // Apply job hunt camera zoom (scale around baby's screen position)
                    if ((currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2) && jobHuntCameraZoom !== 1.0) {
                        const z = jobHuntCameraZoom;
                        const babyScreenX = baby ? baby.x + topDownOffsetX : width / 2;
                        const babyScreenY = baby ? baby.y + topDownOffsetY : height / 2;
                        ctx.translate(babyScreenX, babyScreenY);
                        ctx.scale(z, z);
                        ctx.translate(-babyScreenX, -babyScreenY);
                    }
                    ctx.translate(topDownOffsetX, topDownOffsetY);
                    // Clip to world bounds
                    ctx.beginPath();
                    ctx.rect(0, 0, worldWidth, worldHeight);
                    ctx.clip();

                    if (currentScene === SCENE.PART_TIME) {
                        drawPartTimeBackground();
                    } else if (currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2) {
                        drawJobHuntBackground();
                    } else if (currentScene === SCENE.CITY) {
                        drawCityBackground();
                    }
                    drawToneDrops();
                    // CITY: family followers draw
                    if (currentScene === SCENE.CITY) {
                        if (thirtiesKid) thirtiesKid.drawTopDown(ctx, thirtiesKid.walkCycle);
                        if (thirtiesSpouse) thirtiesSpouse.drawTopDown(ctx, thirtiesSpouse.walkCycle);
                    }
                    if (baby) baby.drawTopDown(ctx, baby.walkCycle);
                    ctx.restore();
                }

                // Second interview pass text overlay
                if (secondInterviewText && secondInterviewText.alpha > 0) {
                    ctx.save();
                    const stAlpha = secondInterviewText.alpha;
                    const stScale = secondInterviewText.scale;
                    const shimmer = secondInterviewText.shimmer || 0;
                    const cx = width / 2, cy = height / 2;

                    // Background dim overlay
                    ctx.globalAlpha = stAlpha * 0.35;
                    ctx.fillStyle = "#000";
                    ctx.fillRect(0, 0, width, height);

                    // Sparkle particles
                    if (secondInterviewText.sparkles) {
                        secondInterviewText.sparkles.forEach(s => {
                            if (s.life <= 0) return;
                            ctx.globalAlpha = s.life * stAlpha;
                            ctx.fillStyle = `hsl(${s.hue}, 85%, 70%)`;
                            ctx.beginPath();
                            ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
                            ctx.fill();
                            // Star sparkle cross
                            ctx.strokeStyle = `hsla(${s.hue}, 90%, 80%, ${s.life * 0.6})`;
                            ctx.lineWidth = 1;
                            const len = s.size * 1.5;
                            ctx.beginPath();
                            ctx.moveTo(s.x - len, s.y); ctx.lineTo(s.x + len, s.y);
                            ctx.moveTo(s.x, s.y - len); ctx.lineTo(s.x, s.y + len);
                            ctx.stroke();
                        });
                    }

                    // Gold glow behind text
                    ctx.globalAlpha = stAlpha * 0.5;
                    const glowR = 140 * stScale;
                    const glow = ctx.createRadialGradient(cx, cy - 10, 0, cx, cy - 10, glowR);
                    glow.addColorStop(0, "rgba(255,210,80,0.6)");
                    glow.addColorStop(0.5, "rgba(255,180,50,0.2)");
                    glow.addColorStop(1, "rgba(255,180,50,0)");
                    ctx.fillStyle = glow;
                    ctx.fillRect(cx - glowR, cy - 10 - glowR, glowR * 2, glowR * 2);

                    // Main Japanese text
                    ctx.globalAlpha = stAlpha;
                    ctx.textAlign = "center";
                    ctx.textBaseline = "middle";
                    const fontSize = Math.round(42 * stScale);
                    ctx.font = `900 ${fontSize}px 'Zen Maru Gothic', sans-serif`;
                    // Gold gradient text
                    const shimOff = Math.sin(shimmer * 0.05) * 20;
                    const textGrad = ctx.createLinearGradient(cx - 150 + shimOff, cy - 20, cx + 150 + shimOff, cy + 20);
                    textGrad.addColorStop(0, "#ffe082");
                    textGrad.addColorStop(0.3, "#fff8e1");
                    textGrad.addColorStop(0.5, "#ffd54f");
                    textGrad.addColorStop(0.7, "#fff8e1");
                    textGrad.addColorStop(1, "#ffca28");
                    ctx.fillStyle = textGrad;
                    ctx.shadowColor = "rgba(255,180,50,0.9)";
                    ctx.shadowBlur = 30;
                    ctx.fillText(secondInterviewText.textJa || "", cx, cy - 14);
                    // Stroke outline for readability
                    ctx.shadowBlur = 0;
                    ctx.strokeStyle = "rgba(180,120,20,0.35)";
                    ctx.lineWidth = 1.5;
                    ctx.strokeText(secondInterviewText.textJa || "", cx, cy - 14);

                    // English subtitle
                    ctx.shadowColor = "rgba(255,200,100,0.6)";
                    ctx.shadowBlur = 12;
                    const enSize = Math.round(18 * stScale);
                    ctx.font = `600 ${enSize}px 'Zen Maru Gothic', sans-serif`;
                    ctx.fillStyle = "rgba(255,245,220,0.9)";
                    ctx.fillText(secondInterviewText.textEn || "", cx, cy + 24);
                    ctx.restore();
                }

                // === Adult Confirmation UI Overlay (top-down scenes) ===
                drawConfirmationOverlay();

                drawToyStatsHud();
                drawCumulativeStatsHud();
                drawLabelAnimations(ctx);
            } else if (currentScene === SCENE.CRAWL || currentScene === SCENE.CRAWL2 || currentScene === SCENE.TODDLE1 || currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.TRAVEL || currentScene === SCENE.THIRTIES) {
                // Skip audio and movement if confirmation dialog or travel still is active
                if (!adultConfirmation.active && !travelStill.active) {
                    updateToneDropProximity();
                }
                updateScoreHudPreviewRow();

                if (baby) {
                    if (!isMinigameActive && !adultConfirmation.active && !travelStill.active) {
                        baby.update(orbWorldX);
                        // THIRTIES: family followers
                        if (currentScene === SCENE.THIRTIES && thirtiesSpouse) {
                            thirtiesSpouse.update(baby.x - 55);
                            thirtiesSpouse.y = baby.y;
                        }
                        if (currentScene === SCENE.THIRTIES && thirtiesKid) {
                            thirtiesKid.update(thirtiesSpouse ? thirtiesSpouse.x - 45 : baby.x - 80);
                            thirtiesKid.y = baby.y;
                        }
                        // THIRTIES: left-edge exit transition
                        if (currentScene === SCENE.THIRTIES && thirtiesMelodyConfirmed
                            && !thirtiesChoiceTransitioning && baby.x < worldWidth * 0.03) {
                            thirtiesChoiceTransitioning = true;
                            fadeScreenTo(1, 1400);
                            setTimeout(() => {
                                startCityPhase();
                            }, 1400);
                        }
                    }
                    if (!travelStill.active) updateCamera();
                }

                // Global visuals update
                envEffects.update(baseRhythmBpm);

                if (currentScene === SCENE.TRAVEL && !travelStill.active) {
                    const groundY = height * 0.55;

                    // A. Sky, Sun & Background
                    drawTravelSky(ctx, groundY);
                    drawTravelSun(ctx, groundY);
                    drawTravelBackMountains(ctx, groundY);

                    // B. Landscape (left/right separated)
                    drawTravelSeaArea(ctx, groundY);
                    drawTravelLeftLandscape(ctx, groundY);
                    drawTravelRightLandscape(ctx, groundY);
                    drawTravelAutumnTrees(ctx, groundY, false);

                    // C. Track & Infrastructure
                    drawTravelTrack(ctx, groundY);
                    drawTravelOverhead(ctx, groundY);
                    drawTravelCentralStation(ctx, groundY, false);

                    // D. Train
                    if (baby) baby.draw(ctx, groundY);

                    // E. Tone Drops
                    ctx.save();
                    ctx.translate(-cameraX, 0);
                    drawToneDrops();
                    ctx.restore();

                    // F. Foreground layers
                    drawTravelAutumnTrees(ctx, groundY, true);
                    drawTravelCentralStation(ctx, groundY, true);
                } else if (travelStill.active) {
                    // Still is rendering — skip all background drawing
                } else {
                    // EXISTING NON-TRAVEL RENDERING
                    ctx.save();
                    ctx.translate(-cameraX, 0);
                    if (currentScene === SCENE.THIRTIES) {
                        drawThirtiesBackground(ctx);
                    } else if (currentScene === SCENE.UNIVERSITY) {
                        drawUniversityBackground();
                    } else if (currentScene === SCENE.ADULT) {
                        drawAdultBackground();
                    } else if (currentScene === SCENE.CHILD2) {
                        drawSchoolBackground();
                    } else if (currentScene === SCENE.CHILD1) {
                        drawChildBackground();
                    } else {
                        drawCrawlBackground();
                    }
                    
                    envEffects.draw(ctx, cameraX);
                    drawToneDrops();
                    // Draw order: kid (back) → spouse (middle) → baby (front)
                    if (currentScene === SCENE.THIRTIES) {
                        if (thirtiesKid) thirtiesKid.draw(ctx);
                        if (thirtiesSpouse) thirtiesSpouse.draw(ctx);
                    }
                    if (baby) baby.draw(ctx);
                    ctx.restore();
                }

                // THIRTIES: "go outside" prompt (screen coordinates, after camera restore)
                if (currentScene === SCENE.THIRTIES && thirtiesMelodyConfirmed) {
                    const promptAlpha = 0.5 + 0.3 * Math.sin(Date.now() * 0.003);
                    ctx.save();
                    ctx.globalAlpha = promptAlpha;
                    ctx.fillStyle = "#5a4a3a";
                    ctx.font = "bold 1.1rem 'Zen Maru Gothic', sans-serif";
                    ctx.textAlign = "center";
                    ctx.fillText("← 外に出ましょう", width / 2, height * 0.28);
                    ctx.font = "0.75rem 'Zen Maru Gothic', sans-serif";
                    ctx.fillStyle = "#9a8a7a";
                    ctx.fillText("Let's go outside ←", width / 2, height * 0.28 + 22);
                    ctx.restore();
                }

                // === Adult Confirmation UI Overlay ===
                drawConfirmationOverlay();

                // === Travel Still Overlay ===
                if (travelStill.active) {
                    travelStill.progress = Math.min(1, (Date.now() - travelStill.startTime) / travelStill.duration);
                    if (travelStill.type === "sea") {
                        drawSeaStill(ctx, travelStill.progress);
                    } else if (travelStill.type === "mountain") {
                        drawMountainStill(ctx, travelStill.progress);
                    }
                    // After fully drawn + 2s hold, fade out → next phase
                    if (travelStill.progress >= 1 && !travelStill.endScheduled) {
                        travelStill.endScheduled = true;
                        setTimeout(() => {
                            // Fade out audio over 1.4s alongside visual fade
                            if (travelStillAudio) {
                                const audio = travelStillAudio;
                                const fadeStart = audio.volume;
                                const fadeSteps = 28;
                                const fadeInterval = 1400 / fadeSteps;
                                let step = 0;
                                const audioFade = setInterval(() => {
                                    step++;
                                    audio.volume = Math.max(0, fadeStart * (1 - step / fadeSteps));
                                    if (step >= fadeSteps) {
                                        clearInterval(audioFade);
                                        audio.pause();
                                        audio.src = '';
                                    }
                                }, fadeInterval);
                                travelStillAudio = null;
                            }
                            fadeScreenTo(1, 1400);
                            setTimeout(() => {
                                travelStill.active = false;
                                // Restore score HUD
                                const scoreHud = document.getElementById('score-hud');
                                if (scoreHud) scoreHud.style.display = '';
                                startThirtiesPhase();
                                fadeScreenTo(0, 1300);
                            }, 1400);
                        }, 2000);
                    }
                }

                drawToyStatsHud();
                drawCumulativeStatsHud();
                drawLabelAnimations(ctx);
                drawOffscreenToneArrows();
            } else {
                // Title/Choice Background
                ctx.fillStyle = palette.bg;
                ctx.fillRect(0, 0, width, height);
                blobs.forEach(b => { b.update(); b.draw(ctx); });
            }

            // 2b-2d: Skip orb/particles/hover during lesson phase
            if (currentScene === SCENE.LESSON) {
                orbEl.style.opacity = '0';
                drawLabelAnimations(ctx);
            } else if (currentScene === SCENE.ENTERTAINMENT && slotMachine.active) {
                // Show orb as cursor during slot machine
                orbEl.style.left = mouseX + 'px';
                orbEl.style.top = mouseY + 'px';
                orbEl.style.opacity = '1';
            } else {
                updateAndDrawOrbParticles();
                updateOrbScreenPosition();
                if (hoverInfoEl) hoverInfoEl.classList.remove('visible');
            }

            // 3. Update Audio (Proximity)
            if (currentScene === SCENE.CHOICE) {
                updateProximityAudio();
            }
            if (activeMinigame) {
                const rect = minigameCanvas.getBoundingClientRect();
                // 表示サイズと内部解像度の比率を計算（ズレを完全に解消）
                const scaleX = minigameCanvas.width / rect.width;
                const scaleY = minigameCanvas.height / rect.height;
                const minigameMouseX = (mouseX - rect.left) * scaleX;
                const minigameMouseY = (mouseY - rect.top) * scaleY;

                activeMinigame.update(minigameMouseX, minigameMouseY);
                if (activeMinigame) {
                    activeMinigame.draw();
                    // When finished/failed: remove quit button, enable click-to-close after brief delay
                    if ((activeMinigame.state === 'finished' || activeMinigame.state === 'failed') && !activeMinigame._resultSetup) {
                        activeMinigame._resultSetup = true;
                        activeMinigame._resultClickReady = false;
                        const btn = document.getElementById('minigame-quit-btn');
                        if (btn) btn.remove();
                        // Brief delay so result screen is visible before accepting clicks
                        setTimeout(() => { if (activeMinigame) activeMinigame._resultClickReady = true; }, 1500);
                    }
                    // Draw "click to continue" hint on result screen
                    if (activeMinigame._resultClickReady && minigameCtx) {
                        const mc = minigameCtx;
                        const cw = minigameCanvas.width, ch = minigameCanvas.height;
                        mc.save();
                        mc.fillStyle = `rgba(255,255,255,${0.5 + 0.3 * Math.sin(Date.now() * 0.004)})`;
                        mc.font = "600 16px 'Zen Maru Gothic', sans-serif";
                        mc.textAlign = "center"; mc.textBaseline = "bottom";
                        mc.fillText("クリックして教室に戻る", cw / 2, ch - 30);
                        mc.restore();
                    }
                }
            }
            requestAnimationFrame(animate);
        }

        // ==========================================
        // Interactions & Audio Logic
        // ==========================================
        
        const uiTitle = document.getElementById('title-group');
        const uiChoice = document.getElementById('choice-group');
        const startBtn = document.getElementById('start-btn');
        const btnLeft = document.getElementById('btn-left');
        const btnMiddle = document.getElementById('btn-middle');
        const btnRight = document.getElementById('btn-right');
        const btnFast = document.getElementById('btn-fast');
        const sceneFade = document.getElementById('scene-fade');
        const scoreHud = document.getElementById('score-hud');
        const scoreTracks = document.getElementById('score-tracks');
        const scoreMeta = document.getElementById('score-meta');
        const scoreToggleBtn = document.getElementById('score-toggle-btn');
        const settingsBtn = document.getElementById('settings-btn');
        const settingsPanel = document.getElementById('settings-panel');
        const settingsTracksEl = document.getElementById('settings-tracks');
        const settingsCloseBtn = document.getElementById('settings-close-btn');
        const minigameWrapper = document.getElementById('minigame-wrapper');
        const minigameCanvas = document.getElementById('minigame-canvas');
        const minigameCtx = minigameCanvas ? minigameCanvas.getContext('2d') : null;

        // ======== VOLUME MANAGEMENT SYSTEM ========
        function addVolumeTrack(trackId) {
            if (volumeState[trackId]) return; // already added
            const info = VOLUME_TRACKS.find(t => t.id === trackId);
            if (!info) return;
            const row = document.createElement('div');
            row.className = 'vol-row';
            row.dataset.track = trackId;
            row.innerHTML =
                '<button class="vol-mute-btn" title="Mute">\u266A</button>' +
                '<span class="vol-label">' + info.label + '</span>' +
                '<button class="vol-dec-btn">\u25C1</button>' +
                '<div class="vol-bar-wrap"><div class="vol-bar-fill"></div><div class="vol-bar-thumb"></div></div>' +
                '<button class="vol-inc-btn">\u25B7</button>' +
                '<span class="vol-pct">80%</span>';
            settingsTracksEl.appendChild(row);
            const st = { volume: 80, muted: false, el: row };
            volumeState[trackId] = st;

            const fill = row.querySelector('.vol-bar-fill');
            const thumb = row.querySelector('.vol-bar-thumb');
            const pct = row.querySelector('.vol-pct');
            fill.style.background = info.color;
            fill.style.width = '80%';
            thumb.style.left = '80%';

            function updateBarUI() {
                fill.style.width = st.volume + '%';
                thumb.style.left = st.volume + '%';
                pct.textContent = st.volume + '%';
            }
            function setVol(v) {
                st.volume = Math.max(0, Math.min(100, Math.round(v)));
                updateBarUI();
                applyTrackVolume(trackId);
            }
            // Mute button
            row.querySelector('.vol-mute-btn').addEventListener('click', function(e) {
                e.stopPropagation();
                st.muted = !st.muted;
                row.classList.toggle('muted', st.muted);
                applyTrackVolume(trackId);
            });
            // Dec / Inc
            row.querySelector('.vol-dec-btn').addEventListener('click', function(e) { e.stopPropagation(); setVol(st.volume - 5); });
            row.querySelector('.vol-inc-btn').addEventListener('click', function(e) { e.stopPropagation(); setVol(st.volume + 5); });
            // Bar drag
            const barWrap = row.querySelector('.vol-bar-wrap');
            let dragging = false;
            function barPos(e) {
                const rect = barWrap.getBoundingClientRect();
                const clientX = e.touches ? e.touches[0].clientX : e.clientX;
                return Math.max(0, Math.min(100, (clientX - rect.left) / rect.width * 100));
            }
            function onDown(e) {
                e.preventDefault(); e.stopPropagation();
                dragging = true;
                setVol(barPos(e));
            }
            function onMove(e) {
                if (!dragging) return;
                e.preventDefault();
                setVol(barPos(e));
            }
            function onUp() { dragging = false; }
            barWrap.addEventListener('mousedown', onDown);
            barWrap.addEventListener('touchstart', onDown, { passive: false });
            window.addEventListener('mousemove', onMove);
            window.addEventListener('touchmove', onMove, { passive: false });
            window.addEventListener('mouseup', onUp);
            window.addEventListener('touchend', onUp);

            // Apply initial volume
            applyTrackVolume(trackId);
        }

        function applyTrackVolume(trackId) {
            const st = volumeState[trackId];
            if (!st) return;
            const vol = st.muted ? 0 : st.volume;
            const apply = function(synth, defaultDb) {
                if (!synth) return;
                const db = vol === 0 ? -100 : defaultDb + (vol - 100) * 0.5;
                synth.volume.value = db;
            };
            switch (trackId) {
                case 'kick':
                    if (baseGroove && baseGroove.kickSynth) apply(baseGroove.kickSynth, -8);
                    break;
                case 'hat':
                    if (carryHatSynth) apply(carryHatSynth, inheritedHatVolumeDb);
                    break;
                case 'snare':
                    if (carrySnareSynth) apply(carrySnareSynth, inheritedSnareVolumeDb);
                    if (carrySnareBody) apply(carrySnareBody, inheritedSnareBodyVolumeDb);
                    break;
                case 'cymbal':
                    if (carryCymbalSynth) apply(carryCymbalSynth, inheritedCymbalVolumeDb);
                    break;
                case 'bass':
                    if (carryBassSynth) apply(carryBassSynth, -16);
                    toneDrops.forEach(function(d) { if (d.bassSynth) apply(d.bassSynth, -16); });
                    break;
                case 'keyboard':
                    if (carryKeyboardSynth) apply(carryKeyboardSynth, -22);
                    break;
                case 'keys2':
                    if (carryKeys2Synth) apply(carryKeys2Synth, -22);
                    break;
                case 'lead':
                    if (carryLeadSynth) apply(carryLeadSynth, -12);
                    break;
                case 'texture':
                    toneDrops.forEach(function(d) { if (d.cityTexture && d.keyboardSynth) apply(d.keyboardSynth, -22); });
                    break;
            }
        }

        // Settings button events
        settingsBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            settingsPanelOpen = !settingsPanelOpen;
            settingsPanel.classList.toggle('hidden', !settingsPanelOpen);
        });
        settingsCloseBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            settingsPanelOpen = false;
            settingsPanel.classList.add('hidden');
        });
        // Prevent clicks inside panel from closing it / propagating
        settingsPanel.addEventListener('click', function(e) { e.stopPropagation(); });
        settingsPanel.addEventListener('mousedown', function(e) { e.stopPropagation(); });
        settingsPanel.addEventListener('touchstart', function(e) { e.stopPropagation(); });
        // Close settings panel when clicking outside
        document.addEventListener('click', function() {
            if (settingsPanelOpen) {
                settingsPanelOpen = false;
                settingsPanel.classList.add('hidden');
            }
        });

        function fadeScreenTo(opacity, durationMs) {
            sceneFade.style.transition = `opacity ${durationMs}ms ease`;
            sceneFade.style.opacity = String(opacity);
            // Hide settings during white-screen fade
            if (opacity >= 1) {
                settingsBtn.style.display = 'none';
                if (settingsPanelOpen) {
                    settingsPanelOpen = false;
                    settingsPanel.classList.add('hidden');
                }
            }
        }

        async function ensureAudioReady() {
            try {
                await Tone.start();
                if (Tone.context.state !== 'running') {
                    await Tone.context.resume();
                }
            } catch (err) {
                // Keep gameplay progression even if browser autoplay policy warns.
                console.warn('Audio resume skipped:', err);
            }
        }

        function setScoreHudVisible(visible) {
            scoreHud.classList.toggle('visible', visible);
        }

        function updateScoreToggleUi() {
            const available = (currentScene === SCENE.CRAWL || currentScene === SCENE.CRAWL2 || currentScene === SCENE.TODDLE1 || currentScene === SCENE.CHILD1 || currentScene === SCENE.CHILD2 || currentScene === SCENE.ADULT || currentScene === SCENE.UNIVERSITY || currentScene === SCENE.PART_TIME || currentScene === SCENE.JOB_HUNT || currentScene === SCENE.JOB_HUNT2 || currentScene === SCENE.TRAVEL || currentScene === SCENE.THIRTIES || currentScene === SCENE.CITY) && !!baseRhythmInfo;
            scoreToggleBtn.classList.remove('visible');
            setScoreHudVisible(available);
            // Settings button: visible only during gameplay scenes
            settingsBtn.style.display = available ? '' : 'none';
            if (!available && settingsPanelOpen) {
                settingsPanelOpen = false;
                settingsPanel.classList.add('hidden');
            }
        }

        function withAlpha(hslColor, alpha) {
            const m = hslColor.match(/hsl\(([^)]+)\)/i);
            if (!m) return `rgba(255,255,255,${alpha})`;
            return `hsla(${m[1]}, ${alpha})`;
        }

        function applyScoreHudTheme() {
            const accentA = floorColor || palette.colors[2];
            const accentB = babyColorScheme.body || palette.colors[0];
            const accentC = babyColorScheme.limb || palette.colors[1];
            scoreHud.style.setProperty('--score-bg-a', withAlpha(accentA, 0.32));
            scoreHud.style.setProperty('--score-bg-b', withAlpha(accentB, 0.24));
            scoreHud.style.setProperty('--score-step-off', withAlpha(accentB, 0.24));
            scoreHud.style.setProperty('--score-step-kick', withAlpha(accentC, 1));
            scoreHud.style.setProperty('--score-step-hat', withAlpha(accentA, 0.98));
            scoreHud.style.setProperty('--score-step-hat-dense', withAlpha(palette.btnColor, 0.98));
            scoreHud.style.setProperty('--score-playhead', withAlpha(babyColorScheme.skin, 0.98));
        }

        function renderScoreRows(previewDropIndex = null) {
            if (!baseRhythmInfo) return;
            const isChild = currentScene === SCENE.CHILD1;
            const isChild2 = currentScene === SCENE.CHILD2;
            const isAdult = currentScene === SCENE.ADULT;
            const isUniversity = currentScene === SCENE.UNIVERSITY;
            const isPartTime = currentScene === SCENE.PART_TIME;
            const isJobHunt = currentScene === SCENE.JOB_HUNT;
            const isJobHunt2 = currentScene === SCENE.JOB_HUNT2;
            const isTravel = currentScene === SCENE.TRAVEL;
            const isThirties = currentScene === SCENE.THIRTIES;
            const isCity = currentScene === SCENE.CITY;
            const isPostAdult = isUniversity || isPartTime || isJobHunt || isJobHunt2 || isTravel || isThirties || isCity;
            const rows = [];
            let chordRow = null;

            // Pagination support for JOB_HUNT2, TRAVEL, and THIRTIES
            const usePagination = (isJobHunt2 || isTravel || isThirties || isCity) && scoreHudState.pageCount > 1;
            const displayPage = scoreHudState.currentPage;
            const pageOffset = usePagination ? displayPage * scoreHudState.stepsPerPage : 0;
            const displaySteps = usePagination ? scoreHudState.stepsPerPage : null; // null = show all
            const slicePage = (arr) => {
                if (!arr || !usePagination) return arr;
                return arr.slice(pageOffset, pageOffset + scoreHudState.stepsPerPage);
            };

            // --- PREVIEW ROW LOGIC (Hovering a Tone Drop) ---
            // --- PREVIEW ROW LOGIC (Hovering a Tone Drop) ---
            // THIRTIES timbre drops have no sound — skip preview rows for them
            if (previewDropIndex !== null && toneDrops[previewDropIndex] && toneDrops[previewDropIndex].instrument !== "timbre" && toneDrops[previewDropIndex].instrument !== "melody") {
                const preview = toneDrops[previewDropIndex];
                const isCymbal = preview.instrument === "cymbal";
                const isSnare = preview.instrument === "snare";
                const isChord = preview.instrument === "chord";
                const isBass = preview.instrument === "bass" || preview.instrument === "keyboard";
                const isModifier = preview.instrument === "modifier";

                if (isBass) {
                    if (isTravel && preview.keys2Pattern) {
                        // TRAVEL: only show Keys2 preview (Keys is already inherited)
                        rows.push({
                            label: 'Keys2',
                            pattern: slicePage(preview.keys2Pattern),
                            styleClass: 'bass',
                            sustainType: slicePage(preview.keys2SustainType || null)
                        });
                    } else {
                        const kbLabel = preview.cityTexture ? 'Texture' : (preview.instrument === "keyboard" ? 'Keys' : (preview.activityName || 'Bass'));
                        rows.push({
                            label: kbLabel,
                            pattern: slicePage(preview.pattern),
                            styleClass: 'bass',
                            sustainType: slicePage(preview.keyboardSustainType || preview.bassSustainType || null)
                        });
                    }
                } else if (isChord && isChild && preview.chordProgression) {
                    chordRow = {
                        side: preview.chordSide,
                        chords: preview.chordProgression.chords
                    };
                } else if (!isChord && !isModifier) {
                    const instrLabel = isCymbal ? 'Cymbal' : (isSnare ? 'Snare' : 'Hat');
                    const instrStyle = isCymbal ? (preview.hudStyleClass || 'cymbal') :
                        (isSnare ? (preview.hudStyleClass || 'snare') : (previewDropIndex >= 2 ? 'hat-dense' : 'hat'));
                    rows.push({
                        label: preview.toy?.name || `${instrLabel} ${previewDropIndex + 1}`,
                        pattern: slicePage(preview.pattern),
                        styleClass: instrStyle
                    });
                }
            }

            // --- INHERITED ROWS LOGIC (The sounds the user already has) ---
            if ((isThirties || isCity) && leadPattern) {
                rows.push({ label: 'Lead', pattern: slicePage(leadPattern), styleClass: 'lead', sustainType: slicePage(leadSustainType || null) });
            }
            if ((isPartTime || isJobHunt || isJobHunt2 || isTravel || isThirties || isCity) && inheritedKeys2Pattern) {
                rows.push({ label: 'Keys2', pattern: slicePage(inheritedKeys2Pattern), styleClass: 'bass', sustainType: slicePage(inheritedKeys2SustainType || null) });
            }
            if ((isUniversity || isPartTime || isJobHunt || isJobHunt2 || isTravel || isThirties || isCity) && inheritedKeyboardPattern) {
                rows.push({ label: 'Keys', pattern: slicePage(inheritedKeyboardPattern), styleClass: 'bass', sustainType: slicePage(inheritedKeyboardSustainType || null) });
            }
            if ((isAdult || isPostAdult) && inheritedBassPattern) {
                rows.push({
                    label: 'Bass',
                    pattern: slicePage(inheritedBassPattern),
                    styleClass: inheritedBassStyleClass || 'bass',
                    sustainType: slicePage(inheritedBassSustainType || null)
                });
            }
            if ((isChild || isChild2 || isAdult || isPostAdult) && inheritedCymbalPattern) {
                rows.push({ label: 'Cymbal', pattern: slicePage(inheritedCymbalPattern), styleClass: inheritedCymbalStyleClass || 'cymbal' });
            }
            if ((currentScene === SCENE.TODDLE1 || isChild || isChild2 || isAdult || isPostAdult) && inheritedSnarePattern) {
                rows.push({ label: 'Snare', pattern: slicePage(inheritedSnarePattern), styleClass: inheritedSnareStyleClass || 'snare' });
            }
            if (currentScene === SCENE.CRAWL2 || currentScene === SCENE.TODDLE1 || isChild || isChild2 || isAdult || isPostAdult) {
                const carryPattern = inheritedHatPattern || baseRhythmInfo.baseHatPattern;
                if (carryPattern) {
                    rows.push({ label: 'Hat', pattern: slicePage(carryPattern), styleClass: inheritedHatStyleClass || 'hat' });
                }
            }
            // Keep kick as the bottom-most permanent row.
            rows.push({ label: 'Kick', pattern: slicePage(baseRhythmInfo.kickPattern), styleClass: 'kick' });

            scoreTracks.innerHTML = '';
            scoreHudState.rows = [];
            scoreHudState.chordCells = null;
            scoreHudState.barLabelCells = null;
            scoreHudState.paginationEl = null;
            const effectiveSteps = displaySteps || baseRhythmInfo.kickPattern.length;
            // For pagination, totalSteps reflects the full loop length for audio,
            // but display uses stepsPerPage
            scoreHudState.totalSteps = baseRhythmInfo.kickPattern.length;
            scoreHudState.currentStep = -1;
            const displayTotal = usePagination ? scoreHudState.stepsPerPage : scoreHudState.totalSteps;
            const beatSpan = (100 * STEPS_PER_BEAT) / displayTotal;
            const barSpan = (100 * STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar) / displayTotal;
            scoreTracks.style.setProperty('--steps', String(displayTotal));
            scoreTracks.style.setProperty('--beat-span', `${beatSpan}%`);
            scoreTracks.style.setProperty('--bar-span', `${barSpan}%`);

            // Chord row (CHILD1 hover only — interactive preview)
            if (chordRow) {
                const chordRowEl = document.createElement('div');
                chordRowEl.className = 'score-row';
                const chordLabel = document.createElement('div');
                chordLabel.className = 'score-label';
                chordLabel.textContent = 'Chord';
                const chordGrid = document.createElement('div');
                chordGrid.className = 'score-grid-chord';
                chordGrid.style.gridTemplateColumns = `repeat(${baseRhythmInfo.bars}, 1fr)`;
                const chordCells = [];
                for (let i = 0; i < baseRhythmInfo.bars; i++) {
                    const cell = document.createElement('div');
                    cell.className = 'score-chord-cell';
                    const chordFac = CHILD_FACILITIES.find(f => f.id === chordRow.side);
                    cell.classList.add(chordFac && chordFac.chordMode === 'major' ? 'chord-kg' : 'chord-home');
                    cell.textContent = chordRow.chords[i % chordRow.chords.length];
                    chordCells.push(cell);
                    chordGrid.appendChild(cell);
                }
                chordRowEl.appendChild(chordLabel);
                chordRowEl.appendChild(chordGrid);
                scoreTracks.appendChild(chordRowEl);
                scoreHudState.chordCells = chordCells;
            }

            // Chord name bar labels (CHILD2+/ADULT/post-adult: show chord names above each bar)
            if ((isChild2 || isAdult || isPostAdult) && inheritedChordProgression) {
                const barLabelRow = document.createElement('div');
                barLabelRow.className = 'score-bar-labels';
                const barLabelLeft = document.createElement('div');
                barLabelLeft.className = 'score-label';
                barLabelLeft.textContent = '';
                barLabelRow.appendChild(barLabelLeft);
                const barLabelGrid = document.createElement('div');
                barLabelGrid.className = 'score-bar-label-grid';
                barLabelGrid.style.gridTemplateColumns = `repeat(${baseRhythmInfo.bars}, 1fr)`;
                const chordNames = inheritedChordProgression.chords;
                const barLabelCells = [];
                for (let i = 0; i < baseRhythmInfo.bars; i++) {
                    const lbl = document.createElement('div');
                    lbl.className = 'score-bar-label';
                    lbl.textContent = chordNames[i % chordNames.length];
                    barLabelCells.push(lbl);
                    barLabelGrid.appendChild(lbl);
                }
                barLabelRow.appendChild(barLabelGrid);
                scoreTracks.appendChild(barLabelRow);
                scoreHudState.barLabelCells = barLabelCells;
            }

            // Drum rows (wrapped in drum-block for structured scenes)
            const drumBlock = (isChild || isChild2 || isAdult || isPostAdult) ? document.createElement('div') : null;
            if (drumBlock) drumBlock.className = 'drum-block';

            rows.forEach(row => {
                const rowEl = document.createElement('div');
                rowEl.className = 'score-row';
                if (row.label.startsWith('Hat') || row.label.startsWith('Snare') || row.label.startsWith('Cymbal') || row.label.startsWith('Bass') || row.label.startsWith('Keys') || row.label.startsWith('Lead')) rowEl.classList.add('preview');

                // THIRTIES: melody preview glow on hovered Keys/Keys2 rows
                if (currentScene === SCENE.THIRTIES && thirtiesHoveredRoom && !thirtiesMelodyConfirmed) {
                    if (row.label === 'Lead') {
                        rowEl.classList.add('melody-preview');
                    }
                }

                const labelEl = document.createElement('div');
                labelEl.className = 'score-label';
                labelEl.textContent = row.label;

                const gridEl = document.createElement('div');
                gridEl.className = 'score-grid';
                gridEl.style.setProperty('--steps', String(displayTotal));

                const stepEls = [];
                const patLen = row.pattern ? row.pattern.length : displayTotal;
                for (let i = 0; i < displayTotal; i++) {
                    const stepEl = document.createElement('div');
                    stepEl.className = 'score-step';
                    if (row.pattern && row.pattern[i]) {
                        stepEl.classList.add('on');
                        stepEl.classList.add(row.styleClass);
                    }
                    // Sustain type classes for visually connected notes
                    if (row.sustainType && row.sustainType[i]) {
                        stepEl.classList.add('sus-' + row.sustainType[i]);
                    }
                    stepEls.push(stepEl);
                    gridEl.appendChild(stepEl);
                }

                rowEl.appendChild(labelEl);
                rowEl.appendChild(gridEl);
                if (drumBlock) {
                    drumBlock.appendChild(rowEl);
                } else {
                    scoreTracks.appendChild(rowEl);
                }
                scoreHudState.rows.push(stepEls);
            });

            if (drumBlock) scoreTracks.appendChild(drumBlock);

            // Apply bar highlights spanning all rows (JOB_HUNT2 modifier tones / TRAVEL page2 bars)
            if ((isJobHunt2 || isTravel) && scoreHudState.rows.length > 0) {
                const barSteps = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
                const totalRows = scoreHudState.rows.length;
                const applyColumnBorder = (barIdx, color, style) => {
                    const barStart = barIdx * barSteps;
                    for (let r = 0; r < totalRows; r++) {
                        const rowSteps = scoreHudState.rows[r];
                        const barEnd = Math.min(barStart + barSteps - 1, rowSteps.length - 1);
                        for (let s = barStart; s <= barEnd && s < rowSteps.length; s++) {
                            // Top border only on first row, bottom only on last row
                            if (r === 0) rowSteps[s].style.borderTop = `2px ${style} ${color}`;
                            if (r === totalRows - 1) rowSteps[s].style.borderBottom = `2px ${style} ${color}`;
                            // Left/right on all rows at bar edges
                            if (s === barStart) rowSteps[s].style.borderLeft = `2px ${style} ${color}`;
                            if (s === barEnd) rowSteps[s].style.borderRight = `2px ${style} ${color}`;
                        }
                    }
                };
                // Permanent highlights from consumed modifiers
                if (scoreHudState.barHighlights) {
                    scoreHudState.barHighlights.forEach(hl => {
                        if (hl.page !== displayPage) return;
                        applyColumnBorder(hl.barIndex, hl.color, 'solid');
                    });
                }
                // Hover preview: show solid border for hovered modifier's target bar (JOB_HUNT2)
                if (previewDropIndex !== null && toneDrops[previewDropIndex] &&
                    toneDrops[previewDropIndex].instrument === "modifier" &&
                    !toneDrops[previewDropIndex].consumed &&
                    displayPage === 1) {
                    const hvDrop = toneDrops[previewDropIndex];
                    applyColumnBorder(hvDrop.targetBarOnPage2, hvDrop.dropColor, 'solid');
                }
                // TRAVEL: always show border on page2 last 2 bars (the varied section)
                if (isTravel && displayPage === 1) {
                    // Find the closest hovered drop for its color, otherwise use a default
                    let travelColor = "rgba(255,255,255,0.5)";
                    toneDrops.forEach(d => {
                        if (d.travelPage2Bars && d.isHovered) travelColor = d.dropColor;
                    });
                    const lastBar0 = baseRhythmInfo.bars - 2;
                    const lastBar1 = baseRhythmInfo.bars - 1;
                    applyColumnBorder(lastBar0, travelColor, 'solid');
                    applyColumnBorder(lastBar1, travelColor, 'solid');
                }
                // Hover preview: highlight page2 varied bars for TRAVEL keyboard tones
                if (isTravel && previewDropIndex !== null && toneDrops[previewDropIndex] &&
                    toneDrops[previewDropIndex].travelPage2Bars && displayPage === 1) {
                    const hvDrop = toneDrops[previewDropIndex];
                    hvDrop.travelPage2Bars.forEach(barIdx => {
                        applyColumnBorder(barIdx, hvDrop.dropColor, 'solid');
                    });
                }
            }

            // Pagination dots for JOB_HUNT2 / TRAVEL
            if (usePagination) {
                const pagDiv = document.createElement('div');
                pagDiv.className = 'score-pagination';
                for (let p = 0; p < scoreHudState.pageCount; p++) {
                    const dot = document.createElement('div');
                    dot.className = 'score-dot';
                    if (p === scoreHudState.currentPage) dot.classList.add('active');
                    pagDiv.appendChild(dot);
                }
                scoreTracks.appendChild(pagDiv);
                scoreHudState.paginationEl = pagDiv;
            }

            if (baseGroove) {
                updateScoreHudPlayhead(baseGroove.step % scoreHudState.totalSteps);
            }
        }

        function updateScoreHudPreviewRow() {
            if (!baseRhythmInfo) return;
            let nextPreview = null;
            let best = -Infinity;
            toneDrops.forEach((drop, i) => {
                if (!drop.isHovered) return;
                if (drop.proximityVol > best) {
                    best = drop.proximityVol;
                    nextPreview = i;
                }
            });
            if (scoreHudState.previewDropIndex === nextPreview) return;
            scoreHudState.previewDropIndex = nextPreview;
            renderScoreRows(nextPreview);
        }

        function buildScoreHud() {
            if (!baseRhythmInfo) return;
            scoreMeta.textContent = `${baseRhythmInfo.beatsPerBar}/4 x ${baseRhythmInfo.bars}  |  ${Math.round(baseRhythmInfo.bpm)} BPM`;
            scoreHudState.previewDropIndex = null;
            // Reset pagination for scenes without pagination
            if (currentScene !== SCENE.JOB_HUNT2 && currentScene !== SCENE.TRAVEL && currentScene !== SCENE.THIRTIES && currentScene !== SCENE.CITY) {
                scoreHudState.pageCount = 1;
                scoreHudState.currentPage = 0;
                scoreHudState.stepsPerPage = 0;
                scoreHudState.barHighlights = [];
            }
            applyScoreHudTheme();
            renderScoreRows(null);
        }

        function updateScoreHudPlayhead(step) {
            if (!scoreHudState.totalSteps) return;

            // Pagination: detect page switch for JOB_HUNT2
            const usePagination = scoreHudState.pageCount > 1 && scoreHudState.stepsPerPage > 0;
            let displayStep = step;
            if (usePagination) {
                const page = Math.floor(step / scoreHudState.stepsPerPage) % scoreHudState.pageCount;
                if (page !== scoreHudState.currentPage) {
                    scoreHudState.currentPage = page;
                    renderScoreRows(scoreHudState.previewDropIndex); // re-render with new page slice
                }
                displayStep = step % scoreHudState.stepsPerPage;
            }

            if (scoreHudState.currentStep === displayStep) return;
            if (scoreHudState.currentStep >= 0) {
                scoreHudState.rows.forEach(row => {
                    row[scoreHudState.currentStep]?.classList.remove('playhead');
                });
            }
            scoreHudState.rows.forEach(row => {
                row[displayStep]?.classList.add('playhead');
            });
            // Update chord cell highlighting
            if (baseRhythmInfo) {
                const barSteps = STEPS_PER_BEAT * baseRhythmInfo.beatsPerBar;
                const effectiveStep = usePagination ? displayStep : step;
                const currentBar = Math.floor(effectiveStep / barSteps) % baseRhythmInfo.bars;
                if (scoreHudState.chordCells) {
                    scoreHudState.chordCells.forEach((cell, i) => {
                        cell.classList.toggle('active', i === currentBar);
                    });
                }
                if (scoreHudState.barLabelCells) {
                    scoreHudState.barLabelCells.forEach((cell, i) => {
                        cell.classList.toggle('active', i === currentBar);
                    });
                }
            }
            scoreHudState.currentStep = displayStep;
        }

        const blobs = [];
        palette.colors.forEach(c => blobs.push(new OrganicBlob(c)));

        animate();
        initOrbPosition();

        // Sound consent modal
        const soundModal = document.getElementById('sound-modal-overlay');
        const soundModalBtn = document.getElementById('sound-modal-btn');
        soundModalBtn.addEventListener('click', async () => {
            soundModal.classList.add('hidden');
            await ensureAudioReady();
            // Start title BGM (use Audio element to avoid CORS with file://)
            titleBgmPlayer = new Audio('sounds/Atokata-1(Fast).mp3');
            titleBgmPlayer.loop = true;
            titleBgmPlayer.volume = 0.4;
            titleBgmPlayer.play().catch(() => {});
            setTimeout(() => { soundModal.style.display = 'none'; }, 600);
        });

        // Start Button (Title -> Choice)
        startBtn.addEventListener('click', async () => {
            await ensureAudioReady();

            // Animation
            document.getElementById('ripple-effect').classList.add('ripple-anim');
            startBtn.style.transform = "scale(0.9)";

            playTitleToneConfirmSound();

            // Fade out title BGM over 1 second
            if (titleBgmPlayer && !titleBgmPlayer.paused) {
                const bgm = titleBgmPlayer;
                const startVol = bgm.volume;
                const fadeStart = Date.now();
                const fadeDur = 1000;
                const fadeStep = () => {
                    const elapsed = Date.now() - fadeStart;
                    if (elapsed >= fadeDur) {
                        bgm.pause();
                        bgm.src = '';
                        titleBgmPlayer = null;
                        return;
                    }
                    bgm.volume = startVol * (1 - elapsed / fadeDur);
                    requestAnimationFrame(fadeStep);
                };
                fadeStep();
            }

            // UI Switch
            uiTitle.style.opacity = 0;
            setTimeout(() => {
                uiTitle.style.display = 'none';
                uiChoice.style.display = 'flex';
                // Trigger reflow
                void uiChoice.offsetWidth;
                uiChoice.style.opacity = 1;

                currentScene = SCENE.CHOICE;
                initProximityAudio();
                // Reposition orb above middle choice button
                setTimeout(() => {
                    const midRect = btnMiddle.getBoundingClientRect();
                    orbWorldX = midRect.left + midRect.width / 2;
                    orbWorldY = midRect.top - 60;
                    updateOrbScreenPosition();
                }, 50);
            }, 1000);
        });

        btnLeft.addEventListener('click', () => {
            void makeChoice('left', palette.colors[1]);
        });
        btnMiddle.addEventListener('click', () => {
            void makeChoice('middle', palette.colors[2]);
        });
        btnRight.addEventListener('click', () => {
            void makeChoice('right', palette.colors[3]);
        });
        btnFast.addEventListener('click', () => {
            void makeChoice('fast', palette.colors[4]);
        });

        function randInt(min, max) {
            return Math.floor(Math.random() * (max - min + 1)) + min;
        }

        const ABC_RULES = {
            4: {
                rule1: ["A","A","A","B","A","A","A","B","A","A","A","B","A","A","A","C"],
                rule2: ["A","A","B","A","A","A","B","A","A","A","B","A","A","B","A","C"],
                rule3: ["A","B","A","A","A","B","A","A","A","B","A","A","A","A","B","C"]
            },
            3: {
                rule1: ["A","A","B","A","A","B","A","A","B","A","A","C"],
                rule2: ["A","B","A","A","B","A","A","B","A","B","A","C"],
                rule3: ["B","A","A","B","A","A","B","A","A","A","B","C"]
            }
        };

        const KICK_MOTIF_SETS = [
            { A:[1,0,0,0], B:[1,0,1,0], C:[0,0,1,0] },
            { A:[1,0,0,0], B:[1,0,0,1], C:[0,1,0,0] },
            { A:[1,0,0,0], B:[1,0,1,0], C:[0,0,0,1] },
            { A:[1,0,0,0], B:[1,0,0,1], C:[0,0,1,0] }
        ];

        const HAT_MOTIF_SETS = [
            { A:[0,0,1,0], B:[0,1,0,1], C:[0,0,0,1] },
            { A:[0,1,0,0], B:[0,0,1,1], C:[0,1,0,1] },
            { A:[0,0,1,0], B:[0,1,1,0], C:[0,0,0,1] },
            { A:[0,1,0,1], B:[0,0,1,0], C:[0,1,0,0] }
        ];

        function rotateArray(arr, offset) {
            const out = [];
            for (let i = 0; i < arr.length; i++) out.push(arr[(i + offset) % arr.length]);
            return out;
        }

        function expandAbcLettersToSteps(letters, motifMap) {
            const steps = [];
            for (const letter of letters) steps.push(...motifMap[letter]);
            return steps;
        }

        function pickKickStepInBeat(kickPattern, beatIndex) {
            const base = beatIndex * STEPS_PER_BEAT;
            for (let i = 0; i < STEPS_PER_BEAT; i++) {
                if (kickPattern[base + i]) return base + i;
            }
            return base;
        }

        function snapHatPatternToKickGrid(hatPattern, kickPattern, variant = 0) {
            const totalBeats = Math.floor(hatPattern.length / STEPS_PER_BEAT);
            const snapped = new Array(hatPattern.length).fill(false);
            const kickHits = [];
            for (let i = 0; i < kickPattern.length; i++) {
                if (kickPattern[i]) kickHits.push(i);
            }
            if (!kickHits.length) return snapped;

            for (let beat = 0; beat < totalBeats; beat++) {
                const base = beat * STEPS_PER_BEAT;
                const hitSlots = [];
                for (let i = 0; i < STEPS_PER_BEAT; i++) {
                    if (hatPattern[base + i]) {
                        hitSlots.push(i);
                    }
                }
                if (!hitSlots.length) continue;

                const slot = hitSlots[Math.min(hitSlots.length - 1, variant % hitSlots.length)];
                const target = base + slot;
                const ranked = kickHits
                    .map(k => ({ k, d: Math.abs(k - target) }))
                    .sort((a, b) => a.d - b.d);
                const pickIdx = Math.min(ranked.length - 1, variant % Math.min(3, ranked.length));
                snapped[ranked[pickIdx].k] = true;
            }
            return snapped;
        }

        function makeAbcSample(beatsPerBar, bars, index) {
            const rules = ABC_RULES[beatsPerBar];
            const ruleNames = Object.keys(rules);
            const ruleName = ruleNames[index % ruleNames.length];
            const baseLetters = rules[ruleName];
            const letters = rotateArray(baseLetters, index % beatsPerBar);

            const kickMotifs = KICK_MOTIF_SETS[index % KICK_MOTIF_SETS.length];
            const hatMotifs = HAT_MOTIF_SETS[(index + 1) % HAT_MOTIF_SETS.length];

            const kickPattern = expandAbcLettersToSteps(letters, kickMotifs);
            const rawHatPattern = expandAbcLettersToSteps(letters, hatMotifs);
            const hatPattern = snapHatPatternToKickGrid(rawHatPattern, kickPattern);

            return {
                id: index + 1,
                ruleName,
                letters,
                beatsPerBar,
                bars,
                kickPattern,
                hatPattern
            };
        }

        function makeAbcPatternBank(beatsPerBar, bars, count = 10) {
            const out = [];
            for (let i = 0; i < count; i++) out.push(makeAbcSample(beatsPerBar, bars, i));
            return out;
        }

        function pickRandom(arr) {
            return arr[randInt(0, arr.length - 1)];
        }

        function makeLeftSparseSample() {
            const letters = [];
            for (let bar = 0; bar < RHYTHM_BARS; bar++) {
                if (bar % 2 === 0) letters.push("A", "N", "N", "B");
                else letters.push("A", "N", "N", "N");
            }
            const kickMotifs = { A:[1,0,0,0], B:[1,0,0,1], C:[0,0,1,0], N:[0,0,0,0] };
            const hatMotifs = { A:[0,1,0,0], B:[0,0,1,0], C:[0,0,0,1], N:[0,0,0,0] };
            const kickPattern = expandAbcLettersToSteps(letters, kickMotifs);
            const rawHat = expandAbcLettersToSteps(letters, hatMotifs);
            return {
                id: 0,
                ruleName: "left_sparse_A--B_A---",
                letters,
                beatsPerBar: 4,
                bars: RHYTHM_BARS,
                kickPattern,
                hatPattern: snapHatPatternToKickGrid(rawHat, kickPattern)
            };
        }

        function spawnBeatRipple(button, volumeDb) {
            const rect = button.getBoundingClientRect();
            const ripple = document.createElement('div');
            ripple.className = 'beat-ripple';
            ripple.style.left = (rect.left + rect.width / 2) + 'px';
            ripple.style.top = (rect.top + rect.height / 2) + 'px';
            const alpha = Math.max(0.12, Math.min(0.36, (volumeDb + 100) / 180));
            ripple.style.background = `rgba(255, 255, 255, ${alpha})`;
            document.body.appendChild(ripple);
            ripple.addEventListener('animationend', () => ripple.remove(), { once: true });
        }

        function createKickTrack(button, bpm, sample) {
            const stepMs = 60000 / bpm / STEPS_PER_BEAT; // 16th-note grid
            return {
                button,
                bpm,
                stepMs,
                beatsPerBar: sample.beatsPerBar,
                bars: sample.bars,
                ruleName: sample.ruleName,
                letters: sample.letters.slice(),
                pattern: sample.kickPattern.slice(),
                hatPattern: sample.hatPattern.slice(),
                step: 0,
                nextTick: 0,
                timer: null,
                volumeDb: -100,
                hoverActive: false,
                running: false,
                synth: new Tone.MembraneSynth({
                    pitchDecay: 0.06,
                    octaves: 5,
                    oscillator: { type: "sine" },
                    envelope: { attack: 0.001, decay: 0.45, sustain: 0, release: 0.25 },
                    volume: -100
                }).toDestination()
            };
        }

        function startKickTrack(track) {
            track.running = true;
            track.nextTick = performance.now() + track.stepMs;
            const tick = () => {
                if (!track.running) return;
                const now = performance.now();
                while (track.nextTick <= now + 4) {
                    if (track.hoverActive && track.pattern[track.step]) {
                        track.synth.volume.value = track.volumeDb;
                        track.synth.triggerAttackRelease("C1", "8n");
                        spawnBeatRipple(track.button, track.volumeDb);
                    }
                    if (track.hoverActive) {
                        track.step = (track.step + 1) % track.pattern.length;
                    }
                    track.nextTick += track.stepMs;
                }
                track.timer = setTimeout(tick, 20);
            };
            tick();
        }

        // Proximity Audio Setup
        function initProximityAudio() {
            // Left: sparse custom, Middle: regular, Right: eager(3/4), Fast: very fast(4/4)
            const leftBpm = randInt(52, 66);
            const middleBpm = randInt(62, 78);
            const rightBpm = Math.max(middleBpm + 12, randInt(84, 108));
            const fastBpm = Math.max(rightBpm + 12, randInt(112, 138));
            const leftBank = makeAbcPatternBank(4, RHYTHM_BARS, 10);
            const middleBank = makeAbcPatternBank(4, RHYTHM_BARS, 10);
            const rightBank = makeAbcPatternBank(3, RHYTHM_BARS, 10);
            const fastBank = makeAbcPatternBank(4, RHYTHM_BARS, 10);
            const leftSample = makeLeftSparseSample() || pickRandom(leftBank);
            const middleSample = pickRandom(middleBank);
            const rightSample = pickRandom(rightBank);
            const fastSample = pickRandom(fastBank);
            choiceRhythm = {
                left: { bpm: leftBpm, sample: leftSample },
                middle: { bpm: middleBpm, sample: middleSample },
                right: { bpm: rightBpm, sample: rightSample },
                fast: { bpm: fastBpm, sample: fastSample }
            };

            // Left: custom sparse, Middle: 4/4 x4, Right: fast 3/4 x4, Fast: very fast 4/4 x4
            leftTrack = createKickTrack(btnLeft, leftBpm, leftSample);
            middleTrack = createKickTrack(btnMiddle, middleBpm, middleSample);
            rightTrack = createKickTrack(btnRight, rightBpm, rightSample);
            fastTrack = createKickTrack(btnFast, fastBpm, fastSample);
            startKickTrack(leftTrack);
            startKickTrack(middleTrack);
            startKickTrack(rightTrack);
            startKickTrack(fastTrack);
        }

        function updateProximityAudio() {
            const getInfo = (btn) => {
                const rect = btn.getBoundingClientRect();
                const cx = rect.left + rect.width/2;
                const cy = rect.top + rect.height/2;
                const dist = Math.sqrt((mouseX-cx)**2 + (mouseY-cy)**2);
                const maxD = 500;
                const vol = dist > maxD ? -100 : (-100 + (1 - dist/maxD) * 105); // -100 to +5
                const isOver = (
                    mouseX >= rect.left &&
                    mouseX <= rect.right &&
                    mouseY >= rect.top &&
                    mouseY <= rect.bottom
                );
                return { btn, dist, vol, isOver };
            };

            const leftInfo = getInfo(btnLeft);
            const middleInfo = getInfo(btnMiddle);
            const rightInfo = getInfo(btnRight);
            const fastInfo = getInfo(btnFast);

            if(leftTrack) leftTrack.volumeDb = leftInfo.vol;
            if(middleTrack) middleTrack.volumeDb = middleInfo.vol;
            if(rightTrack) rightTrack.volumeDb = rightInfo.vol;
            if(fastTrack) fastTrack.volumeDb = fastInfo.vol;

            const setTrackHoverState = (track, active) => {
                if (!track) return;
                if (active && !track.hoverActive) {
                    // Start from bar-1 beat-1 whenever hovered.
                    track.step = 0;
                    track.nextTick = performance.now() + 10;
                }
                track.hoverActive = active;
            };
            // Sound/ripple only when the cursor is directly over the button.
            setTrackHoverState(leftTrack, leftInfo.isOver);
            setTrackHoverState(middleTrack, middleInfo.isOver);
            setTrackHoverState(rightTrack, rightInfo.isOver);
            setTrackHoverState(fastTrack, fastInfo.isOver);

            // Visual Hover: always keep exactly one button hovered (nearest one).
            const candidates = [leftInfo, middleInfo, rightInfo, fastInfo].sort((a, b) => a.dist - b.dist);
            btnLeft.classList.remove('hovered');
            btnMiddle.classList.remove('hovered');
            btnRight.classList.remove('hovered');
            btnFast.classList.remove('hovered');
            candidates[0].btn.classList.add('hovered');
        }

        function stopProximityAudio() {
            const stopTrack = (track) => {
                if (!track) return;
                track.running = false;
                if (track.timer) clearTimeout(track.timer);
                if (track.synth) track.synth.dispose();
            };
            stopTrack(leftTrack);
            stopTrack(middleTrack);
            stopTrack(rightTrack);
            stopTrack(fastTrack);
            leftTrack = null;
            middleTrack = null;
            rightTrack = null;
            fastTrack = null;
        }

        function playTitleToneConfirmSound() {
            const synth = new Tone.PolySynth(Tone.Synth, {
                volume: -12,
                oscillator: { type: 'sine' },
                envelope: { attack: 0.005, decay: 0.6, sustain: 0.01, release: 1.2 }
            }).toDestination();
            synth.triggerAttackRelease(["C5", "E5", "G5", "B5"], "4n");
            setTimeout(() => synth.dispose(), 1400);
        }

        function playKickChoiceConfirmSound() {
            const synth = new Tone.PolySynth(Tone.Synth, {
                volume: -14,
                oscillator: { type: 'sine' },
                envelope: { attack: 0.003, decay: 0.5, sustain: 0.01, release: 1.0 }
            }).toDestination();
            synth.triggerAttackRelease(["D5", "F#5", "A5"], "8n");
            setTimeout(() => {
                synth.triggerAttackRelease(["D6"], "8n");
                setTimeout(() => synth.dispose(), 600);
            }, 120);
        }

        // getToneDropAtScreenPoint removed — selection now via tune bubble

        function transitionToLevel2(clickedDrop) {
            if (level2TransitionLock || currentScene !== SCENE.CRAWL) return;
            level2TransitionLock = true;
            playTitleToneConfirmSound();
            addVolumeTrack('hat');
            if (clickedDrop.toy) selectedToys.push(clickedDrop.toy);
            inheritedHatPattern = clickedDrop.pattern ? clickedDrop.pattern.slice() : null;
            inheritedHatStyleClass = clickedDrop.hudStyleClass || 'hat';
            inheritedHatSoundConfig = clickedDrop.hatSoundConfig ? { ...clickedDrop.hatSoundConfig } : null;
            const hatVolNow = clickedDrop.hatClosedSynth?.volume?.value;
            inheritedHatVolumeDb = (Number.isFinite(hatVolNow) && hatVolNow > -90) ? hatVolNow : -25;
            const sx = clickedDrop.x - cameraX;
            const sy = clickedDrop.y;
            const ripple = document.createElement('div');
            ripple.className = 'ripple ripple-anim';
            ripple.style.position = 'fixed';
            ripple.style.left = (sx - 40) + 'px';
            ripple.style.top = (sy - 40) + 'px';
            document.body.appendChild(ripple);
            fadeScreenTo(1, 1200);
            setTimeout(() => {
                finishLevel2Transition();
                fadeScreenTo(0, 1300);
                ripple.remove();
            }, 1200);
        }

        // Choice Click (Choice -> Crawl)
        async function makeChoice(side, color) {
            if(currentScene !== SCENE.CHOICE) return;
            await ensureAudioReady();
            
            chosenColor = color;
            currentScene = SCENE.TRANSITION;
            addVolumeTrack('kick');
            const chosenSide = side;
            const sideState = choiceRhythm[chosenSide];
            baseRhythmBpm = sideState ? sideState.bpm : 72;
            Tone.Transport.bpm.value = baseRhythmBpm;
            const chosenTrack = chosenSide === 'left'
                ? leftTrack
                : (chosenSide === 'middle'
                    ? middleTrack
                    : (chosenSide === 'right' ? rightTrack : fastTrack));
            if (chosenTrack) {
                baseRhythmInfo = {
                    bpm: chosenTrack.bpm,
                    beatsPerBar: chosenTrack.beatsPerBar,
                    bars: chosenTrack.bars,
                    ruleName: chosenTrack.ruleName,
                    letters: chosenTrack.letters.slice(),
                    kickPattern: chosenTrack.pattern.slice(),
                    baseHatPattern: chosenTrack.hatPattern.slice()
                };
            }

            // Capture button center before hiding the choice UI.
            const targetBtn = chosenSide === 'left'
                ? btnLeft
                : (chosenSide === 'middle'
                    ? btnMiddle
                    : (chosenSide === 'right' ? btnRight : btnFast));
            const rect = targetBtn.getBoundingClientRect();
            
            stopProximityAudio();
            startBaseGroove();
            uiChoice.style.pointerEvents = 'none';

            // Same ripple behavior as start button.
            const ripple = document.createElement('div');
            ripple.className = 'ripple ripple-anim';
            ripple.style.position = 'fixed';
            ripple.style.left = (rect.left + rect.width / 2 - 40) + 'px';
            ripple.style.top = (rect.top + rect.height / 2 - 40) + 'px';
            document.body.appendChild(ripple);

            targetBtn.style.transform = "scale(0.9)";

            setTimeout(() => {
                uiChoice.style.display = 'none';
                ripple.remove();
                fadeScreenTo(1, 1400);
                setTimeout(() => {
                    finishTransition();
                    fadeScreenTo(0, 1500);
                }, 1400);
            }, 1000);

            playKickChoiceConfirmSound();
        }

        function finishTransition() {
            currentScene = SCENE.CRAWL;
            floorColor = pickFloorColor();
            baby = new Baby(babyColorScheme);
            selectedToys = [];
            inheritedHatPattern = null;
            inheritedHatStyleClass = 'hat';
            inheritedHatSoundConfig = null;
            inheritedHatVolumeDb = -25;
            disposeCarryHatLayer();
            initToneDrops();
            buildScoreHud();
            updateScoreToggleUi();
            orbWorldX = baby.x;
            orbWorldY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            orbParticles = [];
        }

        function finishLevel2Transition() {
            currentScene = SCENE.CRAWL2;
            if (baby) {
                baby.scale = 0.95;
            } else {
                baby = new Baby(babyColorScheme);
                baby.scale = 0.95;
            }
            initSnareDrops();
            initCarryHatLayer();
            buildScoreHud();
            updateScoreToggleUi();
            level2TransitionLock = false;
            orbWorldX = baby.x;
            orbWorldY = height * ROOM_WALL_RATIO + TONE_FLOOR_OFFSET;
            orbParticles = [];
        }

        function transitionToToddler1(clickedDrop) {
            if (toddlerTransitionLock || currentScene !== SCENE.CRAWL2) return;
            toddlerTransitionLock = true;
            playTitleToneConfirmSound();
            addVolumeTrack('snare');
            if (clickedDrop.toy) selectedToys.push(clickedDrop.toy);
            inheritedSnarePattern = clickedDrop.pattern ? clickedDrop.pattern.slice() : null;
            inheritedSnareVelocity = clickedDrop.velocityPattern ? clickedDrop.velocityPattern.slice() : null;
            inheritedSnareStyleClass = clickedDrop.hudStyleClass || 'snare';
            inheritedSnareSoundConfig = clickedDrop.snareSoundConfig ? { ...clickedDrop.snareSoundConfig } : null;
            const snareVolNow = clickedDrop.snareSynth?.volume?.value;
            const snareBodyVolNow = clickedDrop.snareBody?.volume?.value;
            inheritedSnareVolumeDb = (Number.isFinite(snareVolNow) && snareVolNow > -90) ? snareVolNow : -20;
            inheritedSnareBodyVolumeDb = (Number.isFinite(snareBodyVolNow) && snareBodyVolNow > -90) ? snareBodyVolNow : -18;
            const sx = clickedDrop.x - cameraX;
            const sy = clickedDrop.y;
            const ripple = document.createElement('div');
            ripple.className = 'ripple ripple-anim';
            ripple.style.position = 'fixed';
            ripple.style.left = (sx - 40) + 'px';
            ripple.style.top = (sy - 40) + 'px';
            document.body.appendChild(ripple);
            fadeScreenTo(1, 1200);
            setTimeout(() => {
                finishToddlerTransition();
                fadeScreenTo(0, 1300);
                ripple.remove();
            }, 1200);
        }

